# ЖУРНАЛ ПОМИЛОК — усе, що зламалось, видно в адмінці
# ══════════════════════════════════════════════════════════════════
# Проблема: 232 місця в коді пишуть logger.warning/error. Усе летить
# у Railway-логи, куди власниця не заглядає. Помилки живуть тижнями.
#
# Рішення: перехоплювач ловить КОЖЕН warning/error автоматично і кладе
# в БД. Нічого не треба переписувати — працює для всіх 232 місць одразу.
#
# Видно: адмінка → ⚙️ Система → 🚨 Помилки

_ERR_MAX      = 200    # більше не тримаємо — старі витісняються
_ERR_DEDUP_S  = 300    # та сама помилка частіше ніж раз на 5 хв → рахуємо, не дублюємо

# Шум, який НЕ помилка (мережеві таймаути, юзер заблокував бота тощо)
_ERR_IGNORE = (
    "Query is too old",
    "Message is not modified",
    "message to edit not found",
    "bot was blocked by the user",
    "user is deactivated",
    "Forbidden: bot can't initiate",
    "Timed out",
    "httpx",
)


def _err_key(msg: str) -> str:
    """Ключ для дедуплікації — перші 80 символів без чисел."""
    import re as _re
    return _re.sub(r"\d+", "#", (msg or "")[:80])


def _err_log(level: str, msg: str, where: str = ""):
    """Кладе помилку в БД. Тихо — сам ніколи не падає."""
    try:
        if not msg:
            return
        for ign in _ERR_IGNORE:
            if ign.lower() in msg.lower():
                return

        import time as _t
        db  = load_db()
        arr = db.get("_errors", [])
        if not isinstance(arr, list):
            arr = []

        now = int(_t.time())
        key = _err_key(msg)

        # Та сама помилка нещодавно → збільшуємо лічильник
        for e in arr:
            if e.get("key") == key and (now - e.get("last", 0)) < _ERR_DEDUP_S:
                e["count"] = e.get("count", 1) + 1
                e["last"]  = now
                db["_errors"] = arr
                save_db(db)
                # Повторюється часто → системна проблема, треба сказати
                why = _alert_should(msg, e["count"])
                if why:
                    _alert_queue.append((str(msg)[:300], where, e["count"], why))
                return

        arr.insert(0, {
            "key":   key,
            "level": level,
            "msg":   str(msg)[:500],
            "where": where[:120],
            "first": now,
            "last":  now,
            "count": 1,
            "seen":  False,
        })
        db["_errors"] = arr[:_ERR_MAX]
        save_db(db)

        # 🔔 Алерт власниці — тільки якщо серйозно (гроші/база або 5+ повторів)
        if level == "error":
            why = _alert_should(msg, 1)
            if why:
                _alert_queue.append((str(msg)[:300], where, 1, why))
    except Exception:
        pass   # журнал помилок не має права зламати бота


class _ErrHandler(logging.Handler):
    """Перехоплює logger.warning / error / exception → у БД."""
    def emit(self, record):
        try:
            if record.levelno < logging.WARNING:
                return
            # Не ловимо власні помилки збереження — рекурсія
            if record.name.startswith(("httpx", "telegram.vendor", "asyncio")):
                return
            _err_log(
                "error" if record.levelno >= logging.ERROR else "warning",
                record.getMessage(),
                f"{record.module}:{record.lineno}",
            )
        except Exception:
            pass


