def _err_classify(exc: Exception) -> tuple:
    """Розпізнає тип помилки → (ключ, повідомлення юзеру, діагноз)."""
    txt = f"{type(exc).__name__} {exc}".lower()
    for marks, key, user_msg, diag in _ERR_KINDS:
        if any(m in txt for m in marks):
            return key, user_msg, diag
    return "unknown", _ERR_FALLBACK, "Невідома помилка. Дивись текст нижче."


