_ACTION_RETRY = {
    "start_lesson":    "retry_lesson",
    "show_progress":   "retry_progress",
    "open_diagnostic": "retry_diag",
}


async def guard(update, ctx, exc: Exception, what: str = "", retry_cb: str = ""):
    """
    Асистент помилок. Кличеться з except.

    update   — Update (щоб знати кому писати)
    exc      — сам виняток
    what     — що робили ("урок дня", "розмова з Chainy")
    retry_cb — callback_data кнопки «Спробувати ще» (необов'язково)

    Ніколи не падає сам.
    """
    key, user_msg, diag = _err_classify(exc)

    # 1. У журнал — з діагнозом
    try:
        _err_log(
            "error",
            f"[{what or 'дія'}] {type(exc).__name__}: {exc}",
            f"guard:{key}",
        )
    except Exception:
        pass

    # 2. Юзеру — людською мовою
    if not user_msg:
        return   # фонова помилка, юзера не турбуємо

    try:
        chat_id = None
        if getattr(update, "effective_chat", None):
            chat_id = update.effective_chat.id
        elif getattr(update, "effective_user", None):
            chat_id = update.effective_user.id
        if not chat_id:
            return

        kb = None
        if retry_cb:
            kb = InlineKeyboardMarkup([[
                InlineKeyboardButton("🔄 Спробувати ще", callback_data=retry_cb)
            ]])

        head = f"*{what}*\n\n" if what else ""
        await ctx.bot.send_message(
            chat_id=chat_id,
            text=head + user_msg,
            parse_mode="Markdown",
            reply_markup=kb,
        )
    except Exception:
        pass   # навіть повідомлення про помилку не має ламати бота


# ── АЛЕРТИ ВЛАСНИЦІ ──────────────────────────────────────────────
# ПРАВИЛО: не засмічувати. Алерт іде ТІЛЬКИ якщо:
#   1. Помилка стосується ГРОШЕЙ або БАЗИ (втрата даних) — одразу
#   2. Та сама помилка повторилась 5+ разів за годину — щось системне
# Решта — тихо в журнал, дивись коли зручно.

_ALERT_COOLDOWN_S = 1800   # той самий алерт не частіше ніж раз на 30 хв
_ALERT_REPEAT     = 5      # скільки повторів, щоб вважати системним
_ALERT_SENT: dict = {}     # key → коли востаннє слали
_alert_queue: list = []    # синхронний _err_log кладе сюди, async job розсилає

# Помилки, які НЕ можна пропустити
_ALERT_CRITICAL = (
    "wayforpay", "payment", "invoice", "оплат",     # гроші
    "database", "postgres", "pool", "save_db",       # база
)


def _alert_should(msg: str, count: int) -> str:
    """Чи слати алерт? Повертає причину або ''."""
    low = (msg or "").lower()
    for m in _ALERT_CRITICAL:
        if m in low:
            return "critical"
    if count >= _ALERT_REPEAT:
        return "repeat"
    return ""


async def _alert_owner(app, msg: str, where: str, count: int, why: str):
    """Пише власниці в Telegram. Тихо — сам ніколи не падає."""
    try:
        import time as _t
        key = _err_key(msg)
        now = int(_t.time())
        if now - _ALERT_SENT.get(key, 0) < _ALERT_COOLDOWN_S:
            return                       # нещодавно вже слали
        _ALERT_SENT[key] = now

        if why == "critical":
            head = "🔴 *КРИТИЧНО*\n_Гроші або база — не ігноруй._"
        else:
            head = f"⚠️ *Помилка повторюється*\n_{count} разів за годину — схоже на системну._"

        txt = (
            f"{head}\n\n"
            f"`{str(msg)[:250]}`\n\n"
            f"📍 {where}\n\n"
            f"Деталі: /admin → ⚙️ Система → 🚨 Помилки"
        )
        await app.bot.send_message(chat_id=ADMIN_ID, text=txt, parse_mode="Markdown")
    except Exception:
        pass


async def job_flush_alerts(ctx: ContextTypes.DEFAULT_TYPE):
    """Розсилає накопичені алерти. Раз на хвилину — щоб не спамити."""
    if not _alert_queue:
        return
    batch = _alert_queue[:5]
    del _alert_queue[:len(batch)]
    for msg, where, count, why in batch:
        try:
            await _alert_owner(ctx.application, msg, where, count, why)
        except Exception:
            pass


