def _change_log(kind: str, what: str, detail: str = ""):
    """Записує подію в журнал змін. Тихо — сам не падає.

    kind: 'switch' | 'fix' | 'deploy' | 'admin'
    """
    try:
        import time as _t
        db  = load_db()
        arr = db.get("_changes", [])
        if not isinstance(arr, list):
            arr = []
        arr.insert(0, {
            "kind":   kind,
            "what":   str(what)[:200],
            "detail": str(detail)[:200],
            "at":     int(_t.time()),
        })
        db["_changes"] = arr[:150]
        save_db(db)
    except Exception:
        pass


def _changes_state() -> dict:
    """Журнал змін для адмінки: версії + події."""
    try:
        arr = load_db().get("_changes", [])
        if not isinstance(arr, list):
            arr = []
    except Exception:
        arr = []

    import time as _t
    now = int(_t.time())

    def _ago(ts):
        d = now - int(ts or 0)
        if d < 60:    return "щойно"
        if d < 3600:  return f"{d // 60} хв тому"
        if d < 86400: return f"{d // 3600} год тому"
        return f"{d // 86400} дн тому"

    ICON = {"switch": "🎛", "fix": "🔧", "deploy": "🚀", "admin": "👤"}
    events = [{
        "icon":   ICON.get(e.get("kind"), "•"),
        "what":   e.get("what", ""),
        "detail": e.get("detail", ""),
        "ago":    _ago(e.get("at")),
    } for e in arr[:60]]

    return {
        "version":   BOT_VERSION,
        "changelog": CHANGELOG,
        "events":    events,
    }


