def _role_of(uid: int) -> str:
    """Хто це. Порядок важливий: адмін > розробник > блогер > учень."""
    try:
        if is_admin(uid):
            return "admin"
        if is_developer(uid):
            return "dev"
        if is_blogger(uid):
            return "blogger"
    except Exception:
        pass
    return "student"


async def _apply_menu(bot, uid: int, role: str = ""):
    """Ставить меню одній людині за її роллю. Тихо — не падає."""
    from telegram import (
        BotCommand, MenuButtonCommands, MenuButtonWebApp, WebAppInfo,
    )
    role = role or _role_of(uid)
    try:
        if role == "student":
            # Учениці — додаток (якщо рубильник увімкнено)
            if SHELL_ENABLED:
                await bot.set_chat_menu_button(
                    chat_id=uid,
                    menu_button=MenuButtonWebApp(
                        text="Open", web_app=WebAppInfo(url=SHELL_URL)
                    ),
                )
            else:
                await bot.set_chat_menu_button(
                    chat_id=uid, menu_button=MenuButtonCommands()
                )
            return

        # Персоналу — СПИСОК КОМАНД, не «Open».
        # Інакше вони не бачать /admin, /switches, /blogger.
        MENUS = {"blogger": MENU_BLOGGER, "admin": MENU_ADMIN, "dev": MENU_DEV}
        cmds = MENUS.get(role, [])
        if cmds:
            await bot.set_my_commands(
                [BotCommand(c, d) for c, d in cmds],
                scope={"type": "chat", "chat_id": uid},
            )
        await bot.set_chat_menu_button(
            chat_id=uid, menu_button=MenuButtonCommands()
        )
    except Exception as e:
        logger.warning(f"menu {role} {uid}: {e}")


async def _apply_menus_all(bot):
    """Розставляє меню всьому персоналу. Кличеться в post_init."""
    done = {"admin": 0, "dev": 0, "blogger": 0}
    try:
        staff = []
        if ADMIN_ID:
            staff.append((int(ADMIN_ID), "admin"))
        for u in _SUB_ADMINS:
            staff.append((int(u), "admin"))
        for u in _DEV_IDS:
            staff.append((int(u), "dev"))
        for u in get_registered_bloggers().keys():
            try:
                staff.append((int(u), "blogger"))
            except Exception:
                pass

        seen = set()
        for uid, role in staff:
            if uid in seen:
                continue          # адмін-блогер лишається адміном (перший виграв)
            seen.add(uid)
            await _apply_menu(bot, uid, role)
            done[role] = done.get(role, 0) + 1

        logger.info(
            f"Меню: {done['admin']} адмін, {done['dev']} dev, {done['blogger']} блогер"
        )
    except Exception as e:
        logger.warning(f"_apply_menus_all: {e}")


def _err_install():
    """Вішаємо перехоплювач. Кличеться в post_init, коли БД уже готова."""
    try:
        h = _ErrHandler()
        h.setLevel(logging.WARNING)
        logging.getLogger().addHandler(h)
        logger.info("🚨 Журнал помилок увімкнено — дивись в адмінці")
    except Exception as e:
        logger.warning(f"err_install: {e}")

