# ── КИЇВСЬКИЙ ЧАС ───────────────────────────────────────────────
#
# ПРОБЛЕМА
# ────────
# Railway працює в UTC. `datetime.now()` дає час СЕРВЕРА, не Києва —
# влітку різниця 3 години, взимку 2.
#
# Для більшості місць це неважливо (лічильники, ключі тижня).
# Але там, де час БАЧИТЬ ЛЮДИНА, це прямий обман: блогер пише
# «завтра 19:00», а бот рахує «завтра» від UTC-опівночі. О 01:00
# за Києвом «завтра» для бота — це ще сьогодні.
#
# ЧОМУ НЕ МІНЯЄМО ВСІ 213 `datetime.now()`
# ────────────────────────────────────────
# Бо це зламало б усе, що вже налаштоване на UTC: job'и о 9:00,
# ключі тижня, дати оплат. Міняємо ТІЛЬКИ там, де час показують
# людині. Решта хай живе в UTC — вона там і має жити.
#
# ЛІТНІЙ / ЗИМОВИЙ ЧАС
# ────────────────────
# Київ: UTC+2 взимку, UTC+3 влітку. Жорстка константа помилялась би
# пів року. Європа переходить в останню неділю березня і жовтня.

def _kyiv_offset(dt_utc: datetime) -> int:
    """UTC-зсув Києва на конкретну дату: +3 влітку, +2 взимку.

    Перехід — остання неділя березня (вперед) і жовтня (назад),
    о 01:00 UTC. Рахуємо самі, щоб не тягнути залежність pytz/zoneinfo,
    якої може не бути в контейнері.
    """
    y = dt_utc.year

    def last_sunday(month: int) -> datetime:
        # 31-ше число місяця, відступаємо назад до неділі
        d = datetime(y, month, 31, 1, 0, tzinfo=timezone.utc)
        while d.weekday() != 6:               # 6 = неділя
            d -= timedelta(days=1)
        return d

    return 3 if last_sunday(3) <= dt_utc < last_sunday(10) else 2


def kyiv_now() -> datetime:
    """Поточний час у Києві. Для всього, що бачить людина."""
    u = datetime.now(timezone.utc)
    return u.astimezone(timezone(timedelta(hours=_kyiv_offset(u))))


def local_time_for(s: dict, hhmm: str) -> str:
    """Переводить київський час у час учениці.

        local_time_for(s, "19:00")  →  "18:00"   (для Варшави, UTC+1... +2)

    НАВІЩО
    ──────
    Учениці в Польщі, Німеччині, Канаді. «Live о 19:00» без пояса —
    це запрошення, на яке половина запізниться або прийде дарма.

    Пояс уже зберігається: `utc_offset` у стані, заповнюється при
    /start (guess_utc_offset) і міняється через /timezone.

    Повертає "" якщо:
      • поясу немає — тоді просто нічого не показуємо, без вигадок
      • пояс збігається з київським — показувати те саме двічі безглуздо
    """
    import re as _re

    off = s.get("utc_offset")
    if off is None:
        return ""

    m = _re.match(r"^(\d{1,2}):(\d{2})$", (hhmm or "").strip())
    if not m:
        return ""

    kyiv_off = _kyiv_offset(datetime.now(timezone.utc))
    try:
        delta = int(off) - kyiv_off
    except (TypeError, ValueError):
        return ""

    if delta == 0:
        return ""                       # той самий пояс — не дублюємо

    h = (int(m.group(1)) + delta) % 24
    return f"{h:02d}:{m.group(2)}"


# ── Кеш для Claude відповідей ────────────────────────
import time as _time
_CLAUDE_CACHE: dict = {}

def claude_cache_get(key: str):
    entry = _CLAUDE_CACHE.get(key)
    if entry and _time.time() < entry["exp"]:
        return entry["v"]
    return None

def claude_cache_set(key: str, value, ttl_hours: int = 24):
    _CLAUDE_CACHE[key] = {"v": value, "exp": _time.time() + ttl_hours * 3600}


