# ══════════════════════════════════════════════════════════════════
# РУБИЛЬНИКИ — приймають БУДЬ-ЯКИЙ здоровий глузд
# ══════════════════════════════════════════════════════════════════
# Раніше SHELL_ENABLED чекав "1", а решта — "true". Написав не те —
# рубильник мовчки вимикався. Тепер працює будь-що:
#   УВІМК:  1  true  yes  on  y  t  так  вкл  ✅  (регістр не важливий)
#   ВИМК:   0  false no  off n  f  ні   викл  (і будь-яке сміття)
_FLAG_ON  = {"1", "true", "yes", "on", "y", "t", "так", "вкл", "✅", "+"}
_FLAG_OFF = {"0", "false", "no", "off", "n", "f", "ні", "нi", "викл", "❌", "-", ""}

def _flag(name: str, default: bool = True) -> bool:
    """ENV-рубильник. Розуміє 1/true/yes/on/так. Невідоме → default + WARNING."""
    raw = os.environ.get(name)
    if raw is None:
        return default
    v = str(raw).strip().lower()
    if v in _FLAG_ON:
        return True
    if v in _FLAG_OFF:
        return False
    # Хтось написав щось дивне — не мовчимо, кричимо в лог
    logger.warning(
        f"⚠️ РУБИЛЬНИК {name}='{raw}' — не розпізнано! "
        f"Вмикай: 1/true/yes/on. Вимикай: 0/false/no/off. "
        f"Зараз працює ДЕФОЛТ ({'увімк' if default else 'вимк'})."
    )
    return default


SHELL_ENABLED = _flag("SHELL_ENABLED", True)

