def shell_url(screen: str, **params) -> str:
    """Посилання на екран усередині оболонки.

        shell_url("s-buddy")                        → …/index_v2.html?s=s-buddy
        shell_url("s-buddy", context="video", vid=X) → …?s=s-buddy&context=video&vid=X

    Контекст (video / checkin) передається далі — мініап його читає
    так само, як читав у standalone-версії. Нічого не губиться.
    """
    import urllib.parse as _up

    if not SHELL_ENABLED:
        # Відкат: старий окремий файл. Працює, лише якщо файл є в репо.
        f = _SHELL_SCREENS.get(screen)
        if not f:
            return SHELL_URL
        u = GITHUB_PAGES_URL.rstrip("/") + "/" + f
        return u + ("?" + _up.urlencode(params) if params else "")

    q = {"s": screen}
    q.update({k: v for k, v in params.items() if v not in (None, "")})
    sep = "&" if "?" in SHELL_URL else "?"
    return SHELL_URL + sep + _up.urlencode(q)
