async def wfp_verify_webhook(data: dict) -> bool:
    """Перевіряє підпис webhook від Wayforpay."""
    sign_params = [
        data.get("merchantAccount", ""),
        data.get("orderReference", ""),
        data.get("amount", ""),
        data.get("currency", ""),
        data.get("authCode", ""),
        data.get("cardPan", ""),
        data.get("transactionStatus", ""),
        data.get("reasonCode", ""),
    ]
    expected = wfp_sign(sign_params)
    received = data.get("merchantSignature", "")
    logger.info(f"WFP webhook: expected={expected}, received={received}")
    return expected == received

def wfp_parse_order(order_ref: str) -> tuple:
    """Розбирає orderReference → (user_id, plan)."""
    try:
        # формат: sc_basic_123456_1234567890
        parts   = order_ref.split("_")
        plan    = parts[1]
        user_id = int(parts[2])
        return user_id, plan
    except Exception:
        return 0, ""

# ── Wayforpay Webhook Handler ─────────────────────────
# ══════════════════════════════════════════════════════════════════
# ЗАПОБІЖНИК ДЛЯ URL МІНІАПІВ
#
# Telegram: reply_markup ≤ 10 240 байт. Ми передаємо дані в мініап
# ЧЕРЕЗ URL (?d=<json>) — тому довгий JSON ламає всю клавіатуру,
# і повідомлення НЕ ВІДПРАВЛЯЄТЬСЯ ВЗАГАЛІ.
#
# Помилка при цьому маскується: BadRequest успадкований від
# NetworkError у PTB, тому error_handler (25698) записував її як
# "Telegram network issue" і мовчки ковтав. Симптом для власниці:
# «профіль не відкривається», і жодного натяку на причину.
#
# Цей запобіжник — остання лінія. Він не рятує дані, але:
#   1) не дає клавіатурі впасти мовчки
#   2) пише В ЛОГ ЧЕСНУ ПРИЧИНУ з назвою мініапа й розміром
# ══════════════════════════════════════════════════════════════════
_TG_MARKUP_LIMIT = 10240
_URL_SAFE_LIMIT  = 3500   # на один мініап-URL; у профілі їх кілька


def _guard_miniapp_url(url: str, name: str, uid: int = 0) -> str:
    """Ловить надто довгий URL ДО того, як Telegram відмовить."""
    n = len(url.encode("utf-8"))
    if n > _URL_SAFE_LIMIT:
        logger.error(
            "MINIAPP URL ЗАВЕЛИКИЙ: %s = %s байт (ліміт %s), uid=%s. "
            "Клавіатура впаде з 'Reply markup is too long'. "
            "Скоротіть дані в URL — не додавайте списки без зрізу.",
            name, n, _URL_SAFE_LIMIT, uid,
        )
    return url


def _build_chain_dashboard_url(uid: int, s: dict, db: dict | None = None) -> str:
    """
    Будує URL для Chain Dashboard з даними юзера.
    db — передавати якщо вже є (уникає зайвого load_db()).
    Один прохід по БД для top + leaderboard одночасно.
    """
    import json as _json, urllib.parse as _ul
    if db is None:
        db = load_db()

    chain   = get_chain(s)
    friends = []

    # Збираємо друзів
    ref_uid = s.get("referrer_uid")
    if ref_uid:
        ref_s = db.get(str(ref_uid), {})
        if isinstance(ref_s, dict) and ref_s.get("name"):
            friends.append({
                "name":  ref_s.get("name", "Друг"),
                "chain": get_chain(ref_s).get("length", 0),
                "role":  "friend",
            })

    # Один прохід: top + leaderboard одночасно
    top_chain, top_name = 0, ""
    uid_str   = str(uid)

    # ── Повний лідерборд для ВСІХ періодів (усі 6 категорій) через спільну функцію ──
    # Дані всіх періодів одразу → фронт перемикає миттєво, без нових запитів.
    def _slim(u):
        # компактний entry для дашборду — без важких полів (ref_friends/badges),
        # щоб URL не перевищив ліміт Telegram (reply markup too long)
        d = u.get("consist", [])
        consist_pct = round(sum(1 for x in d if x) / len(d) * 100) if d else 0
        return {
            "name":   u.get("name", ""),
            "chain":  u.get("chain", 0),
            "xp":     u.get("xp", 0),
            "streak": u.get("streak", 0),
            "jump":   u.get("jump", 0),
            "consist": consist_pct,          # вже відсоток, не масив
            "ref_chained": u.get("ref_chained", 0),
            "me":     u.get("me", False),
        }
    def _top8(period):
        _users, _, _ = _compute_leaderboard_users(db, uid, s, period)
        _t7  = [u for u in _users if not u["me"]][:7]
        _me  = next((u for u in _users if u["me"]), None)
        _out = _t7 + ([_me] if _me else [])
        _out.sort(key=lambda x: x["chain"], reverse=True)
        return [_slim(u) for u in _out]
    # У URL кладемо лише дефолтний період (all); day/week/month фронт довантажить fetch-ом
    lb = _top8("all")
    _lb_users, _lb_friend, _lb_overtook = _compute_leaderboard_users(db, uid, s, "all")
    # top (не сам юзер) — для вкладки Мережа (по повній довжині)
    for _u in _lb_users:
        _cl = _u.get("chain_all", _u.get("chain", 0))
        if not _u.get("me") and _cl > top_chain:
            top_chain = _cl
            top_name  = _u.get("name", "")
    # lb вже обчислено вище (_top8('all')) — дефолтний період для першого показу

    p = get_prices(s)
    boost_until  = s.get("xp_boost_until", "")
    today_str    = datetime.now().strftime("%Y-%m-%d")
    boost_active = bool(boost_until and boost_until >= today_str)
    boost_days   = 0
    if boost_active:
        try:
            boost_days = max(1, (datetime.strptime(boost_until, "%Y-%m-%d") - datetime.now()).days + 1)
        except Exception:
            boost_days = 1

    data = {
        "name":              s.get("name", ""),
        "uid":               uid,
        # ⚠️ has_access — ЩОБ ГОЛОВНИЙ ЕКРАН НЕ БРЕХАВ ПРО ЗАМОК.
        #
        # У s-home блок Speaking Buddy мав ЗАШИТИЙ бейдж «PREMIUM» і замок
        # «🔒 Розблокуй AI-розмови з Premium» — статично, у розмітці.
        # Дві помилки одразу:
        #   1) Chainy доступний і в Basic (bot.py: Basic → status='paid'),
        #      а не тільки в Premium — бейдж брехав
        #   2) замок висів НАВІТЬ У ТОГО, ХТО ВЖЕ ЗАПЛАТИВ: людина щойно
        #      купила Basic, заходить — і бачить «розблокуй». Це найгірший
        #      момент для сумніву в покупці.
        #
        # Мініап не міг цього знати: у D не було ЖОДНОГО поля про доступ.
        # Тепер є. Те саме поле вже віддається в paywall (р. ~2031) —
        # логіка спільна, джерело правди одне.
        "has_access":        is_in_trial(s) or is_premium(s),
        "chain_length":      chain.get("length", 0),
        "chain_status":      chain.get("status", "new"),
        "trial_links":       7,
        "xp_total":          s.get("xp_total", 0),
        "xp_boost":          boost_active,
        "xp_boost_days":     boost_days,
        "identity_state":    s.get("identity_state", "new"),
        "done_lessons":      len(s.get("done_lessons", [])),
        "streak_days":       s.get("streak_days", 0),
        "best_streak":       s.get("best_streak", 0),
        # ⚠️ friends[:10] — НЕ КОСМЕТИКА, ЦЕ ФІКС ПАДІННЯ ПРОФІЛЮ.
        #
        # УВАГА, ЩОБ НЕ СПЛУТАТИ: тут ідеться про дані, ЗАКОДОВАНІ В URL
        # кнопки-мініапа. Це НЕ база даних. База — PostgreSQL, і вона
        # працює нормально. Проблема суто в довжині ПОСИЛАННЯ.
        #
        # Було: увесь список друзів запаковувався в URL. Кожен друг ≈ 100
        # байт, а кирилиця при URL-кодуванні роздувається ВТРИЧІ. На ~25
        # друзях посилання перевищує ліміт Telegram (клавіатура ≤ 10 240
        # байт) → BadRequest → ПРОФІЛЬ НЕ ВІДКРИВАЄТЬСЯ ВЗАГАЛІ.
        #
        # Бомба сповільненої дії: першими її ловлять НАЙАКТИВНІШІ — ті, хто
        # привів найбільше друзів. Система карала найкращих.
        #
        # Зріз 10, а не 20: при 20 запас до ліміту лише 10% — будь-яке нове
        # поле поверне падіння. При 10 запас 40%.
        #
        # 🔧 ТЕХБОРГ (правильне рішення, не на сьогодні):
        # Дані взагалі не мають їхати в URL. Мініап має запитувати їх у
        # бота (GET /chain_dashboard?uid=...) і брати з PostgreSQL — тоді
        # ліміту немає взагалі, і зрізи не потрібні. Але це зачіпає ВСІ
        # мініапи разом, тому окремою задачею після запуску.
        "friends":           friends[:10],
        "friends_total":     len(friends),   # справжня кількість — для мініапа
        "top_user":          {"name": top_name, "chain": top_chain} if top_name else None,
        "leaderboard_chain": lb[:6],
        "basic_price":       p["basic_price"],
        "basic_link":        p["basic_link"],
        "prem_price":        p["prem_price"],
        "prem_link":         p["prem_link"],
    }
    base = GITHUB_PAGES_URL.rstrip("/")
    return _guard_miniapp_url(
        f"{base}/chain_dashboard.html?d={_ul.quote(_json.dumps(data, ensure_ascii=False))}",
        "chain_dashboard", uid)


async def handle_paywall(request):
    """Віддає paywall.html.

    ══════════════════════════════════════════════════════════════
    🔴 ТУТ БУЛО ЗАМКНЕНЕ КОЛО — НУЛЬ ВИРУЧКИ
    ══════════════════════════════════════════════════════════════
    Якщо paywall.html немає в репозиторії — цей роут віддавав ГОЛИЙ 404.

    Що бачила людина:
      профіль → «Обрати план» → відкривається WebApp → 404 / біла сторінка
      → закриває → повертається в бот → бот знову пропонує paywall → КОЛО.

    Заплатити було НЕМОЖЛИВО. Ніде. Ніяк.

    ТЕПЕР: замість 404 віддаємо РОБОЧУ сторінку вибору плану, зібрану
    прямо тут. Вона веде на /pay — той самий ендпоінт, що й кнопки в чаті,
    і він працює (віддає форму WayForPay, яка сама сабмітиться).

    Тобто: навіть якщо мініап не задеплоєно, зламано або видалено —
    ЛЮДИНА ВСЕ ОДНО МОЖЕ ЗАПЛАТИТИ. Гроші не залежать від одного файлу.
    """
    from aiohttp.web import FileResponse, Response
    import pathlib

    for path in [
        pathlib.Path(__file__).parent / "paywall.html",
        pathlib.Path("paywall.html"),
        pathlib.Path("/app/paywall.html"),
    ]:
        if path.exists():
            return FileResponse(path, headers={
                "Access-Control-Allow-Origin": "*",
                "Cache-Control": "no-cache",
            })

    # ── ЗАПАСНА СТОРІНКА. Не 404, а робоча оплата. ──
    logger.warning("paywall.html НЕ ЗНАЙДЕНО — віддаю запасну сторінку оплати")

    q   = dict(request.rel_url.query)
    uid = 0
    try:
        # Дані приходять у ?d=<json>, як і в мініап
        import json as _j, urllib.parse as _ul
        _d = _j.loads(_ul.unquote(q.get("d", "{}")))
        uid = int(_d.get("my_uid") or 0)
    except Exception:
        _d = {}

    if not uid:
        try:
            uid = int(q.get("uid", "0"))
        except ValueError:
            uid = 0

    s = get_s(uid) if uid else {}
    p = get_prices(s) if uid else {"basic_price": BASIC_PRICE,
                                   "prem_price": PREMIUM_PRICE_FULL,
                                   "basic_6m_price": "", "prem_6m_price": ""}

    def _u(plan, price):
        try:
            return wfp_create_payment_url(uid, plan, float(price)) if uid else ""
        except Exception:
            return ""

    plans = [
        ("⚡️", "Basic", p.get("basic_price"), _u("basic", p.get("basic_price", 0)),
         "Ваша карта · TutorMe · Chainy · щоденні уроки"),
    ]
    if premium_visible():
        plans.append(("🌟", "Premium", p.get("prem_price"), _u("premium", p.get("prem_price", 0)),
                      "Усе з Basic + ефіри з розборами та уроками щотижня"))
    if p.get("basic_6m_price"):
        plans.append(("⚡️", "Basic · 6 місяців", p["basic_6m_price"],
                      _u("basic_6m", p["basic_6m_price"]), "Вигідніше за помісячну"))
    if premium_visible() and p.get("prem_6m_price"):
        plans.append(("🌟", "Premium · 6 місяців", p["prem_6m_price"],
                      _u("premium_6m", p["prem_6m_price"]), "Максимум і найвигідніше"))

    cards = ""
    for emoji, name, price, url, desc in plans:
        if not price:
            continue
        disabled = "" if url else "opacity:.4;pointer-events:none"
        cards += f"""
        <a class="plan" href="{url or '#'}" style="{disabled}">
          <div class="pl-top">
            <span class="pl-name">{emoji} {name}</span>
            <span class="pl-price">${fmt_price(price)}</span>
          </div>
          <div class="pl-desc">{desc}</div>
        </a>"""

    html = f"""<!DOCTYPE html>
<html lang="uk"><head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Обрати план</title>
<script src="https://telegram.org/js/telegram-web-app.js"></script>
<style>
 *{{box-sizing:border-box;margin:0;padding:0}}
 body{{background:#0f0f14;color:#f0f0f5;font-family:-apple-system,'Segoe UI',system-ui,sans-serif;
      padding:22px 16px;line-height:1.5}}
 h1{{font-size:20px;margin-bottom:6px}}
 .sub{{color:#8a8a99;font-size:13px;margin-bottom:22px}}
 .plan{{display:block;background:#1a1a24;border:1px solid #2c2c3a;border-radius:14px;
       padding:16px;margin-bottom:12px;text-decoration:none;color:inherit;transition:.15s}}
 .plan:active{{transform:scale(.985);border-color:#7c6ef7}}
 .pl-top{{display:flex;justify-content:space-between;align-items:center;margin-bottom:6px}}
 .pl-name{{font-weight:700;font-size:15px}}
 .pl-price{{font-weight:800;font-size:19px;color:#7c6ef7}}
 .pl-desc{{font-size:12.5px;color:#8a8a99;line-height:1.5}}
 .note{{margin-top:18px;font-size:11.5px;color:#5a5a68;text-align:center;line-height:1.6}}
</style></head>
<body>
 <h1>Обрати план</h1>
 <div class="sub">Оплата через WayForPay · картою</div>
 {cards or '<div class="note">Плани тимчасово недоступні. Напишіть у підтримку.</div>'}
 <div class="note">Автосписань немає.<br>Коли період завершиться — продовжите вручну.</div>
<script>
 try {{ const t = window.Telegram?.WebApp; t?.ready(); t?.expand(); }} catch(e) {{}}
</script>
</body></html>"""

    return Response(text=html, content_type="text/html", headers={
        "Access-Control-Allow-Origin": "*",
        "Cache-Control": "no-cache",
    })


def _build_paywall_url(uid: int, s: dict) -> str:
    """Будує URL для Paywall Mini App з усіма потрібними даними.

    ══════════════════════════════════════════════════════════════
    🔴 ТУТ БУЛО ЗАМКНЕНЕ КОЛО — ЛЮДИНА НЕ МОГЛА ЗАПЛАТИТИ
    ══════════════════════════════════════════════════════════════
    Paywall отримував ТІЛЬКИ `basic_link` / `prem_link` з ENV
    (BASIC_LINK, PREMIUM_LINK). Якщо ENV не задані — це ПОРОЖНІ РЯДКИ.

    Що бачила людина:
      профіль → paywall → тисне ціну → нікуди (порожнє посилання)
      → повертається в бот → бот пропонує paywall → КОЛО.

    І при цьому в боті ВЖЕ Є робочий генератор посилань:
    wfp_create_payment_url() — він створює платіжний URL САМ, без ENV.
    Ним користуються кнопки в чаті, і вони працюють.

    Paywall про нього просто НЕ ЗНАВ.

    ТЕПЕР: генеруємо посилання прямо тут і кладемо в `*_pay` поля.
    ENV-посилання лишаються як `*_link` — для зворотної сумісності
    (раптом мініап їх десь читає), але пріоритет у згенерованих.
    """
    import json as _j, urllib.parse as _ul

    p        = get_prices(s)
    chain    = get_chain(s)
    scores   = s.get("scores", [])
    avg      = round(sum(sc.get("score", 0) for sc in scores[-10:]) / len(scores[-10:])) if scores else 0

    # ── ГЕНЕРУЄМО платіжні посилання. Не залежимо від ENV. ──
    def _pay(plan, price):
        try:
            return wfp_create_payment_url(uid, plan, float(price))
        except Exception as _e:
            logger.warning(f"paywall pay url {uid}/{plan}: {_e}")
            return ""

    basic_pay = _pay("basic",   p["basic_price"])
    prem_pay  = _pay("premium", p["prem_price"])
    b6_pay    = _pay("basic_6m",   p["basic_6m_price"]) if p.get("basic_6m_price") else ""
    p6_pay    = _pay("premium_6m", p["prem_6m_price"])  if p.get("prem_6m_price")  else ""

    data = {
        "my_name":      s.get("name", ""),
        "my_uid":       uid,
        "chain_length": chain.get("length", 0),
        "done_lessons": len(s.get("done_lessons", [])),
        "xp_total":     s.get("xp_total", 0),
        "avg_score":    avg,
        "level":        s.get("level", "A1"),
        "streak_days":  s.get("streak_days", 0),
        "basic_price":  p["basic_price"],
        "prem_price":   p["prem_price"],
        "basic_6m":     p.get("basic_6m_price", ""),
        "prem_6m":      p.get("prem_6m_price", ""),

        # ✅ ГОЛОВНЕ: робочі платіжні посилання. Мініап має вести СЮДИ.
        "basic_pay":    basic_pay,
        "prem_pay":     prem_pay,
        "basic_6m_pay": b6_pay,
        "prem_6m_pay":  p6_pay,

        # Старі ENV-посилання. Порожні, якщо ENV не задані — тому НЕ
        # покладатись на них. Лишені для сумісності зі старим мініапом.
        "basic_link":   p["basic_link"]   or basic_pay,
        "prem_link":    p["prem_link"]    or prem_pay,
        "basic_6m_link":p.get("basic_6m_link", "") or b6_pay,
        "prem_6m_link": p.get("prem_6m_link", "")  or p6_pay,

        # ══════════════════════════════════════════════════════════
        # СТАН ДОСТУПУ — ПРАВДА З БОТА, А НЕ ЗДОГАД МІНІАПА
        #
        # 🔴 БУЛО: paywall.html вирішував, що показати, ЗА ДОВЖИНОЮ
        # ЛАНЦЮЖКА:  if (chain >= 7) → «пробний завершено!»
        #
        # Але ланцюжок ≥ 7 — це НЕ «доступ вичерпано». Це просто 7 днів
        # поспіль. Людина могла бути ВСЕРЕДИНІ челенджу (тобто мати повний
        # доступ), мати ланцюжок 8 — і paywall казав їй «пробний завершено».
        # І навпаки: кинула на Д3 з ланцюжком 3 — доступу вже немає, а
        # paywall писав «Розблокуй повний доступ», ніби вона просто новенька.
        #
        # Мініап ВГАДУВАВ те, що бот ЗНАЄ точно. Тепер бот каже прямо.
        #
        # Термінологія: слова «пробний період» у продукті НЕМАЄ.
        # Воно створює обіцянку, якої в коді не існує (тріалу як окремої
        # сутності немає — є челендж), і звучить як відбирання: «у тебе
        # закінчилось». Кажемо натомість про те, що ПОПЕРЕДУ: «розблокуйте
        # далі». Той самий момент, але людина рухається вперед, а не втрачає.
        "has_access":   is_in_trial(s) or is_premium(s),
        "in_challenge": (s.get("challenge_state") or {}).get("status") == "active",
        "challenge_done": (s.get("challenge_state") or {}).get("status") in ("completed", "abandoned"),

        # 🙈 PREMIUM_LAUNCH_ENABLED (Конституція 19-20): той самий принцип,
        # що й has_access вище — мініап не вгадує, бот каже прямо. Поки
        # False, s-profile/paywall.html має ховати Premium-картку і
        # показувати лише Basic, навіть якщо prem_price/prem_pay нижче
        # присутні в даних (лишені для сумісності, не для показу).
        "premium_visible": premium_visible(),

        # 24.07: явний поточний план — новий дизайн профілю ("Free (Ви тут)"
        # / "Basic (Ви тут)" тощо) потребує точного значення, не здогадки
        # з has_access. "free" = не платив ще ні разу.
        "current_plan": (
            "premium" if is_premium_only(s)
            else "basic" if is_basic(s)
            else "free"
        ),

        # ⚠️ ПОВНІ ціни — щоб мініап не вигадував їх сам.
        # У paywall.html було зашито FULL_BASIC=22, FULL_PREM=93. Зміните
        # ціну в Railway — а «економію» він рахуватиме від СТАРОЇ, і людина
        # побачить неправдивий відсоток знижки. Тепер джерело правди — бот.
        "full_basic":   BASIC_PRICE,
        "full_prem":    PREMIUM_PRICE_FULL,

        "source":       p["source"],
        "ref_note":     p["ref_note"].strip(),
        "blogger_name": s.get("affiliate_blogger", ""),
    }
    base = GITHUB_PAGES_URL.rstrip("/")
    return _guard_miniapp_url(
        f"{base}/paywall.html?d={_ul.quote(_j.dumps(data, ensure_ascii=False))}",
        "paywall", uid)


async def handle_leaderboard(request):
    """Віддає leaderboard.html."""
    from aiohttp.web import FileResponse
    import pathlib
    for path in [
        pathlib.Path(__file__).parent / "leaderboard.html",
        pathlib.Path("leaderboard.html"),
        pathlib.Path("/app/leaderboard.html"),
    ]:
        if path.exists():
            return FileResponse(path, headers={
                "Access-Control-Allow-Origin": "*",
                "Cache-Control": "no-cache",
            })
    from aiohttp.web import Response
    return Response(text="leaderboard.html not found", status=404)


def build_referral_tree_sizes(db: dict) -> dict:
    """
    22.07: розмір ВСЬОГО піддерева рефералів для кожного uid — не лише
    прямих запрошених (те, що вже рахував ref_index/ref_chained), а
    рекурсивно: друзі друзів, і так далі, всі покоління.

    Власниця: «переможець марафону — той, чия ланка найбільша (від кого
    найбільша гілка)». ref_chained рахував тільки перший рівень —
    A запросив B, B запросив C і D → ref_chained[A] було 1 (тільки B),
    не 3. Ця функція рахує саме розмір гілки, як просила власниця.

    Повертає {uid_str: розмір_піддерева}. Розмір — кількість НАЩАДКІВ
    (не рахує самого себе), тобто скільки людей у сумі приєдналось
    через цю людину, на будь-якому рівні вглиб.

    Захист від циклів: referrer_uid теоретично міг би вказувати сам на
    себе або утворити цикл через пошкоджені дані — visited не дає
    піти в нескінченну рекурсію.
    """
    # children[uid] = [список тих, кого uid запросив напряму]
    children: dict[str, list[str]] = {}
    for u, us in db.items():
        if not isinstance(us, dict) or u in DB_SKIP_KEYS:
            continue
        ruid = us.get("referrer_uid")
        if not ruid:
            continue
        children.setdefault(str(ruid), []).append(u)

    sizes: dict[str, int] = {}

    def _subtree_size(uid: str, visited: set) -> int:
        if uid in sizes:
            return sizes[uid]
        if uid in visited:
            return 0  # цикл у даних — не зациклюємось
        visited = visited | {uid}
        total = 0
        for child in children.get(uid, []):
            total += 1 + _subtree_size(child, visited)
        sizes[uid] = total
        return total

    for uid in list(children.keys()):
        _subtree_size(uid, set())

    return sizes


def _compute_leaderboard_users(db: dict, uid: int, s: dict, period: str = "week") -> tuple[list, str, bool]:
    """
    Спільна логіка лідерборду — рахує всі 6 категорій за один прохід.
    Переиспользується і Leaderboard-мініапом, і вбудованим лідербордом Chain Dashboard.
    Повертає (users_sorted_by_chain, friend_name, friend_overtook).
    """
    from datetime import timedelta
    today    = datetime.now()
    week_ago = (today - timedelta(days=7)).strftime("%Y-%m-%d")
    # Межа періоду для фільтрації по датах (scores містять дати активності)
    _period_days = {"day": 1, "week": 7, "month": 30, "all": None}.get(period, None)
    period_cutoff = ((today - timedelta(days=_period_days)).strftime("%Y-%m-%d")
                     if _period_days else "")
    uid_str  = str(uid)

    ref_uid     = s.get("referrer_uid")
    friend_name = ""
    if ref_uid:
        _rs = db.get(str(ref_uid), {})
        if isinstance(_rs, dict):
            friend_name = _rs.get("name", "")

    # Індекс рефералів (для категорії Chains)
    ref_index = {}
    for _u, _us in db.items():
        if not isinstance(_us, dict) or _u in DB_SKIP_KEYS:
            continue
        _ruid = _us.get("referrer_uid")
        if not _ruid:
            continue
        _rk = str(_ruid)
        bucket = ref_index.setdefault(_rk, {"total": 0, "repeated": 0, "chained": 0, "friends": []})
        bucket["total"] += 1
        did_repeat = bool(_us.get("last_sc_reply_transcript") or _us.get("sc_referrer"))
        _clen = chain_links(_us)
        did_chain = _clen > 0
        if did_repeat:
            bucket["repeated"] += 1
        if did_chain:
            bucket["chained"] += 1
        bucket["friends"].append({
            "name":     (_us.get("name", "") or "?")[:16],
            "repeated": did_repeat,
            "chained":  did_chain,
        })

    # 22.07: розмір ВСЬОГО піддерева рефералів (всі покоління), не лише
    # прямих запрошених — окремо від ref_index вище, який рахує тільки
    # перший рівень. build_referral_tree_sizes на весь db, не лише на
    # ref_index, бо їй потрібен повний ланцюжок referrer_uid для рекурсії.
    tree_sizes = build_referral_tree_sizes(db)

    users = []
    for u, us in db.items():
        if not isinstance(us, dict) or u in DB_SKIP_KEYS: continue
        if not us.get("onboarding_done"): continue

        chain_len = chain_links(us)
        xp_total  = us.get("xp_total", 0) or 0
        streak    = us.get("streak_days", 0) or 0

        week_xp = 0
        for sc in us.get("scores", []):
            if sc.get("date", "")[:10] >= week_ago:
                week_xp += XP_AWARDS.get("session", 15)
        for ph in us.get("mined_sentences", []):
            if ph.get("date", "")[:10] >= week_ago:
                week_xp += XP_AWARDS.get("phrase_saved", 5)

        # ── Період-залежні метрики (день/тиждень/місяць/весь час) ──
        if period_cutoff:
            period_sessions = sum(1 for sc in us.get("scores", [])
                                  if sc.get("date", "")[:10] >= period_cutoff)
            period_xp = period_sessions * XP_AWARDS.get("session", 15)
            for ph in us.get("mined_sentences", []):
                if ph.get("date", "")[:10] >= period_cutoff:
                    period_xp += XP_AWARDS.get("phrase_saved", 5)
        else:
            period_sessions = chain_len
            period_xp = xp_total

        scores    = us.get("scores", [])
        week_s    = [sc.get("score", 0) for sc in scores if sc.get("date","")[:10] >= week_ago]
        old_s     = [sc.get("score", 0) for sc in scores if sc.get("date","")[:10] < week_ago]
        avg_new   = sum(week_s)/len(week_s) if week_s else 0
        avg_old   = sum(old_s)/len(old_s)   if old_s  else avg_new
        jump      = round(avg_new - avg_old, 1)

        consist = []
        for i in range(6, -1, -1):
            day = (today - timedelta(days=i)).strftime("%Y-%m-%d")
            done = any(sc.get("date","")[:10] == day for sc in scores)
            consist.append(1 if done else 0)

        entry = {
            "name":    us.get("name", "")[:20],
            "chain":   period_sessions,
            "chain_all": chain_len,
            "xp":      period_xp,
            "streak":  streak,
            "jump":    max(0, round(jump, 0)),
            "consist": consist,
            "me":      u == uid_str,
            "friend":  (str(ref_uid) == u) if ref_uid else False,
        }
        _rb = ref_index.get(u)
        if _rb:
            entry["ref_total"]    = _rb["total"]
            entry["ref_repeated"] = _rb["repeated"]
            entry["ref_chained"]  = _rb["chained"]
            entry["ref_friends"]  = _rb["friends"][:12]
        else:
            entry["ref_total"]    = 0
            entry["ref_repeated"] = 0
            entry["ref_chained"]  = 0
            entry["ref_friends"]  = []
        # 22.07: розмір ВСЬОГО піддерева (не лише прямих ref_chained) —
        # власниця: «переможець — той, чия ланка найбільша, від кого
        # найбільша гілка» + «люди мають бачити всю свою ланку».
        entry["ref_tree_size"] = tree_sizes.get(u, 0)
        if us.get("badges"):
            entry["badges"] = us.get("badges", [])[:3]
        users.append(entry)

    users_by_chain = sorted(users, key=lambda x: x["chain"], reverse=True)
    my_rank     = next((i+1 for i,u in enumerate(users_by_chain) if u["me"]), 0)
    friend_rank = next((i+1 for i,u in enumerate(users_by_chain) if u["friend"]), 0)
    friend_overtook = bool(friend_rank and my_rank and friend_rank < my_rank)
    return users_by_chain, friend_name, friend_overtook


def _build_leaderboard_url(uid: int, s: dict,
                            period: str = "week",
                            db: dict | None = None) -> str:
    """
    Будує URL для Leaderboard Mini App.
    Використовує спільну _compute_leaderboard_users.
    """
    import json as _j, urllib.parse as _ul
    if db is None:
        db = load_db()

    users_by_chain, friend_name, friend_overtook = _compute_leaderboard_users(db, uid, s, period)

    data = {
        "my_uid":         uid,
        "my_name":        s.get("name", ""),
        "period":         period,
        "category":       "chain",
        "users":          users_by_chain[:20],
        "friend_name":    friend_name,
        "friend_overtook":friend_overtook,
        "reset_day":      "понеділок",
    }
    base = GITHUB_PAGES_URL.rstrip("/")
    return f"{base}/leaderboard.html?d={_ul.quote(_j.dumps(data, ensure_ascii=False))}"


def _OLD_build_leaderboard_url_UNUSED(uid: int, s: dict,
                            period: str = "week",
                            db: dict | None = None) -> str:
    """
    Будує URL для Leaderboard Mini App.
    Один прохід по БД — рахує всі 5 категорій одночасно.
    """
    import json as _j, urllib.parse as _ul
    from datetime import timedelta
    if db is None:
        db = load_db()

    today    = datetime.now()
    week_ago = (today - timedelta(days=7)).strftime("%Y-%m-%d")
    uid_str  = str(uid)

    # Друг юзера
    ref_uid     = s.get("referrer_uid")
    friend_name = ""
    if ref_uid:
        ref_s = db.get(str(ref_uid), {})
        if isinstance(ref_s, dict):
            friend_name = ref_s.get("name", "")

    # ── [Chains] Індекс рефералів: для кого хто запросив + чи повторив фразу
    #    + чи став ланкою. Один прохід, потім O(1) на юзера. ──
    #    referrer_uid(str) → {"total", "repeated", "chained", "friends":[...]}
    ref_index = {}
    for _u, _us in db.items():
        if not isinstance(_us, dict) or _u in DB_SKIP_KEYS:
            continue
        _ruid = _us.get("referrer_uid")
        if not _ruid:
            continue
        _rk = str(_ruid)
        bucket = ref_index.setdefault(_rk, {"total": 0, "repeated": 0, "chained": 0, "friends": []})
        bucket["total"] += 1
        # «повторив фразу» = зробив голосову/відео відповідь на челендж
        did_repeat = bool(_us.get("last_sc_reply_transcript") or _us.get("sc_referrer"))
        # «став ланкою» = має активний ланцюжок (chain length > 0)
        _clen = chain_links(_us)
        did_chain = _clen > 0
        if did_repeat:
            bucket["repeated"] += 1
        if did_chain:
            bucket["chained"] += 1
        bucket["friends"].append({
            "name":     (_us.get("name", "") or "?")[:16],
            "repeated": did_repeat,
            "chained":  did_chain,
        })

    users = []
    for u, us in db.items():
        if not isinstance(us, dict) or u in DB_SKIP_KEYS: continue
        if not us.get("onboarding_done"): continue

        chain_len = chain_links(us)
        xp_total  = us.get("xp_total", 0) or 0
        streak    = us.get("streak_days", 0) or 0   # справжній стрік (дні поспіль), окремо від ланцюжка

        # Weekly XP
        week_xp = 0
        for sc in us.get("scores", []):
            if sc.get("date", "")[:10] >= week_ago:
                week_xp += XP_AWARDS.get("session", 15)
        for ph in us.get("mined_sentences", []):
            if ph.get("date", "")[:10] >= week_ago:
                week_xp += XP_AWARDS.get("phrase_saved", 5)

        # Score jump (покращення за тиждень)
        scores    = us.get("scores", [])
        week_s    = [sc.get("score", 0) for sc in scores if sc.get("date","")[:10] >= week_ago]
        old_s     = [sc.get("score", 0) for sc in scores if sc.get("date","")[:10] < week_ago]
        avg_new   = sum(week_s)/len(week_s) if week_s else 0
        avg_old   = sum(old_s)/len(old_s)   if old_s  else avg_new
        jump      = round(avg_new - avg_old, 1)

        # Consistency (7 днів)
        consist = []
        for i in range(6, -1, -1):
            day = (today - timedelta(days=i)).strftime("%Y-%m-%d")
            done = any(sc.get("date","")[:10] == day for sc in scores)
            consist.append(1 if done else 0)

        entry = {
            "name":    us.get("name", "")[:20],
            "chain":   chain_len,
            "xp":      xp_total if period == "all" else week_xp,
            "streak":  streak,
            "jump":    max(0, round(jump, 0)),
            "consist": consist,
            "me":      u == uid_str,
            "friend":  (str(ref_uid) == u) if ref_uid else False,
        }
        # ── [Chains] Реферальні метрики цього юзера ──
        _rb = ref_index.get(u)
        if _rb:
            entry["ref_total"]    = _rb["total"]
            entry["ref_repeated"] = _rb["repeated"]
            entry["ref_chained"]  = _rb["chained"]
            entry["ref_friends"]  = _rb["friends"][:12]
        else:
            entry["ref_total"]    = 0
            entry["ref_repeated"] = 0
            entry["ref_chained"]  = 0
            entry["ref_friends"]  = []
        if us.get("badges"):
            entry["badges"] = us.get("badges", [])[:3]
        users.append(entry)

    # FOMO — чи друг обігнав по chain
    users_by_chain = sorted(users, key=lambda x: x["chain"], reverse=True)
    my_rank     = next((i+1 for i,u in enumerate(users_by_chain) if u["me"]), 0)
    friend_rank = next((i+1 for i,u in enumerate(users_by_chain) if u["friend"]), 0)
    friend_overtook = bool(friend_rank and my_rank and friend_rank < my_rank)

    data = {
        "my_uid":         uid,
        "my_name":        s.get("name", ""),
        "period":         period,
        "category":       "chain",
        "users":          users_by_chain[:20],  # топ-20 достатньо для UI
        "friend_name":    friend_name,
        "friend_overtook":friend_overtook,
        "reset_day":      "понеділок",
    }
    base = GITHUB_PAGES_URL.rstrip("/")
    return f"{base}/leaderboard.html?d={_ul.quote(_j.dumps(data, ensure_ascii=False))}"


