def get_micro_product(key: str) -> dict:
    """Мікро-продукт за ключем (community/video/feedback)."""
    return MICRO_PRODUCTS.get(key, {})


def enabled_micro_products() -> list:
    """Список (key, product) увімкнених мікро-продуктів (де готова видача)."""
    return [(k, v) for k, v in MICRO_PRODUCTS.items() if v.get("enabled")]


async def _deliver_micro_product(bot, user_id: int, plan: str, amount: str, order_ref: str):
    """
    Видача мікро-продукту після оплати (низький чек).

    Каркас: оплата вже пройшла (WayForPay), тут — реєстрація покупки + видача.
    Видача параметризована через MICRO_PRODUCTS: коли готовий реальний контент
    або лінк — вставляється в поле `deliver` (callable) або `link` продукту.
    Поки лінк не готовий — покупка фіксується, юзеру йде чесне «готуємо / чекайте».

    plan: micro_community | micro_video | micro_feedback
    """
    key = plan.replace("micro_", "", 1)
    prod = MICRO_PRODUCTS.get(key, {})
    title = prod.get("title", "Ваш продукт")

    # Реєструємо покупку (durable — для аналітики та повторної видачі)
    try:
        s = get_s(user_id)
        purchases = s.get("micro_purchases", [])
        purchases.append({
            "key": key, "order": order_ref, "amount": amount,
            "at": datetime.now().isoformat(), "delivered": False,
        })
        upd_s(user_id, {"micro_purchases": purchases})
    except Exception as e:
        logger.warning(f"micro purchase log {user_id}: {e}")

    # Трекінг (durable)
    try:
        from analytics import track_event
        await track_event(user_id, f"micro_buy_{key}", get_s(user_id), upd_s)
    except Exception:
        pass

    # Подяка
    try:
        await bot.send_message(
            user_id,
            f"✅ *Дякуємо за покупку!*\n\n{title} оплачено 🤍",
            parse_mode="Markdown",
        )
    except Exception as e:
        logger.warning(f"micro thanks {user_id}: {e}")

    # ── Видача ──
    delivered = False
    try:
        deliver_fn = prod.get("deliver")   # callable(bot, uid) → bool, коли готова
        link = prod.get("link", "")         # готовий лінк на контент/дію
        if callable(deliver_fn):
            delivered = bool(await deliver_fn(bot, user_id))
        elif link:
            await bot.send_message(
                user_id,
                f"🎁 Ось Ваш доступ:\n{link}",
                parse_mode="Markdown",
            )
            delivered = True
    except Exception as e:
        logger.warning(f"micro deliver {user_id} {key}: {e}")

    if not delivered:
        # Видача ще не підключена — чесно ставимо в чергу (лінк вставите потім)
        try:
            db = load_db()
            q = db.get("_micro_delivery_queue", [])
            q.append({"uid": user_id, "key": key, "order": order_ref,
                      "at": datetime.now().isoformat()})
            db["_micro_delivery_queue"] = q
            save_db(db)
        except Exception:
            pass
        try:
            await bot.send_message(
                user_id,
                "🎁 Ваш продукт готуємо — надішлемо сюди найближчим часом. Дякуємо за терпіння 🤍",
                parse_mode="Markdown",
            )
        except Exception:
            pass
    logger.info(f"micro delivered={delivered} {key} → user {user_id}")


async def job_pending_payment_followup(ctx: ContextTypes.DEFAULT_TYPE):
    """
    21.07: наздоганяє тих, хто відкрив сторінку оплати, але вона не
    завершилась успіхом протягом 20+ хвилин. Запускається кожні 10хв,
    перевіряє поле pending_payment у стані кожного студента.

    ТРИ РІЗНІ ГІЛКИ, різний текст — не "один шаблон на всіх":
    1. outcome=None (просто зник, вебхук не приходив) — м'яке нагадування,
       може відволікся чи передумав, БЕЗ натяку на провину.
    2. outcome="declined" (WayForPay реально відхилив картку) — вибачення
       + альтернативний спосіб оплати, наша/банківська проблема, не його.
    3. outcome=None АЛЕ prem/basic вже активний — оплата пройшла, вебхук
       просто запізнився повз цю перевірку. НЕ надсилаємо нічого, тихо
       чистимо pending_payment. Це другий, незалежний захист від хибного
       нагадування тому, хто вже заплатив (перший — очищення в
       _process_payment одразу при успіху).

    Одна спроба на один pending_payment (`followup_sent`), не спамимо.
    """
    db    = load_db()
    now   = datetime.now()

    for uid, s in db.items():
        if not isinstance(s, dict) or str(uid) in DB_SKIP_KEYS:
            continue
        pp = s.get("pending_payment")
        if not pp or not isinstance(pp, dict):
            continue
        if pp.get("followup_sent"):
            continue

        try:
            opened_at = datetime.strptime(pp.get("opened_at", ""), "%Y-%m-%d %H:%M:%S")
        except (ValueError, TypeError):
            continue
        minutes_since = (now - opened_at).total_seconds() / 60
        if minutes_since < 20:
            continue  # ще рано — людина могла бути посеред оплати щойно

        uid_int = int(uid) if str(uid).isdigit() else None
        if not uid_int:
            continue

        # ── Гілка 3: оплата насправді пройшла, вебхук запізнився ──
        # Перевіряємо ЖИВИЙ стан ще раз, не довіряємо тому, що прочитали
        # на початку цього проходу — activate_plan міг спрацювати щойно.
        # is_premium() покриває і Basic, і Premium — обидва пишуться в
        # те саме поле premium_until (звірено: is_basic() = is_premium()
        # + plan=="basic", тож окрема перевірка is_basic() тут зайва).
        _fresh = get_s(uid_int)
        if is_premium(_fresh):
            upd_s(uid_int, {"pending_payment": None})
            continue

        plan   = pp.get("plan", "basic")
        amount = pp.get("amount", 0)
        outcome = pp.get("outcome")

        try:
            if outcome == "declined":
                # ── Гілка 2: банк/картка реально відхилили ──
                text = (
                    "Побачила, що оплата не пройшла — картка не була прийнята "
                    "(це не обов'язково твоя провина, іноді банки блокують "
                    "міжнародні платежі).\n\n"
                    "Якщо хочеш — спробуй ще раз, або напиши мені, яка картка "
                    "не спрацювала, і я підкажу альтернативу."
                )
            else:
                # ── Гілка 1: просто відкрив і зник ──
                text = (
                    "Бачу, ти відкривав(-ла) оплату трохи раніше — не було "
                    "часу дійти до кінця?\n\n"
                    "Посилання ще чинне, якщо хочеш продовжити 👇"
                )
            await _safe_send(ctx.bot, uid_int, text, parse_mode="Markdown")
            pp["followup_sent"] = True
            upd_s(uid_int, {"pending_payment": pp})
        except Exception as e:
            logger.warning(f"pending_payment_followup uid={uid_int}: {e}")


async def _process_payment(user_id: int, plan: str, amount: str, order_ref: str):
    """Активує план і надсилає повідомлення — викликається після відповіді WayForPay."""
    from telegram import Bot
    bot = Bot(token=BOT_TOKEN)

    # 21.07: оплата ПРОЙШЛА — знімаємо позначку "очікує оплату" одразу,
    # ДО решти обробки. Це структурний захист, не залежить від того, чи
    # встигне джоба нагадувань перевірити вчасно: якщо вебхук прийшов
    # пізно, а нагадування вже було заплановане — воно бачить чистий
    # pending_payment і не надсилається (перевірка в самій джобі).
    try:
        upd_s(user_id, {"pending_payment": None})
    except Exception as _e:
        logger.warning(f"pending_payment очистити uid={user_id}: {_e}")

    # Визначаємо чи це повторна оплата (продовження) чи перша
    s_before     = get_s(user_id)
    is_renewal   = bool(s_before.get("premium_until"))

    # ── ЖУРНАЛ ПЛАТЕЖІВ (finance.py) ──
    # Раніше оплати БЕЗ блогера не логувались ніде — тільки _payouts,
    # і то лише за рефералом. Тому «скільки прийшло за місяць» бот не знав.
    # Тепер пишемо КОЖНУ оплату. Це єдина точка, через яку вони проходять.
    try:
        _fs   = get_s(user_id)
        _blog = _fs.get("affiliate_blogger", "") or ""
        _ref  = _fs.get("affiliate_ref", "") or ""
        try:
            _amt = float(amount) if amount else None
        except (TypeError, ValueError):
            _amt = None
        log_payment(user_id, plan, amount=_amt, blogger=_blog, ref=_ref,
                    kind=("product" if plan.startswith("micro_") else "subscription"))
    except Exception as _e:
        logger.warning(f"finance log_payment: {_e}")

    # ── МІКРО-ПРОДУКТИ (низький чек: micro_community, micro_video, micro_feedback) ──
    # Не активують підписку — видають окремий продукт. Видача параметризована:
    # реальний контент/лінк вставляється в _deliver_micro_product пізніше.
    if plan.startswith("micro_"):
        await _deliver_micro_product(bot, user_id, plan, amount, order_ref)
        return

    # 6-місячний план — активуємо на 180 днів
    # Реальна сума від WayForPay — щоб Sheets писав ФАКТ, а не довідник
    try:
        _real_amt = float(amount) if amount else None
    except (TypeError, ValueError):
        _real_amt = None

    # ── ВІДНОВЛЕННЯ ЛАНЦЮЖКА ──────────────────────────────────
    # Ставимо ДО activate_plan: вітальне повідомлення має показати
    # вже відновлений стрік, а не «1». Момент оплати — це момент
    # повернення, а не момент старту з нуля.
    #
    # Мовчить, якщо морозити не було чого (нова людина, стрік 0-1).
    _restored = 0
    try:
        _restored = restore_streak_after_pause(user_id)
    except Exception as _e:
        logger.warning(f"restore_streak uid={user_id}: {_e}")

    if plan in ("basic_6m", "premium_6m"):
        base_plan = plan.replace("_6m", "")
        await activate_plan(bot, user_id, base_plan, 180, is_renewal=is_renewal,
                            paid_amount=_real_amt, orig_plan=plan)
    else:
        await activate_plan(bot, user_id, plan, 30, is_renewal=is_renewal,
                            paid_amount=_real_amt, orig_plan=plan)
    logger.info(f"WFP: ✅ activated {plan} for user {user_id} (renewal={is_renewal})")

    # ── Окреме повідомлення про повернений ланцюжок ────────────
    # Навмисно ОКРЕМИМ повідомленням, не рядком у вітальному:
    # це маленька перемога, і вона має мати власний момент.
    if _restored >= 2:
        try:
            await bot.send_message(
                chat_id=user_id,
                text=(
                    f"❄️➡️🔥 *Ланцюжок розморожено!*\n\n"
                    f"Твої *{_restored} дні поспіль* чекали на тебе.\n"
                    f"Нічого не згоріло. Наступне заняття — день *{_restored + 1}*.\n\n"
                    f"_З поверненням._"
                ),
                parse_mode="Markdown"
            )
        except Exception as _e:
            logger.warning(f"streak restore notify uid={user_id}: {_e}")

    # ── Записуємо подію платежу для нарахування комісії блогеру ──
    s2           = get_s(user_id)
    blogger_name = s2.get("affiliate_blogger", "")
    if blogger_name:
        year_month   = datetime.now().strftime("%Y-%m")
        # Комісію рахуємо від суми, яку людина РЕАЛЬНО заплатила (amount з
        # платіжного webhook). Так автоматично враховуються знижки: афіліатна
        # ціна, він-бек (-30%), будь-які акції — блогер отримує 25% від факту.
        try:
            paid_amount = float(amount)
        except (TypeError, ValueError):
            paid_amount = 0.0
        # Fallback, якщо webhook не передав суму — беремо очікувану афіліатну ціну.
        if paid_amount <= 0:
            if plan == "basic_6m":
                paid_amount = BASIC_AFF_6M_PRICE
            elif plan == "premium_6m":
                paid_amount = PREMIUM_AFF_6M_PRICE
            elif plan == "basic":
                paid_amount = float(BASIC_AFFILIATE_PRICE)
            else:
                paid_amount = float(PREMIUM_PRICE_AFF)
        # 23.07: раніше тут була ЛОКАЛЬНА глобальна ставка (BLOGGER_COMMISSION_
        # BASIC/PREMIUM з ENV), яка ігнорувала персональні ставки з
        # _blogger_commissions — build_finance() (адмінка) показував
        # персональну ставку правильно, а РЕАЛЬНЕ нарахування до виплати
        # (це саме той запис нижче) рахувалось по-старому. Два місця з
        # однією логікою розійшлись — знайдено 23.07 при прямому питанні
        # власниці "чи ENV не перекриє персональні ставки". Тепер обидва
        # місця йдуть через ЄДИНЕ джерело істини — commission_rate_for.
        db           = load_db()
        rate         = commission_rate_for(db, plan, blogger_name,
                                            BLOGGER_COMMISSION_BASIC,
                                            BLOGGER_COMMISSION_PREMIUM)
        commission   = round(paid_amount * rate, 2)
        payouts      = db.get("_payouts", [])
        payouts.append({
            "blogger":      blogger_name,
            "student_uid":  str(user_id),
            "student_name": s2.get("name", f"Студент {str(user_id)[-4:]}"),
            "plan":         plan,
            "amount":       paid_amount,
            "commission":   commission,
            "month":        year_month,
            "order_ref":    order_ref,
            "paid":         False,
            "paid_date":    "",
        })
        db["_payouts"] = payouts
        save_db(db)
        logger.info(f"Payout recorded: {blogger_name} ← ${commission} (student {user_id}, {plan})")

    # Premium студент → запрошуємо в групу автоматично
    if plan in ("premium", "premium_6m"):
        asyncio.create_task(_invite_to_premium_group(bot, user_id))

    # Сповіщення адміну — одне повідомлення
    if ADMIN_ID:
        s    = get_s(user_id)
        name = s.get("name", str(user_id))
        ref  = s.get("affiliate_ref", "")
        try:
            await bot.send_message(
                chat_id=ADMIN_ID,
                text=(
                    f"💰 *Нова оплата!*\n\n"
                    f"👤 {name} (`{user_id}`)\n"
                    f"📦 План: *{'Basic ⚡️' if plan == 'basic' else 'Premium 🌟'}*\n"
                    f"💵 Сума: *{amount} {WFP_CURRENCY}*\n"
                    f"🔗 Реферал: {ref or '—'}\n"
                    f"🧾 Order: `{order_ref}`"
                ),
                parse_mode="Markdown"
            )
        except Exception as e:
            logger.warning(f"WFP admin notify error: {e}")

    # Сповіщення блогеру
    ref = get_s(user_id).get("affiliate_ref", "")
    if ref:
        blogger_name = ref.split("_")[0] if "_" in ref else ref
        bloggers     = get_registered_bloggers()
        blogger_id   = next((int(uid) for uid, n in bloggers.items() if n == blogger_name), None)
        if blogger_id:
            try:
                name = get_s(user_id).get("name", str(user_id))
                await bot.send_message(
                    chat_id=blogger_id,
                    text=(
                        f"🎉 *Твій студент оплатив!*\n\n"
                        f"👤 {name}\n"
                        f"📦 {'Basic ⚡️' if plan == 'basic' else 'Premium 🌟'}\n"
                        f"💰 Твоя комісія нарахована"
                    ),
                    parse_mode="Markdown"
                )
            except Exception as e:
                logger.warning(f"WFP blogger notify error: {e}")

# ── Кнопка оплати через Wayforpay ────────────────────
async def cmd_test_wrapped(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """/test_wrapped [USER_ID] — миттєво надсилає місячний Wrapped."""
    if not is_admin(update.effective_user.id):
        return
    args      = ctx.args or []
    target_id = int(args[0]) if args else update.effective_user.id

    # Підміняємо поточний місяць для тесту
    from datetime import timedelta as _td2
    prev_dt = datetime.now().replace(day=1) - _td2(days=1)
    prev_ym = prev_dt.strftime("%Y-%m")

    db  = load_db()
    s   = get_s(target_id)
    if not s:
        await update.message.reply_text(f"❌ Студента `{target_id}` не знайдено.", parse_mode="Markdown")
        return

    # Рахуємо всіх активних для перцентилю
    all_students = []
    for uid2, s2 in db.items():
        if not isinstance(s2, dict) or str(uid2) in DB_SKIP_KEYS: continue
        if not s2.get("onboarding_done"): continue
        st2 = _month_stats(s2, prev_ym)
        all_students.append((uid2, s2, st2))

    total_active = max(len(all_students), 1)
    stats        = _month_stats(s, prev_ym)
    name         = s.get("name", update.effective_user.first_name)
    level        = s.get("level", "A1")
    blogger      = s.get("affiliate_blogger", "")
    streak       = s.get("streak_days", 0)
    xp           = s.get("xp_total", 0)
    monologues   = stats["monologues"]
    phrases      = stats["phrases"]
    avg_score    = stats["avg_score"]
    month_en     = prev_dt.strftime("%B")
    month_ua     = UA_MONTHS_GEN.get(month_en, month_en)
    year         = prev_dt.strftime("%Y")

    # Перцентиль
    if total_active > 1:
        better_than = sum(1 for _,_,st in all_students if st["monologues"] < monologues or (st["monologues"] == monologues and st["avg_score"] < avg_score))
        pct = int(better_than / (total_active - 1) * 100)
    else:
        pct = 100

    if pct >= 90:   star_line = f"\n🏆 *Ти в топ {100-pct}% студентів {month_ua}!*"
    elif pct >= 70: star_line = f"\n🥈 Ти вище *{pct}%* студентів цього місяця!"
    elif pct >= 50: star_line = f"\n📈 Ти активніше половини студентів!"
    else:           star_line = f"\n💪 Наступний місяць буде кращим!"

    if monologues >= 20:   fact = "20+ монологів — це вже серйозна звичка 🔥"
    elif monologues >= 10: fact = "10+ монологів — ти в топ практикуючих! 💪"
    elif monologues >= 5:  fact = "5+ монологів — мозок вже звикає до мови 🧠"
    elif monologues >= 1:  fact = "Перший крок зроблено — далі буде легше!"
    else:                   fact = "Цей місяць — старт нового тебе 🚀"

    blogger_line = f"\n\n_{month_ua} разом з @{blogger}_ 🎙" if blogger else ""

    text = (
        f"🧪 *Тест Wrapped* для `{target_id}`:\n\n"
        f"🎵 *Твій {month_ua} {year} у SpeakChain*\n\n"
        f"👤 *{name}* · {LEVEL_NAMES.get(level, level)}\n\n"
        f"🎙 Монологів записано: *{monologues}*\n"
        f"📚 Нових фраз: *{phrases}*\n"
        f"🏆 Середній бал: *{avg_score}/100*\n"
        f"🔥 Дні поспіль: *{streak}*\n"
        f"⚡️ XP всього: *{xp:,}*"
        f"{star_line}"
        f"\n\n💡 _{fact}_"
        f"{blogger_line}"
    )

    await ctx.bot.send_message(
        chat_id=target_id,
        text=text,
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup([
            [InlineKeyboardButton("📊 Мій прогрес",           callback_data="show_progress"),
             InlineKeyboardButton("🎙 Практикувати",          callback_data="fork_choose")],
            [InlineKeyboardButton("📤 Поділитись у соцмережах", callback_data="share_socials")],
        ])
    )
    if target_id != update.effective_user.id:
        await update.message.reply_text(f"✅ Надіслано до `{target_id}`", parse_mode="Markdown")


async def cmd_deliver_pending(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """
    Адмін: дошле всі покупки/claim-и, що чекали в черзі, поки не було контенту.
    Запусти ПІСЛЯ того, як завантажив файл/лінк у Railway (книга, мікропродукт,
    подарунок за фразу). Безпечно запускати повторно — вже видане пропускається.
    """
    if not is_admin(update.effective_user.id):
        return
    bot = ctx.bot
    delivered, still_waiting = 0, 0

    # 1) Мікропродукти (gift_book, extra_product, community...) з _micro_delivery_queue
    #
    # РАНІШЕ ТУТ БУЛА ГОНКА (знайдено й виправлено 21.07):
    # db читався ОДИН РАЗ на вході, потім у циклі йшов await на кожен
    # елемент (deliver_fn/send_message), і лише ПІСЛЯ ВСЬОГО циклу —
    # один фінальний save_db(db) з накопиченим rest[]. Якщо за час
    # цього циклу хтось інший (напр. новий webhook оплати через
    # _deliver_micro_product) дописував у _micro_delivery_queue свій
    # load_db()/save_db() — фінальний запис тут перезаписував увесь
    # список застарілою версією db, і щойно доданий елемент мовчки
    # губився (lost update), хоча людина за нього заплатила.
    #
    # Виправлення — той самий патерн, що вже є в проєкті для
    # challenge_state (_patch_cstate): читаємо СВІЖИЙ db прямо перед
    # кожним точковим записом, видаляємо РІВНО ОДИН елемент за його
    # унікальним order_ref, а не весь список одним махом наприкінці.
    try:
        db = load_db()
        queue = list(db.get("_micro_delivery_queue", []))
    except Exception as e:
        logger.warning(f"deliver_pending micro queue load: {e}")
        queue = []

    for item in queue:
        uid, key, order = item.get("uid"), item.get("key"), item.get("order")
        prod = MICRO_PRODUCTS.get(key, {})
        deliver_fn = prod.get("deliver")
        ok = False
        try:
            if callable(deliver_fn):
                ok = bool(await deliver_fn(bot, uid))
            elif prod.get("link"):
                await bot.send_message(uid, f"🎁 Ось Ваш доступ:\n{prod['link']}")
                ok = True
        except Exception as e:
            logger.warning(f"deliver_pending micro {uid}/{key}: {e}")
        if ok:
            delivered += 1
            # Точкове видалення — свіже читання + запис БЕЗ await між
            # ними, тому не зачіпає елементи, додані іншим потоком
            # виконання, поки цей await вище чекав на мережу.
            try:
                if order:
                    # Точкове видалення за унікальним order_ref.
                    _db2 = load_db()
                    _q2 = [x for x in _db2.get("_micro_delivery_queue", [])
                           if x.get("order") != order]
                    _db2["_micro_delivery_queue"] = _q2
                    save_db(_db2)
                else:
                    # Страховка: якщо колись у чергу потрапить елемент
                    # без order_ref, порівняння лише за order видалило
                    # б УСІ такі елементи разом. _db2 — щойно перечитаний
                    # з диску об'єкт, тому порівняння за identity (is)
                    # тут не спрацює (інший об'єкт у пам'яті з тим самим
                    # вмістом) — порівнюємо за складеним ключем (uid,
                    # key, at), який лишається унікальним навіть без
                    # order_ref, бо at — мітка часу створення елемента.
                    _sig = (item.get("uid"), item.get("key"), item.get("at"))
                    _db2 = load_db()
                    _q2 = [x for x in _db2.get("_micro_delivery_queue", [])
                           if (x.get("uid"), x.get("key"), x.get("at")) != _sig]
                    _db2["_micro_delivery_queue"] = _q2
                    save_db(_db2)
            except Exception as e:
                logger.warning(f"deliver_pending micro dequeue {uid}/{key}: {e}")
        else:
            still_waiting += 1

    # 2) Подарунок за кодову фразу (прапорець code_phrase_gift_pending у стані)
    try:
        gift_file = os.environ.get("CODE_PHRASE_GIFT_FILE_ID", "")
        gift_link = os.environ.get("CODE_PHRASE_GIFT_LINK", "")
        if gift_file or gift_link:
            db = load_db()
            for uid_str, s in list(db.items()):
                if not isinstance(s, dict):
                    continue
                cs = s.get("challenge_state", {})
                if not cs.get("code_phrase_gift_pending"):
                    continue
                try:
                    _uid = int(uid_str)
                    if gift_file:
                        await bot.send_document(_uid, gift_file,
                            caption="🎁 Ваш подарунок за зібрану фразу тижня. Пишаюся Вами 🤍")
                    else:
                        await bot.send_message(_uid, f"🎁 Ваш подарунок за фразу:\n{gift_link}")
                    _patch_cstate(_uid, {"code_phrase_gift_pending": False}, force=True)
                    delivered += 1
                except Exception as e:
                    logger.warning(f"deliver_pending code_phrase {uid_str}: {e}")
                    still_waiting += 1
    except Exception as e:
        logger.warning(f"deliver_pending code_phrase: {e}")

    await update.message.reply_text(
        f"✅ Дошилка завершена.\n\n"
        f"Видано зараз: {delivered}\n"
        f"Ще чекають (контент не задано?): {still_waiting}\n\n"
        f"_Якщо хтось лишився в черзі — перевір, чи задано file_id/лінк у Railway._",
        parse_mode="Markdown",
    )


