def gs_sync_onboarding():
    """Дві вкладки: «Онбординг — зведення» (воронка + розподіл %) і
    «Онбординг — письмові» (вільні відповіді). Пакетне оновлення (з /analytics)."""
    try:
        gc = _get_gs_client()
        if not gc:
            return
        sh = gc.open_by_key(GOOGLE_SHEET_ID)
        rep = get_retention_report(load_db)
        if rep.get("error"):
            logger.warning(f"gs_sync_onboarding: report error {rep['error']}")
            return

        respondents = rep.get("onb_respondents", 0)
        opened      = rep.get("onb_opened", 0)

        # ── Вкладка 1: ЗВЕДЕННЯ (воронка + розподіл %) ──
        try:
            ws1 = sh.worksheet("Онбординг — зведення")
        except Exception:
            ws1 = sh.add_worksheet(title="Онбординг — зведення", rows=300, cols=6)

        def pct(a, b):
            return f"{round(a / b * 100)}%" if b else "0%"

        rows = []
        rows.append([f"ОНБОРДИНГ — ЗВЕДЕННЯ   (оновлено {datetime.now().strftime('%Y-%m-%d %H:%M')})"])
        rows.append([f"Відкрили квіз: {opened}", f"Завершили: {respondents}",
                     f"% завершення: {rep.get('onb_completion_rate', 0)}%"])
        rows.append([])
        rows.append(["── ВОРОНКА (де кидають) ──"])
        rows.append(["Крок", "Екран", "Дійшли", "% від відкривших"])
        funnel = rep.get("onb_funnel", {})
        for step in sorted(funnel):
            reached = funnel[step]
            rows.append([step, _ONB_STEP_NAMES.get(step, f"крок {step}"),
                         reached, pct(reached, opened)])
        rows.append([])
        rows.append(["── РОЗПОДІЛ ВІДПОВІДЕЙ (% від тих, хто завершив) ──"])
        rows.append(["Питання", "Варіант", "Обрали", "%"])
        for field in ("goals","speaking_blocks","tried_before","missing_before",
                      "fluent_means","expectations","time_per_day"):
            dist = rep.get(f"onb_{field}", {})
            if not dist:
                continue
            title = _ONB_FIELD_TITLES.get(field, field)
            labels = _ONB_LABELS.get(field, {})
            first = True
            for key, cnt in dist.items():
                rows.append([title if first else "",
                             labels.get(key, key), cnt, pct(cnt, respondents)])
                first = False
        ws1.clear()
        ws1.update(rows)

        # ── Вкладка 2: ПИСЬМОВІ ВІДПОВІДІ ──
        try:
            ws2 = sh.worksheet("Онбординг — письмові")
        except Exception:
            ws2 = sh.add_worksheet(title="Онбординг — письмові", rows=1000, cols=4)
        rows2 = [["ID", "Ім'я", "Чого бракувало (своє)", "Очікування (своє)"]]
        db = load_db()
        for uid, s in db.items():
            if not isinstance(s, dict):
                continue
            mo = (s.get("missing_other") or "").strip()
            eo = (s.get("expectations_other") or "").strip()
            if mo or eo:
                rows2.append([str(uid), s.get("name", ""), mo, eo])
        ws2.clear()
        ws2.update(rows2)

        logger.info(f"gs_sync_onboarding: зведення({respondents} завершили) + письмові({len(rows2)-1})")
    except Exception as e:
        logger.warning(f"gs_sync_onboarding error: {e}")


def gs_sync_payout_log():
    """Синхронізує РУЧНИЙ журнал виплат (23.07, _payout_log) в окремий
    лист Google Sheets — "PayoutLog". НЕ те саме, що gs_sync_payouts()
    вище: та функція синхронізує АВТОМАТИЧНЕ нарахування (_payouts,
    лист "Payouts"), ця — ручні записи власниці про факт переказу
    (ім'я/дата/сума/коментар). Окремий лист, бо це різні сутності з
    різною кількістю колонок і різним змістом."""
    try:
        gc = _get_gs_client()
        if not gc: return
        sh  = gc.open_by_key(GOOGLE_SHEET_ID)
        ws  = _ensure_sheet(sh, "PayoutLog", [
            "Дата", "Блогер", "Сума($)", "Коментар", "Записано (час)"
        ])
        db  = load_db()
        log = get_payout_log(db)  # найновіші перші
        rows = [[
            e.get("date", ""), e.get("blogger", ""), e.get("amount", ""),
            e.get("note", ""), e.get("logged_at", ""),
        ] for e in log]
        if rows:
            ws.clear()
            ws.append_row(["Дата", "Блогер", "Сума($)", "Коментар", "Записано (час)"])
            ws.append_rows(rows)
    except Exception as e:
        logger.warning(f"gs_sync_payout_log error: {e}")


def gs_sync_payouts():
    """Синхронізує виплати в Google Sheets (лист Payouts)."""
    try:
        gc = _get_gs_client()
        if not gc: return
        sh      = gc.open_by_key(GOOGLE_SHEET_ID)
        ws      = _ensure_sheet(sh, "Payouts", [
            "Місяць","Блогер","Студент","UID","Тариф","Сума($)","Комісія($)","Статус","Дата виплати"
        ])
        db      = load_db()
        payouts = db.get("_payouts", [])
        rows    = []
        for p in sorted(payouts, key=lambda x: (x.get("month",""), x.get("blogger","")), reverse=True):
            rows.append([
                p.get("month",""),
                p.get("blogger",""),
                p.get("student_name",""),
                p.get("student_uid",""),
                p.get("plan",""),
                p.get("amount",""),
                p.get("commission",""),
                "✅ Виплачено" if p.get("paid") else "⏳ Очікує",
                p.get("paid_date",""),
            ])
        if rows:
            ws.clear()
            ws.append_row(["Місяць","Блогер","Студент","UID","Тариф","Сума($)","Комісія($)","Статус","Дата виплати"])
            ws.append_rows(rows)
    except Exception as e:
        logger.warning(f"gs_sync_payouts error: {e}")
    """Синхронізує список блогерів в окремий лист Google Sheets."""
    try:
        gc = _get_gs_client()
        if not gc:
            return
        sh = gc.open_by_key(GOOGLE_SHEET_ID)

        # Створюємо лист якщо не існує
        try:
            ws = sh.worksheet(BLOGGERS_SHEET_NAME)
        except Exception:
            ws = sh.add_worksheet(title=BLOGGERS_SHEET_NAME, rows=100, cols=10)

        bloggers  = get_registered_bloggers()
        codes     = get_blogger_codes()
        db        = load_db()

        # Заголовки
        headers = [
            "Ім'я", "Telegram ID", "Статус",
            "Студентів всього", "Basic", "Premium", "На тріалі",
            "Активних цього місяця", "Дохід (комісія)", "Дата реєстрації"
        ]

        rows = [headers]
        for uid, name in bloggers.items():
            students = [
                s for k, s in db.items()
                if isinstance(s, dict) and
                (s.get("affiliate_blogger","") == name or
                 s.get("affiliate_ref","").startswith(name))
            ]
            total   = len(students)
            basic   = sum(1 for s in students if is_premium(s) and s.get("plan","basic") == "basic")
            premium = sum(1 for s in students if is_premium(s) and s.get("plan") == "premium")
            trial   = sum(1 for s in students if is_in_trial(s))
            active  = sum(1 for s in students
                          if s.get("last_date","") >= datetime.now().strftime("%Y-%m-01"))
            _rb = commission_rate_for(db, "basic", name, BLOGGER_COMMISSION_BASIC, BLOGGER_COMMISSION_PREMIUM)
            _rp = commission_rate_for(db, "premium", name, BLOGGER_COMMISSION_BASIC, BLOGGER_COMMISSION_PREMIUM)
            revenue = round(basic * float(BASIC_AFFILIATE_PRICE) * _rb +
                             premium * float(PREMIUM_AFFILIATE_PRICE) * _rp, 2)
            reg_date = db.get(uid, {}).get("registered_at", "—") if uid in db else "—"

            rows.append([
                name, uid, "✅ Активний",
                total, basic, premium, trial,
                active, f"${revenue}", reg_date
            ])

        # Невикористані коди — окремим блоком
        if codes:
            rows.append([])
            rows.append(["⏳ Невикористані коди", "", "", "", "", "", "", "", "", ""])
            rows.append(["Код", "Для блогера", "", "", "", "", "", "", "", ""])
            for code, name in codes.items():
                rows.append([code, name, "", "", "", "", "", "", "", ""])

        ws.clear()
        ws.update(rows)
        logger.info(f"Bloggers sheet synced: {len(bloggers)} bloggers")
    except Exception as e:
        logger.warning(f"gs_sync_bloggers error: {e}")

def gs_save_db_backup():
    """Зберігає весь students.json в Google Sheets (один рядок JSON)."""
    try:
        gc = _get_gs_client()
        if not gc:
            return
        sh  = gc.open_by_key(GOOGLE_SHEET_ID)
        try:
            ws = sh.worksheet(BACKUP_SHEET_NAME)
        except gspread.WorksheetNotFound:
            ws = sh.add_worksheet(title=BACKUP_SHEET_NAME, rows=10, cols=3)
            ws.append_row(["Timestamp", "Size", "Data"])

        db_path = Path(DB)
        if not db_path.exists():
            return
        data_str = db_path.read_text(encoding="utf-8")
        ts       = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        size     = len(data_str)

        # Оновлюємо перший рядок даних (рядок 2)
        try:
            ws.update("A2:C2", [[ts, size, data_str]])
        except Exception:
            ws.append_row([ts, size, data_str])
        logger.info(f"DB backup saved to Sheets ({size} bytes)")
    except Exception as e:
        logger.warning(f"gs_save_db_backup error: {e}")

def gs_load_db_backup() -> bool:
    """Завантажує students.json з Google Sheets при старті."""
    try:
        gc = _get_gs_client()
        if not gc:
            return False
        sh = gc.open_by_key(GOOGLE_SHEET_ID)
        try:
            ws = sh.worksheet(BACKUP_SHEET_NAME)
        except gspread.WorksheetNotFound:
            return False

        rows = ws.get_all_values()
        if len(rows) < 2 or not rows[1][2]:
            return False

        data_str = rows[1][2]
        # Валідуємо JSON
        data = json.loads(data_str)
        if not isinstance(data, dict):
            return False

        # Записуємо в файл
        Path(DB).write_text(data_str, encoding="utf-8")
        logger.info(f"DB restored from Sheets ({len(data)} students)")
        return True
    except Exception as e:
        logger.warning(f"gs_load_db_backup error: {e}")
        return False

async def job_backup_db(ctx):
    """Job: зберігає DB в Sheets кожні 30 хвилин."""
    gs_save_db_backup()

# ── POLYGLOT PATCH — SRS job ──────────────────────────
async def job_srs_reminder(ctx: ContextTypes.DEFAULT_TYPE):
    """Щоденно о 11:00: нагадує про SRS-повторення."""
    db    = load_db()
    today = datetime.now().strftime("%Y-%m-%d")
    for uid, s in db.items():
        if not isinstance(s, dict): continue
        if _is_in_active_challenge(s): continue  # у челенджі — не дублюємо
        if not _is_student_for_notify(uid, s): continue
        if str(uid) in DB_SKIP_KEYS: continue
        if not s.get("onboarding_done"):
            continue
        if not (is_premium(s) or is_in_trial(s)):
            continue
        if s.get("srs_remind_date") == today:
            continue
        due           = _srs_due_words(s)
        video_history = s.get("video_history", [])
        if not due and not video_history:
            continue
        upd_s(int(uid), {"srs_remind_date": today})

        # Вибираємо відео для повторення (найстаріше переглянуте)
        review_video = None
        if video_history:
            # Пропонуємо відео яке давно не переглядали (останнє в списку = найстаріше)
            import random
            review_video = random.choice(video_history[-3:]) if len(video_history) >= 3 else video_history[-1]

        try:
            kb = [[InlineKeyboardButton("🧠 Повторити фрази", callback_data="srs_start"),
                   InlineKeyboardButton("⏭ Пізніше",          callback_data="srs_skip")]]

            if review_video:
                player_url = _player_url(review_video["url"], s)
                kb.insert(0, [InlineKeyboardButton(
                    "▶️ Переглянути знову у плеєрі",
                    web_app=WebAppInfo(url=player_url)
                )] if player_url else [InlineKeyboardButton(
                    "▶️ Переглянути знову",
                    url=review_video["url"]
                )])
                text = (
                    f"🧠 *Час повторити фрази!*\n\n"
                    f"📚 Фраз до повторення: *{len(due)}*\n\n"
                    f"🎬 *З бібліотеки* — переглянь ще раз і потренуй shadowing:\n"
                    f"`youtube.com/watch?v={review_video['vid_id']}`\n\n"
                    "2 хвилини зараз = фраза назавжди 🎯"
                )
            else:
                words_preview = ", ".join(f"*{w['word']}*" for w in due[:4])
                suffix = " та ще..." if len(due) > 4 else ""
                text = (
                    f"🧠 *Час повторити фрази!*\n\n"
                    f"До повторення: {words_preview}{suffix}\n\n"
                    "2 хвилини зараз = фраза назавжди 🎯"
                )

            await _safe_send(
                ctx.bot,
                int(uid),
                text,
                parse_mode="Markdown",
                reply_markup=InlineKeyboardMarkup(kb)
            )
        except Exception as e:
            logger.warning(f"SRS reminder failed {uid}: {e}")

