async def job_streak_rescue(ctx: ContextTypes.DEFAULT_TYPE):
    """Щоденно о 21:00 — нагадує студентам у яких сьогодні ще не було активності і є стрік > 2."""
    import datetime as _dt
    db    = load_db()
    today = datetime.now().strftime("%Y-%m-%d")

    for uid, s in db.items():
        if not isinstance(s, dict): continue
        if not _is_student_for_notify(uid, s): continue
        if str(uid) in DB_SKIP_KEYS: continue
        if not s.get("onboarding_done"): continue
        if _is_in_active_challenge(s): continue   # v12: у челенджі — свій вечірній нудж
        # v12: фільтр «тільки платні/тріал» ПРИБРАНО.
        # Фріміум (челендж позаду, ще не платить) — це саме та людина, яку
        # треба тримати. Вечірня мотивація висить на ній, поки не оплатить.
        # Новачків і так відсіює streak >= 2.

        streak = s.get("streak_days", 0)
        if streak < 2: continue                          # немає що рятувати

        last_date = s.get("last_date", "")
        if last_date == today: continue                  # вже активний сьогодні

        # Не надсилати якщо вже надіслали rescue сьогодні
        if s.get("streak_rescue_date") == today: continue
        upd_s(int(uid), {"streak_rescue_date": today})

        name = s.get("name", "")
        name_line = f"*{name}*, " if name else ""
        msg = random.choice(STREAK_RESCUE_MSGS).format(streak=streak)
        motiv = random.choice(MOTIVATIONAL)          # v12: мотивація — сюди, не в челендж
        body = f"{name_line}{msg}\n\n_{motiv}_{STREAK_RESCUE_IMMERSION}"

        try:
            await _safe_send(
                ctx.bot,
                int(uid),
                body,
                parse_mode="Markdown",
                reply_markup=InlineKeyboardMarkup([
                    [InlineKeyboardButton("🎙 Сказати одну фразу", callback_data="rescue_choose")],
                    # 23.07: shell_url("ov-player") — той самий фікс, що в main_menu()
                    ([InlineKeyboardButton("💤 Просто слухати",
                        web_app=WebAppInfo(url=shell_url("ov-player")))]
                     if GITHUB_PAGES_URL else
                     [InlineKeyboardButton("💤 Просто слухати", callback_data="immersion_done")]),
                ])
            )
            logger.info(f"Streak rescue sent to {uid} (streak={streak})")
        except Exception as e:
            logger.warning(f"Streak rescue failed {uid}: {e}")


# ── Win-back: за прикладом Dara — одне чесне запитання на 7-й день ────
# 23.07: job_streak_rescue вище рятує СЬОГОДНІШНЮ бездіяльність (стрік
# горить), job_challenge_winback — вузько про челендж-воронку і вимкнений
# за замовчуванням. Жоден не покриває загальний випадок «людина просто
# перестала заходити». Власниця обрала конкретний, перевірений патерн
# (скріншот від розробника Dara) замість трирівневої ескалації: рівно
# ОДНЕ повідомлення на 7-й день, вільний текст, особисто. Не кнопки —
# кнопка дає швидшу, але поверхневу відповідь; тут ціль — чесна причина,
# а не голосування.
#
# Guard `winback_done` — рівно один нудж на людину, не по колу щотижня.
async def job_winback_check(ctx: ContextTypes.DEFAULT_TYPE):
    """Щодня о 16:00 — хто мовчить рівно 7+ днів і ще не отримав нудж."""
    db    = load_db()
    today = datetime.now()

    for uid, s in db.items():
        if not isinstance(s, dict): continue
        if not _is_student_for_notify(uid, s): continue
        if str(uid) in DB_SKIP_KEYS: continue
        if not s.get("onboarding_done"): continue
        if s.get("winback_done"): continue  # вже питали — не повторюємо

        last_date = s.get("last_date", "")
        if not last_date: continue
        try:
            days_gone = (today - datetime.fromisoformat(last_date)).days
        except Exception:
            continue
        if days_gone < 7: continue

        upd_s(int(uid), {"winback_done": True, "awaiting_winback_text": True})
        body = (
            "Привіт! Я засновниця SpeakChain. Ти практикував(ла) англійську "
            "з ботом.\n\n"
            "Одне питання: що завадило тобі продовжити? Стало нудно, забула(в) "
            "про це, надто складно, знайшла(ов) щось краще, чи щось інше?\n\n"
            "Чесна відповідь допоможе мені більше, ніж ввічлива. "
            "Просто напиши тут."
        )
        try:
            await _safe_send(ctx.bot, int(uid), body, parse_mode="Markdown")
            logger.info(f"Winback sent to {uid} (days_gone={days_gone})")
        except Exception as e:
            logger.warning(f"Winback failed {uid}: {e}")


async def handle_winback_text_reply(update, ctx) -> bool:
    """Перехоплює вільну відповідь після win-back-нуджу.
    Повертає True якщо повідомлення оброблено — виклик з handle_text() ДО звичайної логіки."""
    uid = update.effective_user.id
    s = get_s(uid)
    if not s.get("awaiting_winback_text"):
        return False
    text = (update.message.text or "").strip()
    if not text:
        return False
    log = s.get("winback_reasons", [])
    log.append({"text": text[:500], "date": datetime.now().strftime("%Y-%m-%d %H:%M")})
    upd_s(uid, {"winback_reasons": log, "awaiting_winback_text": False})
    await update.message.reply_text("Дякую, що написала(в) чесно. Це реально допомагає 🙏")
    return True


async def cmd_admin_winback(update, ctx):
    """/admin_winback — відповіді на win-back, читання власницею. Найновіші зверху."""
    if not is_admin(update.effective_user.id):
        return
    db = load_db()
    entries = []
    for uid, s in db.items():
        if not isinstance(s, dict): continue
        for r in s.get("winback_reasons", []):
            entries.append((uid, s.get("name", ""), r))
    entries.sort(key=lambda x: x[2].get("date", ""), reverse=True)
    if not entries:
        await update.message.reply_text("Поки що жодної відповіді на win-back.")
        return
    lines = ["📋 *Win-back — відповіді (останні 30)*\n"]
    for uid, name, r in entries[:30]:
        who = f"{name} ({uid})" if name else str(uid)
        lines.append(f"• {r.get('date','')} — *{who}*: {r.get('text','')}")
    await update.message.reply_text("\n".join(lines), parse_mode="Markdown")


