ENABLE_DAILY_CHECKIN = _flag("ENABLE_DAILY_CHECKIN", False)
# Staged rollout: "admin" | "10" | "all"
CHECKIN_ROLLOUT      = os.environ.get("CHECKIN_ROLLOUT", "admin")
CHECKIN_DEFAULT_HOUR = int(os.environ.get("CHECKIN_DEFAULT_HOUR", "18"))


# ── Гейт розкатки ───────────────────────────────────────────────────────────
def _checkin_in_rollout(uid: int) -> bool:
    """Хто потрапляє в розкатку. ADMIN_ID тут — int (як у bot.py)."""
    if not ENABLE_DAILY_CHECKIN:
        return False
    if CHECKIN_ROLLOUT == "admin":
        return uid == ADMIN_ID
    if CHECKIN_ROLLOUT == "10":
        return uid % 10 == 0            # детермінований 10% bucket
    return True                          # "all"


def _checkin_log_event(kind: str):
    """Глобальний денний лічильник check-in (точна історія по днях).
    kind: 'sent' | 'replied' | 'snoozed'. Живе в службовому записі _checkin_log,
    який доданий у DB_SKIP_KEYS (не плутається з юзерами). Обрізаємо до 90 днів."""
    try:
        today = datetime.now().strftime("%Y-%m-%d")
        db = load_db()
        log = db.get("_checkin_log", {})
        day = log.get(today, {"sent": 0, "replied": 0, "snoozed": 0})
        day[kind] = day.get(kind, 0) + 1
        log[today] = day
        # тримаємо лише останні 90 днів
        if len(log) > 90:
            for k in sorted(log.keys())[:-90]:
                log.pop(k, None)
        db["_checkin_log"] = log
        _DB_MEM["data"] = db
        _DB_DIRTY.add("_checkin_log")
    except Exception as e:
        logger.warning(f"checkin log event failed: {e}")


def _feature_log_event(feature: str, kind: str = "use"):
    """Глобальний денний лічильник подій фічі (для admin-аналітики).
    feature: 'victory' | 'video_practice' | 'grammar_decay' тощо.
    Службовий запис _feature_log у DB_SKIP_KEYS, історія 90 днів."""
    try:
        today = datetime.now().strftime("%Y-%m-%d")
        db = load_db()
        log = db.get("_feature_log", {})
        day = log.get(today, {})
        fkey = f"{feature}:{kind}"
        day[fkey] = day.get(fkey, 0) + 1
        log[today] = day
        if len(log) > 90:
            for k in sorted(log.keys())[:-90]:
                log.pop(k, None)
        db["_feature_log"] = log
        _DB_MEM["data"] = db
        _DB_DIRTY.add("_feature_log")
    except Exception as e:
        logger.warning(f"feature log event failed ({feature}): {e}")


def _checkin_pick_hour(s: dict) -> int:
    """Персональний час. Поки що: явний вибір юзера або дефолт.
    (Навчання часу по активності — фаза 2, коли зʼявиться годинна гістограма.)"""
    h = s.get("checkin_hour")
    if isinstance(h, int) and 0 <= h <= 23:
        return h
    return CHECKIN_DEFAULT_HOUR


# ── Серверний промпт (захист від підміни, як у решті Chainy) ────────────────
async def _checkin_build_message(s: dict) -> str:
    """Будує ОДИН рядок check-in. Memory-гачок, якщо є збережена тема."""
    name  = (s.get("name") or "").strip()
    topic = (s.get("last_buddy_topic") or "").strip()
    streak = s.get("streak_days", 0)
    today = datetime.now().strftime("%Y-%m-%d")
    at_risk = streak >= 3 and s.get("last_date", "") != today

    sys = (
        "Ти Chainy — теплий дружній AI-співрозмовник для практики англійської. "
        "Напиши РІВНО одне коротке повідомлення українською (макс 30 слів), "
        "від першої особи, як друг що згадав про людину. Одне відкрите питання "
        "в кінці. Без слова 'нагадування', без формальностей, 1 доречний емодзі."
    )
    if topic:
        ctx = f"Імʼя: {name or 'друже'}. Минула розмова була про: {topic}. Повернись до теми природно."
    else:
        ctx = f"Імʼя: {name or 'друже'}. Памʼяті ще немає — спитай щось легке, щоб почати розмову англійською."
    if at_risk:
        ctx += f" Серія {streak} днів поспіль під загрозою — мʼяко підбадьор не втратити її."

    try:
        cr = await claude_create_async(
            model="claude-haiku-4-5-20251001",
            max_tokens=80,
            system=sys,
            messages=[{"role": "user", "content": ctx}],
        )
        text = (cr.content[0].text or "").strip()
        if text:
            return text
    except Exception as e:
        logger.warning(f"checkin build failed: {e}")
    # Fallback — без AI
    if name:
        return f"Привіт, {name} 👋 Як твоя англійська сьогодні? Розкажи мені одну річ!"
    return "Привіт 👋 Як твоя англійська сьогодні? Розкажи мені одну річ!"


# ── Сам job: щогодини о :07, сам фільтрує за персональним часом ─────────────
async def job_daily_checkin(ctx: ContextTypes.DEFAULT_TYPE):
    """Chainy сам пише юзеру в його персональну годину. 1/день, з гардрейлами."""
    if not ENABLE_DAILY_CHECKIN:
        return
    now   = datetime.now()
    today = now.strftime("%Y-%m-%d")
    sent  = 0
    db    = load_db()

    for uid, s in db.items():
        if not isinstance(s, dict):            continue
        if not _is_student_for_notify(uid, s): continue
        if str(uid) in DB_SKIP_KEYS:           continue
        try:
            uid_i = int(uid)
        except (TypeError, ValueError):
            continue

        if not _checkin_in_rollout(uid_i):     continue
        if _is_in_active_challenge(s):         continue   # v12: у челенджі — свій потік
        if not s.get("onboarding_done"):       continue
        if not s.get("checkin_enabled", True): continue
        if not (is_premium(s) or is_in_trial(s)):   continue
        if s.get("checkin_sent_date") == today:     continue   # кап 1/день
        if s.get("last_date", "") == today:         continue   # вже активний — не турбуємо
        if _checkin_pick_hour(s) != now.hour:       continue

        msg = await _checkin_build_message(s)
        kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("🎤 Відповісти голосом", callback_data="checkin_reply:voice"),
             InlineKeyboardButton("💬 Текстом",            callback_data="checkin_reply:text")],
            [InlineKeyboardButton("😴 Не зараз",            callback_data="checkin_snooze")],
        ])
        try:
            ok = await _safe_send(ctx.bot, uid_i, msg, reply_markup=kb)
            if ok:
                upd_s(uid_i, {"checkin_sent_date": today})
                _checkin_log_event("sent")
                sent += 1
        except Exception as e:
            logger.warning(f"checkin send failed {uid}: {e}")

    if sent:
        logger.info(f"[checkin] sent={sent} hour={now.hour}")


# ── Callback: юзер натиснув «Відповісти» ────────────────────────────────────
async def cb_checkin_reply(update, ctx):
    q = update.callback_query
    await q.answer()
    uid = q.from_user.id
    # ── лог відповіді (точна історія + reply rate) ──
    today = datetime.now().strftime("%Y-%m-%d")
    s = get_s(uid)
    if s.get("checkin_sent_date") == today and s.get("checkin_replied_date") != today:
        upd_s(uid, {"checkin_replied_date": today,
                    "checkin_replies_total": s.get("checkin_replies_total", 0) + 1})
        _checkin_log_event("replied")
    try:
        mode = q.data.split(":", 1)[1]
    except IndexError:
        mode = "text"

    chainy_url = shell_url("s-buddy", context="checkin", mode=mode)
    kb = InlineKeyboardMarkup([[
        InlineKeyboardButton("🤖 Відкрити Chainy", web_app=WebAppInfo(url=chainy_url))
    ]])
    txt = ("Супер! Тисни — продовжимо розмову 👇" if mode == "voice"
           else "Окей! Відкрий Chainy і пиши мені прямо там 👇")
    try:
        await q.edit_message_reply_markup(reply_markup=None)
    except Exception:
        pass
    await ctx.bot.send_message(uid, txt, reply_markup=kb)


# ── Callback: мʼякий snooze на +3 год (не opt-out) ──────────────────────────
async def cb_checkin_snooze(update, ctx):
    q = update.callback_query
    await q.answer("Добре, нагадаю пізніше 😴")
    uid   = q.from_user.id
    today = datetime.now().strftime("%Y-%m-%d")
    _checkin_log_event("snoozed")
    upd_s(uid, {"checkin_snooze_total": get_s(uid).get("checkin_snooze_total", 0) + 1})
    try:
        await q.edit_message_reply_markup(reply_markup=None)
    except Exception:
        pass


