async def _classify_word_cefr_ai(word: str) -> str:
    """Одноразова AI-класифікація CEFR-рівня для слів поза Oxford-словником.
    Результат кешується в srs_words[word]['cefr'], тож виклик — раз на слово."""
    try:
        prompt = (
            f'Classify the CEFR level of the English word/phrase: "{word}".\n'
            'Reply with EXACTLY one token: A1, A2, B1, B2, C1 or C2. No other text.'
        )
        cr = await claude_create_async(
            model="claude-haiku-4-5-20251001", max_tokens=5,
            messages=[{"role": "user", "content": prompt}]
        )
        lvl = cr.content[0].text.strip().upper()[:2]
        return lvl if lvl in {"A1", "A2", "B1", "B2", "C1", "C2"} else None
    except Exception as e:
        logger.warning(f"_classify_word_cefr_ai error: {e}")
        return None


async def _enrich_phrase(phrase: str, level: str) -> dict:
    """
    Якщо у фрази немає перекладу/прикладу — генеруємо через Claude.
    Повертає {translation, example} або {}.
    """
    try:
        prompt = (
            f'English phrase: "{phrase}"\n'
            f'Student level: {level}\n\n'
            'Reply ONLY with valid JSON, no markdown:\n'
            '{"translation": "Ukrainian translation", '
            '"example": "Short example sentence in English"}'
        )
        cr = await claude_create_async(
            model="claude-haiku-4-5-20251001",
            max_tokens=120,
            messages=[{"role": "user", "content": prompt}]
        )
        import json as _j
        raw = cr.content[0].text.strip()
        raw = raw[raw.find("{"):raw.rfind("}")+1]
        return _j.loads(raw)
    except Exception as e:
        logger.warning(f"_enrich_phrase error: {e}")
        return {}


async def job_phrase_of_day(ctx: ContextTypes.DEFAULT_TYPE):
    """Щоденно о 8:30 — надсилає студенту фразу дня.
    Пріоритет джерел: блогерська фраза тижня → власний SRS → банк-fallback.
    Безкоштовно всім (Д7-анонс).
    """
    import random as _rnd
    db    = load_db()
    today = datetime.now().strftime("%Y-%m-%d")

    for uid, s in db.items():
        if not isinstance(s, dict): continue
        if _is_in_active_challenge(s): continue  # у челенджі — свій потік, не дублюємо
        if not _is_student_for_notify(uid, s): continue
        if str(uid) in DB_SKIP_KEYS: continue
        if not s.get("onboarding_done"): continue
        # 🔓 Фраза дня — БЕЗКОШТОВНО всім (Д7-анонс обіцяє це як retention-гак).
        # Раніше був платний гейт; знято свідомо. Монетизація — деінде
        # (Chainy-ліміт, платні фічі), а щоденна фраза тримає звичку в усіх.
        if s.get("phrase_of_day_date") == today: continue

        srs_db = s.get("srs_words", {})

        # ── ДЖЕРЕЛО ФРАЗИ (пріоритет) ─────────────────────────────────────
        #   1) Блогерська «фраза тижня» на сьогодні (свіжий контент від блогера)
        #   2) Власний SRS користувача
        #   3) Безкоштовний банк-ротація (fallback, якщо нема ні того, ні того)
        word = translation = example = ""
        _src_kind = ""
        _phrase_video = ""      # 🎬 відео блогера до фрази дня (YouTube ID)

        # 1) Блогерська фраза тижня (єдиний формат week_phrases = {"1".."7":текст},
        #    ключ = день тижня; заповнюється або з blogger.html, або /phrase_week)
        blogger_name = s.get("affiliate_blogger", "")
        if blogger_name:
            _bstate = _get_blogger_state_by_name(db, blogger_name)
            if _bstate:
                _wp = _bstate.get("week_phrases") or {}
                # день тижня 1..7 (пн=1) → фраза цього дня
                _dow = datetime.now().weekday() + 1  # weekday(): пн=0 → 1
                # Сумісність: week_phrases може бути рядком (старий формат)
                # або dict {text, id, video_url} (новий, для демо-петлі).
                _raw = _wp.get(str(_dow))
                if isinstance(_raw, dict):
                    _cand  = (_raw.get("text") or "").strip()
                    _cvid  = (_raw.get("video_url") or _raw.get("video") or "").strip()
                else:
                    _cand  = (_raw or "").strip()
                    # 🎬 Відео блогера до фрази дня — окремий словник
                    _cvid  = ((_bstate.get("week_phrase_videos") or {}).get(str(_dow)) or "").strip()
                if _cand:
                    word = _cand
                    _src_kind = "blogger_week"
                    _phrase_video = _cvid or ""

        _use_free_bank = (not word) and (not srs_db)

        if word and _src_kind == "blogger_week":
            # блогерська фраза — переклад/приклад можна не мати; лишаємо як є
            pass
        elif _use_free_bank:
            # Безкоштовний користувач без колекції — беремо з банку (Д7-обіцянка).
            try:
                from challenge_content import get_free_daily_phrase
                _fp = get_free_daily_phrase(datetime.now().timetuple().tm_yday)
            except Exception:
                _fp = {}
            if not _fp:
                continue
            word        = _fp.get("phrase", "")
            translation = _fp.get("tr", "")
            example     = _fp.get("ex", "")
            if not word:
                continue
        else:
            # Всі фрази — з або без перекладу
            candidates = list(srs_db.items())
            if not candidates:
                continue

            # Пріоритет — найменш відомі
            candidates.sort(key=lambda x: x[1].get("count_know", 0))
            import random as _rnd
            word, entry = _rnd.choice(candidates[:5])

            translation = entry.get("translation", "")
            example     = entry.get("example", "")

            # Якщо немає перекладу — генеруємо через AI і зберігаємо
            if not translation and not example:
                level   = s.get("level", "A1")
                enriched = await _enrich_phrase(word, level)
                if enriched:
                    translation = enriched.get("translation", "")
                    example     = enriched.get("example", "")
                    # Зберігаємо в SRS щоб наступного разу не генерувати
                    srs_db[word]["translation"] = translation
                    srs_db[word]["example"]     = example
                    upd_s(int(uid), {"srs_words": srs_db})
                else:
                    continue  # AI не відповів — пропускаємо

        intro = _rnd.choice(PHRASE_OF_DAY_INTROS)
        text  = f"{intro}\n\n🔤 *{word}*"
        if translation:
            text += f"\n📖 _{translation}_"
        if example:
            text += f"\n\n💬 _{example}_"
        text += "\n\n👇 Використай цю фразу у монолозі — і вона залишиться назавжди!"

        upd_s(int(uid), {"phrase_of_day_date": today})
        try:
            # 🎬 Якщо блогер вклав відео до фрази — даємо кнопку подивитись
            _rows = []
            if _phrase_video:
                _rows.append([InlineKeyboardButton(
                    "🎬 Дивитись відео від блогера",
                    url=f"https://youtu.be/{_phrase_video}",
                )])
            _rows.append([InlineKeyboardButton("🎙 Записати монолог з цією фразою", callback_data="remind_record")])
            _rows.append([InlineKeyboardButton("⏭ Побачимось завтра",              callback_data="phrase_skip")])

            await _safe_send(
                ctx.bot,
                int(uid),
                text,
                parse_mode="Markdown",
                reply_markup=InlineKeyboardMarkup(_rows),
            )
        except Exception as e:
            logger.warning(f"phrase_of_day {uid}: {e}")


async def job_sleep_reminder(ctx: ContextTypes.DEFAULT_TYPE):
    """Щоденно о 22:00: нагадування про пасивне слухання перед сном."""
    db    = load_db()
    today = datetime.now().strftime("%Y-%m-%d")
    for uid, s in db.items():
        if not isinstance(s, dict): continue
        if not _is_student_for_notify(uid, s): continue
        if str(uid) in DB_SKIP_KEYS: continue
        if not s.get("onboarding_done"):
            continue
        if not (is_premium(s) or is_in_trial(s)):
            continue
        if s.get("sleep_remind_date") == today:
            continue
        level    = s.get("level", "A1")
        resource = SLEEP_AUDIO_RESOURCES.get(level, "аудіо англійською")
        msg_tmpl = random.choice(SLEEP_MESSAGES)
        upd_s(int(uid), {"sleep_remind_date": today})
        try:
            await _safe_send(
                ctx.bot,
                int(uid),
                msg_tmpl.format(resource=resource),
                parse_mode="Markdown",
                reply_markup=InlineKeyboardMarkup([[
                    InlineKeyboardButton("✅ Вмикаю зараз",  callback_data="immersion_done"),
                    InlineKeyboardButton("⏭ Не сьогодні",   callback_data="sleep_skip"),
                ]])
            )
        except Exception as e:
            logger.warning(f"Sleep reminder failed {uid}: {e}")

