# ════════════════════════════════════════════════════════════
# PERFORMANCE LAYER — connection pool + write-behind cache
# ════════════════════════════════════════════════════════════

# ── PostgreSQL Connection Pool (5-20 з'єднань) ─────────────
_PG_POOL = None

# Стан пулу: щоб не перестворювати його по колу щосекунди
_PG_POOL_STATE = {"failed_at": 0, "fails": 0}


def _pg_pool_reset(reason: str = ""):
    """Викидає мертвий пул, щоб наступний виклик створив новий.

    🔴 БУЛА ДІРА: _get_pg_pool() перевіряв `if _PG_POOL is None`.
    Якщо пул СТВОРИВСЯ, а потім ПОМЕР (база впала й піднялась —
    звичайна річ на Railway), то _PG_POOL уже НЕ None — він просто
    зламаний. І код НІКОЛИ не пробував його перестворити.

    Результат: PostgreSQL піднялась за хвилину, а бот назавжди лишився
    зі здохлим пулом і писав у JSON. До наступного рестарту бота.
    """
    global _PG_POOL
    if _PG_POOL is None:
        return
    try:
        _PG_POOL.closeall()
    except Exception:
        pass
    _PG_POOL = None
    _PG_POOL_STATE["failed_at"] = int(_time.time())
    _PG_POOL_STATE["fails"] += 1
    logger.warning("♻️ PG пул скинуто (%s). Наступний запит створить новий.",
                   reason or "мертвий")


def _get_pg_pool():
    """
    Ліниво ініціалізує connection pool.

    Розмір береться з ENV (можна міняти без зміни коду):
      PG_POOL_MIN (дефолт 5)  — завжди готові з'єднання
      PG_POOL_MAX (дефолт 50) — максимум паралельних з'єднань

    ⚠️ PG_POOL_MAX НЕ МОЖЕ бути більшим за max_connections самої БД.
       Railway PG за замовчуванням max_connections=100. Перш ніж піднімати
       PG_POOL_MAX вище ~80, треба підняти max_connections у Railway PG
       (або поставити PgBouncer — тоді пул може бути великим, а реальних
        з'єднань до БД лишиться мало).
       Кожне PG-з'єднання ~5-10 MB RAM.
    """
    global _PG_POOL
    if not DATABASE_URL:
        return None
    if _PG_POOL is None:
        # Backoff: якщо щойно падали — не гатимо базу щосекунди.
        # Пауза росте: 0 → 2с → 4с → 8с → ... → максимум 30с.
        _f = _PG_POOL_STATE["fails"]
        if _f:
            _wait = min(30, 2 ** min(_f, 5))
            if int(_time.time()) - _PG_POOL_STATE["failed_at"] < _wait:
                return None          # ще рано — база не встигла піднятись
        try:
            import psycopg2.pool
            pool_min = int(os.environ.get("PG_POOL_MIN", "5"))
            pool_max = int(os.environ.get("PG_POOL_MAX", "50"))
            if pool_max < pool_min:
                pool_max = pool_min
            _PG_POOL = psycopg2.pool.ThreadedConnectionPool(
                pool_min,
                pool_max,
                DATABASE_URL,
                sslmode="require",
                connect_timeout=5,
                keepalives=1,           # TCP keepalive — щоб з'єднання не рвались
                keepalives_idle=30,     # після 30 сек idle — надсилаємо keepalive
                keepalives_interval=10, # кожні 10 сек повторюємо
                keepalives_count=5,     # 5 спроб перш ніж вважати з'єднання мертвим
            )
            _PG_POOL_STATE["fails"] = 0      # піднялись — забуваємо історію
            logger.info(f"✅ PG connection pool ready ({pool_min}-{pool_max} conns)")
        except Exception as e:
            _PG_POOL_STATE["failed_at"] = int(_time.time())
            _PG_POOL_STATE["fails"] += 1
            logger.warning("PG pool init error (спроба %s): %s",
                           _PG_POOL_STATE["fails"], e)
    return _PG_POOL

def _pg_conn():
    """
    Бере з'єднання з пулу.
    Якщо з'єднання мертве (timeout, network drop) — автоматично reconnect.
    """
    pool = _get_pg_pool()
    if not pool:
        return None
    try:
        conn = pool.getconn()
        if conn is None:
            return None
        # Перевіряємо чи з'єднання живе (ping)
        try:
            conn.cursor().execute("SELECT 1")
            conn.rollback()  # rollback після ping щоб не було відкритої транзакції
        except Exception:
            # З'єднання мертве — закриваємо і беремо нове.
            # Другий getconn теж може впасти (база лежить) — тому в try,
            # а не «на удачу»: раніше виняток летів у зовнішній except
            # і пул скидався випадково, без closeall() → зʼєднання текли.
            try:
                pool.putconn(conn, close=True)
            except Exception:
                pass
            try:
                conn = pool.getconn()
            except Exception as _e2:
                _pg_pool_reset(f"getconn після ping: {_e2}")
                return None
        return conn
    except Exception as e:
        logger.warning(f"PG pool getconn: {e}")
        # ♻️ Чистий скид: closeall() + backoff, щоб не гатити базу щосекунди.
        # БУЛО: _PG_POOL = None напряму — старі зʼєднання лишались відкритими
        # і текли, а нові спроби йшли без паузи.
        _pg_pool_reset(str(e))
        return None

def _pg_release(conn):
    """Повертає з'єднання в пул."""
    pool = _get_pg_pool()
    if pool and conn:
        try:
            pool.putconn(conn)
        except Exception:
            pass

