#  ЧОМУ ЛІЧИЛЬНИКИ, А НЕ ТЕКСТИ:
#  save_db() перезаписує ВСЮ базу одним JSONB щоразу. Якби ми писали
#  текст фрази в кожного учня (200 записів × N учнів), база б виросла
#  утричі — і кожен flush коштував би втричі більше. Назавжди.
#  Замість цього тримаємо ОДИН словник на блогера з лічильниками:
#  той самий "I get it" у 300 учнів = один запис зі значенням 300.
#  У ~50 разів дешевше, дані ті самі.
#
#  Структура в БД (новий службовий ключ, як _payouts чи _topic_popularity):
#    db["_content_stats"]["<blogger>"] = {
#        "saved":   {"I get it": 34},    # скільки разів ЗБЕРЕГЛИ
#        "spoken":  {"I get it": 89},    # скільки разів ПРОГОВОРИЛИ вголос
#        "videos":  {"Small talk": 21},  # збережень із цього відео
#        "grammar": {"Present Simple": 55},
#    }
#    db["_content_stats"]["_all"] = {...}   # те саме, але по всій платформі
#                                           # (для адмін-аналітики)
#
#  Нічого зі старого не чіпає: mined_sentences, spoken_total,
#  phrases_spoken лишаються як були. Лічильники йдуть ПАРАЛЕЛЬНО.
# ═══════════════════════════════════════════════════════════════════

_CS_MAX_PHRASES = 400      # стеля унікальних фраз на блогера
_CS_MAX_VIDEOS  = 100
_CS_MAX_GRAMMAR = 100
_CS_ALL         = "_all"   # псевдо-блогер: агрегат по всій платформі


def _cs_bump(uid: int, bucket: str, key: str, limit: int = _CS_MAX_PHRASES):
    """Інкрементує лічильник — і для блогера учня, і для платформи.

    uid    — учень
    bucket — "saved" | "spoken" | "videos" | "grammar"
    key    — текст фрази / назва відео / граматична тема
    """
    key = (key or "").strip()
    if not key:
        return
    key = key[:120]

    try:
        s = get_s(uid)
    except Exception:
        return

    blogger = (s.get("affiliate_blogger") or "").strip().lower()

    db   = load_db()
    root = db.setdefault("_content_stats", {})

    # Рахуємо і для блогера (якщо є), і завжди — для платформи цілком
    targets = [_CS_ALL]
    if blogger:
        targets.append(blogger)

    for t in targets:
        bstats  = root.setdefault(t, {})
        counter = bstats.setdefault(bucket, {})
        counter[key] = counter.get(key, 0) + 1

        # Хвіст обрізаємо: лишаємо найпопулярніші
        if len(counter) > limit:
            top = sorted(counter.items(), key=lambda kv: kv[1], reverse=True)[:limit]
            bstats[bucket] = dict(top)


def _cs_top(scope: str, bucket: str, n: int = 5) -> list:
    """Топ-N як [{"name": ..., "count": ...}]. scope = ім'я блогера або "_all"."""
    scope = (scope or "").strip().lower()
    if not scope:
        return []
    counter = (
        load_db().get("_content_stats", {}).get(scope, {}).get(bucket, {})
    )
    if not counter:
        return []
    top = sorted(counter.items(), key=lambda kv: kv[1], reverse=True)[:n]
    return [{"name": k, "count": v} for k, v in top]


def _cs_total(scope: str, bucket: str) -> int:
    """Сума лічильників у корзині."""
    scope = (scope or "").strip().lower()
    if not scope:
        return 0
    counter = (
        load_db().get("_content_stats", {}).get(scope, {}).get(bucket, {})
    )
    return sum(counter.values()) if counter else 0


def _cs_uniq(scope: str, bucket: str) -> int:
    """Скільки УНІКАЛЬНИХ фраз/відео/тем у корзині."""
    scope = (scope or "").strip().lower()
    if not scope:
        return 0
    counter = (
        load_db().get("_content_stats", {}).get(scope, {}).get(bucket, {})
    )
    return len(counter) if counter else 0


def _blogger_levels(students) -> dict:
    """Розподіл за рівнями. students = [(uid, state), ...]."""
    out = {}
    for _uid, s in students:
        if not isinstance(s, dict):
            continue
        lvl = (s.get("level") or "").strip()
        if lvl:
            out[lvl] = out.get(lvl, 0) + 1
    return out


def _blogger_progress_summary(students, username: str) -> dict:
    """
    22.07: середні методичні показники по всій аудиторії блогера —
    для картки «Прогрес аудиторії» в кабінеті блогера.
    students = [(uid, state), ...], той самий формат що _blogger_levels.

    Джерела полів (усі вже наявні в стані студента, звірено):
    - avg_study_days   <- registered_at (скільки днів тому зареєструвався)
    - level_ups        <- level_history (кількість зафіксованих переходів
                          рівня за весь час, по всій аудиторії разом)
    - avg_words        <- srs_words через compute_vocab_volume (сума
                          обсягів по всіх банках, як у решті проєкту)
    - referrals_brought <- інші студенти БД, чий referrer_uid є в цьому
                          списку (реферали, приведені студентами САМЕ
                          цього блогера — не реферали самого блогера)
    - daily_minutes    <- 23.07: тепер РЕАЛЬНО рахується. Джерело —
                          speaking_seconds_total (голос/відео, точна
                          Telegram-тривалість, handle_voice/handle_video)
                          + player_minutes_total (плеєр, playback_sec).
                          Ділимо на avg_study_days, бо обидва поля —
                          НАКОПИЧУВАЛЬНІ за весь час навчання, не за
                          сьогодні. "На день" тут — середнє за весь
                          період, не факт сьогоднішньої сесії.
    """
    if not students:
        return {
            "count": 0, "avg_study_days": None, "avg_words": None,
            "level_ups_total": None, "referrals_brought": None,
            "daily_minutes": None,
        }

    now = datetime.now()
    study_days = []
    for _uid, s in students:
        if not isinstance(s, dict):
            continue
        reg = s.get("registered_at", "")
        if reg:
            try:
                d = (now - datetime.strptime(str(reg)[:10], "%Y-%m-%d")).days
                if d >= 0:
                    study_days.append(d)
            except Exception:
                pass

    level_ups = 0
    for _uid, s in students:
        if not isinstance(s, dict):
            continue
        hist = s.get("level_history", [])
        if isinstance(hist, list):
            level_ups += max(0, len(hist) - 1)  # перший запис = старт, не перехід

    words = []
    for _uid, s in students:
        if not isinstance(s, dict):
            continue
        try:
            vol = compute_vocab_volume(s.get("srs_words", {}))
            words.append(sum(vol.values()) if isinstance(vol, dict) else 0)
        except Exception:
            pass

    student_uids = {str(uid) for uid, _s in students}
    referrals_brought = 0
    db = load_db()
    for _uid, other_s in db.items():
        if not isinstance(other_s, dict):
            continue
        ref_uid = other_s.get("referrer_uid")
        if ref_uid and str(ref_uid) in student_uids:
            referrals_brought += 1

    # 23.07: середня практика на день, за весь час навчання кожного студента.
    # Персональний "хв/день" рахуємо ОКРЕМО для кожного студента (його
    # накопичена практика / його власні дні навчання), а не загальну суму
    # практики групи поділену на загальну суму днів — інакше один старий
    # активний студент і десять нових неактивних дали б однаково викривлену
    # середню. Кожен студент дає свою чесну персональну швидкість.
    daily_minutes_per_student = []
    for _uid, s in students:
        if not isinstance(s, dict):
            continue
        reg = s.get("registered_at", "")
        if not reg:
            continue
        try:
            days = (now - datetime.strptime(str(reg)[:10], "%Y-%m-%d")).days
        except Exception:
            continue
        if days < 1:
            continue
        speaking_min = s.get("speaking_seconds_total", 0) / 60
        player_min   = s.get("player_minutes_total", 0)
        daily_minutes_per_student.append((speaking_min + player_min) / days)

    return {
        "count":             len(students),
        "avg_study_days":    round(sum(study_days) / len(study_days)) if study_days else None,
        "avg_words":         round(sum(words) / len(words)) if words else None,
        "level_ups_total":   level_ups,
        "referrals_brought": referrals_brought,
        "daily_minutes":     (round(sum(daily_minutes_per_student) / len(daily_minutes_per_student), 1)
                               if daily_minutes_per_student else None),
    }


def load_db() -> dict:
    """Повертає in-memory DB (завантажує один раз при старті)."""
    if _DB_MEM["data"] is not None:
        return _DB_MEM["data"]
    # 23.07: таймер лише навколо РЕАЛЬНОГО холодного читання (нижче),
    # не навколо кешованого шляху вище — цікавить час рестарту бота,
    # не швидкість кешу. Метрика для адмінки, Реєстр K-10.
    _load_start = _time.monotonic()
    # Одноразове завантаження при старті
    if DATABASE_URL:
        conn = _pg_conn()
        if conn:
            try:
                with conn.cursor() as cur:
                    cur.execute("SELECT data FROM speakchain_db WHERE id='main'")
                    row = cur.fetchone()
                    result = row[0] if row else {}
                    _DB_MEM["data"] = result
                    _DB_LOAD_MS["value"] = round((_time.monotonic() - _load_start) * 1000, 1)
                    return result
            except Exception as e:
                logger.warning(f"PG load error: {e}")
            finally:
                _pg_release(conn)
    try:
        result = json.loads(Path(DB).read_text()) if Path(DB).exists() else {}
        _DB_MEM["data"] = result
        _DB_LOAD_MS["value"] = round((_time.monotonic() - _load_start) * 1000, 1)
        return result
    except Exception:
        _DB_MEM["data"] = {}
        return {}


def save_db(db: dict):
    """Зберігає БД в PostgreSQL або JSON. Викликати тільки з flush job."""
    if DATABASE_URL:
        conn = _pg_conn()
        if conn:
            try:
                with conn.cursor() as cur:
                    cur.execute("""
                        INSERT INTO speakchain_db (id, data)
                        VALUES ('main', %s::jsonb)
                        ON CONFLICT (id) DO UPDATE SET data = EXCLUDED.data
                    """, (json.dumps(db, ensure_ascii=False),))
                conn.commit()
                return
            except Exception as e:
                logger.warning(f"PG save error: {e}")
            finally:
                _pg_release(conn)
    try:
        Path(DB).write_text(json.dumps(db, ensure_ascii=False, indent=2))
    except Exception as e:
        logger.warning(f"JSON save error: {e}")


# ── Модулі отримують доступ до бази (щоб не імпортувати bot.py — циклічний імпорт) ──
ai_costs_init(load_db, save_db, logger)
finance_init(load_db, save_db, logger)
shared_chain_init(load_db, save_db)
lottery_init(load_db, save_db, logger)


