# ── Rate limiter для масових розсилок ────────────────────────
# Telegram: 30 повідомлень/сек глобально, 1 повідомлення/сек на юзера
# При 5000 юзерів без затримки → 429 Too Many Requests
# asyncio.sleep(0.034) = ~29 msg/sec → безпечно

_TG_SEND_DELAY  = 0.034   # секунд між повідомленнями в job-розсилках
_BATCH_SIZE     = 1000    # юзерів на батч
_BATCH_PAUSE    = 5.0     # секунд паузи між батчами


async def _send_in_batches(bot, tasks: list, batch_size: int = _BATCH_SIZE, pause: float = _BATCH_PAUSE) -> dict:
    """
    Надсилає повідомлення батчами щоб не перевантажувати Telegram.

    tasks — список coroutines або callable що повертають coroutine.
    Кожен батч: batch_size задач → пауза pause секунд → наступний батч.

    При 5000 юзерів і batch_size=1000:
      5 батчів × ~34 сек кожен + 4 паузи × 5 сек = ~190 сек (~3 хв)
    """
    stats = {"sent": 0, "errors": 0}
    total = len(tasks)

    for batch_start in range(0, total, batch_size):
        batch = tasks[batch_start:batch_start + batch_size]
        batch_num = batch_start // batch_size + 1
        total_batches = (total + batch_size - 1) // batch_size

        logger.info(f"Batch {batch_num}/{total_batches}: sending {len(batch)} messages")

        for task in batch:
            try:
                if callable(task):
                    result = await task()
                else:
                    result = await task
                if result is not False:
                    stats["sent"] += 1
                else:
                    stats["errors"] += 1
            except Exception as e:
                stats["errors"] += 1
                logger.warning(f"batch task error: {e}")
            await asyncio.sleep(_TG_SEND_DELAY)

        # Пауза між батчами (крім останнього)
        if batch_start + batch_size < total:
            logger.info(f"Batch {batch_num} done. Pausing {pause}s before next batch...")
            await asyncio.sleep(pause)

    logger.info(f"All batches done: {stats}")
    return stats

async def _safe_send_video(bot, chat_id: int, file_id: str,
                          caption: str | None = None) -> bool:
    """Надсилає відео з тим самим захистом, що й _safe_send.

    Блогер шле відео в чат бота → ми маємо file_id → пересилаємо учням.
    Файл не качається і не зберігається: Telegram тримає його в себе,
    ми лише передаємо посилання на нього. Тому це швидко й не їсть диск.

    Кружечок (video_note) підпису НЕ підтримує — Telegram відхилить.
    Тому для кружечків шлемо текст окремим повідомленням.
    """
    from telegram.error import RetryAfter, Forbidden, BadRequest

    for attempt in range(3):
        try:
            kw = {}
            if caption:
                kw = {"caption": caption, "parse_mode": "Markdown"}
            await bot.send_video(chat_id=chat_id, video=file_id, **kw)
            await asyncio.sleep(_TG_SEND_DELAY)
            return True
        except RetryAfter as e:
            wait = e.retry_after + 1
            logger.warning(f"Rate limit (video) {chat_id}, waiting {wait}s")
            await asyncio.sleep(wait)
        except Forbidden:
            upd_s(chat_id, {"bot_blocked": True})
            return False
        except BadRequest as e:
            # Найчастіше: file_id протух або це кружечок (video_note).
            # Пробуємо як кружечок — інакше учениця не отримає нічого.
            logger.warning(f"BadRequest video {chat_id}: {e}")
            try:
                await bot.send_video_note(chat_id=chat_id, video_note=file_id)
                await asyncio.sleep(_TG_SEND_DELAY)
                return True
            except Exception:
                return False
        except Exception as e:
            logger.warning(f"send_video {chat_id} attempt {attempt+1}: {e}")
            await asyncio.sleep(1)
    return False


async def _safe_send(bot, chat_id: int, text: str, **kwargs) -> bool:
    """
    Надсилає повідомлення з автоматичним retry при 429.
    Повертає True якщо успішно, False якщо юзер заблокував бота.
    Використовувати в усіх job-циклах замість bot.send_message напряму.
    """
    from telegram.error import RetryAfter, Forbidden, BadRequest
    for attempt in range(3):
        try:
            await bot.send_message(chat_id=chat_id, text=text, **kwargs)
            await asyncio.sleep(_TG_SEND_DELAY)
            return True
        except RetryAfter as e:
            wait = e.retry_after + 1
            logger.warning(f"Rate limit hit for {chat_id}, waiting {wait}s")
            await asyncio.sleep(wait)
        except Forbidden:
            # Юзер заблокував бота — позначаємо і пропускаємо
            upd_s(chat_id, {"bot_blocked": True})
            return False
        except BadRequest as e:
            logger.warning(f"BadRequest {chat_id}: {e}")
            return False
        except Exception as e:
            logger.warning(f"send_message {chat_id} attempt {attempt+1}: {e}")
            await asyncio.sleep(1)
    return False


def get_s(uid: int) -> dict:
    return load_db().get(str(uid), {})


def upd_s(uid: int, data: dict, force: bool = False):
    """
    Оновлює дані юзера в пам'яті.
    force=True → одразу в PostgreSQL (для платежів та критичних даних).
    force=False (default) → тільки в пам'яті, flush кожні 30 сек.
    """
    db = load_db()
    db.setdefault(str(uid), {}).update(data)
    _DB_MEM["data"] = db
    _DB_DIRTY.add(str(uid))
    if force:
        save_db(db)


def _patch_cstate(uid: int, patch: dict, force: bool = False):
    """
    Race-safe оновлення окремих полів challenge_state.

    Проблема: запис усього cstate через upd_s(uid, {"challenge_state": cstate})
    може затерти зміни, що сталися між читанням cstate і записом (напр. джоба
    прочитала cstate, зробила await, а юзер тим часом оновив свій стан — і
    запис джоби відкочує зміну юзера — lost update).

    Рішення: читаємо СВІЖИЙ cstate з БД перед самим записом і оновлюємо лише
    потрібні поля (patch), не весь об'єкт. Вікно гонки закривається, бо між
    свіжим читанням і записом немає await.
    """
    db = load_db()
    _u = db.setdefault(str(uid), {})
    _cs = dict(_u.get("challenge_state") or {})
    _cs.update(patch)
    _u["challenge_state"] = _cs
    _DB_MEM["data"] = db
    _DB_DIRTY.add(str(uid))
    if force:
        save_db(db)


# ── Batch flush — раз на 30 секунд ──────────────────────────
# Скільки flush-ів поспіль упало — для сповіщення й діагностики
_FLUSH_FAILS = {"n": 0, "notified": False}


async def job_flush_db(ctx=None):
    """
    Зберігає тільки змінених юзерів (dirty) замість всього blob.

    ══════════════════════════════════════════════════════════════
    ТУТ БУЛО ТРИ ВАДИ, І КОЖНА ВЕЛА ДО ВТРАТИ ДАНИХ КОРИСТУВАЧІВ
    ══════════════════════════════════════════════════════════════

    1) _DB_DIRTY.clear() СТОЯВ ПЕРЕД ЗБЕРЕЖЕННЯМ.
       Список змінених очищався ДО того, як дані записано. Якщо запис
       падав — зміни зникали НАЗАВЖДИ: наступний flush уже не знав, що
       їх треба зберегти. Людина пройшла урок, отримала XP — і все це
       випарувалось, бо база моргнула на секунду.
       ТЕПЕР: чистимо ТІЛЬКИ після успіху. Упало — повертаємо в чергу.

    2) if conn: — А ЯКЩО None?
       Тоді код мовчки провалювався у JSON-fallback. На Railway файлова
       система ЕФЕМЕРНА: при наступному деплої файл зникає РАЗОМ ІЗ
       УСІМА ДАНИМИ. І ніхто про це не знав.
       ТЕПЕР: сповіщення власниці + лічильник падінь.

    3) JSON-FALLBACK МОВЧАВ.
       logger.warning — і все. Ви дізналися б про втрату бази з того,
       що користувачі почали скаржитись.
       ТЕПЕР: 🔴 у лог + сповіщення в телеграм на 3-му падінні поспіль.
    """
    if not _DB_DIRTY:
        return

    dirty_uids  = set(_DB_DIRTY)
    dirty_count = len(dirty_uids)
    # ⚠️ НЕ чистимо _DB_DIRTY тут! Тільки після успішного запису.

    db = _DB_MEM.get("data")
    if db is None:
        return

    if DATABASE_URL:
        conn = _pg_conn()
        if conn:
            try:
                dirty_patch = {uid: db[uid] for uid in dirty_uids if uid in db}
                if dirty_patch:
                    with conn.cursor() as cur:
                        cur.execute("""
                            INSERT INTO speakchain_db (id, data)
                            VALUES ('main', %s::jsonb)
                            ON CONFLICT (id) DO UPDATE
                            SET data = speakchain_db.data || EXCLUDED.data
                        """, (json.dumps(dirty_patch, ensure_ascii=False),))
                    conn.commit()

                # ✅ УСПІХ — тільки ТЕПЕР чистимо чергу
                for _u in dirty_uids:
                    _DB_DIRTY.discard(_u)
                _FLUSH_FAILS["n"] = 0
                _FLUSH_FAILS["notified"] = False

                logger.info(f"DB flush: {dirty_count} dirty → PG patch "
                            f"({len(json.dumps(dirty_patch).encode())//1024}KB)")
                return
            except Exception as e:
                _FLUSH_FAILS["n"] += 1
                logger.error(
                    "🔴 PG FLUSH УПАВ (%s-й раз поспіль): %s\n"
                    "   %s змін НЕ збережено — лишаються в черзі, спробуємо ще.",
                    _FLUSH_FAILS["n"], e, dirty_count
                )
                # Зміни лишаються в _DB_DIRTY → наступний flush спробує знову
                await _flush_alert_if_needed()
                return          # НЕ падаємо в JSON — це втрата даних на Railway
            finally:
                _pg_release(conn)
        else:
            _FLUSH_FAILS["n"] += 1
            logger.error(
                "🔴 PostgreSQL НЕДОСТУПНА (%s-й раз): не вдалося взяти зʼєднання.\n"
                "   %s змін чекають у черзі.",
                _FLUSH_FAILS["n"], dirty_count
            )
            await _flush_alert_if_needed()
            return

    # ── DATABASE_URL узагалі не задана → JSON. Це вже свідомий вибір. ──
    try:
        await asyncio.to_thread(save_db, db)
        for _u in dirty_uids:
            _DB_DIRTY.discard(_u)
        logger.info(f"DB flush: {dirty_count} dirty → JSON file")
    except Exception as e:
        logger.error(f"🔴 JSON flush упав: {e} — {dirty_count} змін у черзі")


async def _flush_alert_if_needed():
    """Три падіння поспіль — пишемо власниці. Раніше не смикаємо.

    Одне падіння — може бути мережеве моргання, база сама встане.
    Три поспіль — це вже не збіг: щось справді зламалось, і кожна
    хвилина без запису = дані користувачів висять у памʼяті й зникнуть
    при першому ж рестарті.
    """
    if _FLUSH_FAILS["n"] < 3 or _FLUSH_FAILS["notified"]:
        return
    _FLUSH_FAILS["notified"] = True
    if not ADMIN_ID or not _HTTP_BOT:
        return
    try:
        await _HTTP_BOT.send_message(
            chat_id=ADMIN_ID,
            text=(
                "🔴 *БАЗА НЕ ЗБЕРІГАЄТЬСЯ*\n\n"
                f"PostgreSQL не приймає записи вже *{_FLUSH_FAILS['n']}* спроб поспіль.\n\n"
                "Дані користувачів зараз ЛИШЕ В ПАМʼЯТІ. Якщо бот перезапуститься — "
                "усе, що вони зробили від останнього успішного запису, ЗНИКНЕ.\n\n"
                "*Що робити:*\n"
                "1. Railway → PostgreSQL → перевірте, чи він живий\n"
                "2. Railway → Logs → шукайте `PG FLUSH УПАВ`\n"
                "3. Якщо база впала — перезапустіть її, НЕ бота\n\n"
                "_Бот далі тримає зміни в черзі й пробує зберегти. "
                "Дані не викидаються._"
            ),
            parse_mode="Markdown",
        )
    except Exception as e:
        logger.warning(f"flush alert: {e}")

def _pg_init():
    """Створює таблицю якщо не існує."""
    conn = _pg_conn()
    if not conn:
        return
    try:
        with conn.cursor() as cur:
            cur.execute("""
                CREATE TABLE IF NOT EXISTS speakchain_db (
                    id   TEXT PRIMARY KEY DEFAULT 'main',
                    data JSONB NOT NULL DEFAULT '{}'
                )
            """)
            cur.execute("""
                INSERT INTO speakchain_db (id, data)
                VALUES ('main', '{}')
                ON CONFLICT (id) DO NOTHING
            """)
        conn.commit()
        logger.info("✅ PostgreSQL table ready")
    except Exception as e:
        logger.warning(f"PG init error: {e}")
    finally:
        _pg_release(conn)

# ── Social URL detection ──────────────────────────────
def detect_platform(url: str) -> str:
    """Return 'youtube'|'tiktok'|'instagram'|'unknown'"""
    u = url.lower()
    if "youtube.com" in u or "youtu.be" in u: return "youtube"
    if "tiktok.com" in u or "vm.tiktok" in u: return "tiktok"
    if "instagram.com" in u or "instagr.am" in u: return "instagram"
    return "unknown"

def is_supported_video(url: str) -> bool:
    return detect_platform(url) != "unknown"

# ── YouTube API search ───────────────────────────────
async def youtube_search(query: str, max_results: int = 5,
                         age_group: str = "adult",
                         max_duration_min: int = 8) -> list[dict]:
    """Search YouTube and return list of {id, url, title, channel, duration_sec}"""
    if not YOUTUBE_API_KEY:
        return []
    # Дітям — short (до 4 хв), дорослим — medium (до 20 хв, фільтруємо по 8 хв нижче)
    duration = "short" if age_group == "kids" else "medium"
    params = {
        "part":             "snippet",
        "q":                query,
        "type":             "video",
        "maxResults":       max_results * 2,  # беремо більше щоб є з чого фільтрувати
        "relevanceLanguage":"en",
        "videoDuration":    duration,
        "videoEmbeddable":  "true",
        "videoSyndicated":  "true",
        "videoDefinition":  "high",
        "videoCategoryId":  "27",
        "order":            "relevance",
        "key":              YOUTUBE_API_KEY,
    }
    search_url = "https://www.googleapis.com/youtube/v3/search?" + urllib.parse.urlencode(params)
    try:
        async with aiohttp.ClientSession() as session:
            async with session.get(search_url, timeout=aiohttp.ClientTimeout(total=8)) as r:
                data = await r.json()

        video_ids = [
            item["id"].get("videoId","")
            for item in data.get("items", [])
            if item["id"].get("videoId","")
        ]
        if not video_ids:
            return []

        # Запитуємо тривалість через contentDetails
        details_url = (
            "https://www.googleapis.com/youtube/v3/videos?"
            + urllib.parse.urlencode({
                "part": "contentDetails,snippet",
                "id":   ",".join(video_ids),
                "key":  YOUTUBE_API_KEY,
            })
        )
        async with aiohttp.ClientSession() as session:
            async with session.get(details_url, timeout=aiohttp.ClientTimeout(total=8)) as r:
                details = await r.json()

        def parse_duration(iso: str) -> int:
            """ISO 8601 PT4M13S → секунди."""
            import re
            m = re.match(r"PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?", iso or "")
            if not m: return 9999
            h, mn, s = (int(x or 0) for x in m.groups())
            return h * 3600 + mn * 60 + s

        results = []
        for item in details.get("items", []):
            vid_id   = item.get("id","")
            duration = parse_duration(item.get("contentDetails",{}).get("duration",""))
            # Відфільтровуємо відео довші max_duration_min хвилин
            if duration > max_duration_min * 60:
                continue
            snippet = item.get("snippet", {})
            results.append({
                "id":           f"yt_{vid_id}",
                "url":          f"https://www.youtube.com/watch?v={vid_id}",
                "title":        snippet.get("title", ""),
                "channel":      snippet.get("channelTitle", ""),
                "duration_sec": duration,
            })
            if len(results) >= max_results:
                break

        return results
    except Exception as e:
        logger.warning(f"YouTube API error: {e}")
        return []

# ── Next unmastered CEFR topic ───────────────────────
def next_cefr_topic(s: dict) -> str | None:
    """Return the first unmastered grammar topic for the student's level."""
    level    = s.get("level", "A1")
    mastered = s.get("mastered_grammar", [])
    for topic in CEFR_GRAMMAR.get(level, []):
        if topic not in mastered:
            return topic
    return None

