async def check_and_send_milestone(bot, user_id: int, lesson_count: int, s: dict):
    """Перевіряє Milestone після N уроків і надсилає святковий момент."""
    if lesson_count not in MILESTONES:
        return
    emoji, msg    = MILESTONES[lesson_count]
    level         = s.get("level", "A1")
    level_name    = LEVEL_NAMES.get(level, level)
    level_msg     = MILESTONE_LEVEL_MESSAGES.get(level, "")
    streak        = s.get("streak_days", 0)
    mined_cnt     = len(s.get("mined_sentences", []))
    first_file    = s.get("first_voice_file_id", "")
    first_date    = s.get("first_voice_date", "")
    first_score   = s.get("first_voice_score", 0)
    last_scores   = s.get("scores", [])
    recent_score  = last_scores[-1].get("score", 0) if last_scores else 0

    text = (
        f"{emoji} *Milestone: {lesson_count} {'урок' if lesson_count == 1 else 'уроків'}!*\n\n"
        f"{msg}\n\n"
        f"📊 Рівень: *{level_name}*\n"
        f"🔥 Дні поспіль: *{streak}*\n"
        f"💎 Збережених фраз: *{mined_cnt}*\n\n"
        f"_{level_msg}_"
    )

    kb_rows = [
        [InlineKeyboardButton("📤 Поділитись досягненням", callback_data="share_socials")],
    ]

    # ── Спеціальний момент на уроці 10: «До і після» ──
    if lesson_count == 10 and first_file and recent_score > 0:
        diff = recent_score - first_score
        sign = "+" if diff >= 0 else ""
        text += (
            f"\n\n🎙 *Мій прогрес у говорінні:*\n"
            f"Перший монолог: *{first_score}/100* _{first_date}_\n"
            f"Зараз: *{recent_score}/100*\n"
            f"Зростання: *{sign}{diff} балів* {'📈' if diff >= 0 else '📉'}\n\n"
            "⬇️ Нижче — твій перший голосовий запис"
        )
        kb_rows.insert(0, [InlineKeyboardButton(
            "🎙 Порівняти голоси", callback_data="before_after"
        )])

    try:
        await bot.send_message(
            chat_id=user_id,
            text=text,
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(kb_rows)
        )
        if lesson_count == 10 and first_file:
            await bot.send_voice(
                chat_id=user_id,
                voice=first_file,
                caption=f"🎙 Твій перший монолог — _{first_date}_",
                parse_mode="Markdown"
            )
            await bot.send_message(
                chat_id=user_id,
                text=(
                    "⬆️ Твій перший монолог\n\n"
                    "Чуєш різницю? Це і є прогрес.\n\n"
                    "_Продовжуй — через 10 уроків ти знову почуєш цю різницю_ 🚀"
                ),
                parse_mode="Markdown",
                reply_markup=InlineKeyboardMarkup([[
                    InlineKeyboardButton("🎯 Далі!", callback_data="fork_choose")
                ]])
            )
    except Exception as e:
        logger.warning(f"Milestone send error {user_id}: {e}")


# ── Авто share-картка в момент майлстону (ланцюжок розмов / level-up) ──
_MILESTONE_SHARE_LABEL = {
    "streak_7":   "7 днів поспіль",
    "streak_30":  "30 днів поспіль",
    "streak_40":  "40 днів поспіль",
    "streak_100": "100 днів поспіль",
}

async def send_milestone_share(bot, user_id: int, milestone: str, level_up: tuple | None = None):
    """Проактивно пропонує поділитися в момент гордості.

    milestone — один зі стрік-майлстонів (streak_7/30/40/100) або None.
    level_up  — кортеж (old_level, new_level) при підвищенні CEFR-рівня, або None.
    Картка говорить мовою продукту (ланцюжок розмов) і показує особисті
    досягнення студента: рівень, довжину ланцюжка, освоєні фрази, бал мовлення.
    """
    if not ENABLE_MILESTONE_SHARE:
        return
    if not milestone and not level_up:
        return
    try:
        s = get_s(user_id)
        # ── Особисті досягнення студента ──
        chain      = get_chain(s)
        chain_len  = chain_links(s)
        level      = s.get("level", "A1")
        level_name = LEVEL_NAMES.get(level, level)
        phrases    = len(s.get("mined_sentences", []))
        scores     = s.get("scores", [])
        avg_score  = round(sum(sc.get("score", 0) for sc in scores[-10:]) / len(scores[-10:])) if scores else 0

        # ── Заголовок: ланцюжок розмов або новий рівень ──
        if level_up:
            old_lvl, new_lvl = level_up
            head = f"🎉 *Новий рівень: {old_lvl} → {new_lvl}!*"
            lead = "Ти піднявся на новий рівень англійської. Це варто показати світу."
        else:
            label = _MILESTONE_SHARE_LABEL.get(milestone, "новий рубіж")
            head = f"🔥 *Твій ланцюжок розмов: {label}!*"
            lead = "Ти не пропускаєш — щодня говориш англійською. Це рідкість. Поділись і надихни інших."

        # ── Блок особистих досягнень ──
        _lk = "ланка" if chain_len == 1 else "ланки" if 2 <= chain_len <= 4 else "ланок"
        ach = f"📊 Рівень: *{level_name}*\n🔗 Ланцюжок розмов: *{chain_len} {_lk}*\n💎 Освоєно фраз: *{phrases}*"
        if avg_score > 0:
            ach += f"\n🎙 Середній бал мовлення: *{avg_score}/100*"

        text = f"{head}\n\n{lead}\n\n{ach}"

        await bot.send_message(
            chat_id=user_id,
            text=text,
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton("📤 Поділитись досягненням", callback_data="share_socials")
            ]])
        )
    except Exception as e:
        logger.warning(f"Milestone share error {user_id}: {e}")

