def _monthly_revenue(s: dict) -> float:
    """
    Місячний дохід від одного платного користувача — за ФАКТИЧНОЮ ціною.

    Джерело трафіку визначається канонічною get_source()/get_prices() —
    блогер, друг-реферал чи органіка. 6-місячні плани діляться на 6, бо
    MRR — це МІСЯЧНИЙ дохід (оплата 397 за 6 міс = ~66/міс).

    🔴 БУЛО: has_ref = bool(s.get("affiliate_ref")) — рахував тільки
    блогерських рефералів, друга-реферала (sc_referrer) завжди відносив
    до повної ціни. У дашборді /admin_analytics і AI-інсайтах MRR від
    friend-каналу був завищений (той самий клас багів, що й у
    cb_offer_accepted/cmd_premium, виправлено v29).
    ТЕПЕР: канонічна get_prices(s) — ті самі змінні, що й у логіці оплати.
    Використовується в handle_admin_analytics_data і handle_ai_insights.
    """
    plan = s.get("plan", "basic")
    p    = get_prices(s)
    if plan == "basic":
        return float(p["basic_price"])
    if plan == "premium":
        return float(p["prem_price"])
    if plan == "basic_6m":
        return float(p["basic_6m_price"]) / 6.0
    if plan == "premium_6m":
        return float(p["prem_6m_price"]) / 6.0
    return 0.0


# ── Аліаси для зворотної сумісності ──────────────────
# ⚠️ Раніше тут було PREMIUM_MONTHLY_PRICE = BASIC_PRICE — помилкова рівність
# (Premium за ціною Basic). Зараз аліас указує на реальну Premium-ціну. Наразі
# читачів немає (лише це визначення), але лишаємо коректним про запас.
PREMIUM_MONTHLY_PRICE  = PREMIUM_PRICE_FULL
PREMIUM_AFFILIATE_PRICE= PREMIUM_PRICE_AFF
FREE_TRIAL_DAYS = 7  # залишаємо константу для сумісності зі старим кодом
TRIAL_BUFFER_DAYS = 2  # Варіант 3: буфер доступу для новачка ДО старту челенджу

def is_premium(s: dict) -> bool:
    until = s.get("premium_until", "")
    if not until:
        return False
    try:
        return datetime.strptime(until, "%Y-%m-%d") >= datetime.now()
    except Exception:
        return False

def is_basic(s: dict) -> bool:
    """True якщо активний Basic план."""
    return is_premium(s) and s.get("plan", "basic") == "basic"

def is_premium_only(s: dict) -> bool:
    """True якщо активний Premium план."""
    return is_premium(s) and s.get("plan") == "premium"


def has_trial_feature(s: dict, feature: str) -> bool:
    """
    Перевіряє доступ до фічі залежно від статусу юзера.

    Trial (1-7 ланок) відкриває:
      'roadmap'      — Roadmap A1→C2 (повний шлях і статистика)
      'gap_analysis' — Gap analysis після монологу

    Все інше — тільки платно.
    """
    if is_premium(s):
        return True
    trial_status = get_trial_status(s)
    if trial_status in (STATUS_TRIAL, STATUS_TRIAL_DONE):
        return feature in ("roadmap", "gap_analysis")
    return False

def is_in_trial(s: dict) -> bool:
    """
    Варіант 3: челендж = trial. Доступ до контенту, поки людина:
      • в АКТИВНОМУ челенджі (проходить 7 днів — це і є trial), АБО
      • новачок у короткому буфері до старту челенджу (щоб не впертись
        у paywall перш ніж спробувати челендж).
    Після завершення челенджу — False (чистий оффер, без безкоштовного обходу).
    """
    cs = s.get("challenge_state") or {}
    status = cs.get("status", "")

    # 1) В активному челенджі — повний доступ (челендж і є trial)
    if status == "active":
        return True

    # 2) Завершив/кинув челендж — trial вичерпано (чистий оффер)
    if status in ("completed", "abandoned"):
        return False

    # 3) Ще не стартував челендж — малий буфер від реєстрації (TRIAL_BUFFER_DAYS),
    #    щоб новачок встиг дійти до старту челенджу без paywall.
    reg = s.get("registered_at", "")
    if not reg:
        return True  # старі акаунти без дати — не караємо
    try:
        from datetime import timedelta
        reg_date = datetime.strptime(reg[:10], "%Y-%m-%d")
        return datetime.now() <= reg_date + timedelta(days=TRIAL_BUFFER_DAYS)
    except Exception:
        return True


def trial_days_left(s: dict) -> int:
    """Скільки днів буфера/челенджу лишилось (для текстів, що це показують)."""
    cs = s.get("challenge_state") or {}
    status = cs.get("status", "")
    if status == "active":
        # у челенджі — днів до кінця 7-денного челенджу
        try:
            from challenge_content import CHALLENGE_LENGTH as _CL
        except Exception:
            _CL = 7
        day = cs.get("day", 1)
        return max(0, _CL - day + 1)
    if status in ("completed", "abandoned"):
        return 0
    reg = s.get("registered_at", "")
    if not reg:
        return TRIAL_BUFFER_DAYS
    try:
        from datetime import timedelta
        reg_date = datetime.strptime(reg[:10], "%Y-%m-%d")
        left = (reg_date + timedelta(days=TRIAL_BUFFER_DAYS) - datetime.now()).days
        return max(0, left)
    except Exception:
        return 0

