def get_lessons(s):
    goal  = s.get("goal","daily")
    level = s.get("level","A1")
    if goal not in VIDEOS: goal = "daily"
    lessons = VIDEOS.get(goal,{}).get(level,[])
    if not lessons: lessons = VIDEOS.get("daily",{}).get(level,[])
    return lessons

def next_lesson(s):
    done = s.get("done_lessons",[])
    for l in get_lessons(s):
        if l["id"] not in done: return l
    return None

# Режим перегляду для супер-адміна (зберігається в пам'яті)
_ADMIN_VIEW_MODE: dict = {}  # {uid: "admin" | "student" | "blogger"}

def get_admin_mode(uid: int) -> str:
    return _ADMIN_VIEW_MODE.get(uid, "admin")

def set_admin_mode(uid: int, mode: str):
    _ADMIN_VIEW_MODE[uid] = mode

def next_admin_mode(uid: int) -> str:
    """Переключає режим по колу: admin → student → blogger → admin."""
    modes = ["admin", "student", "blogger"]
    current = get_admin_mode(uid)
    next_mode = modes[(modes.index(current) + 1) % len(modes)]
    set_admin_mode(uid, next_mode)
    return next_mode

MODE_LABELS = {
    "admin":   "👑 Адмін",
    "student": "👤 Студент",
    "blogger": "📣 Блогер",
}


def main_menu(uid: int = 0) -> ReplyKeyboardMarkup:
    """Дві головні кнопки — і обидві ДІЇ.

    ЧОМУ ДВІ, А НЕ ЧОТИРИ
    ─────────────────────
    Було: Урок дня · Chainy · Словник · Профіль.
    Дві останні — не дії, а ЗВІТИ про дії. Поставивши їх поруч,
    ми щодня пропонували вибір: «зробити» або «подивитись на зроблене».
    Втомлена людина обирає друге — воно легше і теж «про англійську».
    Відкрила прогрес, подивилась графік, закрила бота. Нічого не сталось.

    Тепер: слухати+shadowing (вхід) і говорити (вихід). Повний цикл
    засвоєння мови. Втекти в «подивитись» нікуди.

    Словник і прогрес нікуди не поділись — вони в «Open» і показуються
    ПІСЛЯ сесії, коли є що показати. Не кнопка, а нагорода.
    """
    # Плеєр — ЧЕРЕЗ ОБОЛОНКУ (shell_url), нарада тімліда/девелопера/дизайнера 23.07.
    #
    # 🔴 БУЛО: пряме посилання на player.html, в обхід оболонки. Свідомий
    # компроміс заради швидшого деплою (sync.py — окремий крок синхронізації
    # з ov-player). Ціна компромісу: у standalone window.closeOv не існує,
    # тож і «вийти без завершення уроку», і «завершити урок» падали на
    # TG.close() — ВЕСЬ застосунок гаснув. Людина не бачила свій +XP і
    # ланцюжок, мусила заново відкривати бота через /start.
    #
    # ТЕПЕР: shell_url("ov-player") — той самий патерн, що вже працює для
    # Chainy нижче. closeOv() реальна і в оболонці, і хрестик, і апаратна
    # кнопка «назад» Telegram працюють як і в решті оверлеїв. Fallback на
    # SHELL_ENABLED=0 — _SHELL_SCREENS["ov-player"]="player.html", файл
    # лишається на місці й далі синхронізується sync.py як раніше.
    player_url = shell_url("ov-player")
    chainy_url = shell_url("s-buddy")
    rows = [
        [KeyboardButton("🎬 Практика по відео", web_app=WebAppInfo(url=player_url)),
         KeyboardButton("🎙 Говорити",          web_app=WebAppInfo(url=chainy_url))],
    ]
    # Кнопка переключення режиму — для адміна й sub-адмінів.
    #
    # 21.07: було is_super_admin(uid) — бачив лише той ОДИН uid, що
    # записаний у Railway як ADMIN_ID. Власниця технічно записана як
    # sub-admin (SUB_ADMIN_IDS), тому is_admin(uid) = так, а
    # is_super_admin(uid) = ні — кнопка не з'являлась узагалі.
    #
    # ⚠️ ФІНАНСИ НЕ ЧІПАЄМО. can_access_financials() і далі перевіряє
    # ТІЛЬКИ is_super_admin — sub-admin, навіть переключившись у режим
    # «адмін» цією кнопкою, MRR/виплат/цін не побачить. Це окрема,
    # вужча функція, яку ця правка не зачіпає.
    if uid and is_admin(uid):
        mode = get_admin_mode(uid)
        rows.append([KeyboardButton(f"🔄 Режим: {MODE_LABELS[mode]}")])

        # 21.07: другий рядок — «Панель адміна» поряд із «Open».
        #
        # ⚠️ КРИТИЧНО: умова тут — get_admin_mode(uid)=="admin", НЕ
        # просто is_admin(uid). Учениця НІКОЛИ не має бачити цей рядок —
        # включно з тим випадком, коли САМА власниця (адмін) перемкнулась
        # кнопкою «🔄 Режим» у режим «👤 Студент», щоб пройти продукт
        # її очима (звірка A-20). У режимі student mode=="student", ця
        # умова хибна, рядок не додається — клавіатура чиста, як в
        # будь-якої звичайної учениці. Панель з'являється РІВНО тоді,
        # коли людина сама явно обрала «👑 Адмін» цим самим перемикачем.
        if mode == "admin":
            rows.append([KeyboardButton("👤 Панель адміна")])
    return ReplyKeyboardMarkup(rows, resize_keyboard=True, is_persistent=True)

def active_lesson_kb(video_url: str, s: dict = None) -> InlineKeyboardMarkup:
    """Кнопки під активним уроком."""
    vid_id   = extract_youtube_id(video_url)
    platform = detect_platform(video_url)
    if s is None:
        s = {}
    if WEBAPP_URL and vid_id and platform == "youtube":
        watch_btn = InlineKeyboardButton("▶️ Дивитись відео",
            web_app={"url": f"{WEBAPP_URL}?v={vid_id}&d={urllib.parse.quote(json.dumps({'level':s.get('level','A1'),'mastered':s.get('mastered_grammar',[]),'done_lessons':len(s.get('done_lessons',[]))},ensure_ascii=False))}"})
    else:
        watch_btn = InlineKeyboardButton("▶️ Дивитись відео", url=video_url)
    return InlineKeyboardMarkup([
        [watch_btn],
        [InlineKeyboardButton("🎙 Записати монолог", callback_data="remind_record")],
    ])

def breadcrumb(s: dict) -> str:
    """Рядок навігації: A1 · Present Perfect · Урок 3"""
    level    = s.get("level", "A1")
    mastered = s.get("mastered_grammar", [])
    topic    = next_cefr_topic(s) or "Всі теми пройдено 🏆"
    done     = len(s.get("done_lessons", []))
    return f"_{level} · {topic} · Урок {done + 1}_"

def extract_youtube_id(url: str) -> str | None:
    if not url:
        return None
    url = url.strip()
    # Блогер може вставити голий ID (11 символів) — приймаємо як є
    if re.fullmatch(r"[a-zA-Z0-9_-]{11}", url):
        return url
    patterns = [
        r"youtube\.com/watch\?.*?v=([a-zA-Z0-9_-]{11})",   # ?v= може бути не першим параметром
        r"youtu\.be/([a-zA-Z0-9_-]{11})",
        r"youtube\.com/embed/([a-zA-Z0-9_-]{11})",
        r"youtube\.com/shorts/([a-zA-Z0-9_-]{11})",        # Shorts — головний формат коротких відео
        r"youtube\.com/live/([a-zA-Z0-9_-]{11})",
        r"youtube\.com/v/([a-zA-Z0-9_-]{11})",
    ]
    for p in patterns:
        m = re.search(p, url)
        if m: return m.group(1)
    return None

def miniapp_video_url(video_url: str) -> str:
    """Генерує пряме посилання на плеєр через Mini App."""
    vid_id = extract_youtube_id(video_url)
    if not vid_id:
        return MINIAPP_URL
    return f"{MINIAPP_URL}?startapp={vid_id}"


def _parse_ref_deeplink(param: str):
    """Розбирає deep link виду ref_... на (ref_code, platform, clean_ref, vid_id).

    Підтримує ОБИДВА формати ID відео в посиланні:
      • ref_BLOGGER_yt_VIDEOID      ← формат генератора (актуальний)
      • ref_BLOGGER_video_VIDEOID   ← старий формат
      • ref_BLOGGER                 ← без відео

    Повертає:
      ref_code  — повний код реферала БЕЗ хвоста відео (для збереження як affiliate_ref)
      platform  — YouTube / Instagram / TikTok / Facebook / Twitter-X / Unknown
      clean_ref — чисте ім'я блогера (без суфікса платформи)
      vid_id    — 11-символьний YouTube ID або None
    """
    rest   = param[4:]  # все після "ref_"
    vid_id = None

    # 1) Явний роздільник _video_ (старий формат)
    if "_video_" in rest:
        head, tail = rest.split("_video_", 1)
        candidate  = tail.split("_")[0]
        if re.fullmatch(r"[a-zA-Z0-9_-]{11}", candidate):
            vid_id = candidate
        rest = head  # ref_code = все до _video_

    # 2) Формат _yt_VIDEOID — генератор кладе ID одразу після суфікса платформи
    #    Напр. ref_username_yt_dQw4w9WgXcQ → платформа yt + відео dQw4w9WgXcQ
    if vid_id is None:
        m = re.search(r"_(yt|ig|tt|fb|tw)_([a-zA-Z0-9_-]{11})$", rest)
        if m:
            vid_id = m.group(2)
            # лишаємо суфікс платформи у rest, щоб нижче визначити platform
            rest = rest[: m.start()] + "_" + m.group(1)

    ref_code = rest

    platform_map = {
        "_yt": "YouTube", "_ig": "Instagram",
        "_tt": "TikTok",  "_fb": "Facebook",
        "_tw": "Twitter/X",
    }
    platform  = "Unknown"
    clean_ref = ref_code
    for suffix, pname in platform_map.items():
        if ref_code.endswith(suffix):
            platform  = pname
            clean_ref = ref_code[:-len(suffix)]
            break

    return ref_code, platform, clean_ref, vid_id


def _player_url(video_url: str, s: dict) -> str:
    """Будує URL плеєра з даними студента для Journey strip."""
    vid_id = extract_youtube_id(video_url)
    if not vid_id or not WEBAPP_URL:
        return ""
    _base = (BOT_WEBHOOK_URL or "").rstrip("/")
    data = {
        "level":        s.get("level", "A1"),
        "mastered":     s.get("mastered_grammar", []),
        "done_lessons": len(s.get("done_lessons", [])),
        "levels":       LEVELS_ORDER,
        "cefr_grammar": CEFR_GRAMMAR,
        "xp_total":     s.get("xp_total", 0),
        "streak_days":  s.get("streak_days", 0),
        "player_minutes_total": s.get("player_minutes_total", 0),
        "api":          BOT_WEBHOOK_URL,
        "captions_url": f"{_base}/captions" if _base else "",
        "uid":          s.get("uid", 0),
        "name":         s.get("name", ""),
    }
    encoded = urllib.parse.quote(json.dumps(data, ensure_ascii=False))
    return f"{WEBAPP_URL}?v={vid_id}&d={encoded}"


def video_watch_keyboard(video_url: str, s: dict = None, show_dur: bool = False) -> InlineKeyboardMarkup:
    """Кнопка ▶️ що відкриває відео: через оболонку (ov-player), інакше зовнішнє посилання.

    23.07, нарада тімліда/девелопера/дизайнера: переведено з прямого WEBAPP_URL
    на shell_url("ov-player") — той самий фікс, що вже стоїть у main_menu().
    Дані студента (рівень, XP, api) тепер підвантажує сама оболонка через
    _build_player_shell_url() (той самий механізм, що s-home/s-social/s-profile)
    — кнопці лишається передати лише яке саме відео відкрити.

    🔴 ЗНАЙДЕНО при переході: WEBAPP_URL і _player_url() досі жили в коді
    (5 реальних місць виклику саме через video_watch_keyboard — перше завдання
    онбордингу, нагадування, естафети), окремо від головних кнопок і з тим самим
    структурним ризиком TG.close(). Функції active_lesson_kb/active_lesson_kb_v2
    виявились СПРАВЖНІМ мертвим кодом — жодного виклику ніде в файлі, лишились
    недоторканими (технічний борг, прибрати окремим проходом).
    """
    vid_id   = extract_youtube_id(video_url)
    platform = detect_platform(video_url)

    if vid_id and platform == "youtube":
        url = shell_url("ov-player", v=vid_id)
        watch_btn = InlineKeyboardButton("▶️ Дивитись відео", web_app={"url": url})
    else:
        watch_btn = InlineKeyboardButton("▶️ Дивитись відео", url=video_url)

    return InlineKeyboardMarkup([[watch_btn]])

