# ── /start ────────────────────────────────────────────
# ════════════════════════════════════════════════════════════════════════════
# CALLBACK: Старт челенджу (Challenge Flow)
# ════════════════════════════════════════════════════════════════════════════

async def cb_start_challenge(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """Callback для кнопки 'Почати челендж'."""
    query = update.callback_query
    user_id = query.from_user.id
    await query.answer()
    
    if not CHALLENGE_FLOW_LOADED:
        await query.edit_message_text("❌ Челендж модуль не завантажено")
        return
    
    # Визначити flow type з callback_data
    flow_type = query.data.replace("start_challenge_", "")  # "blogger" або "organic"
    
    s = get_s(user_id)
    blogger_name = s.get("affiliate_blogger", "")
    
    # Розпочати челендж
    if flow_type == "blogger" and blogger_name:
        flow = ChallengeFlowBlogger(get_s, upd_s)
        flow.start_challenge(user_id, blogger_name=blogger_name)
        text = get_notification("day_0_morning", flow_type="blogger", blogger_name=blogger_name)
        _fact_flow = "blogger"
    else:
        flow = ChallengeFlowOrganic(get_s, upd_s)
        flow.start_challenge(user_id)
        text = get_notification("day_0_morning", flow_type="organic")
        _fact_flow = "organic"

    # 📊 Трекінг старту челенджу (фактичний flow, не заявлений у кнопці)
    try:
        from analytics import track_event
        asyncio.create_task(
            track_event(user_id, f"challenge_start_{_fact_flow}", get_s(user_id), upd_s))
    except Exception:
        pass

    await query.edit_message_text(text or "Челендж розпочато! 🚀", parse_mode="Markdown")
    
    # Запустити День 0 завдання
    asyncio.create_task(_route_challenge_day_0(ctx.bot, user_id, _fact_flow))

# ════════════════════════════════════════════════════════════════════════════

async def _route_challenge_day_0(bot, user_id: int, flow_type: str):
    """
    Стартове повідомлення одразу після «Розпочати».
    Канон дня 1: максимально легкий вхід, БЕЗ запису себе (запис — на день 2).
    Далі щоранку доставляється відео дня + завдання (job_challenge_video_delivery).

    ВАЖЛИВО: даємо кнопку «до завдання Д1» одразу (інакше людина бачить опис Д1,
    але не може його завершити — і наступного ранку джоба дублює Д1). Плюс
    позначаємо доставку Д1 сьогодні, щоб джоба не повторювала вступ.
    """
    try:
        msg = (
            "🎬 *Ваш челендж розпочався!*\n\n"
            "Сьогодні — день 1, і ми просто тренуємось. Нічого страшного:\n"
            "1. Розкажіть про себе простими словами — і де Вам найбільше "
            "бракує розмовної англійської\n"
            "2. Повторіть за мною одну фразу в плеєрі — як тінь\n"
            "3. Пограйте зі скоромовками «як вийде»\n\n"
            "Без запису себе — це завтра. Кожен крок веде до вільного потоку 🔗"
        )
        kb = InlineKeyboardMarkup([[
            InlineKeyboardButton("✅ До завдання дня 1", callback_data="challenge_task_1")
        ]])
        await bot.send_message(user_id, msg, parse_mode="Markdown", reply_markup=kb)

        # Позначаємо, що Д1 уже доставлено сьогодні — джоба завтра просуне на Д2
        # (коли Д1 завершено), а не повторить вступ Д1.
        try:
            _s = get_s(user_id)
            _cs = _s.get("challenge_state") or {}
            _cs["last_video_sent_day"] = 1
            _cs["last_video_sent_date"] = datetime.now().strftime("%Y-%m-%d")
            upd_s(user_id, {"challenge_state": _cs})
        except Exception:
            pass
    except Exception as e:
        logger.error(f"Error in _route_challenge_day_0: {e}")

# ════════════════════════════════════════════════════════════════════════════
# КОМАНДА: Start
# ════════════════════════════════════════════════════════════════════════════

async def cmd_start(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    # В групах /start ігноруємо
    if update.effective_chat and update.effective_chat.type in ("group", "supergroup", "channel"):
        return
    logger.info(f"START from {user.id} {user.first_name}")

    # ── Demo entry point (вхід для ВСІХ: demo або demo_<phrase_id>) ──
    if ctx.args and (ctx.args[0] == "demo"
                     or ctx.args[0].startswith("demo_")):
        upd_s(user.id, {"traffic_source": SOURCE_DEMO})
        return await handle_demo_entry(update, ctx, get_s, upd_s)

    # ── Shared Chain виклик (Speaking Challenge deeplink) ─
    # 21.07: sc:token — НОВИЙ токенізований формат (фраза не в URL).
    #        sc_uid_phrase — СТАРИЙ, лишається для вже розісланих посилань.
    #        Обидва веде в той самий handle_challenge_deeplink — вона сама
    #        розрізняє формат за роздільником.
    if ctx.args and (ctx.args[0].startswith("sc:") or ctx.args[0].startswith("sc_")):
        s = get_s(user.id)
        upd_s(user.id, {"traffic_source": SOURCE_FRIEND})
        return await handle_challenge_deeplink(ctx.bot, user.id, s, ctx.args[0], upd_s)

    # ── Friend-реферал (?start=ref_username) — прямий вхід друга ──
    # Ставимо referrer_uid, щоб нижче спрацював friend-landing → челендж.
    # (Раніше referrer_uid ставився лише через player.html-вебхук; прямий
    #  /start ref_ його не ставив, і friend-flow не запускався.)
    if ctx.args and ctx.args[0].startswith("ref_"):
        _s0 = get_s(user.id)
        if not _s0.get("referrer_uid") and not _s0.get("is_blogger"):
            _raw = ctx.args[0][4:]  # прибрати 'ref_'
            # відрізати платформенні суфікси (_yt/_ig/_tt/_fb) якщо є
            for _suf in ("_yt", "_ig", "_tt", "_fb"):
                if _raw.endswith(_suf):
                    _raw = _raw[:-len(_suf)]
                    break
            try:
                _db = load_db()
                _ruid = next(
                    (int(k) for k, v in _db.items()
                     if isinstance(v, dict) and not v.get("is_blogger")
                     and (v.get("username") == _raw or str(k) == _raw)),
                    None
                )
                # не даємо запросити самого себе
                if _ruid and _ruid != user.id:
                    upd_s(user.id, {"referrer_uid": _ruid, "traffic_source": SOURCE_FRIEND})
            except Exception as _e:
                logger.warning(f"ref_ parse {user.id}: {_e}")

    s    = get_s(user.id)

    # ── Реферальний бонус — старт з ланки 3 ──────────────
    if not s.get("ref_bonus_applied") and s.get("referrer_uid"):
        s_with_bonus = apply_referral_bonus(dict(s))
        upd_s(user.id, {
            "chain":            s_with_bonus["chain"],
            "ref_bonus_applied": True,
        })
        # П.4 — Friend landing замість звичайного /start
        referrer_uid = s.get("referrer_uid")
        if referrer_uid and not s.get("friend_landing_shown"):
            upd_s(user.id, {"friend_landing_shown": True})
            asyncio.create_task(_send_friend_landing(ctx.bot, user.id, int(referrer_uid), s))
            return
        s = get_s(user.id)

    # Зберігаємо базові дані і синхронізуємо в Sheets при кожному /start
    is_new = not s.get("registered_at")
    _utc_offset = guess_utc_offset(s, user)
    upd_s(user.id, {
        "telegram_id":  user.id,
        "name":         user.first_name,
        "username":     user.username or "",
        "active":       True,
        "registered_at": s.get("registered_at") or datetime.now().strftime("%Y-%m-%d"),
        "language_code": getattr(user, "language_code", "") or s.get("language_code", ""),
        "utc_offset":   s.get("utc_offset") if s.get("utc_offset") is not None else _utc_offset,
        "partner_reg_step": "",
        "waiting_blogger_code": False,
        "waiting_gen_ref": False,
        "waiting_blogger_username": False,
    })
    asyncio.create_task(gs_sync_student(user.id))

    # ── Повернення вже налаштованого студента ──
    if s.get("onboarding_done"):
        streak     = s.get("streak_days", 0)
        done       = len(s.get("done_lessons", []))
        level      = LEVEL_NAMES.get(s.get("level",""), "")
        streak_line = f"🔥 Дні поспіль: *{streak}*\n" if streak > 1 else ""

        await update.message.reply_text(
            f"З поверненням, {user.first_name}! 👋\n\n"
            f"{streak_line}"
            f"📊 Рівень: *{level}* · Уроків: *{done}*\n\n"
            "Продовжуємо? 👇",
            parse_mode="Markdown",
            reply_markup=main_menu(update.effective_user.id)
        )
        return

    # ── Тест на рівень був розпочатий але не завершений ──
    if s.get("placement_active") and s.get("placement_current"):
        await update.message.reply_text(
            f"Привіт, {user.first_name}! 👋\n\n"
            "Схоже, ти вже починав тест на визначення рівня але не завершив його.\n\n"
            "Що робимо?",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton("▶️ Продовжити тест",    callback_data="plc_resume")],
                [InlineKeyboardButton("🔄 Почати спочатку",    callback_data="plc_restart")],
            ])
        )
        return

    # ── Deeplink: ?start=VIDEO_ID (посилання з відео блогера) ──
    args        = ctx.args
    video_param = args[0] if args else None

    # ── Deeplink: ref_BLOGGER  /  ref_BLOGGER_yt_VIDEOID  /  ref_BLOGGER_video_VIDEOID ──
    # Розуміємо ОБИДВА формати відео в лінку: _yt_ (як будує генератор) і _video_ (старий).
    if video_param and video_param.startswith("ref_"):
        ref_code, platform, clean_ref, vid_id = _parse_ref_deeplink(video_param)

        # Не перезаписуємо реферал якщо він вже є — лише дістаємо vid_id для запуску відео
        if not get_s(user.id).get("affiliate_ref"):
            upd_s(user.id, {
                "affiliate_ref":      ref_code,
                "affiliate_platform": platform,
                "affiliate_blogger":  clean_ref,
            })

        if vid_id:
            # Є YouTube відео — одразу запускаємо урок (миттєвий WOW)
            video_url = f"https://www.youtube.com/watch?v={vid_id}"
            upd_s(user.id, {
                "waiting_video":    False,
                "current_lesson_id":"custom",
                "custom_video_url": video_url,
                "videos_watched":   0,
            })
            await update.message.reply_text(
                "Я SpeakChain — твій AI-тренер з англійської. "
                "Починаємо з відео, яке ти щойно дивився 👇",
                parse_mode="Markdown"
            )
            await _send_first_video_task(update.message, ctx, video_url, user.id)
            return
        # Без відео — продовжуємо до онбоардингу нижче

    # ── Новий онбоардинг: пропонувати ЧЕЛЕНДЖ ──
    if not s.get("challenge_state"):  # Новий користувач, не в челенджі
        # Встановлюємо базовий профіль
        upd_s(user.id, {
            "level":            "A1",
            "goal":             "daily",
            "done_lessons":     [],
            "scores":           [],
            "mastered_grammar": [],
            "onboarding_done":  True,
            "is_first_lesson":  True,
            "registered_at":    datetime.now().strftime("%Y-%m-%d"),
        })
        asyncio.create_task(gs_sync_student(user.id))
        
        # Пропонуємо челендж якщо модуль завантажен
        if CHALLENGE_FLOW_LOADED:
            # Визначити тип flow (blogger vs organic)
            blogger_name = s.get("affiliate_blogger", "")
            flow_type = "blogger" if blogger_name else "organic"

            # Один головний CTA (челендж), демо — дрібним лінком нижче (менше тертя вибору).
            kb = InlineKeyboardMarkup([
                [InlineKeyboardButton("🚀 Почати челендж «Заговори»",
                                      callback_data=f"start_challenge_{flow_type}")],
                [InlineKeyboardButton("🎬 Спершу спробувати демо",
                                      callback_data="demo_entry")],
            ])

            await update.message.reply_text(
                "*7 днів — і Ви почуєте власний голос до і після.* 🎯\n\n"
                "За тиждень Ви:\n"
                "• заговорите англійською щодня, крок за кроком;\n"
                "• отримаєте персональну карту й свій рівень;\n"
                "• наприкінці — подарунок саме під Ваші ситуації 🎁\n\n"
                "Почнемо?",
                parse_mode="Markdown",
                reply_markup=kb,
            )
            return
    
    # ── Якщо challenge flow не завантажен або користувач вже вибрав, запускаємо урок ──
    await update.message.reply_text(
        "Вчи англійську по відео блогерів 🎬\n"
        "AI знаходить твої прогалини 🎯\n"
        "Говори з живими партнерами 👥\n\n"
        "Підбираю твоє перше відео... 🔍",
        parse_mode="Markdown",
        reply_markup=main_menu(update.effective_user.id)
    )
    # Встановлюємо базовий профіль (якщо не встановлено вище)
    if not s.get("onboarding_done"):
        upd_s(user.id, {
            "level":            "A1",
            "goal":             "daily",
            "done_lessons":     [],
            "scores":           [],
            "mastered_grammar": [],
            "onboarding_done":  True,
            "is_first_lesson":  True,
            "registered_at":    datetime.now().strftime("%Y-%m-%d"),
        })
        asyncio.create_task(gs_sync_student(user.id))
    await _auto_send_next_lesson(ctx.bot, user.id)

# ── Helper: надіслати завдання по першому відео ──────
async def _send_first_video_task(message, ctx, video_url: str, user_id: int):
    """Перше відео — WOW онбоардинг.

    Миттєво показуємо кнопку плеєра з шаблонним завданням (один тап до відео),
    а точніше AI-завдання (граматика + підказки з цього відео) довантажуємо
    у фоні й оновлюємо те саме повідомлення, коли воно готове.
    """
    s     = get_s(user_id)
    level = s.get("level", "A1")

    # Дефолтний (миттєвий) шаблон — показуємо ОДРАЗУ, без очікування AI
    topic   = "Повтори за спікером або запиши своє відео, використавши слова і фрази з цього відео."
    grammar = "Present Simple"
    hint    = "I think... / In my opinion... / I found it interesting that..."

    # Зберігаємо одразу, щоб кнопка плеєра й перший монолог працювали без затримки
    upd_s(user_id, {
        "current_lesson_id":           "custom",
        "current_lesson_data":         {"id":"custom","url":video_url,"title":"Перше відео","grammar":grammar,"topic":topic,"hint":hint},
        "custom_video_url":            video_url,
        "pending_first_video_grammar": grammar,
        "pending_first_video_topic":   topic,
        "is_first_lesson":             True,
    })

    # 1) МИТТЄВО: повідомлення з кнопкою плеєра (один тап до відео)
    s   = get_s(user_id)
    msg = await message.reply_text(
        f"🎬 *Перше завдання!*\n\n"
        f"🎤 {topic}\n\n"
        f"💡 _{hint}_\n\n"
        "Натисни ▶️ — відео вже чекає. Подивись → повтори вголос або запиши відео → натисни 🎙 👇",
        parse_mode="Markdown",
        reply_markup=video_watch_keyboard(video_url, s, show_dur=True)
    )

    # 2) У ФОНІ: довантажуємо точніше AI-завдання й оновлюємо те саме повідомлення
    asyncio.create_task(
        _enrich_first_video_task(ctx, msg, video_url, user_id, level)
    )


async def _enrich_first_video_task(ctx, msg, video_url: str, user_id: int, level: str):
    """Фонове уточнення першого завдання через AI — оновлює вже показане повідомлення."""
    try:
        pr = (
            f"Student level: {level}. Video: {video_url}\n"
            f"Create a shadowing task — student repeats after the speaker OR records a short video using words from this video.\n"
            f"Reply ONLY:\n"
            f"TOPIC: [Ukrainian instruction starting with: 'Повтори за спікером або запиши своє відео, використавши слова і фрази з цього відео.']\n"
            f"GRAMMAR: [one simple grammar point]\n"
            f"HINT: [2-3 simple English phrases from the video to repeat]"
        )
        cr = await claude_create_async(
            model="claude-haiku-4-5-20251001", max_tokens=200,
            messages=[{"role": "user", "content": pr}]
        )
        task    = cr.content[0].text
        topic   = "Повтори за спікером або запиши своє відео, використавши слова і фрази з цього відео."
        grammar = "Present Simple"
        hint    = "I think... / In my opinion... / I found it interesting that..."
        for line in task.splitlines():
            line = line.strip()
            if line.startswith("TOPIC:"):    topic   = line[6:].strip()
            elif line.startswith("GRAMMAR:"): grammar = line[8:].strip()
            elif line.startswith("HINT:"):    hint    = line[5:].strip()

        upd_s(user_id, {
            "current_lesson_data":         {"id":"custom","url":video_url,"title":"Перше відео","grammar":grammar,"topic":topic,"hint":hint},
            "pending_first_video_grammar": grammar,
            "pending_first_video_topic":   topic,
        })

        s = get_s(user_id)
        await msg.edit_text(
            f"🎬 *Перше завдання!*\n\n"
            f"🎤 {topic}\n\n"
            f"💡 _{hint}_\n\n"
            "Натисни ▶️ — відео вже чекає. Подивись → повтори вголос або запиши відео → натисни 🎙 👇",
            parse_mode="Markdown",
            reply_markup=video_watch_keyboard(video_url, s, show_dur=True)
        )
    except Exception as e:
        # Якщо AI не відповів — лишається миттєвий шаблон, нічого не ламаємо
        logger.error(f"First video task enrich error: {e}")

# ── Entry callbacks: обери / я вже обрав ─────────────
async def cb_entry(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    q    = update.callback_query
    user = q.from_user
    await q.answer()

    if q.data == "entry_choose":
        # Не запускаємо онбоардинг одразу — спочатку два відео
        upd_s(user.id, {"videos_watched": 0, "waiting_video": False})
        await q.edit_message_text("🔍 Підбираю відео для тебе...")
        await _auto_send_next_lesson(ctx.bot, user.id)

    elif q.data == "entry_own":
        upd_s(user.id, {"waiting_video": True, "videos_watched": 0})
        await q.edit_message_text(
            "Надішли посилання на відео:\n"
            "• 🎬 YouTube\n\n"
            "👇",
            parse_mode="Markdown"
        )

