    age_code = q.data.replace("kids_age_","")
    age_map  = {
        "0":  ("kids",  "A1", "0–3 років"),
        "4":  ("kids",  "A1", "4–6 років"),
        "7":  ("kids",  "A1", "7–9 років"),
        "10": ("teen",  "A1", "10–12 років"),
        "13": ("teen",  "A2", "13–15 років"),
    }
    age_group, default_level, age_label = age_map.get(age_code, ("kids", "A1", ""))

    upd_s(user.id, {"age_group": age_group, "kids_age": age_label})

