    sign = "+" if offset >= 0 else ""
    await q.edit_message_text(
        f"✅ *UTC{sign}{offset} збережено*\n\n"
        "Нагадування приходитимуть о *21:00 за твоїм часом*.\n\n"
        "Підбираю перше відео для тебе... 🔍",
        parse_mode="Markdown"
    )
