async def _send_lesson_for_topic(bot, uid: int, s: dict, forced_topic_name: str):
    """
    Розділ M (24.07): «Відео» на екрані прогресу (s-prog → openTopic)
    для КОНКРЕТНО обраної теми, не чергової CEFR-теми. Раніше цей крок
    і крок «Таблиця вголос» обидва мовчки вели в cmd_lesson() — та не
    приймає topic_key взагалі, шукала випадкове відео рівня студента.
    Людина тиснула «Відео на Present Perfect» і отримувала щось інше.

    Той самий потік, що cmd_lesson (youtube_search_lesson → fallback
    next_lesson → підвищення рівня → _send_merged_lesson_card), але:
      - через bot.send_message(chat_id=uid), не update.message — цю
        функцію кличуть з open_topic_step, де update.message не
        гарантований (дія прийшла з мініапу, не з команди в чаті);
      - forced_topic_name прокидається в youtube_search_lesson, яка
        шукає САМЕ цю тему (Step 0, вище пріоритету за next_cefr_topic).
    """
    level = s.get("level", "A1")
    phrase = random.choice(MOTIVATIONAL)
    await bot.send_message(chat_id=uid, text=phrase)
    thinking = await bot.send_message(chat_id=uid, text="🔍 Підбираю відео...")

    lesson = await youtube_search_lesson(s, forced_topic_name=forced_topic_name)
    if not lesson:
        lesson = next_lesson(s)

    if not lesson:
        idx    = LEVELS_ORDER.index(level) if level in LEVELS_ORDER else -1
        next_l = LEVELS_ORDER[idx + 1] if idx < len(LEVELS_ORDER) - 1 else None
        try:
            await thinking.delete()
        except Exception:
            pass
        if next_l:
            upd_s(uid, {"level": next_l, "done_lessons": []})
            await bot.send_message(
                chat_id=uid,
                text=(f"🎉 Рівень *{LEVEL_NAMES[level]}* пройдено!\n\n"
                      f"Переходимо на *{LEVEL_NAMES[next_l]}* 🚀\n\n"
                      "Натисни *🎬 Наступне відео* щоб продовжити."),
                parse_mode="Markdown",
                reply_markup=main_menu(),
            )
        else:
            await bot.send_message(chat_id=uid, text="🏆 Ти пройшов усі рівні! Браво!")
        return

    upd_s(uid, {"current_lesson_id": lesson["id"], "current_lesson_data": lesson})
    try:
        await thinking.delete()
    except Exception:
        pass
    await _send_merged_lesson_card(bot, uid, lesson, s)


# ── /lesson ───────────────────────────────────────────
async def cmd_lesson(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    s    = get_s(user.id)

    if not s.get("goal") or not s.get("level"):
        kids_age = s.get("kids_age", "")
        is_small_kid = kids_age in ("0–1 рік", "1–3 роки", "0–3 років", "4–6 років")
        if not is_small_kid:
            await update.message.reply_text(
                "Схоже, ми ще не знайомі 👋\n\n"
                "Дай відповідь на кілька запитань, щоб отримати свій індивідуальний прогрес 👇",
                parse_mode="Markdown"
            )
        await update.message.reply_text(
            "Для чого тобі потрібна англійської? 👇",
            parse_mode="Markdown",
            reply_markup=goal_kb()
        )
        return

    level = s.get("level", "A1")
    done  = s.get("done_lessons", [])

    phrase = random.choice(MOTIVATIONAL)
    await update.message.reply_text(phrase)
    thinking = await update.message.reply_text("🔍 Підбираю відео...")

    # ── 1. Спробуємо YouTube API ──
    lesson = await youtube_search_lesson(s)

    # ── 2. Fallback на бібліотеку ──
    if not lesson:
        lesson = next_lesson(s)

    # ── 3. Якщо бібліотека теж вичерпана — підвищуємо рівень ──
    if not lesson:
        idx    = LEVELS_ORDER.index(level) if level in LEVELS_ORDER else -1
        next_l = LEVELS_ORDER[idx + 1] if idx < len(LEVELS_ORDER) - 1 else None
        await thinking.delete()
        if next_l:
            upd_s(user.id, {"level": next_l, "done_lessons": []})
            await update.message.reply_text(
                f"🎉 Рівень *{LEVEL_NAMES[level]}* пройдено!\n\n"
                f"Переходимо на *{LEVEL_NAMES[next_l]}* 🚀\n\n"
                "Натисни *🎬 Наступне відео* щоб продовжити.",
                parse_mode="Markdown",
                reply_markup=main_menu()
            )
        else:
            await update.message.reply_text("🏆 Ти пройшов усі рівні! Браво!")
        return

    upd_s(user.id, {"current_lesson_id": lesson["id"], "current_lesson_data": lesson})
    total = len(get_lessons(s)) or 10

    await thinking.delete()

    source_label = ""
    if lesson.get("channel"):
        source_label = f"\n_📺 {lesson['channel']}_"
    cefr_label = ""
    if lesson.get("cefr_topic"):
        cefr_label = f"\n🎯 *CEFR тема:* _{lesson['cefr_topic']}_"

    await _send_merged_lesson_card(ctx.bot, user.id, lesson, s)

