async def cmd_myvideo(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """🎬 Мої відео — заклик ввести посилання + кнопка бібліотека."""
    user = update.effective_user
    s    = get_s(user.id)
    history = s.get("video_history", [])
    msg = update.message or (update.callback_query and update.callback_query.message)

    # Будуємо кнопки плеєра для останнього відео (якщо є)
    kb = []
    if history and WEBAPP_URL:
        last = history[0]
        vid_id = last.get("vid_id", "")
        title  = (last.get("title") or "останнє відео")[:30]
        if vid_id:
            player_url = _player_url(last.get("url", f"https://youtu.be/{vid_id}"), s)
            if player_url:
                kb.append([InlineKeyboardButton(
                    f"▶️ Відкрити в плеєрі: {title}",
                    web_app=WebAppInfo(url=player_url)
                )])

    # Кнопка бібліотека (тільки якщо є хоч одне відео)
    if history:
        kb.append([InlineKeyboardButton(
            f"📂 Архів ({len(history)} відео)",
            callback_data="myvideo_library"
        )])

    kb.append([InlineKeyboardButton("✅ Я вже обрав відео", callback_data="myvideo_add")])

    await msg.reply_text(
        "🎬 *Встав посилання на YouTube-відео*\n\n"
        "Скопіюй посилання з YouTube і надішли сюди — "
        "відео відкриється в плеєрі з субтитрами і картоткою слів 👇\n\n"
        "_Наприклад: https://youtu.be/dQw4w9WgXcQ_",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(kb) if kb else None,
        disable_web_page_preview=True
    )
    upd_s(user.id, {"waiting_video": True})


async def cb_myvideo_library(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """Показує бібліотеку переглянутих відео."""
    q    = update.callback_query
    user = q.from_user
    s    = get_s(user.id)
    await q.answer()

    history = s.get("video_history", [])
    if not history:
        await q.message.reply_text("📂 Архів поки порожній.")
        return

    lines = ["📂 *Архів відео*\n"]
    _hist_changed = False
    for i, v in enumerate(history[:20], 1):
        vid_id = v.get("vid_id", "")
        date   = v.get("date", "")[:10]
        title  = v.get("title") or ""
        # Task 3: якщо назва відсутня/заглушка — дотягуємо справжню з YouTube і зберігаємо
        if (not title or title == "YouTube відео") and vid_id:
            _real = ""
            try:
                import httpx as _hx
                _oe = _hx.get(f"https://www.youtube.com/oembed?url=https://youtu.be/{vid_id}&format=json", timeout=6)
                if _oe.status_code == 200:
                    _real = (_oe.json().get("title", "") or "")[:80]
                if not _real:
                    _ne = _hx.get(f"https://noembed.com/embed?url=https://youtu.be/{vid_id}", timeout=6)
                    if _ne.status_code == 200:
                        _real = (_ne.json().get("title", "") or "")[:80]
            except Exception:
                pass
            if _real:
                v["title"] = _real
                title = _real
                _hist_changed = True
        if not title:
            title = "YouTube відео"
        url    = v.get("url", f"https://youtu.be/{vid_id}")
        lines.append(f"{i}. [{title}]({url}) _({date})_")
    # зберігаємо дотягнуті назви, щоб більше не смикати мережу
    if _hist_changed:
        try:
            upd_s(user.id, {"video_history": history})
        except Exception:
            pass

    if len(history) > 20:
        lines.append(f"\n_…і ще {len(history)-20} відео_")

    # Кнопки — відкрити в плеєрі для останніх 3
    kb = []
    for v in history[:3]:
        vid_id = v.get("vid_id", "")
        date   = v.get("date", "")[:10]
        if vid_id and WEBAPP_URL:
            player_url = _player_url(v.get("url", f"https://youtu.be/{vid_id}"), s)
            if player_url:
                kb.append([InlineKeyboardButton(
                    f"▶️ Плеєр ({date})",
                    web_app=WebAppInfo(url=player_url)
                )])

    await q.message.reply_text(
        "\n".join(lines),
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(kb) if kb else None,
        disable_web_page_preview=True
    )


