def _errors_state() -> dict:
    """Журнал помилок для адмінки: список + зведення."""
    try:
        arr = load_db().get("_errors", [])
        if not isinstance(arr, list):
            arr = []
    except Exception:
        arr = []

    import time as _t
    now = int(_t.time())
    day = now - 86400

    def _ago(ts):
        d = now - int(ts or 0)
        if d < 60:    return "щойно"
        if d < 3600:  return f"{d // 60} хв тому"
        if d < 86400: return f"{d // 3600} год тому"
        return f"{d // 86400} дн тому"

    items = []
    for e in arr[:100]:
        last  = int(e.get("last", 0))
        quiet = now - last                      # скільки часу мовчить
        fix   = e.get("fix") or {}              # {"by":..., "note":..., "at":...}

        # Статус: як бот сам оцінює стан помилки
        if fix.get("note"):
            status, hint = "fixed", fix["note"]
        elif quiet > 7 * 86400:
            status, hint = "gone", "Не повторювалась 7+ днів — схоже, зникла сама"
        elif quiet > 86400:
            status, hint = "quiet", "Мовчить понад добу"
        elif e.get("count", 1) >= 5:
            status, hint = "hot", "Повторюється — треба дивитись"
        else:
            status, hint = "open", "Свіжа, чекає на розбір"

        # Що робити — підказка з класифікатора
        try:
            _, _, diag = _err_classify(Exception(e.get("msg", "")))
        except Exception:
            diag = ""

        items.append({
            "level":  e.get("level", "warning"),
            "msg":    e.get("msg", ""),
            "where":  e.get("where", ""),
            "count":  e.get("count", 1),
            "ago":    _ago(last),
            "fresh":  quiet < 3600,
            "seen":   bool(e.get("seen")),
            "key":    e.get("key", ""),
            "status": status,
            "hint":   hint,
            "diag":   diag,
            "fix_by": fix.get("by", ""),
            "fix_at": _ago(fix["at"]) if fix.get("at") else "",
        })

    errs_24h = sum(e.get("count", 1) for e in arr
                   if int(e.get("last", 0)) > day and e.get("level") == "error")
    warn_24h = sum(e.get("count", 1) for e in arr
                   if int(e.get("last", 0)) > day and e.get("level") != "error")

    return {
        "items":     items,
        "total":     len(arr),
        "errors_24h": errs_24h,
        "warns_24h":  warn_24h,
        "unseen":    sum(1 for e in arr if not e.get("seen")),
    }


def _switches_state() -> list:
    """Живий стан рубильників — для /switches і для адмінки (вкладка 🎛)."""
    live = {
        "SHELL_ENABLED":                  "1" if SHELL_ENABLED else "0",
        "ENABLE_ONBOARDING_V2":           "true" if ENABLE_ONBOARDING_V2 else "false",
        "ENABLE_DAILY_CHECKIN":           "true" if ENABLE_DAILY_CHECKIN else "false",
        "ENABLE_VICTORY_CARD":            "true" if ENABLE_VICTORY_CARD else "false",
        "ENABLE_MILESTONE_SHARE":         "true" if ENABLE_MILESTONE_SHARE else "false",
        "ENABLE_VIDEO_TO_BUDDY":          "true" if ENABLE_VIDEO_TO_BUDDY else "false",
        "ENABLE_GRAMMAR_DECAY_FROM_CHAT": "true" if ENABLE_GRAMMAR_DECAY_FROM_CHAT else "false",
        "RUN_MODE":                       os.environ.get("RUN_MODE", "all"),
    }
    out = []
    for env, on_val, default, name, does, when in _SWITCHES:
        cur = live.get(env, "?")
        out.append({
            "env":     env,
            "name":    name,
            "value":   cur,
            "default": default,
            "on":      (cur == on_val),
            "does":    does,
            "when":    when,
        })
    return out


async def cb_err_retry(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """Кнопка «🔄 Спробувати ще» з повідомлення про помилку."""
    q = update.callback_query
    try:
        await q.answer()
    except Exception:
        pass

    RETRY = {
        "retry_lesson":   cmd_myvideo,
        "retry_progress": cmd_progress,
        "retry_diag":     cmd_diagnostic,
    }
    fn = RETRY.get(q.data)
    if not fn:
        return

    # Прибираємо кнопку — щоб не тиснули двічі
    try:
        await q.edit_message_reply_markup(reply_markup=None)
    except Exception:
        pass

    try:
        fake = _FakeWebAppUpdate(update.effective_user, update.effective_chat.id)
        await fn(fake, ctx)
    except Exception as e:
        # Друга спроба теж провалилась — не мовчимо
        await guard(update, ctx, e, "Повторна спроба", "")


async def cmd_switches(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """/switches — усі рубильники: стан, що роблять, коли смикати."""
    user = update.effective_user
    if not is_admin(user.id) and not is_developer(user.id):
        await update.message.reply_text("⛔️ Доступ заборонено.")
        return

    lines = [
        "🎛 *РУБИЛЬНИКИ*",
        "_Аварійні вимикачі. Railway → Variables → Redeploy._",
        "",
    ]
    for s in _switches_state():
        if s["env"] == "RUN_MODE":
            icon, state = "⚙️", s["value"]
        else:
            icon  = "🟢" if s["on"] else "🔴"
            state = "УВІМК" if s["on"] else "ВИМК"
        lines.append(f"{icon} *{s['name']}*")
        lines.append(f"`{s['env']}` = `{s['value']}`  ({state})")
        lines.append(f"_{s['does']}_")
        lines.append(f"👉 {s['when']}")
        lines.append("")

    lines += [
        "━━━━━━━━━━━━━━━━━━",
        "*ЯК СМИКНУТИ*",
        "1. Railway → сервіс → *Variables*",
        "2. Знайди змінну (або додай)",
        "3. Зміни значення → *Redeploy*",
        "4. Перевір: `/switches`",
        "",
        "✅ Вмикає: `1` `true` `yes` `on` `так`",
        "❌ Вимикає: `0` `false` `no` `off`",
        "_Регістр не важливий. Напишеш дурницю — бот не зламається,_",
        "_залишить дефолт і попередить у логах._",
        "",
        "📊 Те саме у вкладці *🎛 Рубильники* в /admin",
    ]

    text = "\n".join(lines)
    for i in range(0, len(text), 3900):
        await update.message.reply_text(text[i:i+3900], parse_mode="Markdown")


