async def cmd_dev_plan(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """/dev_plan [demo|trial|basic|premium] — симулювати план."""
    user = update.effective_user
    if not is_developer(user.id) and not is_admin(user.id):
        return
    args = ctx.args
    plan = args[0].lower() if args else ""
    if plan not in ("demo", "trial", "basic", "premium"):
        await update.message.reply_text("❌ Вкажи: demo | trial | basic | premium")
        return
    set_dev_test_state(user.id, "plan", plan)
    await update.message.reply_text(f"✅ Тестовий план: *{plan}*\nПерезайди в бот щоб побачити зміни.", parse_mode="Markdown")


