def _is_student_for_notify(uid, s) -> bool:
    """True якщо це справжній учень, якому доречні студентські сповіщення.
    Виключає блогерів і адмінів — вони мають робочі кабінети, не вчаться тут.
    Хто хоче вчитися — реєструє окремий учнівський акаунт."""
    try:
        uid_int = int(uid)
    except (ValueError, TypeError):
        return False
    if not isinstance(s, dict):
        return False
    if is_blogger(uid_int) or is_admin(uid_int) or is_developer(uid_int):
        return False
    return True

