def _create_duo_room(uid_a: int, uid_b: int, scenario_id: str) -> str:
    """Створює спільну кімнату парного сценарію. Патерн — точна копія _create_duel."""
    import time as _t
    scenario = DUO_SCENARIOS.get(scenario_id, {})
    room_id  = f"duo_{uid_a}_{uid_b}_{int(_t.time())}"
    db    = load_db()
    rooms = db.get("_active_duo_rooms", {})
    rooms[room_id] = {
        "uid_a": str(uid_a), "uid_b": str(uid_b),
        "scenario_id": scenario_id,
        "scenario_title": scenario.get("title", ""),
        "scenario_desc":  scenario.get("desc", ""),
        "role_a_label": scenario.get("role_a_label", ""),
        "role_b_label": scenario.get("role_b_label", ""),
        "messages":    [],      # [{sender, transcript, is_video, ts}]
        "contributed": [],      # uid-и, що вже лишили ≥1 репліку
        "rewarded":    False,   # анти-дубль нагороди
        "status":      "active",
        "created_at":  datetime.now().strftime("%Y-%m-%d %H:%M"),
    }
    db["_active_duo_rooms"] = rooms
    save_db(db)
    return room_id


def _get_duo_room(room_id: str) -> dict:
    return load_db().get("_active_duo_rooms", {}).get(room_id, {})


def _update_duo_room(room_id: str, data: dict):
    db    = load_db()
    rooms = db.get("_active_duo_rooms", {})
    if room_id in rooms:
        rooms[room_id].update(data)
        db["_active_duo_rooms"] = rooms
        save_db(db)


def _try_claim_duo_reward(room_id: str) -> bool:
    """Атомарно (в межах одного load_db/save_db, БЕЗ await між читанням
    і записом) перевіряє й ставить rewarded=True. Повертає True лише
    для того виклику, який реально виграв гонку.

    Навіщо (21.07): _handle_duo_room_send читає room на початку, потім
    робить await на Whisper-транскрипцію — це вікно до 60 секунд. Якщо
    обидва учасники надсилають репліку майже одночасно, обидва входять
    у транскрипцію, і потім обидва бачать rewarded=False у СВОЄМУ
    застарілому знімку room → обидва нараховують XP + ланку ланцюжка
    обом учасникам. Подвійна нагорода за одну сесію.

    Той самий патерн, що _try_claim_relay_finalize і _patch_cstate:
    рішення ухвалюється на СВІЖИХ даних безпосередньо перед записом."""
    db    = load_db()
    rooms = db.get("_active_duo_rooms", {})
    room  = rooms.get(room_id)
    if not room or room.get("rewarded"):
        return False
    room["rewarded"] = True
    room["status"]   = "completed"
    rooms[room_id]   = room
    db["_active_duo_rooms"] = rooms
    save_db(db)
    return True


# ══════════════════════════════════════════════════════════════
# ВІДЕО-ЕСТАФЕТА «ПЛІТКИ» (C-16/C-17), 21.07
#
# Метод Китайгородської, документ 11 («Секрет і змова», шепіт-
# естафета): кожен учасник чує/бачить ЛИШЕ останнє попереднє відео,
# не всю історію — це і є суть прийому (реакція наживо, ефект
# "зіпсованого телефону"). Тому, на відміну від duo_room (2 людини,
# обидва бачать увесь спільний лог), тут кожен запит стану віддає
# рівно ОДНЕ попереднє повідомлення, а не весь messages[].
#
# Відкрита черга: будь-хто з посиланням може долучитись у будь-який
# момент, без фіксованого розміру групи наперед.
#
# Завершення — БЕЗ ручної кнопки (рішення власниці 21.07, друга
# ітерація): ризик — завершує той, кому набридло чекати, не той, хто
# хотів довести гру до кумедного фіналу. Автозавершення при ПЕРШІЙ
# з двох умов:
#   (1) RELAY_LINK_LIMIT ланок досягнуто — жорсткий поріг, гра сама
#       закривається на піку;
#   (2) RELAY_SILENCE_HOURS без нової ланки — страховка для кімнат,
#       що застигли раніше ліміту.
# Обидві умови перевіряє одна й та сама фонова job
# (job_relay_room_finalize, run_repeating) — не веб-запит користувача,
# щоб завершення не залежало від того, чи хтось саме зараз онлайн.
# ══════════════════════════════════════════════════════════════

RELAY_LINK_LIMIT     = 15   # поріг ланок — гра сама закривається на піку
RELAY_SILENCE_HOURS  = 24   # страховка: без нової ланки стільки годин
RELAY_MIN_LINKS      = 2    # менше 2 ланок — нема що склеювати, кімната просто гасне
# XP за ланку — XP_AWARDS["relay_link"], не окрема константа (єдине
# джерело правди для балансу, як і решта нагород у проєкті).


def _create_relay_room(creator_uid: int, opening_line: str = "") -> str:
    """Створює нову кімнату «Плітки». Патерн — той самий, що _create_duo_room,
    але uid_a/uid_b замінені на відкритий список links[] (N учасників,
    невідома наперед кількість)."""
    import time as _t
    room_id = f"relay_{creator_uid}_{int(_t.time())}"
    db    = load_db()
    rooms = db.get("_active_relay_rooms", {})
    now_iso = datetime.now().isoformat()
    rooms[room_id] = {
        "creator_uid":  str(creator_uid),
        "opening_line": opening_line,       # AI-згенерований зачин фрази, якщо є
        "links": [],
        # [{sender, transcript, file_id, is_video, ts}] — сира ланка
        "participants": [],                 # унікальні uid-и, що лишили ≥1 ланку
        "status":       "active",           # active | finalizing | completed
        "created_at":   now_iso,
        "last_activity": now_iso,           # оновлюється щоразу, коли додається ланка
        "final_video_file_id": "",          # заповнюється після склейки
    }
    db["_active_relay_rooms"] = rooms
    save_db(db)
    return room_id


def _get_relay_room(room_id: str) -> dict:
    return load_db().get("_active_relay_rooms", {}).get(room_id, {})


def _update_relay_room(room_id: str, data: dict):
    db    = load_db()
    rooms = db.get("_active_relay_rooms", {})
    if room_id in rooms:
        rooms[room_id].update(data)
        db["_active_relay_rooms"] = rooms
        save_db(db)


def _try_claim_relay_finalize(room_id: str) -> bool:
    """Атомарно (в межах одного load_db/save_db) перевіряє й переводить
    кімнату active → finalizing. Повертає True лише для того виклику,
    який реально виграв гонку — захист від подвійної фіналізації, коли
    поріг ланок і крон-job (job_relay_room_finalize) спрацьовують майже
    одночасно (той самий клас гонки, що вже фіксувався в проєкті раніше
    для challenge_state, звідти й патерн: читання й запис БЕЗ await між
    ними, single load_db/save_db round-trip)."""
    db    = load_db()
    rooms = db.get("_active_relay_rooms", {})
    room  = rooms.get(room_id)
    if not room or room.get("status") != "active":
        return False
    room["status"] = "finalizing"
    rooms[room_id] = room
    db["_active_relay_rooms"] = rooms
    save_db(db)
    return True


def _relay_room_last_link(room: dict) -> dict:
    """Останню ланку для показу наступному учаснику — НІКОЛИ весь links[],
    щоб не зламати ефект несподіванки шепіт-естафети."""
    links = room.get("links") or []
    return links[-1] if links else {}



