# ГРАМАТИЧНІ CALLBACKS
# ══════════════════════════════════════════════════════════════

async def _send_grammar_explanation(bot, uid: int, topic_key: str, phrase: str = ""):
    """
    C-23 (20.07): єдина точка відправки Кроку 1 (пояснення граматики).
    Раніше цей самий блок (format_explanation → reply_text) був
    продубльований у трьох callbacks (cb_grammar_lesson_start,
    buddy_train continuation, cb_tutor_topic) — тепер один хелпер,
    щоб кнопка нижче з'явилась усюди одразу, без трьох синхронних правок.

    РІШЕННЯ по build_explanation_prompt (методист + CPO, 20.07,
    питання висіло без відповіді з v33):
    Крок 1 лишається СТАТИЧНИМ (format_explanation, стиль Голіцинського)
    — це найчастіший тригер продукту (кожна нова тема, кожен студент),
    заміна на AI-виклик тут означала б постійне навантаження на вартість
    і затримку заради виграшу, який більшість студентів не помітять:
    приклади й так беруться з тієї самої GRAMMAR_MAP. AI-версія
    (build_explanation_prompt) підключена як ОПЦІОНАЛЬНЕ поглиблення —
    кнопка «Не зрозуміло? Поясни інакше», яку тисне лише той, кому
    справді треба. Вартість і затримка — тільки за запитом, не на
    кожен показ.
    """
    explanation = format_explanation(topic_key, phrase)
    if not explanation:
        return
    kb = None
    if topic_key in GRAMMAR_MAP:
        kb = InlineKeyboardMarkup([[
            InlineKeyboardButton("🤔 Не зрозуміло? Поясни інакше",
                                  callback_data=f"gexpl_{topic_key}")
        ]])
    await bot.send_message(uid, explanation, parse_mode="Markdown", reply_markup=kb)


async def cb_grammar_explain_again(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """
    C-23: AI-поглиблене пояснення за запитом студента. Викликається
    ТІЛЬКИ тут — тобто рідко (не на кожен показ Кроку 1), тому вартість
    build_explanation_prompt виправдана саме в цьому місці.
    """
    q = update.callback_query
    user = q.from_user
    topic_key = q.data.replace("gexpl_", "")
    await q.answer("Пояснюю інакше…")

    if topic_key not in GRAMMAR_MAP:
        await q.message.reply_text("⚠️ Тема не знайдена.")
        return

    s = get_s(user.id)
    level = s.get("level", "A1")
    phrase = s.get("grammar_pending_phrase", "") or ""

    try:
        prompt = build_explanation_prompt(phrase, topic_key, level)
        cr = await claude_create_async(
            model="claude-haiku-4-5-20251001",
            max_tokens=500,
            messages=[{"role": "user", "content": prompt}],
            _uid=user.id,
        )
        alt_explanation = (cr.content[0].text or "").strip()
        if not alt_explanation:
            raise ValueError("empty AI explanation")
        await q.message.reply_text(alt_explanation, parse_mode="Markdown")
    except Exception as e:
        logger.warning(f"cb_grammar_explain_again {user.id} topic={topic_key}: {e}")
        # Фолбек: якщо AI недоступний, студент не лишається без відповіді —
        # повторюємо статичне пояснення, а не мовчимо.
        try:
            await q.message.reply_text(
                format_explanation(topic_key, phrase), parse_mode="Markdown")
        except Exception:
            await q.message.reply_text("⚠️ Тимчасово не вдалось пояснити інакше. Спробуй ще раз пізніше.")


async def cb_grammar_lesson_start(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """Студент натиснув 'Так, давай' — запускаємо міні-урок."""
    q    = update.callback_query
    user = q.from_user
    s    = get_s(user.id)
    await q.answer()

    pending_topic  = s.get("grammar_pending_topic", "")
    pending_phrase = s.get("grammar_pending_phrase", "")
    if not pending_topic or pending_topic not in GRAMMAR_MAP:
        await q.message.reply_text("⚠️ Тема не знайдена. Продовжуй дивитись відео!")
        return

    level = s.get("level", "A1")

    # Крок 1: пояснення у стилі Голіцинського
    await _send_grammar_explanation(ctx.bot, user.id, pending_topic, pending_phrase)

    # Крок 2: перша вправа
    import asyncio as _aio
    await _aio.sleep(2)
    await _send_grammar_exercise(ctx.bot, user.id, pending_topic, level, 1, 0)


async def cb_chainy_train_errors(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """Кнопка 'Потренувати теми' з фінальної картки Chainy.
    Бере першу тему з накопичених за сесію помилок і запускає наявний
    потік тренування (пояснення + вправа) — той самий, що й нудж."""
    q    = update.callback_query
    user = q.from_user
    s    = get_s(user.id)
    await q.answer()

    queue = s.get("buddy_train_queue", [])
    topic_key = next((t for t in queue if t in GRAMMAR_MAP), "")
    if not topic_key:
        await q.message.reply_text("⚠️ Теми для тренування не знайдено. Просто продовжуй розмову!")
        return

    # виставляємо pending-тему й переиспользуємо наявний потік уроку
    upd_s(user.id, {"grammar_pending_topic": topic_key, "grammar_pending_phrase": ""})
    level = s.get("level", "A1")

    await _send_grammar_explanation(ctx.bot, user.id, topic_key, "")

    import asyncio as _aio
    await _aio.sleep(2)
    await _send_grammar_exercise(ctx.bot, user.id, topic_key, level, 1, 0)

    # прибираємо опрацьовану тему з черги
    try:
        _rest = [t for t in queue if t != topic_key]
        upd_s(user.id, {"buddy_train_queue": _rest})
    except Exception:
        pass


async def cb_grammar_nudge_snooze(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """Студент натиснув 'Пізніше'."""
    q    = update.callback_query
    user = q.from_user
    s    = get_s(user.id)
    topic_key = s.get("grammar_pending_topic", "")
    if topic_key:
        s_updated = mark_nudge_snoozed(s, topic_key)
        upd_s(user.id, {"grammar_topics": s_updated["grammar_topics"]})
    await q.answer("Добре, нагадаю пізніше 👌")
    try:
        await q.message.edit_reply_markup(reply_markup=None)
    except Exception:
        pass


async def cb_grammar_exercise(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """Студент обрав варіант відповіді у вправі (gram_ex_A/B/C/D)."""
    from telegram import InlineKeyboardButton, InlineKeyboardMarkup
    q    = update.callback_query
    user = q.from_user
    data = q.data
    chosen = data.replace("gram_ex_", "")  # A, B, C або D
    s    = get_s(user.id)
    ex_state = s.get("grammar_exercise_state", {})
    if not ex_state:
        await q.answer()
        return

    correct     = ex_state.get("correct", "")
    explanation = ex_state.get("explanation", "")
    count       = ex_state.get("count", 1)
    score       = ex_state.get("score", 0)
    topic_key   = ex_state.get("topic", "")
    level       = s.get("level", "A1")

    is_correct = (chosen == correct)
    if is_correct:
        score += 1
        result_text = f"✅ Правильно!\n_{explanation}_"
    else:
        result_text = f"❌ Не зовсім. Правильно: *{correct}*\n_{explanation}_"

    await q.answer()
    try:
        await q.message.edit_reply_markup(reply_markup=None)
    except Exception:
        pass
    await q.message.reply_text(result_text, parse_mode="Markdown")

    if count >= 30:
        # Вправу завершено — показуємо результат
        pct = round(score / 30 * 100)
        if pct >= 70:
            s_upd = mark_topic_event(get_s(user.id), topic_key, "quiz_passed")
            s_upd = mark_topic_event(s_upd, topic_key, "lesson_done")
            upd_s(user.id, {"grammar_topics": s_upd["grammar_topics"]})
        s2 = get_s(user.id)
        events = s2.get("grammar_topics", {}).get(topic_key, {})
        mastery = compute_mastery({
            k: events.get(k, False)
            for k in ["first_contact","lesson_done","quiz_passed","used_in_free","spaced_rep"]
        })
        from grammar_engine import _make_bar
        bar = _make_bar(mastery)
        t   = GRAMMAR_MAP.get(topic_key, {})
        await ctx.bot.send_message(
            chat_id=user.id,
            text=(
                f"🎉 *Вправу завершено!*\n\n"
                f"Правильних: *{score}/30* ({pct}%)\n\n"
                f"{bar} *{mastery}%* — _{t.get('ua', topic_key)}_\n\n"
                f"{'Відмінно! Тема засвоєна 💪' if pct >= 70 else 'Продовжуй — практика дає результат!'}"
            ),
            parse_mode="Markdown"
        )
        upd_s(user.id, {"grammar_exercise_state": {}})
    else:
        # Наступна вправа
        form = "positive" if count < 10 else ("negative" if count < 20 else "question")
        ex_state["count"] = count + 1
        ex_state["score"] = score
        upd_s(user.id, {"grammar_exercise_state": ex_state})
        await _send_grammar_exercise(ctx.bot, user.id, topic_key, level, count + 1, score)


async def _send_grammar_exercise(bot, uid: int, topic_key: str, level: str, count: int, score: int):
    """
    Надсилає одну вправу студенту, з кешованого пулу (20.07: додано
    кешування — дивись EXERCISE_CACHE вище). Генерує новий пул через
    Claude лише коли кеш порожній або всі вправи пулу вже показані
    цьому студенту в поточній сесії.
    """
    from telegram import InlineKeyboardButton, InlineKeyboardMarkup
    import json as _j
    import random as _r

    form = "positive" if count <= 10 else ("negative" if count <= 20 else "question")

    ex_state_prev = get_s(uid).get("grammar_exercise_state", {}) or {}
    used_idx = set(ex_state_prev.get("used_pool_idx", [])) \
        if ex_state_prev.get("topic") == topic_key and ex_state_prev.get("form") == form else set()

    pool = get_cached_exercise_pool(topic_key, level, form) or []
    available = [i for i in range(len(pool)) if i not in used_idx]

    try:
        if not available:
            # Кеш порожній або вичерпаний студентом — генеруємо новий пул
            prompt = build_exercise_prompt(topic_key, level, form, pool_size=EXERCISE_POOL_SIZE)
            cr = await claude_create_async(
                model="claude-haiku-4-5-20251001",
                max_tokens=1200,
                messages=[{"role": "user", "content": prompt}]
            )
            raw = cr.content[0].text.strip()
            raw = raw[raw.find("["):raw.rfind("]")+1]
            pool = _j.loads(raw)
            if not isinstance(pool, list) or not pool:
                raise ValueError("Claude не повернув непорожній масив вправ")
            store_exercise_pool(topic_key, level, form, pool)
            used_idx = set()
            available = list(range(len(pool)))

        idx = _r.choice(available)
        ex  = pool[idx]
        used_idx.add(idx)

        sentence    = ex.get("sentence", "")
        opts        = ex.get("options", {})
        signal      = ex.get("signal", "")
        correct     = ex.get("correct", "")
        expl        = ex.get("explanation", "")

        # Зберігаємо стан вправи + які індекси пулу вже показані цьому студенту
        upd_s(uid, {"grammar_exercise_state": {
            "topic":         topic_key,
            "form":          form,
            "correct":       correct,
            "sentence":      sentence,
            "count":         count,
            "score":         score,
            "explanation":   expl,
            "used_pool_idx": sorted(used_idx),
        }})

        kb = InlineKeyboardMarkup([[
            InlineKeyboardButton(f"A) {opts.get('A','')}", callback_data="gram_ex_A"),
            InlineKeyboardButton(f"B) {opts.get('B','')}", callback_data="gram_ex_B"),
        ],[
            InlineKeyboardButton(f"C) {opts.get('C','')}", callback_data="gram_ex_C"),
            InlineKeyboardButton(f"D) {opts.get('D','')}", callback_data="gram_ex_D"),
        ]])

        form_icon = "✅" if form == "positive" else ("❌" if form == "negative" else "❓")
        text = f"📝 *Вправа {count}/30* {form_icon}\n\n{sentence}"
        if signal:
            text += f"\n\n🔑 _{signal}_"

        await bot.send_message(
            chat_id=uid,
            text=text,
            parse_mode="Markdown",
            reply_markup=kb
        )
    except Exception as e:
        logger.warning(f"Grammar exercise send error: {e}")
        await bot.send_message(
            chat_id=uid,
            text="⚠️ Помилка генерації вправи. Спробуй пізніше."
        )


