async def cmd_grammar_topic(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """/topic [topic_key] — показує таблицю Голіцинського для теми.

    v13.1: сама таблиця — довідковий контент (як /help), лишається текстом.
    Але додано кнопку в застосунок — та сама тема там дає повний робочий
    цикл (відео → таблиця → вправи → Chainy), а не тільки таблицю."""
    user  = update.effective_user
    args  = ctx.args or []
    topic = args[0] if args else ""
    _url  = shell_url("s-prog")
    _app_btn = InlineKeyboardMarkup([[
        InlineKeyboardButton("📊 Відкрити тему в застосунку", web_app=WebAppInfo(url=_url))
    ]])
    if not topic or topic not in GRAMMAR_MAP:
        topics_list = "\n".join(
            f"• `{k}` — {v['ua']}"
            for k, v in sorted(GRAMMAR_MAP.items(), key=lambda x: x[1]["order"])
        )
        await update.message.reply_text(
            f"📚 *Всі граматичні теми:*\n\n{topics_list}\n\nВикористовуй: /topic past_simple",
            parse_mode="Markdown",
            reply_markup=_app_btn
        )
        return
    text = format_table_only(topic)
    await update.message.reply_text(text, parse_mode="Markdown", reply_markup=_app_btn)



