async def classify_topic_llm(phrase: str) -> str | None:
    """
    Рівень 2 класифікації — Claude Haiku для фраз без regex-матчу.
    Повертає topic_key або None.
    """
    topics_list = ", ".join(GRAMMAR_MAP.keys())
    prompt = (
        f"Classify this English phrase into ONE grammar topic.\n"
        f"Phrase: \"{phrase}\"\n"
        f"Available topics: {topics_list}\n"
        f"Respond ONLY with valid JSON, no markdown:\n"
        f'{{\"topic\": \"past_simple\", \"confidence\": 0.95}}'
    )
    try:
        cr = await claude_create_async(
            model="claude-haiku-4-5-20251001",
            max_tokens=60,
            messages=[{"role": "user", "content": prompt}]
        )
        import json as _j
        raw  = cr.content[0].text.strip()
        raw  = raw[raw.find("{"):raw.rfind("}")+1]
        data = _j.loads(raw)
        topic      = data.get("topic", "")
        confidence = float(data.get("confidence", 0))
        if confidence >= 0.75 and topic in GRAMMAR_MAP:
            return topic
    except Exception as e:
        logger.warning(f"classify_topic_llm error: {e}")
    return None



async def _detect_used_in_free(uid: int, transcript: str):
    """
    Аналізує транскрипт монологу студента.
    Якщо знаходить граматичні структури з вивчених тем — відмічає used_in_free.
    """
    s = get_s(uid)
    grammar = s.get("grammar_topics", {})
    if not grammar:
        return

    # Перевіряємо лише теми де є перший контакт але used_in_free ще False
    candidates = [
        k for k, v in grammar.items()
        if v.get("first_contact") and not v.get("used_in_free")
    ]
    if not candidates:
        return

    found = []
    for topic_key in candidates:
        # Швидка перевірка regex — чи є ця структура в транскрипті
        detected = detect_topic(transcript)
        if detected == topic_key:
            found.append(topic_key)
        # Також перевіряємо по сигнальних словах
        t = GRAMMAR_MAP.get(topic_key, {})
        signals = t.get("signals", [])
        transcript_lower = transcript.lower()
        if any(sig.lower() in transcript_lower for sig in signals if len(sig) > 3):
            if topic_key not in found:
                found.append(topic_key)

    if not found:
        return

    # Оновлюємо used_in_free для знайдених тем
    s_fresh = get_s(uid)
    for topic_key in found:
        s_fresh = mark_topic_event(s_fresh, topic_key, "used_in_free")

    upd_s(uid, {"grammar_topics": s_fresh["grammar_topics"]})

    # Повідомляємо студента
    if found:
        t     = GRAMMAR_MAP.get(found[0], {})
        ua    = t.get("ua", found[0])
        events = s_fresh.get("grammar_topics", {}).get(found[0], {})
        mastery = compute_mastery({
            k: events.get(k, False)
            for k in ["first_contact","lesson_done","quiz_passed","used_in_free","spaced_rep"]
        })
        from grammar_engine import _make_bar
        try:
            from telegram import Bot
            bot = Bot(token=BOT_TOKEN)
            await bot.send_message(
                chat_id=uid,
                text=(
                    f"🌟 *Чудово!* Ти використав нову структуру в монолозі!\n\n"
                    f"_{ua}_\n\n"
                    f"{_make_bar(mastery)} *{mastery}%* засвоєно"
                ),
                parse_mode="Markdown"
            )
        except Exception as e:
            logger.warning(f"_detect_used_in_free notify error: {e}")


async def _detect_vocab_in_speech(uid: int, transcript: str):
    """Зараховує слова рівня студента, ПРОМОВЛЕНІ в монолозі/voice-reply.

    23.07: виправлено методичну помилку, знайдену на нараді з методистом.
    БУЛО: одне промовляння одразу давало count_know=2 — той самий поріг,
    що й повне SRS-закріплення (_is_word_known). Рецептивне й продуктивне
    знання слова — різні стадії засвоєння (Melka, 1997; Nation, 2001),
    дослідження вимагають щонайменше кілька значущих зустрічей з
    інтервалом (5-12 за різними джерелами), не одну. Одна репліка з
    монологу — це один момент, навіть якщо слово прозвучало кілька разів
    у ній самій (повторення в одному видиху не рахуються окремими
    зустрічами, інакше студентка, яка повторила слово тричі поспіль,
    штучно накрутила б лічильник за секунди).

    ТЕПЕР: перше промовляння слова = count_know 1 (як звичайна картка
    після одного "know", не одразу "засвоєно"). Поріг "засвоєно"
    (_is_word_known: count_know>=2) досягається тільки коли слово
    промовлене повторно в ІНШИЙ окремий день — spoken_days зберігає
    множину дат, не лічильник повторень усередині сесії."""
    try:
        s      = get_s(uid)
        level  = s.get("level", "A1")
        srs_db = s.get("srs_words", {})
        found  = detect_spoken_vocab(transcript, level, srs_db)
        if not found:
            return
        today = datetime.now().strftime("%Y-%m-%d")
        for word, cefr in found:
            e = srs_db.get(word, {"interval_days": 0, "count_know": 0, "count_learn": 0})
            e["cefr"] = cefr
            # L-05: той самий lazy-backfill теми, що й у _srs_update_word —
            # слово, промовлене в мовленні, теж отримує тег теми, якщо
            # потрапляє в keyword-якорі topic_map.
            if not e.get("topic"):
                _topic = classify_word_topic(word, e)
                if _topic:
                    e["topic"] = _topic
            _spoken_days = set(e.get("spoken_days", []))
            _is_new_day  = today not in _spoken_days
            _spoken_days.add(today)
            # тримаємо лише останні 30 дат — досить для порогу засвоєння,
            # не дає списку рости необмежено на дуже активних студентах
            e["spoken_days"] = sorted(_spoken_days)[-30:]
            if _is_new_day:
                # рахуємо ЛИШЕ коли слово прозвучало в НОВИЙ день —
                # це і є «повторна зустріч», а не повторення в тій самій репліці
                e["count_know"] = e.get("count_know", 0) + 1
            e["interval_days"] = max(e.get("interval_days", 0), 3 if e["count_know"] < 2 else 7)
            e["next_review"]   = _srs_next_date("know", e["interval_days"])
            e["type"]          = e.get("type", "spoken")
            srs_db[word] = e
        # vocab_learned (список «показати користувачу») — лише слова, що
        # реально перетнули поріг засвоєння цим разом, не кожне почуте
        learned = s.get("vocab_learned", [])
        for word, _ in found:
            _e = srs_db.get(word, {})
            if _e.get("count_know", 0) >= 2 and word not in learned:
                learned.append(word)
        upd_s(uid, {"srs_words": srs_db, "vocab_learned": learned})

        # Методично різні події (23.07): «вперше почули слово в мовленні»
        # і «слово реально засвоєне» (друга окрема зустріч) — це не одне
        # й те саме, повідомлення тепер каже правду про кожне.
        _newly_mastered = [(w, c) for w, c in found if srs_db.get(w, {}).get("count_know", 0) >= 2]
        _first_seen     = [(w, c) for w, c in found if srs_db.get(w, {}).get("count_know", 0) < 2]

        try:
            from telegram import Bot
            bot = Bot(token=BOT_TOKEN)
            if _newly_mastered:
                lvls      = sorted({c for _, c in _newly_mastered})
                words_str = ", ".join(f"*{w}*" for w, _ in _newly_mastered[:5])
                _n        = len(_newly_mastered)
                _word_uk  = "слово" if _n == 1 else ("слова" if 2 <= _n <= 4 else "слів")
                await bot.send_message(
                    chat_id=uid,
                    text=(
                        f"\U0001f5e3 *+{_n} {_word_uk} засвоєно в мовленні!*\n\n"
                        f"Ти вживаєш наживо вже вдруге: {words_str}\n"
                        f"Рівень: {', '.join(lvls)} — зараховано в лексику \U0001f4d6"
                    ),
                    parse_mode="Markdown"
                )
            elif _first_seen:
                # Перша зустріч — не спамимо окремим повідомленням щоразу
                # (це рецептивна стадія, не подія-досягнення), лише тихо
                # логуємо для аналітики.
                logger.info(f"vocab first-seen in speech uid={uid}: {[w for w,_ in _first_seen][:10]}")
        except Exception as e:
            logger.warning(f"_detect_vocab_in_speech notify error: {e}")
    except Exception as e:
        logger.warning(f"_detect_vocab_in_speech error: {e}")


async def cb_duel_challenge(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """Студент натиснув ⚔️ Кинути виклик після монологу."""
    q    = update.callback_query
    user = q.from_user
    s    = get_s(user.id)
    await q.answer()

    blogger_name = s.get("affiliate_blogger", "")
    if not blogger_name:
        await q.edit_message_text(
            "⚔️ Виклики доступні тільки студентам блогерів.\n\n"
            "Зареєструйся через реферальне посилання блогера!",
            parse_mode="Markdown"
        )
        return

    db        = load_db()
    opponents = _get_duel_opponents(user.id, blogger_name, db)
    if not opponents:
        await q.edit_message_text(
            "😔 Поки немає інших студентів @{} того ж рівня.\n\n"
            "Виклики з'являться коли приєднається більше студентів! 💪".format(blogger_name),
            parse_mode="Markdown"
        )
        return

    # Показуємо список опонентів
    score    = s.get("last_voice_score", 0)
    topic    = s.get("voice_lesson_data", {}).get("topic", "") or s.get("current_lesson_data", {}).get("topic", "Speaking challenge")
    # Зберігаємо тему і бал для майбутнього виклику
    upd_s(user.id, {"pending_duel_topic": topic, "pending_duel_score": score})

    kb = []
    for opp_uid, opp_name, opp_lvl in opponents:
        kb.append([InlineKeyboardButton(
            f"⚔️ {opp_name} ({opp_lvl})",
            callback_data=f"duel_send_{opp_uid}"
        )])
    kb.append([InlineKeyboardButton("❌ Скасувати", callback_data="duel_cancel")])

    await q.edit_message_text(
        f"⚔️ *Кому кидаємо виклик?*\n\n"
        f"Тема: _{topic}_\n"
        f"Твій бал: *{score}/100*\n\n"
        "Обери опонента 👇",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(kb)
    )


