async def handle_blogger_welcome_media(update: Update, ctx: ContextTypes.DEFAULT_TYPE) -> bool:
    """Обробляє відео/голос від блогера як привітання. Повертає True якщо оброблено."""
    user = update.effective_user
    s    = get_s(user.id)
