async def cmd_invite_premium_to_group(bot, student_uid: int, blogger_uid: int):
    """Надсилає студенту посилання в Premium групу блогера."""
    s_blogger = get_s(blogger_uid)
    group_id  = s_blogger.get("live_group_id")
