async def cmd_admin_reply(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """/reply <uid> <текст> — адмін відповідає на питання студента."""
    if not is_admin(update.effective_user.id):
        return
    if not ctx.args or len(ctx.args) < 2:
        await update.message.reply_text("Використання: /reply <uid> <текст відповіді>")
        return
    try:
        target_uid = int(ctx.args[0])
        answer     = " ".join(ctx.args[1:])
    except ValueError:
        await update.message.reply_text("❌ Невірний uid")
        return

    # Зберігаємо відповідь в історію
    s       = get_s(target_uid)
    history = s.get("admin_questions", [])
    if history:
        history[-1]["a"] = answer   # відповідь до останнього питання
        upd_s(target_uid, {"admin_questions": history})

    try:
        await ctx.bot.send_message(
            chat_id=target_uid,
            text=(
                f"📬 *Відповідь від адміна:*\n\n{answer}"
            ),
            parse_mode="Markdown"
        )
        await update.message.reply_text(f"✅ Відповідь надіслано студенту {target_uid}")
    except Exception as e:
        await update.message.reply_text(f"❌ Помилка: {e}")

async def cmd_chainy_cost_admin(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """/chainy_cost — АНОМАЛІЇ CHAINY. Хто витрачає забагато AI.

    v13.1: перейменовано з cmd_chainy — ця назва конфліктувала з командою
    /chainy, яку студенти логічно очікують як запуск AI Chainy. Через
    колізію імен студентський /chainy мовчав (is_admin() відсікав усіх,
    хто не власниця), а сама функція — адмінський звіт про витрати —
    ніколи не мала бути публічною командою під цим ім'ям.

    НАВІЩО: рахунок від Anthropic приходить у кінці місяця. Без цього
    екрана Ви дізнаєтесь про людину, яка накрутила $300, ТІЛЬКИ з рахунку —
    коли гроші вже витрачено. Тут видно того ж дня.

    Показує:
      • хто перетнув поріг / уперся у стелю за останні 7 днів
      • скільки це коштувало в доларах
      • прогноз, якщо так триватиме весь місяць
    """
    user = update.effective_user
    if not is_admin(user.id):
        return

    db  = load_db()
    log = (db.get("_chainy_anomalies") or [])

    # Вартість одного повідомлення (той самий розрахунок, що в детекторі)
    COST_MSG = 928 * 0.80 / 1_000_000 + 90 * 4.00 / 1_000_000

    from datetime import timedelta
    week_ago = (datetime.now() - timedelta(days=7)).strftime("%Y-%m-%d")
    recent   = [e for e in log if e.get("d", "") >= week_ago]

    lines = ["🔍 *Chainy — аномалії*", ""]
    lines.append(f"Ліміти: demo *{DEMO_LIMIT}* · trial *{TRIAL_LIMIT}* · paid *{BASIC_LIMIT}*/день")
    lines.append(f"Поріг сигналу: *{CHAINY_ANOMALY_AT}* повідомлень\n")

    if not recent:
        lines.append("✅ *За 7 днів — жодної аномалії.*")
        lines.append("")
        lines.append("_Ніхто не перетнув поріг. Витрати під контролем._")
        await update.message.reply_text("\n".join(lines), parse_mode="Markdown")
        return

    # Групуємо по людині
    by_uid = {}
    for e in recent:
        u = e.get("uid", "?")
        d = by_uid.setdefault(u, {"days": 0, "max": 0, "caps": 0,
                                  "status": e.get("status", "?"), "cost": 0.0})
        d["days"]  += 1
        d["max"]    = max(d["max"], e.get("count", 0))
        d["caps"]  += 1 if e.get("cap") else 0
        d["cost"]  += e.get("cost", 0)

    ranked = sorted(by_uid.items(), key=lambda x: x[1]["cost"], reverse=True)

    total = sum(d["cost"] for _, d in ranked)
    lines.append(f"⚠️ *{len(ranked)}* осіб за 7 днів · витрачено *${total:.2f}*\n")

    for uid_s, d in ranked[:15]:
        # Прогноз: якщо так триватиме 30 днів
        per_day = d["cost"] / max(1, d["days"])
        month   = per_day * 30
        rev     = 19.77 if d["status"] == "paid" else 0.0
        if rev and month > rev:
            mark = "🔴"        # витрати перевищують виручку
        elif month > 5:
            mark = "⚠️"
        else:
            mark = "·"
        cap = f" · уперся в стелю ×{d['caps']}" if d["caps"] else ""
        lines.append(
            f"{mark} `{uid_s}` ({d['status']}) — макс *{d['max']}*/день{cap}\n"
            f"    ${d['cost']:.2f} за {d['days']} дн → прогноз *${month:.2f}*/міс"
        )

    lines.append("")
    lines.append("🔴 — витрати перевищать виручку з цієї людини")
    lines.append("⚠️ — понад $5/міс")
    lines.append("")
    lines.append(f"_Ліміт міняється: Railway → `CHAINY_LIMIT_PAID`_")

    await update.message.reply_text("\n".join(lines), parse_mode="Markdown")


