        webapp_url = GITHUB_PAGES_URL.rstrip("/") + "/blogger.html" + \
                     "?d=" + urllib.parse.quote(json.dumps(blogger_data, ensure_ascii=False))
        # BotFather short name URL (якщо зареєстровано)
        bot_username_cache = getattr(cmd_my_students, '_bot_username', None)
        miniapp_url = f"https://t.me/{bot_username_cache}/blogger" if bot_username_cache else webapp_url
