async def activate_plan(bot, user_id: int, plan: str, days: int, is_renewal: bool = False,
                        paid_amount: float = None, orig_plan: str = ""):
    """paid_amount — ФАКТИЧНА сума від WayForPay. Якщо None — Sheets візьме
       ціну з довідника (константи BASIC_PRICE тощо).
       orig_plan   — оригінальний план (basic_6m), бо сюди приходить base_plan
       без суфікса _6m, і Sheets не знав би, що це 6-місячний."""
    """Активує план — викликається вручну і автоматично через WayForPay webhook."""
    from datetime import timedelta
    until = (datetime.now() + timedelta(days=days)).strftime("%Y-%m-%d")
    s     = get_s(user_id)
    ref   = s.get("affiliate_ref", "")

    upd_s(user_id, {
        "premium_until":  until,
        "plan":           plan,
        "plan_activated": datetime.now().strftime("%Y-%m-%d"),
    }, force=True)  # платіж — зберігаємо одразу в PostgreSQL

    asyncio.create_task(gs_log_payment(user_id, days, until, ref, (orig_plan or plan), paid_amount))
    asyncio.create_task(gs_sync_student(user_id))
    asyncio.create_task(asyncio.to_thread(gs_sync_bloggers))

    # ── Атрибуція оплати до win-back (вікно 48 год = термін дії знижки) ──
    # Якщо оффер показали (winback_offered_at) і людина платить у межах
    # 48 год — це win-back-конверсія. Поза вікном знижка вже мертва, тож
    # НЕ атрибутуємо (інакше метрика забрудниться «випадковими» оплатами).
    try:
        _cs   = s.get("challenge_state", {}) or {}
        _off  = _cs.get("winback_offered_at")
        _flow = _cs.get("winback_flow", "organic")
        if _off and not _cs.get("winback_paid_tracked"):
            _off_dt = datetime.strptime(_off, "%Y-%m-%dT%H:%M")
            if (datetime.now() - _off_dt) <= timedelta(hours=48):
                _base = "premium" if plan == "premium" else "basic"
                from analytics import track_event
                await track_event(user_id, f"winback_paid_{_base}_{_flow}",
                                  get_s(user_id), upd_s)
                # guard — щоб продовження підписки не порахувалось двічі
                _cs2 = get_s(user_id).get("challenge_state", {}) or {}
                _cs2["winback_paid_tracked"] = True
                upd_s(user_id, {"challenge_state": _cs2})
    except Exception as _e:
        logger.warning(f"winback attribution {user_id}: {_e}")

    plan_name = "Basic ⚡️" if plan == "basic" else "Premium 🌟"
    s2        = get_s(user_id)
    name      = s2.get("name", "")
    name_line = f"*{name}*, " if name else ""
    lessons   = len(s2.get("done_lessons", []))
    streak    = s2.get("streak", 0)
    phrases   = len(s2.get("mined_sentences", []))

    if plan == "premium":
        plan_perks = (
            "🌟 *Що відкрито:*\n"
            "• AI-розбір кожного монологу\n"
            "• Speaking challenges від блогера\n"
            "• Доступ до Premium групи\n"
            "• Необмежені уроки і граматика"
        )
    else:
        plan_perks = (
            "⚡️ *Що відкрито:*\n"
            "• AI-оцінка вимови\n"
            "• Персональний плеєр\n"
            "• Уроки і граматика\n"
            "• SRS нагадування фраз"
        )

    try:
        if is_renewal:
            import random as _rnd
            phrase = _rnd.choice(RENEWAL_PHRASES)
            progress_line = ""
            if lessons > 0 or streak > 0:
                progress_line = (
                    f"\n📊 *Мій прогрес:*\n"
                    f"🎙 Уроків: *{lessons}* | 📚 Фраз: *{phrases}* | 🔥 Дні поспіль: *{streak}*\n"
                )
            await bot.send_message(
                chat_id=user_id,
                text=(
                    f"🎉 {name_line}{phrase}\n\n"
                    f"Твій план *{plan_name}* продовжено до *{until}* ✅"
                    f"{progress_line}\n\n"
                    "Продовжуй практику 👇"
                ),
                parse_mode="Markdown",
                reply_markup=main_menu()
            )
        else:
            await bot.send_message(
                chat_id=user_id,
                text=(
                    f"🎉 {name_line}ласкаво просимо до SpeakChain!\n\n"
                    f"Твій план *{plan_name}* активовано до *{until}* ✅\n\n"
                    f"{plan_perks}\n\n"
                    "Натисни кнопку нижче і починай 👇"
                ),
                parse_mode="Markdown",
                reply_markup=main_menu()
            )
    except Exception as e:
        logger.warning(f"activate_plan notify error: {e}")

async def cmd_setpremium(update, ctx):
    if not is_admin(update.effective_user.id):
        return
    args = ctx.args or []
    if len(args) < 2:
        await update.message.reply_text(
            "Використання:\n"
            "/setpremium USER_ID DAYS — Premium\n"
            "/setpremium USER_ID DAYS basic — Basic"
        )
        return
    try:
        target_uid = int(args[0])
        days       = int(args[1])
        plan       = args[2].lower() if len(args) > 2 else "premium"
        if plan not in ("basic", "premium"):
            plan = "premium"
    except ValueError:
        await update.message.reply_text("❌ USER_ID і DAYS мають бути числами.")
        return

    await activate_plan(ctx.bot, target_uid, plan, days)
    s    = get_s(target_uid)
    name = s.get("name", str(target_uid))
    await update.message.reply_text(
        f"✅ {plan.capitalize()} активовано для {name} ({target_uid}) на {days} днів."
    )


