async def cmd_export_audio(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """Витягує збережені placement-аудіо з Telegram і надсилає адміну
    як завантажувані файли (для розміщення на GitHub Pages під мініап Дня 4).

    file_id самі по собі працюють лише через send_voice у чаті; браузерний
    <audio> їх не прочитає. Тому качаємо байти через get_file і віддаємо
    як документ із коректним іменем (audio_a1.mp3 …), готовий класти на Pages.
    """
    if not is_admin(update.effective_user.id):
        return

    # Джерела file_id (порядок пріоритету): робочий словник → конфіг на диску
    sources = dict(PLACEMENT_AUDIO)
    for _cfg_name in ("placement_audio_config.json", "audio_ids.json"):
        _cfg = Path(_cfg_name)
        if _cfg.exists():
            try:
                _data = json.loads(_cfg.read_text())
                for _k, _v in _data.items():
                    if _v and not sources.get(_k):
                        sources[_k] = _v
            except Exception:
                pass

    ordered = [(k, sources.get(k, "")) for k in ("A1", "A2", "B1", "B2", "C1")]
    present = [(k, v) for k, v in ordered if v]
    missing = [k for k, v in ordered if not v]

    if not present:
        await update.message.reply_text(
            "❌ Немає збережених аудіо (ні в PLACEMENT_AUDIO, ні в "
            "placement_audio_config.json / audio_ids.json).\n\n"
            "Схоже, file_id не зберігались. Треба записати 5 аудіо заново: "
            "надішли /resetaudio, потім 5 голосових по порядку."
        )
        return

    await update.message.reply_text(
        f"📤 Витягую {len(present)} аудіо з Telegram — надішлю файлами нижче. "
        "Збережи їх і поклади на GitHub Pages поряд із мініапом Дня 4."
    )

    sent = 0
    for lvl, file_id in present:
        try:
            tg_file = await ctx.bot.get_file(file_id)
            audio_bytes = bytes(await tg_file.download_as_bytearray())
            # Ім'я з рівнем у нижньому регістрі — під шляхи в мініапі
            fname = f"audio_{lvl.lower()}.mp3"
            await update.message.reply_document(
                document=audio_bytes,
                filename=fname,
                caption=f"🎧 {lvl} · {fname}",
            )
            sent += 1
        except Exception as e:
            await update.message.reply_text(
                f"⚠️ {lvl}: не вдалося витягнути ({e}). "
                "file_id міг застаріти — можливо, доведеться перезаписати цей рівень."
            )

    tail = f"\n\nВідсутні рівні: {', '.join(missing)}" if missing else ""
    await update.message.reply_text(
        f"✅ Готово: {sent}/{len(present)} аудіо надіслано.{tail}\n\n"
        "Далі: поклади файли на Pages, а я підключу їх у мініап лістенінгу."
    )

