COMMUNITY_CHANNEL = "@speakchain_community"


# ── Б-1: AI-фільтр входу в спільноту (Конституція 8.2, ТЕХБОРГ Б-1) ──
# Було: grep ai_gate|entry_filter|moderation_gate = 0 у проді. Спільнота —
# 1000-10000 людей, 0 людської модерації (Розділ 8.1) — без воротаря це
# відкритий мікрофон без жодного фільтра.
#
# MVP-межа (свідома, не забудькуватість): гейтимо лише ТЕКСТ — транскрипт
# того, що студент наговорив (він і так уже є з AI-оцінки монологу). Аналіз
# самого відео/аудіо ряду (обличчя, фон, звук) — окремий, важчий борг (Д-5),
# не блокер для старту вітрини.
#
# Безпека помилок в один бік (Конституція 8.2): будь-яка непевність,
# незрозуміла відповідь моделі чи збій API → HOLD, ніколи не PASS.
async def ai_entry_filter(text: str) -> str:
    """
    Воротар pass/hold/reject ПЕРЕД публікацією в Community.
    Порожній транскрипт (немає що аналізувати текстом) → pass — MVP не
    блокує візуальний контент лише через відсутність тексту; це усвідомлена
    межа MVP, не діра в перевірці.
    """
    text = (text or "").strip()
    if not text:
        return "pass"
    if len(text) > 4000:
        text = text[:4000]
    try:
        prompt = (
            "You are a content-moderation gate for a public English-learning "
            "community channel with 1000-10000 members and ZERO human moderators. "
            "Below is a transcript of what a student said out loud in a speaking-"
            "practice recording, about to be published publicly under their name.\n\n"
            f'Transcript: "{text}"\n\n'
            "Classify as exactly one word:\n"
            "PASS — normal, safe, on-topic speech practice (imperfect grammar is fine, "
            "this is a language-learning app)\n"
            "HOLD — unclear, ambiguous, or borderline; needs a human look before publishing\n"
            "REJECT — toxic, hateful, sexual, violent, spam, or otherwise clearly "
            "inappropriate for a public channel\n\n"
            "When uncertain, prefer HOLD over PASS. Reply with EXACTLY one word: "
            "PASS, HOLD, or REJECT — no punctuation, no explanation."
        )
        cr = await claude_create_async(
            model="claude-haiku-4-5-20251001", max_tokens=5,
            messages=[{"role": "user", "content": prompt}]
        )
        verdict = cr.content[0].text.strip().upper()
        if verdict not in {"PASS", "HOLD", "REJECT"}:
            logger.warning(f"ai_entry_filter: неочікувана відповідь {verdict!r} → hold")
            return "hold"
        return verdict.lower()
    except Exception as e:
        logger.warning(f"ai_entry_filter error: {e} → hold (безпека в один бік)")
        return "hold"


# М'яке повідомлення при hold/reject — БЕЗ пояснень (Конституція 8.2 DoD).
# Нікого не звинувачуємо, нікого не ображаємо — «спробуй ще», і все.
_GATE_SOFT_MSG = (
    "🙏 Дякуємо! Цей запис поки не публікуємо в спільноту — спробуй записати "
    "ще один, будь ласка."
)


async def _publish_gated(bot, uid: int, s: dict, kind: str) -> tuple:
    """
    Спільна логіка публікації в Community з воротарем (Б-1) — використовується
    і безкоштовною кнопкою «В Community», і платним мікропродуктом (Б-2).
    kind: "voice" | "video"
    Повертає (verdict: str, published: bool).
    """
    if kind == "voice":
        file_id    = s.get("last_voice_file_id", "")
        transcript = s.get("last_voice_transcript", "") or ""
    else:
        file_id    = s.get("last_video_file_id", "")
        transcript = s.get("pending_video_transcript", "") or ""

    if not file_id:
        return "no_content", False

    verdict = await ai_entry_filter(transcript)
    if verdict != "pass":
        logger.info(f"ai_entry_filter: {kind} {uid} → {verdict}")
        return verdict, False

    name  = s.get("name") or ""
    level = LEVEL_NAMES.get(s.get("level", ""), s.get("level", ""))
    topic = s.get("cycle_topic") or s.get("quiz_lesson_title") or ""

    try:
        if kind == "voice":
            caption = (
                f"🎙 *{name}* — {level}\n"
                + (f"Тема: _{topic}_\n" if topic else "")
                + "\n@SpeakChainBot #SpeakChain #LearnEnglish"
            )
            msg = await bot.send_voice(chat_id=COMMUNITY_CHANNEL, voice=file_id,
                                        caption=caption, parse_mode="Markdown")
        else:
            caption = (
                f"📹 *{name}* — {level}\n"
                + (f"Тема: _{topic}_\n" if topic else "")
                + "Навчається в @SpeakChainBot 🚀"
            )
            try:
                msg = await bot.send_video(chat_id=COMMUNITY_CHANNEL, video=file_id,
                                            caption=caption, parse_mode="Markdown")
            except Exception:
                msg = await bot.send_video_note(chat_id=COMMUNITY_CHANNEL, video_note=file_id)

        db = load_db()
        cm = db.get("_community_posts", {})
        cm[str(msg.message_id)] = {"uid": uid, "name": name}
        db["_community_posts"] = cm
        save_db(db)
        asyncio.create_task(award_xp(bot, uid, "shared_community"))
        if s.get("is_own_video"):
            asyncio.create_task(award_xp(bot, uid, "own_video_published"))
        return "pass", True
    except Exception as e:
        logger.warning(f"_publish_gated {kind} {uid}: {e}")
        return "error", False


async def _deliver_community_post(bot, uid: int) -> bool:
    """
    deliver() для платного мікропродукту MICRO_PRODUCTS['community'] (Б-2).
    Публікує найсвіжіший запис студента (відео пріоритетніше за голос) через
    той самий воротар Б-1. Якщо hold/reject/немає контенту — повертає False:
    виклик у _deliver_micro_product() автоматично поставить у чергу
    _micro_delivery_queue і чесно скаже «готуємо», а не мовчки провалить
    оплачену покупку.
    """
    s = get_s(uid)
    if s.get("last_video_file_id"):
        verdict, ok = await _publish_gated(bot, uid, s, "video")
    elif s.get("last_voice_file_id"):
        verdict, ok = await _publish_gated(bot, uid, s, "voice")
    else:
        return False
    return ok


# Б-2: підключаємо видачу для платного мікропродукту "community" (був
# deliver: None — TODO). Функція оголошена тут (нижче по файлу за
# MICRO_PRODUCTS), тож підключаємо словниковим патчем, а не форвард-
# референсом у самому літералі MICRO_PRODUCTS.
MICRO_PRODUCTS["community"]["deliver"] = _deliver_community_post


