async def cmd_set_challenge(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """Адмін: встановити новий challenge.

    22.07: тема і приз тепер розділені символом "|", щоб можна було задати
    приз щоразу, а не покладатись на статичний дефолт у коді. Формат
    зі старих чатів (тільки тема) і далі працює — приз тоді бере дефолт
    ("+100 XP та бейдж «Marathon Winner»"), НЕ "1 місяць Basic" — платні
    пакети як приз за марафон суперечать правилу продукту "не даруємо
    пакети ні за що".
    """
    if not is_admin(update.effective_user.id):
        await update.message.reply_text("⛔️ Доступ заборонено.")
        return
    args = ctx.args
    if not args:
        await update.message.reply_text(
            "Використання: `/set_challenge Тема челенджу`\n"
            "Або з призом: `/set_challenge Тема челенджу | Приз`\n\n"
            "⚠️ Приз має бути негрошовим — не платні пакети "
            "(правило продукту: не даруємо пакети ні за що).",
            parse_mode="Markdown"
        )
        return
    raw = " ".join(args)
    if "|" in raw:
        topic, prize = raw.split("|", 1)
        topic, prize = topic.strip(), prize.strip()
    else:
        topic, prize = raw.strip(), None
    set_current_challenge(topic, active=True, prize=prize)   # v12: у БД, переживає рестарт

    # Читаємо назад те, що реально збереглось (дефолт застосувався, якщо prize=None)
    _saved_prize = get_current_challenge().get("prize", "+100 XP та бейдж «Marathon Winner» у профілі")

    # Розсилаємо всім студентам
    db = load_db()
    count = 0
    for uid, s in db.items():
        if not isinstance(s, dict): continue
        if not _is_student_for_notify(uid, s): continue
        if str(uid) == "quiz_cache": continue
        if not s.get("onboarding_done"): continue
        try:
            await ctx.bot.send_message(
                chat_id=int(uid),
                text=(
                    f"🏆 *Новий Марафон монологів!*\n\n"
                    f"*Тема:* {topic}\n\n"
                    f"*Приз:* {_saved_prize} 🎁\n\n"
                    "Запиши 30-секундний монолог і опублікуй у Community!\n\n"
                    "/challenge — деталі"
                ),
                parse_mode="Markdown"
            )
            count += 1
        except Exception:
            pass

    await update.message.reply_text(f"✅ Challenge запущено! Приз: {_saved_prize}\nНадіслано {count} студентам.")


async def cmd_award_marathon(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """
    Адмін: /award_marathon <uid> — нагороджує переможця Марафону монологів.
             /award_marathon top — показує топ-5 за розміром гілки рефералів.

    22.07: раніше приз ("1 місяць Basic") лише ОГОЛОШУВАВСЯ текстом —
    коду, що реально видає щось переможцю, не існувало. Тепер приз
    негрошовий (правило: не даруємо пакети ні за що) і видається
    насправді: +100 XP (той самий award_xp, що й решта нагород системи —
    з урахуванням потрійного XP дня і boost'ів, як і всі інші) + бейдж
    marathon_winner у профілі + особисте сповіщення переможцю.

    Критерій переможця (рішення власниці): «той, чия ланка найбільша —
    від кого найбільша гілка». Це РОЗМІР УСЬОГО ПІДДЕРЕВА рефералів
    (build_referral_tree_sizes) — не лише прямих запрошених, а рекурсивно
    всі покоління. /award_marathon top показує топ-5 за цим критерієм,
    щоб не рахувати вручну; фінальне рішення все одно за адміном —
    команда не нагороджує автоматично, тільки підказує.
    """
    if not is_admin(update.effective_user.id):
        await update.message.reply_text("⛔️ Доступ заборонено.")
        return
    if not ctx.args:
        await update.message.reply_text(
            "Використання:\n"
            "`/award_marathon top` — топ-5 за розміром гілки рефералів\n"
            "`/award_marathon <uid>` — нагородити конкретного переможця\n\n"
            "Видає +100 XP і бейдж «Marathon Winner» у профілі, "
            "і надсилає особисте привітання.",
            parse_mode="Markdown"
        )
        return

    if ctx.args[0].lower() == "top":
        db = load_db()
        sizes = build_referral_tree_sizes(db)
        ranked = sorted(sizes.items(), key=lambda kv: kv[1], reverse=True)
        ranked = [(u, n) for u, n in ranked if n > 0][:5]
        if not ranked:
            await update.message.reply_text("Поки що ні в кого немає гілки рефералів (0 запрошених).")
            return
        lines = ["🌳 *Топ-5 за розміром гілки (усі покоління):*\n"]
        for i, (u, n) in enumerate(ranked, 1):
            _s = db.get(u, {})
            _name = _s.get("name", u) if isinstance(_s, dict) else u
            lines.append(f"{i}. {_name} (uid `{u}`) — {n} {_plural_uk(n, 'людина', 'людини', 'людей')} у гілці")
        lines.append(f"\nНагородити: `/award_marathon <uid>`")
        await update.message.reply_text("\n".join(lines), parse_mode="Markdown")
        return

    try:
        winner_uid = int(ctx.args[0])
    except ValueError:
        await update.message.reply_text("❌ Невірний uid (або напиши `/award_marathon top` для підказки)")
        return

    s = get_s(winner_uid)
    if not s:
        await update.message.reply_text(f"❌ Студента з uid {winner_uid} не знайдено")
        return

    already = "marathon_winner" in s.get("badges", [])

    xp_result = await award_xp(ctx.bot, winner_uid, "marathon_winner")
    if not already:
        upd_s(winner_uid, {"badges": s.get("badges", []) + ["marathon_winner"]})

    topic = get_current_challenge().get("topic", "")
    try:
        await ctx.bot.send_message(
            chat_id=winner_uid,
            text=(
                f"🏆 *Вітаємо, ти переміг(ла) у Марафоні монологів!*\n\n"
                + (f"Тема: {topic}\n\n" if topic else "")
                + "🎁 +100 XP нараховано\n"
                "🏅 Бейдж «Marathon Winner» додано до профілю\n\n"
                "Твій монолог справді вирізнявся — так тримати! 🚀"
            ),
            parse_mode="Markdown"
        )
        notified = True
    except Exception as e:
        logger.warning(f"award_marathon notify error uid={winner_uid}: {e}")
        notified = False

    name = s.get("name", str(winner_uid))
    dup_note = " (бейдж уже був — не додано вдруге, XP нараховано)" if already else ""
    notify_note = "" if notified else "\n⚠️ Не вдалося надіслати особисте повідомлення (можливо, заблокував бота)"
    await update.message.reply_text(
        f"✅ Нагороджено {name} (uid {winner_uid}): +100 XP, бейдж «Marathon Winner»{dup_note}{notify_note}"
    )


def _plural_uk(n: int, one: str, few: str, many: str) -> str:
    """Українська множина: 1 людина · 2-4 людини · 5+ людей."""
    a, b = abs(n) % 100, abs(n) % 10
    if a > 10 and a < 20: return many
    if b > 1 and b < 5:   return few
    if b == 1:            return one
    return many



def build_social_captions(name: str, s: dict, score_text: str = "") -> dict:
    import urllib.parse as _up
    BOT_LINK  = "https://t.me/SpeakChainBot"
    level     = LEVEL_NAMES.get(s.get("level",""), s.get("level","")) or "A1"
    done      = len(s.get("done_lessons", []))
    streak    = s.get("streak_days", 0) or 0
    score_l   = f" 🏆 {score_text}" if score_text else ""
    days_l    = ""
    reg_str   = s.get("registered_at","")
    if reg_str:
        try:
            d = (datetime.now() - datetime.strptime(reg_str, "%Y-%m-%d")).days
            if d > 3: days_l = f" · 📅 {d} днів"
        except Exception:
            pass
    lv = s.get("last_levelup_share", "")
    base = f"{'🎉 ' + lv if lv else '🎯 Вчу англійську по відео блогерів у SpeakChain!'}"
    ig = (f"{base}\n\n✅ Рівень: {level} · {done} уроків · 🔥{streak} днів{score_l}{days_l}\n\n"
          f"🤖 ШІ-репетитор + Speaking Partners + roadmap A1→C2\n\n"
          f"👉 {BOT_LINK}\n\n#SpeakChain #LearnEnglish #AIcoach #EnglishChallenge")
    fb = (f"{base}\n\n✅ Рівень: {level} · Уроків: {done} · 🔥 Дні поспіль: {streak}{score_l}{days_l}\n\n"
          f"🤖 ШІ знаходить прогалини → відео → живий фідбек\n\nСпробуй безкоштовно 👉 {BOT_LINK}")
    tw = (f"{'🎉 ' + lv if lv else '🎯 Learning English with SpeakChain!'} "
          f"Level: {level} · {done} lessons · 🔥{streak} days{score_l}\n"
          f"AI coach + speaking partners 🚀 {BOT_LINK} #SpeakChain #LearnEnglish")
    li = (f"{'🎉 ' + lv if lv else '🚀 Learning English with SpeakChain'}\n\n"
          f"✅ Level: {level} · {done} lessons · 🔥{streak}-day streak{score_l}{days_l}\n\n"
          f"AI finds my gaps → personalised videos → live speaking practice.\n\n"
          f"Try free: {BOT_LINK}\n\n#ProfessionalDevelopment #EnglishSkills #AIcoach")
    return {
        "ig_tiktok":   ig, "facebook": fb, "twitter": tw, "linkedin": li,
        "twitter_url":  "https://twitter.com/intent/tweet?text=" + _up.quote(tw),
        "linkedin_url": "https://www.linkedin.com/sharing/share-offsite/?url=" + _up.quote(BOT_LINK),
        "facebook_url": "https://www.facebook.com/sharer/sharer.php?u=" + _up.quote(BOT_LINK),
    }

async def cb_share_socials(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    q    = update.callback_query
    user = q.from_user
    s    = get_s(user.id)
    await q.answer()
    c    = build_social_captions(user.first_name, s, s.get("last_quiz_score_text",""))
    today = datetime.now().strftime("%Y-%m-%d")
    already_triple = s.get("triple_xp_date") == today

    triple_row = (
        [InlineKeyboardButton("✅ Вже опублікував — отримати XP", callback_data="social_published")]
        if not already_triple else
        [InlineKeyboardButton("🔥 Сьогодні вже потрійний XP день!", callback_data="social_already")]
    )

    text = (
        "📱 *Поділись своїм прогресом!*\n\n"
        "━━━━━━━━━━━━━━━━\n"
        "📸 *Instagram / TikTok* — скопіюй:\n"
        f"`{c['ig_tiktok']}`\n\n"
        "━━━━━━━━━━━━━━━━\n"
        "👤 *Facebook* — скопіюй:\n"
        f"`{c['facebook']}`\n\n"
        "━━━━━━━━━━━━━━━━\n"
        "🔥 *Опублікував відео з #SpeakChain?*\n"
        "_Вставте посилання і отримай потрійний XP на весь день!_"
    )
    await q.edit_message_text(
        text, parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup([
            [InlineKeyboardButton("📸 Instagram", url="https://www.instagram.com/"),
             InlineKeyboardButton("🎵 TikTok",    url="https://www.tiktok.com/upload")],
            [InlineKeyboardButton("👤 Facebook",  url=c["facebook_url"])],
            triple_row,
        ])
    )


async def cb_social_published(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """Студент повідомляє що опублікував відео — просимо посилання."""
    q    = update.callback_query
    user = q.from_user
    await q.answer()
    upd_s(user.id, {"waiting_social_link": True})
    await q.edit_message_text(
        "🔗 *Вставте посилання на свою публікацію*\n\n"
        "Переконайся що в пості є хештег *#SpeakChain* 👇",
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup([[
            InlineKeyboardButton("❌ Скасувати", callback_data="social_link_cancel")
        ]])
    )


async def cb_social_already(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    await q.answer("Потрійний XP вже активний сьогодні! 🔥", show_alert=True)


async def cb_social_link_cancel(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """Скасування вставки посилання.

    Кнопка «↩️ Все ж поділитися» — страховка від випадкового тапу.
    Веде на наявний share_socials, нового обробника не треба.
    Модалки «Ви впевнені?» тут навмисно немає: після відмови вона читається
    як тиск. Undo дає той самий результат, але бот не сперечається.
    """
    q = update.callback_query
    await q.answer()
    upd_s(q.from_user.id, {"waiting_social_link": False})
    await q.edit_message_text(
        "Окей, залишається між нами 🤝",
        reply_markup=InlineKeyboardMarkup([[
            InlineKeyboardButton("↩️ Все ж поділитися", callback_data="share_socials")
        ]])
    )




