async def cmd_today(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """/today — Персональний щоденний план."""
    user  = update.effective_user
    s     = get_s(user.id)
    today = datetime.now().strftime("%Y-%m-%d")
    if not s.get("onboarding_done"):
        await update.message.reply_text("👋 Спочатку познайомимось! Натисни /start — це займе 1 хвилину 🚀")
        return
    level       = s.get("level", "A1")
    level_name  = LEVEL_NAMES.get(level, level)
    streak      = s.get("streak_days", 0)
    done_today  = s.get("last_date", "") == today
    due_words   = _srs_due_words(s)
    shadow_cnt  = s.get("shadow_sessions", 0)
    mined_cnt   = len(s.get("mined_sentences", []))
    lessons_cnt = len(s.get("done_lessons", []))

    # ── A-12: постійна точка входу в челендж «Заговори» — раніше кнопка
    # старту показувалась ЛИШЕ ОДИН РАЗ одразу після онбордингу
    # (callback start_challenge_{flow_type}), а /today (найлогічніше
    # місце — саме «сьогодні») не згадувала про челендж узагалі. Якщо
    # людина не тисла тоді — повернутись до нього було нізвідки: /challenge
    # веде на community-челендж (інша функція), текстова кнопка «Челендж
    # дня» — на старий Марафон монологів (weekly_challenge), теж не туди.
    # Тут — той самий, вже перевірений callback, просто видимий щодня.
    cstate_today   = s.get("challenge_state") or {}
    try:
        from challenge_content import CHALLENGE_LENGTH as _CH_LEN
    except Exception:
        _CH_LEN = 7
    # Ті самі три умови, що в nudge-картці й у job_challenge_video_delivery:
    # status + відомий source + день у межах. Інакше на битому стані
    # («День 0», «День 12», чужий source) кнопка вела б у порожній екран.
    challenge_day  = cstate_today.get("day", 0)
    challenge_on   = (
        cstate_today.get("status") == "active"
        and cstate_today.get("source") in ("blogger", "organic")
        and 1 <= challenge_day <= _CH_LEN
    )
    challenge_new  = not cstate_today and CHALLENGE_FLOW_LOADED

    lines = [f"📅 *Твій план на сьогодні*\n"]
    lines.append(f"📊 {level_name}  🔥 {streak} дн.  📚 {lessons_cnt} уроків\n")

    if challenge_new:
        lines.append(
            "🎯 *Челендж «Заговори» — 7 днів*\n"
            "  Ще не починали. Щодня — крок до вільної мови.\n"
        )
    elif challenge_on:
        lines.append(f"🎯 *Челендж «Заговори» — День {challenge_day}/{_CH_LEN}*\n")

    # ── Фраза дня від блогера студента (лише за сьогодні) ──
    try:
        _bname = (s.get("affiliate_blogger", "") or "").strip()
        if _bname:
            _db = load_db()
            for _u, _us in _db.items():
                if not isinstance(_us, dict):
                    continue
                if not _us.get("phrase_of_day"):
                    continue
                if _us.get("phrase_of_day_date") != today:
                    continue
                if not str(_u).isdigit():
                    continue
                if get_blogger_name(int(_u)).lower() == _bname.lower():
                    lines.append(f"💬 *Фраза дня від {_bname}:*\n  _{_us['phrase_of_day']}_\n")
                    break
    except Exception:
        pass

    done_items = []
    if done_today:
        done_items.append("✅ Урок + монолог")
    if not due_words:
        done_items.append("✅ SRS — всі слова повторені")
    if done_items:
        lines.append("*Зроблено:*")
        for item in done_items:
            lines.append(f"  {item}")
        lines.append("")

    todo_items = []
    if not done_today:
        todo_items.append(("🎬", "Відео → Sentence Mining → Shadowing → Монолог  (~12 хв)"))
    if due_words:
        todo_items.append(("🧠", f"SRS: {len(due_words)} слів до повторення  (~2 хв)"))
    todo_items.append(("🎧", "Пасивне занурення: 20–30 хв контенту фоном"))
    todo_items.append(("🌙", "Перед сном: 10–20 хв аудіо англійською"))
    if todo_items:
        lines.append("*Залишилось:*")
        for emoji_s, t in todo_items:
            lines.append(f"  {emoji_s} {t}")
        lines.append("")

    resources = IMMERSION_RESOURCES.get(level, IMMERSION_RESOURCES["B1"])
    lines.append("*🎧 Пасивне занурення — твій рівень:*")
    for r in resources:
        lines.append(f"  {r}")
    lines.append("")

    sleep_res = SLEEP_AUDIO_RESOURCES.get(level, "")
    if sleep_res:
        lines.append(f"*🌙 Аудіо перед сном:*\n  _{sleep_res}_\n")

    lines.append(random.choice(DAILY_TIPS))
    if shadow_cnt > 0 or mined_cnt > 0:
        lines.append(f"\n_Shadowing: {shadow_cnt} сесій  •  Збережених фраз: {mined_cnt}_")

    kb_rows = []
    if challenge_new:
        _cflow_type = "blogger" if s.get("affiliate_blogger") else "organic"
        kb_rows.append([InlineKeyboardButton(
            "🚀 Почати челендж «Заговори»", callback_data=f"start_challenge_{_cflow_type}"
        )])
    elif challenge_on:
        kb_rows.append([InlineKeyboardButton(
            f"👉 Відкрити День {challenge_day}", web_app=WebAppInfo(url=shell_url("ov-challenge"))
        )])
    if not done_today:
        kb_rows.append([InlineKeyboardButton("🎬 Почати урок", callback_data="fork_choose")])
    if due_words:
        kb_rows.append([InlineKeyboardButton(
            f"🧠 SRS ({len(due_words)} слів)", callback_data="srs_start"
        )])
    kb_rows.append([InlineKeyboardButton("📊 Прогрес", callback_data="progress_continue")])

    await update.message.reply_text(
        "\n".join(lines),
        parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup(kb_rows) if kb_rows else main_menu()
    )

