async def cb_today_plan(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """Callback-версія /today для inline-кнопок."""
    q    = update.callback_query
    user = q.from_user
    await q.answer()
    class _FakeMsg:
        async def reply_text(self_inner, *a, **kw):
            await q.message.reply_text(*a, **kw)
    class _FakeUpd:
        effective_user = user
        message = _FakeMsg()
    await cmd_today(_FakeUpd(), ctx)

# ══════════════════════════════════════════════════════════════════
# МОСТИ callback → команда.
#
# Патерн узято з cb_today_plan (вище) — він уже прийнятий у проєкті.
# Причина існування: команди пишуть через update.message.reply_text,
# а в callback-апдейті update.message = None. Прямий виклик впаде.
#
# ⚠️ ЦІ КНОПКИ БУЛИ МЕРТВІ: callback_data є, обробника немає.
# Людина тиснула — бот МОВЧАВ. Ні помилки, ні відповіді. Тиша.
# ══════════════════════════════════════════════════════════════════

def _bridge(q, user):
    """Фейковий update, щоб команда могла відповісти в чат."""
    class _FakeMsg:
        async def reply_text(self_inner, *a, **kw):
            await q.message.reply_text(*a, **kw)
    class _FakeUpd:
        effective_user = user
        message = _FakeMsg()
    return _FakeUpd()


