async def cb_share_voice_confirm(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """Публікує голосовий монолог в Community канал — через воротар Б-1."""
    q    = update.callback_query
    user = q.from_user
    s    = get_s(user.id)
