    app.bot_data["send_phrase_challenge"] = send_phrase_challenge

    def _normalize_demo_phrase(item, blogger_ref=""):
        """рядок (старий week_phrases) або dict → уніфікований dict із id."""
        import hashlib as _hl
        if isinstance(item, str):
            _t = item.strip()
            if not _t:
                return None
            return {"id": _hl.md5(_t.encode()).hexdigest()[:6], "text": _t,
                    "subtitle_uk": "", "video_url": "",
                    "blogger_ref": blogger_ref, "level_hint": ""}
        if isinstance(item, dict) and (item.get("text") or "").strip():
            _d = dict(item)
            _d.setdefault("id", _hl.md5(_d["text"].encode()).hexdigest()[:6])
            _d.setdefault("blogger_ref", blogger_ref)
            _d.setdefault("video_url", "")
            _d.setdefault("subtitle_uk", "")
            _d.setdefault("level_hint", "")
            return _d
        return None

    def _demo_phrase_resolver(phrase_id, uid):
        """Плаский пул усіх фраз усіх блогерів із week_phrases.
        phrase_id → конкретна (те саме відео); порожній → випадкова.
        Порожній пул → None (demo_flow впаде на SEED_PHRASES)."""
        _db = load_db()
        _bloggers = get_registered_bloggers()   # {str(uid): name}
        pool = []
        for _buid, _bname in _bloggers.items():
            _bstate = _db.get(str(_buid)) or {}
            _wp = _bstate.get("week_phrases") or {}
            for _day, _item in _wp.items():
                _rec = _normalize_demo_phrase(_item, _bname)
                if _rec:
                    pool.append(_rec)
        if not pool:
            return None
        if phrase_id:
            for _r in pool:
                if _r["id"] == phrase_id:
                    return _r
        import random as _r2
        return _r2.choice(pool)

    set_demo_phrase_resolver(_demo_phrase_resolver)

