    # ═══════════════════════════════════════════════════
    # GLOBAL ERROR HANDLER — ловить всі помилки у хендлерах
    # ═══════════════════════════════════════════════════
    async def error_handler(update: object, ctx: ContextTypes.DEFAULT_TYPE):
        import traceback
        from telegram.error import RetryAfter, TimedOut, NetworkError, BadRequest
        err = ctx.error

        # ── RetryAfter (429) — Telegram rate limit ──────────────
        # Не логуємо як помилку, просто чекаємо і повторюємо
        if isinstance(err, RetryAfter):
            wait = err.retry_after + 1
            logger.warning(f"Telegram RetryAfter: waiting {wait}s")
            await asyncio.sleep(wait)
            return  # PTB автоматично повторить update

        # ── BadRequest — ЦЕ НЕ МЕРЕЖА, ЦЕ НАША ПОМИЛКА ────────────
        # 🔴 ПАСТКА, ЯКА КОШТУВАЛА ГОДИНИ ДІАГНОСТИКИ:
        # У python-telegram-bot BadRequest УСПАДКОВАНИЙ від NetworkError.
        # Тому перевірка нижче ловила його разом із таймаутами і писала
        # "Telegram network issue" — хоча мережа ні до чого.
        #
        # Реальний випадок: "Reply markup is too long" (клавіатура >10 КБ
        # через довгий URL мініапа). Симптом — «профіль не відкривається».
        # У логах — «мережева проблема». Зв'язок знайти неможливо.
        #
        # BadRequest ЗАВЖДИ означає, що МИ надіслали щось некоректне.
        # Повтор не допоможе — треба лагодити код. Тому логуємо ЧЕСНО
        # і НЕ ковтаємо: помилка йде далі, до звичайного обробника.
        if isinstance(err, BadRequest):
            logger.error(
                "❌ BadRequest (НЕ мережа — НАША помилка): %s\n"
                "   Найчастіші причини:\n"
                "   • Reply markup is too long → клавіатура >10 240 байт "
                "(зазвичай задовгий URL мініапа: список без зрізу)\n"
                "   • Message is too long → текст >4096 символів\n"
                "   • Can't parse entities → зламаний Markdown",
                err,
            )
            # НЕ повертаємось — хай іде у звичайний обробник нижче,
            # щоб адмін отримав сповіщення і трейсбек.

        # ── TimedOut / NetworkError — справді тимчасові мережеві збої ──
        elif isinstance(err, (TimedOut, NetworkError)):
            logger.warning(f"Telegram network issue: {err}")
            await asyncio.sleep(2)
            return  # не відправляємо адміну — це норма

        tb_str  = "".join(traceback.format_exception(type(err), err, err.__traceback__))

        # 1. Завжди пишемо в Railway Logs
        logger.error(f"\n{'='*60}\n❌ UNHANDLED ERROR\n{tb_str}{'='*60}")

        # 2. Повідомляємо адміна в Telegram
        if ADMIN_ID:
            # Скорочуємо якщо дуже довго
            short_tb = tb_str[-1500:] if len(tb_str) > 1500 else tb_str
            update_info = ""
            if update and hasattr(update, "effective_user") and update.effective_user:
                u = update.effective_user
                update_info = f"👤 {u.first_name} (id={u.id})\n"
            if update and hasattr(update, "callback_query") and update.callback_query:
                update_info += f"🔘 callback: {update.callback_query.data!r}\n"
            elif update and hasattr(update, "message") and update.message and update.message.text:
                update_info += f"💬 text: {update.message.text[:80]!r}\n"

            try:
                await ctx.bot.send_message(
                    chat_id=ADMIN_ID,
                    text=(
                        f"🚨 *Помилка в боті*\n\n"
                        f"{update_info}\n"
                        f"`{short_tb}`"
                    ),
                    parse_mode="Markdown"
                )
            except Exception:
                pass  # якщо не вдалось надіслати адміну — не критично

        # 3. Надсилаємо юзеру ввічливе повідомлення
        if update:
            try:
                if hasattr(update, "callback_query") and update.callback_query:
                    await update.callback_query.answer(
                        "⚠️ Щось пішло не так. Спробуй ще раз.", show_alert=False
                    )
                elif hasattr(update, "message") and update.message:
                    await update.message.reply_text(
                        "⚠️ Сталася помилка. Спробуй ще раз або напиши /start"
                    )
            except Exception:
                pass

    app.add_error_handler(error_handler)

