async def handle_topic_table(request):
    """
    POST /topic_table → {ua, signals, table, formula} для GRAMMAR_MAP[topic_key].

    Розділ M (24.07, об'єднання потоку): раніше «Таблиця вголос» йшла
    ТІЛЬКИ в чат окремим повідомленням (_send_grammar_explanation →
    bot.send_message) — розрив кроку, людина мала перемикатись між
    мініапом і Telegram-чатом. Тепер той самий контент (без заголовка
    з фразою — тут заголовок не потрібен, мініап сам малює назву теми)
    доступний як JSON, щоб мініап відрендерив таблицю ПРЯМО в модалці,
    одразу перед кроком «30 речень» — один суцільний потік, без виходу.

    Той самий topic_key-мапінг (CEFR_TO_KEY), що й /exercises_data;
    той самий GRAMMAR_MAP, що й _send_grammar_explanation у чаті —
    ОДНЕ джерело даних, не дублювання: чат-шлях (open_topic_step)
    лишається робочим для тих, хто відкриває крок зі старої картки
    нагадування, мініап-шлях — для суцільного потоку тут.
    """
    if request.method == "OPTIONS":
        return _web.json_response({}, headers=CORS_BUDDY)
    try:
        body = await request.json()
    except Exception:
        return _web.json_response({"error": "bad json"}, status=400, headers=CORS_BUDDY)

    topic = (body.get("topic") or "").strip()

    uid, _auth_err = require_verified_uid(body)
    if _auth_err:
        return _web.json_response({"error": "unauthorized", **_auth_err}, status=401, headers=CORS_BUDDY)

    if not topic:
        return _web.json_response({"error": "topic required"}, status=400, headers=CORS_BUDDY)

    topic_key = CEFR_TO_KEY.get(topic, "")
    if not topic_key or topic_key not in GRAMMAR_MAP:
        # Тема поза покриттям (1/77, "Infinitive + V (full system)",
        # свідомо без мапінгу — v62) — чесна порожня відповідь, фронт
        # сам вирішує як показати "недоступно окремо" (той самий текст,
        # що вже є в open_topic_step для чат-шляху).
        return _web.json_response({"found": False}, headers=CORS_BUDDY)

    t = GRAMMAR_MAP[topic_key]
    return _web.json_response({
        "found":     True,
        "topic_key": topic_key,
        "ua":        t.get("ua", ""),
        "signals":   t.get("signals", []),
        "table":     t.get("table", []),
        "formula":   t.get("formula", ""),
    }, headers=CORS_BUDDY)


async def handle_exercises_data(request):
    """POST /exercises_data → {sentences: [...30 речень...]}"""
    if request.method == "OPTIONS":
        return _web.json_response({"sentences": []}, headers=CORS_BUDDY)
    try:
        body = await request.json()
    except Exception:
        return _web.json_response({"sentences": []}, status=400, headers=CORS_BUDDY)

    topic     = body.get("topic", "")
    level     = body.get("level", "B1")

    uid, _auth_err = require_verified_uid(body)
    if _auth_err:
        return _web.json_response({"sentences": [], **_auth_err}, status=401, headers=CORS_BUDDY)

    if not topic:
        return _web.json_response({"sentences": []}, headers=CORS_BUDDY)

    # Розділ M (24.07, об'єднання потоку): якщо тема має запис у
    # GRAMMAR_MAP — передаємо formula/signals у промпт, щоб 30 речень
    # будувались НА ОСНОВІ тієї самої формули, що студент щойно читав
    # у таблиці, а не з нуля незалежно від неї (Мерфі: приклади ростуть
    # з правила, не існують окремо). Немає запису (1/77) — старий шлях,
    # Claude сама формулює структуру з назви теми.
    topic_key   = CEFR_TO_KEY.get(topic, "")
    formula_hint = ""
    if topic_key and topic_key in GRAMMAR_MAP:
        t = GRAMMAR_MAP[topic_key]
        formula = t.get("formula", "")
        signals = t.get("signals", [])
        if formula:
            formula_hint += f"\nGrammar formula (use this exact structure): {formula}"
        if signals:
            formula_hint += f"\nSignal words to include naturally where relevant: {', '.join(signals[:8])}"

    # Генеруємо 30 речень через Claude (позитивні + заперечні + питальні)
    try:
        prompt = f"""Generate exactly 30 English practice sentences for the grammar topic: {topic}
Level: {level}{formula_hint}

Rules:
- 10 positive/affirmative sentences
- 10 negative sentences
- 10 question sentences
- Each sentence should be natural and conversational
- Variety of subjects (I, you, he, she, we, they)
- Progressively slightly more complex

Return ONLY a JSON array of 30 strings, no markdown:
["sentence 1", "sentence 2", ...]"""

        cr = await claude_create_async(
            model="claude-haiku-4-5-20251001",
            max_tokens=1500,
            messages=[{"role": "user", "content": prompt}]
        )
        raw = cr.content[0].text.strip()
        # Знаходимо JSON масив
        start = raw.find('[')
        end   = raw.rfind(']') + 1
        if start >= 0 and end > start:
            import json as _j
            sentences = _j.loads(raw[start:end])
            sentences = [s for s in sentences if isinstance(s, str) and s.strip()][:30]
            if sentences:
                return _web.json_response({"sentences": sentences}, headers=CORS_BUDDY)
    except Exception as e:
        logger.warning(f"exercises_data Claude error: {e}")

    return _web.json_response({"sentences": []}, headers=CORS_BUDDY)


async def handle_phrase_spoken(request):
    """
    POST /phrase_spoken — кожна проговорена фраза = +1 XP + ланка (chain).
    Дає миттєву мотивацію по ходу вправ (Progress miniapp).
    """
    if request.method == "OPTIONS":
        return _web.Response(headers=CORS_BUDDY)
    try:
        body = await request.json()
    except Exception:
        return _web.json_response({"ok": False}, status=400, headers=CORS_BUDDY)

    # 21.07: require_verified_uid — init_data обовʼязковий (STRICT_INIT_DATA)
    uid, _auth_err = require_verified_uid(body)
    if _auth_err:
        return _web.json_response(_auth_err, status=401, headers=CORS_BUDDY)
    if not uid:
        return _web.json_response({"ok": False}, headers=CORS_BUDDY)

    try:
        s = get_s(uid)
    except Exception:
        return _web.json_response({"ok": False}, headers=CORS_BUDDY)

    per_phrase_xp = XP_AWARDS.get("phrase_spoken", 1)
    updates = {
        "xp_total":       s.get("xp_total", 0) + per_phrase_xp,
        "spoken_total":   s.get("spoken_total", 0) + 1,
        "spoken_today":   s.get("spoken_today", 0) + 1,
        "phrases_spoken": s.get("phrases_spoken", 0) + 1,   # лічильник «ланок»-фраз для мотивації/статистики
    }
    upd_s(uid, updates)

    # ── BAE-лічильник: ЯКУ фразу проговорили ───────────────────────
    #   Раніше рахували «скільки разів», але не «що саме».
    #   Старі поля (spoken_total / phrases_spoken) НЕ чіпаємо.
    try:
        _sent = (body.get("sentence") or "").strip()
        if _sent:
            _cs_bump(uid, "spoken", _sent)
    except Exception as _e:
        logger.warning(f"content_stats spoken: {_e}")
    # ───────────────────────────────────────────────────────────────

    return _web.json_response(
        {"ok": True, "xp_added": per_phrase_xp, "phrases_spoken": updates["phrases_spoken"]},
        headers=CORS_BUDDY,
    )


async def handle_session_activity(request):
    """
    POST /session_activity — фіксує завершену активність
    Використовується з Progress miniapp після exercises.
    """
    if request.method == "OPTIONS":
        return _web.Response(headers=CORS_BUDDY)
    try:
        body = await request.json()
    except Exception:
        return _web.json_response({"ok": False}, status=400, headers=CORS_BUDDY)

    # 21.07: require_verified_uid — init_data обовʼязковий (STRICT_INIT_DATA)
    uid, _auth_err = require_verified_uid(body)
    if _auth_err:
        return _web.json_response(_auth_err, status=401, headers=CORS_BUDDY)
    if not uid:
        return _web.json_response({"ok": False}, headers=CORS_BUDDY)

    activity     = body.get("activity", "")
    topic        = body.get("topic", "")
    spoken_count = int(body.get("spoken_count", 0))

    try:
        s = get_s(uid)
    except Exception:
        return _web.json_response({"ok": False}, headers=CORS_BUDDY)

    updates = {}

    # XP за виконані вправи
    xp_award = XP_AWARDS.get("tutor_me_lesson", 20)
    updates["xp_total"] = s.get("xp_total", 0) + xp_award

    # Рахуємо проговорені фрази
    updates["spoken_total"] = s.get("spoken_total", 0) + spoken_count
    updates["spoken_today"] = s.get("spoken_today", 0) + spoken_count

    # Граматичний прогрес — quiz_passed
    if activity == "exercises_done" and topic:
        from grammar_engine import mark_topic_event as _mte
        try:
            s_upd = _mte(s, topic, "quiz_passed")
            updates["grammar_topics"] = s_upd.get("grammar_topics", {})
        except Exception:
            pass

    upd_s(uid, updates)
    return _web.json_response({"ok": True, "xp_added": xp_award}, headers=CORS_BUDDY)


