async def handle_vocab_data(request):
    """POST /vocab_data → {phrases, due}"""
    if request.method == "OPTIONS":
        return _web.Response(headers=CORS_BUDDY)
    try:
        body = await request.json()
    except Exception:
        return _web.json_response({"error": "Invalid JSON"}, status=400, headers=CORS_BUDDY)

    # 21.07: require_verified_uid — init_data обовʼязковий (STRICT_INIT_DATA)
    uid, _auth_err = require_verified_uid(body)
    if _auth_err:
        return _web.json_response(_auth_err, status=401, headers=CORS_BUDDY)
    if not uid:
        return _web.json_response({"phrases": [], "due": []}, headers=CORS_BUDDY)

    try:
        s = get_s(uid)
    except Exception:
        return _web.json_response({"phrases": [], "due": []}, headers=CORS_BUDDY)

    mined  = s.get("mined_sentences", [])
    srs_db = s.get("srs_words", {})
    today  = datetime.now().strftime("%Y-%m-%d")

    # Будуємо список фраз з SRS статусом (прихований для юзера)
    phrases = []
    for entry in mined:
        phrase = entry.get("phrase", "")
        if not phrase:
            continue
        srs = srs_db.get(phrase, {})
        phrases.append({
            "phrase":        phrase,
            "video_url":     entry.get("video_url", ""),
            "video_time":    entry.get("video_time", 0),
            "grammar_topic": entry.get("grammar_topic", ""),
            "date":          entry.get("date", ""),
        })

    # Фрази для повторення сьогодні (SRS due)
    due = []
    for phrase, srs in srs_db.items():
        next_review = srs.get("next_review", today)
        if next_review <= today:
            # Шукаємо відповідний entry
            entry = next((m for m in mined if m.get("phrase") == phrase), {})
            due.append({
                "phrase":    phrase,
                "video_url": entry.get("video_url", ""),
                "video_time": entry.get("video_time", 0),
            })

    return _web.json_response({
        "phrases": phrases,
        "due":     due,
    }, headers=CORS_BUDDY)


