async def handle_admin_analytics_page(request):
    """GET /admin_analytics → admin_analytics.html"""
    import pathlib
    for path in [
        pathlib.Path(__file__).parent / "miniapps" / "admin_analytics.html",
        pathlib.Path(__file__).parent / "admin_analytics.html",
        pathlib.Path("miniapps/admin_analytics.html"),
        pathlib.Path("admin_analytics.html"),
    ]:
        if path.exists():
            return _web.FileResponse(path, headers={**CORS_BUDDY, "Cache-Control": "no-cache"})
    return _web.Response(text="admin_analytics.html not found", status=404)



# ── Перенесено на рівень модуля (були після запуску сервера → NameError) ──
def _build_checkin_analytics(students: list) -> dict:
    """Рахує метрики Daily Check-in. students = список s-дictів.
    Точна денна історія читається з глобального _checkin_log.
    Повертає None якщо фіча ніколи не слалась (фронт тоді нічого не малює)."""
    from datetime import datetime, timedelta

    today = datetime.now().strftime("%Y-%m-%d")
    last7 = [(datetime.now() - timedelta(days=i)).strftime("%Y-%m-%d") for i in range(7)]

    # ── Точний денний лог (глобальний службовий запис) ──
    clog = load_db().get("_checkin_log", {})

    ever_sent = bool(clog) or any(
        s.get("checkin_sent_date") or s.get("checkin_replies_total") for s in students)
    if not ever_sent:
        return None

    today_row  = clog.get(today, {})
    sent_today = today_row.get("sent", 0)
    replied_today = today_row.get("replied", 0)
    reply_rate = round(replied_today / sent_today * 100) if sent_today else 0

    sent_7d    = sum(clog.get(d, {}).get("sent", 0) for d in last7)
    snooze_7d  = sum(clog.get(d, {}).get("snoozed", 0) for d in last7)
    snooze_rate = round(snooze_7d / sent_7d * 100) if sent_7d else 0

    # Точна історія по днях з логу
    daily = []
    for d in reversed(last7):  # від старих до нових
        row = clog.get(d, {})
        sd, rd = row.get("sent", 0), row.get("replied", 0)
        daily.append({
            "date": d[5:],  # MM-DD
            "sent": sd,
            "replied": rd,
            "pct": round(rd / sd * 100) if sd else 0,
        })

    # Retention lift: група, що отримувала check-in, vs ті, що ні (приблизно)
    def _d_rate(group, key_first, key_last):
        if not group: return 0
        return round(sum(1 for s in group if s.get(key_last)) / len(group) * 100)

    got_checkin = [s for s in students if s.get("checkin_sent_date") or s.get("checkin_replies_total")]
    no_checkin  = [s for s in students if not (s.get("checkin_sent_date") or s.get("checkin_replies_total"))]

    def _active_within(s, days):
        ld = s.get("last_date", "")
        if not ld: return False
        try:
            return (datetime.now() - datetime.strptime(ld, "%Y-%m-%d")).days <= days
        except Exception:
            return False

    retention_lift = [
        {"segment": "Отримували check-in",
         "users": len(got_checkin),
         "d1": round(sum(1 for s in got_checkin if _active_within(s, 1)) / len(got_checkin) * 100) if got_checkin else 0,
         "d7": round(sum(1 for s in got_checkin if _active_within(s, 7)) / len(got_checkin) * 100) if got_checkin else 0},
        {"segment": "Без check-in (контроль)",
         "users": len(no_checkin),
         "d1": round(sum(1 for s in no_checkin if _active_within(s, 1)) / len(no_checkin) * 100) if no_checkin else 0,
         "d7": round(sum(1 for s in no_checkin if _active_within(s, 7)) / len(no_checkin) * 100) if no_checkin else 0},
    ]

    return {
        "sent_today":  sent_today,
        "reply_rate":  reply_rate,
        "sent_7d":     sent_7d,
        "snooze_rate": snooze_rate,
        "daily":       daily,
        "retention_lift": retention_lift,
    }




def _build_features_analytics(students: list) -> dict:
    """Метрики нових фіч (victory card, video→buddy, grammar decay)
    з глобального _feature_log. Повертає None якщо подій ще не було."""
    from datetime import datetime, timedelta
    clog = load_db().get("_feature_log", {})
    if not clog:
        return None

    today = datetime.now().strftime("%Y-%m-%d")
    last7 = [(datetime.now() - timedelta(days=i)).strftime("%Y-%m-%d") for i in range(7)]

    def _sum(feature_kind, days):
        return sum(clog.get(d, {}).get(feature_kind, 0) for d in days)

    # Victory card
    victory = {
        "shown_today":  clog.get(today, {}).get("victory:shown", 0),
        "shown_7d":     _sum("victory:shown", last7),
        "rank_up_7d":   _sum("victory:rank_up", last7),
    }
    victory["rank_up_rate"] = (round(victory["rank_up_7d"] / victory["shown_7d"] * 100)
                               if victory["shown_7d"] else 0)

    # Video → Buddy
    v_start_7d = _sum("video_practice:start", last7)
    video = {
        "start_today":   clog.get(today, {}).get("video_practice:start", 0),
        "start_7d":      v_start_7d,
        "with_summary":  _sum("video_practice:with_summary", last7),
        "by_title":      _sum("video_practice:by_title", last7),
        "retell":        _sum("video_practice:retell", last7),
        "discuss":       _sum("video_practice:discuss", last7),
    }
    video["summary_rate"] = (round(video["with_summary"] / v_start_7d * 100)
                             if v_start_7d else 0)

    # Grammar decay
    decay = {
        "errors_today": clog.get(today, {}).get("grammar_decay:error", 0),
        "errors_7d":    _sum("grammar_decay:error", last7),
    }
    # скільки юзерів мають активне просідання (decay_boost > 0)
    decay["users_with_decay"] = sum(
        1 for s in students
        for t in (s.get("grammar_topics", {}) or {}).values()
        if isinstance(t, dict) and t.get("decay_boost", 0) > 0
    )

    # денна історія для графіка
    daily = []
    for d in reversed(last7):
        row = clog.get(d, {})
        daily.append({
            "date": d[5:],
            "victory": row.get("victory:shown", 0),
            "video": row.get("video_practice:start", 0),
            "decay": row.get("grammar_decay:error", 0),
        })

    return {"victory": victory, "video": video, "decay": decay, "daily": daily}


