# [Phase 3] Адмін-нагадування проблемним учням (режим прев'ю + ручне підтвердження)
#
# Best practices, вбудовані від першого дня:
#   • Frequency cap: не частіше 1 нагадування на людину / 72 год (глобально).
#   • Quiet hours: не слати 22:00–08:00 (за часом сервера).
#   • Дедуп + повага до блокування: пропускаємо bot_blocked, ліміт дотиків на епізод.
#   • Пріоритет сегментів: людина в кількох списках → лише ОДНЕ повідомлення.
#   • Human-in-the-loop: бекенд лише РАХУЄ і ШЛЕ за явним підтвердженням адміна.
#     Автоматичної розсилки без натискання «Надіслати» немає.
# ════════════════════════════════════════════════════════════════════

# Пороги (узгоджені з _build_students_analytics)
NUDGE_STUCK_INACTIVE_DAYS = 7
NUDGE_STUCK_PROGRESS_MAX  = 20
NUDGE_CHURN_DAYS          = 14
NUDGE_FREQ_CAP_HOURS      = 72     # мін. проміжок між нагадуваннями одній людині
NUDGE_QUIET_START         = 22     # не слати з 22:00
NUDGE_QUIET_END           = 8      # ...до 08:00
NUDGE_MAX_TOUCHES         = {      # макс. дотиків на епізод по сегменту
    "churned": 3, "stuck": 4, "unpaid": 2,
}
# Пріоритет: якщо людина підходить під кілька — беремо перший зі списку
NUDGE_SEGMENT_PRIORITY = ["churned", "stuck", "unpaid"]

# Готові варіанти тексту. {name}/{topic}/{level}/{chain}/{lessons} підставляються.
NUDGE_VARIANTS = {
    "stuck": {
        "title": "🟡 Застрягли",
        "desc":  "Низький прогрес + 7+ днів тиші. Тон — конкретний крок, зняти тертя.",
        "variants": [
            "{name}, ти зупинився на «{topic}» — і це остання тема до наступного рівня. 5 хвилин сьогодні, і ти її закриєш 💪",
            "Скучив за англійською? 😊 Твій наступний крок — «{topic}». Один урок, і ти знову в русі.",
            "{name}, ти вже пройшов {lessons} уроків — не давай прогресу застоятися. Продовжимо з «{topic}»?",
        ],
    },
    "churned": {
        "title": "🔴 Кинули (win-back)",
        "desc":  "14+ днів без входу. Тон — нагадати про вкладене, зняти сором за паузу.",
        "variants": [
            "{name}, твій chain на {chain} днів досі тут і чекає 🔥 Перерви трапляються у всіх — повернутись легше, ніж почати. Один урок сьогодні?",
            "Давно не бачились! За цей час англійська нікуди не поділась — вона все ще твоя. 5 хвилин, щоб струсити пил? ☕",
            "{name}, ми зберегли весь твій прогрес: рівень {level}, {lessons} уроків. Продовжимо звідти, де зупинились?",
        ],
    },
    "unpaid": {
        "title": "💸 Не платять",
        "desc":  "Челендж завершено, активність була, оплати немає. Тон — цінність, без тиску. Макс 1-2 дотики.",
        "variants": [
            "{name}, ти пройшов {lessons} уроків і дійшов до {level} — це реальний результат. Продовжимо шлях без обмежень? 🚀",
            "Тиждень позаду, але прогрес лишився з тобою. Готовий рухатись до наступного рівня?",
        ],
    },
}


def _nudge_now():
    from datetime import datetime as _dt
    return _dt.now()


def _nudge_in_quiet_hours(dt=None) -> bool:
    dt = dt or _nudge_now()
    h = dt.hour
    # 22:00–08:00
    if NUDGE_QUIET_START > NUDGE_QUIET_END:
        return h >= NUDGE_QUIET_START or h < NUDGE_QUIET_END
    return NUDGE_QUIET_START <= h < NUDGE_QUIET_END


def _nudge_last_sent_hours_ago(s: dict):
    """Скільки годин тому востаннє слали цій людині адмін-нагадування (будь-яке)."""
    from datetime import datetime as _dt
    log = s.get("admin_nudge_log", [])
    if not log:
        return None
    last = log[-1].get("ts", "")
    try:
        delta = _nudge_now() - _dt.strptime(last, "%Y-%m-%d %H:%M:%S")
        return delta.total_seconds() / 3600.0
    except Exception:
        return None


def _nudge_touches_for_segment(s: dict, segment: str) -> int:
    """Скільки разів вже слали цій людині по цьому сегменту (за поточний епізод)."""
    return sum(1 for e in s.get("admin_nudge_log", []) if e.get("segment") == segment)


def _nudge_eligible(s: dict, segment: str) -> bool:
    """
    Чи можна ЗАРАЗ слати цій людині по цьому сегменту.
    Застосовує: bot_blocked, frequency cap 72h, ліміт дотиків.
    (Quiet hours перевіряється на рівні всієї розсилки, не окремої людини.)
    """
    if s.get("bot_blocked"):
        return False
    # frequency cap
    ago = _nudge_last_sent_hours_ago(s)
    if ago is not None and ago < NUDGE_FREQ_CAP_HOURS:
        return False
    # ліміт дотиків на епізод
    if _nudge_touches_for_segment(s, segment) >= NUDGE_MAX_TOUCHES.get(segment, 3):
        return False
    return True


def _nudge_uid_of(s: dict):
    return s.get("uid") or s.get("id") or s.get("user_id")


def _nudge_classify_segment(s: dict, now, today_str: str):
    """
    Визначає ЄДИНИЙ сегмент для людини за пріоритетом (churned>stuck>unpaid),
    або None. Логіка узгоджена з _build_students_analytics.
    """
    from datetime import datetime as _dt

    la = str(s.get("last_date") or "")[:10]
    inactive = None
    if la:
        try:
            inactive = (now - _dt.strptime(la, "%Y-%m-%d")).days
        except Exception:
            inactive = None

    lvl = s.get("level", "A1")
    topics = CEFR_GRAMMAR.get(lvl, [])
    mastered = s.get("mastered_grammar", [])
    pct = round(len([t for t in mastered if t in topics]) / len(topics) * 100) if topics else 0

    hist = s.get("level_history", [])

    is_churned = inactive is not None and inactive >= NUDGE_CHURN_DAYS
    is_stuck = (inactive is not None and NUDGE_STUCK_INACTIVE_DAYS <= inactive < NUDGE_CHURN_DAYS
                and pct <= NUDGE_STUCK_PROGRESS_MAX)
    is_unpaid = ((not is_premium(s)) and (not is_in_trial(s))
                 and (s.get("done_lessons") or s.get("buddy_stats") or hist))

    flags = {"churned": is_churned, "stuck": is_stuck, "unpaid": is_unpaid}
    for seg in NUDGE_SEGMENT_PRIORITY:
        if flags.get(seg):
            return seg
    return None


def _nudge_fill_text(template: str, s: dict) -> str:
    """Підставляє плейсхолдери з даних учня."""
    lvl = s.get("level", "A1")
    topics = CEFR_GRAMMAR.get(lvl, [])
    mastered = s.get("mastered_grammar", [])
    # наступна незасвоєна тема поточного рівня
    next_topic = next((t for t in topics if t not in mastered), None) or (topics[0] if topics else "нову тему")
    chain = chain_links(s)
    return (template
            .replace("{name}", s.get("name") or "друже")
            .replace("{topic}", next_topic)
            .replace("{level}", LEVEL_NAMES.get(lvl, lvl))
            .replace("{chain}", str(chain))
            .replace("{lessons}", str(len(s.get("done_lessons", [])))))


def _nudge_collect(student_items: list, now, today_str: str) -> dict:
    """
    Розкладає учнів по сегментах (кожен максимум в одному, за пріоритетом)
    і рахує, скільки ЗАРАЗ eligible (пройшли cap/дедуп).

    student_items — список (uid, student_dict), де uid — КЛЮЧ бази (авторитетний id).
    Повертає dict segment -> {"all": [uids], "eligible": [uids], "sample": [...]}.
    """
    from datetime import datetime as _dt
    buckets = {seg: {"all": [], "eligible": [], "sample": []} for seg in NUDGE_VARIANTS}
    for uid, s in student_items:
        seg = _nudge_classify_segment(s, now, today_str)
        if not seg:
            continue
        if uid is None:
            continue
        buckets[seg]["all"].append(uid)
        if _nudge_eligible(s, seg):
            buckets[seg]["eligible"].append(uid)
            if len(buckets[seg]["sample"]) < 12:
                la = str(s.get("last_date") or "")[:10]
                inactive_days = -1
                if la:
                    try:
                        inactive_days = (now - _dt.strptime(la, "%Y-%m-%d")).days
                    except Exception:
                        inactive_days = -1
                buckets[seg]["sample"].append({
                    "uid":   uid,
                    "name":  s.get("name") or "—",
                    "level": s.get("level", "A1"),
                    "inactive_days": inactive_days,
                    "preview": _nudge_fill_text(NUDGE_VARIANTS[seg]["variants"][0], s),
                })
    return buckets


async def handle_admin_nudge_preview(request):
    """
    POST /admin_nudge_preview → сегменти, лічильники (з урахуванням cap/quiet),
    варіанти тексту та приклад списку. НІЧОГО не шле.
    """
    if request.method == "OPTIONS":
        return _web.Response(headers=CORS_BUDDY)
    try:
        body = await request.json()
    except Exception:
        return _web.json_response({"error": "Invalid JSON"}, status=400, headers=CORS_BUDDY)

    # 21.07: require_verified_uid — init_data обовʼязковий (STRICT_INIT_DATA).
    # Раніше uid брався з тіла без перевірки, коли init_data порожній —
    # is_admin(uid) міг спрацювати на чужий, вгаданий/підглянутий id.
    uid, _auth_err = require_verified_uid(body)
    if _auth_err:
        return _web.json_response(_auth_err, status=401, headers=CORS_BUDDY)
    admin_ok = is_admin(uid) or is_developer(uid) or (ADMIN_ID and uid == ADMIN_ID)
    if not admin_ok:
        return _web.json_response({"error": "Доступ заборонено"}, status=403, headers=CORS_BUDDY)

    from datetime import datetime as _dt
    now = _dt.now()
    today_str = now.strftime("%Y-%m-%d")
    db = load_db()
    # (uid, student) — uid це КЛЮЧ бази (авторитетний Telegram id)
    student_items = [
        (k, v) for k, v in db.items()
        if isinstance(v, dict) and k not in DB_SKIP_KEYS
        and any(kk in v for kk in ("onboarding_done", "last_date", "level", "goal", "plan"))
    ]

    buckets = _nudge_collect(student_items, now, today_str)

    segments = []
    for seg, cfg in NUDGE_VARIANTS.items():
        b = buckets[seg]
        segments.append({
            "key":            seg,
            "title":          cfg["title"],
            "desc":           cfg["desc"],
            "variants":       cfg["variants"],
            "total":          len(b["all"]),
            "eligible":       len(b["eligible"]),
            "sample":         b["sample"],
        })

    return _web.json_response({
        "segments":     segments,
        "quiet_hours":  _nudge_in_quiet_hours(now),
        "quiet_window": f"{NUDGE_QUIET_START:02d}:00–{NUDGE_QUIET_END:02d}:00",
        "freq_cap_hours": NUDGE_FREQ_CAP_HOURS,
        "generated_at": now.strftime("%Y-%m-%d %H:%M"),
    }, headers=CORS_BUDDY)


async def handle_admin_nudge_send(request):
    """
    POST /admin_nudge_send → надсилає нагадування ОДНОМУ сегменту.
    Вимагає: segment, text (обраний/відредагований шаблон).
    Застосовує cap/quiet/дедуп ще раз (на випадок, якщо стан змінився),
    шле через _safe_send + _send_in_batches, пише admin_nudge_log.
    """
    if request.method == "OPTIONS":
        return _web.Response(headers=CORS_BUDDY)
    try:
        body = await request.json()
    except Exception:
        return _web.json_response({"error": "Invalid JSON"}, status=400, headers=CORS_BUDDY)

    # 21.07: require_verified_uid — init_data обовʼязковий (STRICT_INIT_DATA).
    # Раніше uid брався з тіла без перевірки, коли init_data порожній —
    # is_admin(uid) міг спрацювати на чужий, вгаданий/підглянутий id.
    uid, _auth_err = require_verified_uid(body)
    if _auth_err:
        return _web.json_response(_auth_err, status=401, headers=CORS_BUDDY)
    admin_ok = is_admin(uid) or is_developer(uid) or (ADMIN_ID and uid == ADMIN_ID)
    if not admin_ok:
        return _web.json_response({"error": "Доступ заборонено"}, status=403, headers=CORS_BUDDY)

    segment = body.get("segment", "")
    text_tpl = (body.get("text") or "").strip()
    confirm = bool(body.get("confirm", False))
    if segment not in NUDGE_VARIANTS:
        return _web.json_response({"error": "Невідомий сегмент"}, status=400, headers=CORS_BUDDY)
    if not text_tpl:
        return _web.json_response({"error": "Порожній текст"}, status=400, headers=CORS_BUDDY)
    if not confirm:
        return _web.json_response({"error": "Потрібне підтвердження"}, status=400, headers=CORS_BUDDY)

    from datetime import datetime as _dt
    now = _dt.now()
    today_str = now.strftime("%Y-%m-%d")

    # Quiet hours — блокуємо всю розсилку
    if _nudge_in_quiet_hours(now):
        return _web.json_response({
            "error": f"Тихі години ({NUDGE_QUIET_START:02d}:00–{NUDGE_QUIET_END:02d}:00). "
                     "Розсилку призупинено, щоб не турбувати вночі."
        }, status=409, headers=CORS_BUDDY)

    db = load_db()
    student_items = [
        (k, v) for k, v in db.items()
        if isinstance(v, dict) and k not in DB_SKIP_KEYS
        and any(kk in v for kk in ("onboarding_done", "last_date", "level", "goal", "plan"))
    ]

    # 23.07: масштабування — прохід по ВСІХ юзерах бази синхронно
    # блокує event loop (а отже й обробку інших запитів/повідомлень
    # бота) на час фільтрації. При сотнях тисяч+ юзерів це вже
    # відчутна пауза. Періодичний asyncio.sleep(0) віддає керування
    # event loop кожні 500 юзерів, не змінюючи ЖОДНОЇ бізнес-логіки
    # класифікації нижче — лише дає іншим запитам "вклинитись" між
    # ітераціями. Дешевий, низькоризиковий крок; повне рішення
    # (по-юзерні рядки в Postgres) — окрема, більша задача, Реєстр K-10.
    targets = []  # список (uid_key, student)
    for i, (uid_key, s) in enumerate(student_items):
        if _nudge_classify_segment(s, now, today_str) != segment:
            continue
        if not _nudge_eligible(s, segment):
            continue
        targets.append((uid_key, s))
        if i % 500 == 0:
            await asyncio.sleep(0)

    if not targets:
        return _web.json_response({"sent": 0, "errors": 0, "skipped": 0,
                                   "note": "Немає кому слати (усі відсіяні лімітами)."},
                                  headers=CORS_BUDDY)

    bot = _HTTP_BOT
    if bot is None:
        return _web.json_response({"error": "Bot instance недоступний"}, status=500, headers=CORS_BUDDY)

    ts_str = now.strftime("%Y-%m-%d %H:%M:%S")
    sent_uids = []

    async def _make_task(uid_key, stu):
        try:
            chat_id = int(uid_key)
        except Exception:
            return False
        msg = _nudge_fill_text(text_tpl, stu)
        ok = await _safe_send(bot, chat_id, msg)
        if ok:
            log = list(stu.get("admin_nudge_log", []))
            log.append({"ts": ts_str, "segment": segment})
            upd_s(chat_id, {"admin_nudge_log": log})
            sent_uids.append(uid_key)
        return ok

    tasks = [(lambda uk=uk, st=st: _make_task(uk, st)) for uk, st in targets]
    stats = await _send_in_batches(bot, tasks)

    return _web.json_response({
        "sent":    stats.get("sent", 0),
        "errors":  stats.get("errors", 0),
        "segment": segment,
        "at":      ts_str,
    }, headers=CORS_BUDDY)


def _admin_content_stats(top_n: int = 10) -> dict:
    """Що учні реально практикують — по всій платформі + розріз по блогерах.

    Читає готові лічильники з db["_content_stats"] — БД не перебирає.
    """
    db   = load_db()
    root = db.get("_content_stats", {}) or {}

    # ── Розріз по блогерах: у кого контент «заходить» ──
    per_blogger = []
    for name, buckets in root.items():
        if name == _CS_ALL or not isinstance(buckets, dict):
            continue
        saved  = buckets.get("saved", {})  or {}
        spoken = buckets.get("spoken", {}) or {}
        s_tot  = sum(saved.values())
        p_tot  = sum(spoken.values())
        if not (s_tot or p_tot):
            continue
        top_s = sorted(spoken.items(), key=lambda kv: kv[1], reverse=True)[:1]
        per_blogger.append({
            "name":         name,
            "saved_total":  s_tot,
            "spoken_total": p_tot,
            "uniq_saved":   len(saved),
            # Скільки разів у середньому проговорюють одну фразу.
            # Високий = учні реально ганяють матеріал, а не просто зберігають.
            "reps":         round(p_tot / len(spoken), 1) if spoken else 0,
            "top_phrase":   top_s[0][0] if top_s else "",
        })
    per_blogger.sort(key=lambda x: x["spoken_total"], reverse=True)

    return {
        "top_spoken":   _cs_top(_CS_ALL, "spoken",  top_n),
        "top_saved":    _cs_top(_CS_ALL, "saved",   top_n),
        "top_videos":   _cs_top(_CS_ALL, "videos",  top_n),
        "top_grammar":  _cs_top(_CS_ALL, "grammar", top_n),
        "spoken_total": _cs_total(_CS_ALL, "spoken"),
        "saved_total":  _cs_total(_CS_ALL, "saved"),
        "uniq_spoken":  _cs_uniq(_CS_ALL, "spoken"),
        "uniq_saved":   _cs_uniq(_CS_ALL, "saved"),
        "by_blogger":   per_blogger,
    }


