# ═══ РУЧНИЙ ЗАПУСК ТИЖНЕВИХ ДЖОБ ДЛЯ QA (23.07, QA Блокер №1) ═══
# НАВІЩО: 4 джоби (нижче) мають guard "if weekday() != N: return" —
# без цього роута логіку фізично не можна перевірити, не чекаючи
# реального дня тижня. Розклад (job_queue) цей роут НЕ чіпає —
# force=True обходить ЛИШЕ guard усередині функції, викликаної напряму.
#
# БЕЗПЕКА:
#  1. WHITELIST, не eval/getattr(globals(), name) — можна викликати
#     ТІЛЬКИ ці 4 конкретні функції, ніяку іншу за довільним іменем.
#  2. is_super_admin (не просто is_admin) — це інструмент з побічним
#     ефектом реальної розсилки студентам/блогерам, суворіше за
#     звичайні фінансові ендпоінти, доступ лише головному ADMIN_ID.
#  3. FakeCtx має лише .bot — усі 4 джоби звірені (grep) і не чіпають
#     ctx.job/ctx.job_queue/інші атрибути, тільки ctx.bot.*.
_ADMIN_RUNNABLE_JOBS = {
    "weekly_questions":        job_send_weekly_questions,
    "blogger_weekly_reminder": job_blogger_weekly_q_reminder,
    "blogger_challenge_winner": job_blogger_challenge_winner,
    "weekly_report":           job_weekly_report,
}


class _FakeCtx:
    """Мінімальна заглушка ContextTypes.DEFAULT_TYPE для forced-запуску.
    Має лише .bot, бо саме це — єдине, що використовують ці 4 джоби
    (звірено grep'ом по тілу кожної перед написанням цього коду)."""
    def __init__(self, bot):
        self.bot = bot


async def handle_admin_run_job(request):
    """POST /admin_run_job — ручний форсований запуск однієї з 4
    тижневих джоб, обходячи ЛИШЕ day/hour-guard (QA Блокер №1).

    Тіло: {"init_data": "...", "job": "weekly_report"}

    НЕ змінює job_queue, НЕ впливає на продакшн-розклад — це прямий
    виклик тієї самої Python-функції з force=True, один раз, зараз."""
    if request.method == "OPTIONS":
        return _web.Response(headers=CORS_BUDDY)
    try:
        body = await request.json()
    except Exception:
        return _web.json_response({"error": "Invalid JSON"}, status=400, headers=CORS_BUDDY)

    uid, _auth_err = require_verified_uid(body)
    if _auth_err:
        return _web.json_response(_auth_err, status=401, headers=CORS_BUDDY)
    if not is_super_admin(uid):
        return _web.json_response({"error": "Доступ заборонено"},
                                  status=403, headers=CORS_BUDDY)

    job_name = str(body.get("job", "") or "")
    job_fn = _ADMIN_RUNNABLE_JOBS.get(job_name)
    if not job_fn:
        return _web.json_response(
            {"error": f"Невідома джоба. Доступні: {', '.join(_ADMIN_RUNNABLE_JOBS)}"},
            status=400, headers=CORS_BUDDY)

    try:
        from telegram import Bot
        fake_bot = Bot(token=BOT_TOKEN)
        fake_ctx = _FakeCtx(fake_bot)
        await job_fn(fake_ctx, force=True)
        logger.info(f"admin_run_job: '{job_name}' форсовано запущено uid={uid}")
        return _web.json_response({"ok": True, "job": job_name}, headers=CORS_BUDDY)
    except Exception as e:
        logger.error(f"admin_run_job '{job_name}' упав: {e}")
        return _web.json_response({"ok": False, "error": str(e)},
                                  status=500, headers=CORS_BUDDY)


async def handle_log_payout(request):
    """POST /admin_log_payout — ручний запис факту виплати блогеру
    (23.07). Тіло: {"init_data", "blogger", "amount", "date", "note"}.

    Це ОКРЕМИЙ журнал від _payouts (нарахування) — власниця підтверджує
    РЕАЛЬНО перерахований переказ, дата/сума вводяться вручну (може
    відрізнятись від нарахованого: округлення, часткова виплата).
    Без квитанції — файлового сховища в проєкті ще немає, власниця
    зберігає квитанції окремо за власним рішенням."""
    if request.method == "OPTIONS":
        return _web.Response(headers=CORS_BUDDY)
    try:
        body = await request.json()
    except Exception:
        return _web.json_response({"error": "Invalid JSON"}, status=400, headers=CORS_BUDDY)

    uid, _auth_err = require_verified_uid(body)
    if _auth_err:
        return _web.json_response(_auth_err, status=401, headers=CORS_BUDDY)
    if not is_admin(uid) or not can_access_financials(uid):
        return _web.json_response({"error": "Доступ заборонено"},
                                  status=403, headers=CORS_BUDDY)

    blogger = str(body.get("blogger", "") or "").strip()
    amount  = body.get("amount")
    date    = str(body.get("date", "") or "").strip()
    note    = str(body.get("note", "") or "").strip()

    if not blogger:
        return _web.json_response({"error": "Ім'я блогера обовʼязкове"},
                                  status=400, headers=CORS_BUDDY)
    try:
        amount = float(amount)
    except (TypeError, ValueError):
        return _web.json_response({"error": "Сума має бути числом"},
                                  status=400, headers=CORS_BUDDY)
    if amount <= 0:
        return _web.json_response({"error": "Сума має бути більшою за 0"},
                                  status=400, headers=CORS_BUDDY)
    # Дата — необов'язкова з фронтенду (log_payout сама підставить
    # сьогодні), але якщо передана — звіряємо формат, щоб у журналі
    # не опинився довільний рядок замість дати.
    if date:
        try:
            datetime.strptime(date, "%Y-%m-%d")
        except ValueError:
            return _web.json_response({"error": "Дата має бути у форматі YYYY-MM-DD"},
                                      status=400, headers=CORS_BUDDY)

    res = log_payout(blogger, amount, date=date, note=note)
    if not res.get("ok"):
        return _web.json_response(res, status=500, headers=CORS_BUDDY)
    asyncio.create_task(asyncio.to_thread(gs_sync_payout_log))
    return _web.json_response(res, headers=CORS_BUDDY)


