async def handle_admin_analytics_data(request):
    """POST /admin_analytics → JSON з аналітикою. Тільки для адмінів."""
    if request.method == "OPTIONS":
        return _web.Response(headers=CORS_BUDDY)

    try:
        body = await request.json()
    except Exception:
        return _web.json_response({"error": "Invalid JSON"}, status=400, headers=CORS_BUDDY)

    # 21.07: require_verified_uid — init_data обовʼязковий (STRICT_INIT_DATA).
    #
    # ⚠️ Було: «GitHub Pages не передає initData, але uid береться з
    # tg.initDataUnsafe» — свідомий компроміс, який довіряв uid із тіла
    # запиту БЕЗ перевірки, коли сторінка відкрита поза Telegram. Саме
    # цей ендпоінт роздає admin_analytics.html — включно з фінансовим
    # блоком (can_access_financials нижче). Власниця попросила закрити
    # цей ризик 21.07 — тепер init_data обовʼязковий завжди.
    uid, _auth_err = require_verified_uid(body)
    if _auth_err:
        return _web.json_response(_auth_err, status=401, headers=CORS_BUDDY)

    # Перевіряємо по is_admin АБО розробник АБО по ADMIN_ID напряму
    admin_ok = is_admin(uid) or is_developer(uid) or (ADMIN_ID and uid == ADMIN_ID)
    if not admin_ok:
        return _web.json_response({"error": "Доступ заборонено"}, status=403, headers=CORS_BUDDY)

    # Розробник і sub-admin не бачать фінансових даних
    is_dev_only = not can_access_financials(uid)

    import time as _t
    from datetime import datetime, timedelta

    db = load_db()
    students = [s for s in db.values()
                if isinstance(s, dict)
                and any(k in s for k in ("onboarding_done", "last_date", "level", "goal", "plan"))]
    today_str = datetime.now().strftime("%Y-%m-%d")
    now = datetime.now()

    # ── Helpers ──
    def days_ago(n):
        return (now - timedelta(days=n)).strftime("%Y-%m-%d")

    def reg_date(s):
        v = s.get("registered_at")
        return str(v)[:10] if v else ""

    def last_active(s):
        v = s.get("last_date")
        return str(v)[:10] if v else ""

    def is_paid(s):
        return bool(is_premium(s))

    def is_trial(s):
        return bool(is_in_trial(s)) and not is_paid(s)

    # ── Overview ──
    total = len(students)
    new_today = sum(1 for s in students if reg_date(s) == today_str)
    new_7d = sum(1 for s in students if reg_date(s) >= days_ago(7))
    new_30d = sum(1 for s in students if reg_date(s) >= days_ago(30))
    active_today = sum(1 for s in students if last_active(s) == today_str)
    paid_users = sum(1 for s in students if is_paid(s))
    trial_users = sum(1 for s in students if is_trial(s))

    # Chain stats
    chains = []
    chain_breaks_today = 0
    for s in students:
        c = chain_links(s)
        chains.append(c)
        # Chain break = вчора активний але сьогодні ні і chain < вчорашнього
        if last_active(s) == days_ago(1) and c == 0:
            chain_breaks_today += 1
    avg_chain = round(sum(chains) / len(chains), 1) if chains else 0

    # Daily registrations (30 days)
    days_labels = [(now - timedelta(days=i)).strftime("%d.%m") for i in range(29, -1, -1)]
    days_keys = [(now - timedelta(days=i)).strftime("%Y-%m-%d") for i in range(29, -1, -1)]
    reg_daily = [sum(1 for s in students if reg_date(s) == dk) for dk in days_keys]
    active_daily = [sum(1 for s in students if last_active(s) == dk) for dk in days_keys]

    # ── Retention ──
    def retention_rate(cohort_date, days):
        cohort = [s for s in students if reg_date(s) == cohort_date]
        if not cohort:
            return None
        cutoff = (datetime.strptime(cohort_date, "%Y-%m-%d") + timedelta(days=days)).strftime("%Y-%m-%d")
        if cutoff > today_str:
            return None  # ще не настало
        retained = sum(1 for s in cohort if last_active(s) >= cutoff)
        return round(retained / len(cohort) * 100)

    # D1/D7/D30 для всієї бази (юзери що зареєструвались 1/7/30 днів тому)
    d1_cohort = [s for s in students if reg_date(s) == days_ago(1)]
    d7_cohort = [s for s in students if reg_date(s) == days_ago(7)]
    d30_cohort = [s for s in students if reg_date(s) == days_ago(30)]

    def ret_from_cohort(cohort, days):
        if not cohort: return 0
        cutoff = today_str
        retained = sum(1 for s in cohort if last_active(s) >= cutoff)
        return round(retained / len(cohort) * 100)

    d1_ret = ret_from_cohort(d1_cohort, 1)
    d7_ret = ret_from_cohort(d7_cohort, 7)
    d30_ret = ret_from_cohort(d30_cohort, 30)

    # Когорти по тижнях (останні 8 тижнів)
    cohorts = []
    for week_ago in range(7, -1, -1):
        week_start = (now - timedelta(weeks=week_ago+1)).strftime("%Y-%m-%d")
        week_end = (now - timedelta(weeks=week_ago)).strftime("%Y-%m-%d")
        cohort = [s for s in students if week_start <= reg_date(s) < week_end]
        entry = {"week": f"W-{week_ago+1}" if week_ago > 0 else "Цей"}
        for days, key in [(1,'d1'),(3,'d3'),(7,'d7'),(14,'d14'),(30,'d30'),(60,'d60'),(90,'d90')]:
            cutoff = (datetime.strptime(week_start, "%Y-%m-%d") + timedelta(days=days)).strftime("%Y-%m-%d")
            if cutoff > today_str or not cohort:
                entry[key] = None
            else:
                retained = sum(1 for s in cohort if last_active(s) >= cutoff)
                entry[key] = round(retained / len(cohort) * 100)
        cohorts.append(entry)

    # Chain breaks (30 days)
    break_labels = days_labels[-14:]
    break_data = []
    for dk in days_keys[-14:]:
        prev = (datetime.strptime(dk, "%Y-%m-%d") - timedelta(days=1)).strftime("%Y-%m-%d")
        breaks = sum(1 for s in students
                     if last_active(s) == prev and (s.get("chain") or {}).get("length", 0) == 0)
        break_data.append(breaks)

    avg_sessions = round(sum((s.get("buddy_stats") or {}).get("total_messages", 0) for s in students) /
                         max(1, sum(1 for s in students if s.get("buddy_stats"))), 1)

    # ── Funnel ──
    registered = total
    demo_users_count = sum(1 for s in students if s.get("buddy_daily") or s.get("buddy_stats"))
    trial_count = sum(1 for s in students if is_trial(s) or is_paid(s))
    paid_count = paid_users

    # Джерела
    # 🔴 БУЛО: s.get("source", "organic") — те саме фантомне поле, що й у
    # transitions вище. Тепер get_source() — канонічна функція (та сама,
    # що рахує ціни в get_prices() і знижку в paywall.html).
    source_map = {}
    for s in students:
        src = get_source(s)
        if src not in source_map:
            source_map[src] = {"users": 0, "paid": 0}
        source_map[src]["users"] += 1
        if is_paid(s):
            source_map[src]["paid"] += 1

    sources_list = sorted([
        {"name": k, "users": v["users"], "paid": v["paid"]}
        for k, v in source_map.items()
    ], key=lambda x: x["users"], reverse=True)[:10]

    # Avg trial chains
    trial_students = [s for s in students if is_trial(s)]
    avg_trial_chains = round(
        sum(len(s.get("done_lessons", [])) for s in trial_students) /
        max(1, len(trial_students)), 1
    )

    # ── Revenue (точний MRR: фактична ціна кожного платника) ──
    # Ціни беруться з тих самих змінних, що й оплата (єдине джерело істини).
    # Афіліат/повна визначається наявністю реф-коду. 6-місячні плани
    # розкладаються на місячний еквівалент (÷6), бо MRR — місячний дохід.
    mrr = round(sum(_monthly_revenue(s) for s in students if is_paid(s)))
    basic_count = sum(1 for s in students
                      if is_paid(s) and s.get("plan", "basic") in ("basic", "basic_6m"))
    premium_count = sum(1 for s in students
                        if is_paid(s) and s.get("plan") in ("premium", "premium_6m"))

    # Revenue по місяцях (6 міс) — сума фактичного місячного доходу кожного
    # платника, що зареєструвався в той місяць (та сама логіка, що й MRR).
    months_labels = [(now - timedelta(days=30*i)).strftime("%b") for i in range(5, -1, -1)]
    revenue_monthly = []
    basic_monthly = []
    premium_monthly = []
    for i in range(5, -1, -1):
        month_start = (now - timedelta(days=30*(i+1))).strftime("%Y-%m")
        month_end = (now - timedelta(days=30*i)).strftime("%Y-%m")
        month_students = [s for s in students
                          if is_paid(s) and reg_date(s)[:7] == month_start]
        month_basic = sum(1 for s in month_students
                          if s.get("plan", "basic") in ("basic", "basic_6m"))
        month_premium = sum(1 for s in month_students
                            if s.get("plan") in ("premium", "premium_6m"))
        revenue_monthly.append(round(sum(_monthly_revenue(s) for s in month_students)))
        basic_monthly.append(month_basic)
        premium_monthly.append(month_premium)

    mrr_delta = revenue_monthly[-1] - revenue_monthly[-2] if len(revenue_monthly) >= 2 else 0
    revenue_month = revenue_monthly[-1] if revenue_monthly else 0

    # Bloggers revenue
    # 🔴 БУЛО: s.get("source", "") — фантомне поле (ніде не пишеться), тож
    # blogger_map завжди був порожній ("continue" на кожному юзері) —
    # bloggers_list у "revenue" мовчки показував [] увесь час.
    # Ключуємо по РЕАЛЬНОМУ імені блогера (affiliate_blogger), не по
    # категорії джерела — це "revenue по кожному блогеру", не по типу трафіку.
    blogger_map = {}
    for s in students:
        _bname = s.get("affiliate_blogger", "")
        if not _bname:
            continue
        if _bname not in blogger_map:
            blogger_map[_bname] = {"users": 0, "paid": 0, "revenue": 0}
        blogger_map[_bname]["users"] += 1
        if is_paid(s):
            blogger_map[_bname]["paid"] += 1
            blogger_map[_bname]["revenue"] += _monthly_revenue(s)

    bloggers_list = sorted([
        {"name": k[:20], "users": v["users"], "paid": v["paid"], "revenue": round(v["revenue"])}
        for k, v in blogger_map.items()
    ], key=lambda x: x["revenue"], reverse=True)[:10]

    # ── Buddy stats ──
    buddy_students = [s for s in students if s.get("buddy_stats")]
    total_buddy_sessions = sum((s.get("buddy_stats") or {}).get("total_sessions", 0) for s in students)
    buddy_active = len(buddy_students)
    buddy_today = sum(1 for s in students
                      if (s.get("buddy_daily") or {}).get("date") == today_str
                      and (s.get("buddy_daily") or {}).get("count", 0) > 0)

    total_msgs = sum((s.get("buddy_stats") or {}).get("total_messages", 0) for s in students)
    avg_msgs = round(total_msgs / max(1, total_buddy_sessions), 1)
    feedback_good = sum((s.get("buddy_stats") or {}).get("feedback_good_count", 0) for s in students)
    feedback_tips = sum((s.get("buddy_stats") or {}).get("feedback_tip_count", 0) for s in students)

    # Top scenarios
    scenario_count = {}
    for s in students:
        for sc in (s.get("buddy_stats") or {}).get("scenarios_tried", []):
            scenario_count[sc] = scenario_count.get(sc, 0) + 1
    top_scenarios = sorted(
        [{"name": k[:30], "sessions": v, "avg_msgs": avg_msgs} for k, v in scenario_count.items()],
        key=lambda x: x["sessions"], reverse=True
    )[:10]
    top_scenario = top_scenarios[0]["name"] if top_scenarios else "—"

    # ── Аналітика: популярність тем за КІЛЬКІСТЮ відкриттів (глобально) ──
    _pop_raw = db.get("_topic_popularity", {}) or {}
    topic_popularity = sorted(
        [{"name": k[:40], "opens": int(v)} for k, v in _pop_raw.items()],
        key=lambda x: x["opens"], reverse=True
    )[:15]

    buddy_sessions_daily = [
        sum(1 for s in students
            if (s.get("buddy_daily") or {}).get("date") == dk)
        for dk in days_keys
    ]

    demo_conv = sum(1 for s in students
                    if s.get("buddy_stats") and is_paid(s))

    # ── Bloggers ──
    bloggers_dict = get_registered_bloggers()
    all_payouts = db.get("_payouts", [])

    # Статистика по кожному блогеру
    blogger_stats = []
    for b_uid, b_name in bloggers_dict.items():
        b_students = [s for s in students
                      if s.get("affiliate_blogger", "") == b_name]
        b_basic   = sum(1 for s in b_students if is_paid(s) and s.get("plan","basic") == "basic")
        b_premium = sum(1 for s in b_students if is_paid(s) and s.get("plan") == "premium")
        b_trial   = sum(1 for s in b_students if is_trial(s))
        b_active  = sum(1 for s in b_students
                        if last_active(s) >= now.strftime("%Y-%m-01"))
        # 23.07: те саме розходження, що вже виправлено в _payouts вище —
        # це ОКРЕМИЙ, третій розрахунок (MRR-оцінка по поточних активних
        # передплатниках, не з фактичних _payments), теж ігнорував
        # персональну ставку. ⚠️ _blogger_commissions ключується по ІМЕНІ
        # блогера (b_name), НЕ по Telegram uid — узгоджено з тим, як
        # admin_analytics.html шле /admin_set_blogger_commission (див.
        # коментар там же) і як build_finance групує per_blogger. Тому
        # тут навмисно b_name, не b_uid.
        _rate_basic   = commission_rate_for(db, "basic",   b_name,
                                             BLOGGER_COMMISSION_BASIC, BLOGGER_COMMISSION_PREMIUM)
        _rate_premium = commission_rate_for(db, "premium", b_name,
                                             BLOGGER_COMMISSION_BASIC, BLOGGER_COMMISSION_PREMIUM)
        b_comm = round(
            b_basic   * float(BASIC_AFFILIATE_PRICE)  * _rate_basic +
            b_premium * float(PREMIUM_PRICE_AFF if hasattr(__builtins__, 'PREMIUM_PRICE_AFF')
                              else os.environ.get("PREMIUM_PRICE_AFF", "79.00")) * _rate_premium,
            2
        )
        # ── Список студентів для клік-розгортання у web-панелі ──
        # Той самий принцип, що й /view_blogger NAME у Telegram (уже живий
        # адмін-інструмент) — тепер ту саму інформацію бачить і веб-дашборд.
        # uid тут потрібен окремо: `students` (список вище) вже без uid,
        # тож проходимо db.items() напряму, як і /view_blogger.
        _b_student_rows = []
        for _uid, _s in db.items():
            if not isinstance(_s, dict) or str(_uid) in DB_SKIP_KEYS:
                continue
            if _s.get("affiliate_blogger", "") != b_name:
                continue
            _b_student_rows.append({
                "uid":          _uid,
                "name":         _s.get("name", "?"),
                "level":        _s.get("level", ""),
                "done_lessons": len(_s.get("done_lessons", [])),
                "streak":       _s.get("streak_days", 0),
                "plan":         "premium" if (is_paid(_s) and _s.get("plan") == "premium")
                                 else "basic" if is_paid(_s)
                                 else "trial" if is_trial(_s) else "none",
                "registered":   reg_date(_s),
            })
        _b_student_rows.sort(key=lambda x: x["done_lessons"], reverse=True)

        blogger_stats.append({
            "name":       b_name,
            "total":      len(b_students),
            "basic":      b_basic,
            "premium":    b_premium,
            "trial":      b_trial,
            "active":     b_active,
            "students":   _b_student_rows[:50],  # стеля — щоб не роздувати payload
            "commission": b_comm,
            # 23.07: поточна ПЕРСОНАЛЬНА ставка (не фактично застосована з
            # оплат, як rate_pct у per_blogger, а те, що ЗАРАЗ ЗБЕРЕЖЕНО в
            # _blogger_commissions) — потрібно, щоб адмінка могла показати
            # й дозволити задати ставку блогеру ДО першого платежу.
            "rate_basic_pct":   round(_rate_basic * 100, 1),
            "rate_premium_pct": round(_rate_premium * 100, 1),
            "has_custom_rate":  bool(get_blogger_commissions(db).get(b_name)),
        })
    blogger_stats.sort(key=lambda x: x["commission"], reverse=True)

    # Підсумок виплат по блогерах і місяцях
    payout_summary_map = {}
    for p in all_payouts:
        key = (p.get("blogger",""), p.get("month",""))
        if key not in payout_summary_map:
            payout_summary_map[key] = {
                "blogger":          p.get("blogger",""),
                "month":            p.get("month",""),
                "total_commission": 0,
                "paid":             p.get("paid", False),
                "paid_date":        p.get("paid_date",""),
            }
        payout_summary_map[key]["total_commission"] += p.get("commission", 0)
        if p.get("paid"):
            payout_summary_map[key]["paid"] = True
            payout_summary_map[key]["paid_date"] = p.get("paid_date","")

    payouts_summary = sorted(
        [{"blogger": v["blogger"], "month": v["month"],
          "total_commission": round(v["total_commission"], 2),
          "paid": v["paid"], "paid_date": v["paid_date"]}
         for v in payout_summary_map.values()],
        key=lambda x: (x["month"], x["blogger"]), reverse=True
    )[:50]

    # ── [Quick win] Всі неоплачені за ВСІ місяці (без ліміту 50/6міс) ──
    # Групуємо всі неоплачені нарахування по (блогер, місяць), щоб борги
    # за пропущені місяці не губились.
    unpaid_map = {}
    for p in all_payouts:
        if p.get("paid"):
            continue
        key = (p.get("blogger", ""), p.get("month", ""))
        if key not in unpaid_map:
            unpaid_map[key] = {"blogger": p.get("blogger", ""), "month": p.get("month", ""),
                               "commission": 0.0, "count": 0}
        unpaid_map[key]["commission"] += p.get("commission", 0)
        unpaid_map[key]["count"] += 1
    unpaid_all = sorted(
        [{"blogger": v["blogger"], "month": v["month"],
          "commission": round(v["commission"], 2), "count": v["count"]}
         for v in unpaid_map.values()],
        key=lambda x: (x["month"], x["blogger"]), reverse=True
    )
    unpaid_all_total = round(sum(u["commission"] for u in unpaid_all), 2)

    # Виплати по місяцях (останні 6 міс) для графіка
    blogger_months = []
    for i in range(5, -1, -1):
        m = (now - timedelta(days=30*i)).strftime("%Y-%m")
        m_label = (now - timedelta(days=30*i)).strftime("%b %Y")
        m_payouts = [p for p in all_payouts if p.get("month","") == m]
        m_commission = round(sum(p.get("commission",0) for p in m_payouts), 2)
        blogger_months.append({
            "label":            m_label,
            "month":            m,
            "total_commission": m_commission,
            "payouts": [{
                "blogger":      p.get("blogger",""),
                "student_name": p.get("student_name",""),
                "plan":         p.get("plan",""),
                "amount":       p.get("amount",0),
                "commission":   p.get("commission",0),
                "paid":         p.get("paid", False),
                "date":         p.get("month",""),
            } for p in m_payouts]
        })

    total_paid_out = round(sum(p.get("commission",0) for p in all_payouts if p.get("paid")), 2)
    pending_this_month = round(sum(
        p.get("commission",0) for p in all_payouts
        if p.get("month","") == now.strftime("%Y-%m") and not p.get("paid")
    ), 2)
    total_referred = sum(len([s for s in students
                               if s.get("affiliate_blogger","") == b_name])
                         for b_name in bloggers_dict.values())

    # ── A/B holdout: нудж-система (control vs treatment) ──
    def _ab_group(s):
        return s.get("nudge_ab_group", "")
    def _in_challenge_ever(s):
        cs = s.get("challenge_state") or {}
        return cs.get("source") == "blogger" and bool(cs.get("started_at"))
    def _challenge_completed(s):
        cs = s.get("challenge_state") or {}
        return cs.get("status") == "completed" or (cs.get("day", 0) >= 6)
    _ab = {"control": {"n": 0, "completed": 0, "paid": 0, "chain_sum": 0},
           "treatment": {"n": 0, "completed": 0, "paid": 0, "chain_sum": 0}}
    for _s_ab in students:
        if not _in_challenge_ever(_s_ab):
            continue
        _g = _ab_group(_s_ab)
        if _g not in _ab:
            continue
        _ab[_g]["n"] += 1
        if _challenge_completed(_s_ab):
            _ab[_g]["completed"] += 1
        if is_paid(_s_ab):
            _ab[_g]["paid"] += 1
        _ab[_g]["chain_sum"] += (_s_ab.get("chain") or {}).get("length", 0) or 0
    def _ab_rates(d):
        n = d["n"] or 1
        return {
            "n": d["n"],
            "completion_rate": round(d["completed"] / n * 100, 1),
            "paid_rate": round(d["paid"] / n * 100, 1),
            "avg_chain": round(d["chain_sum"] / n, 1),
        }
    _ab_control = _ab_rates(_ab["control"])
    _ab_treatment = _ab_rates(_ab["treatment"])
    _uplift_paid = round(_ab_treatment["paid_rate"] - _ab_control["paid_rate"], 1)
    _uplift_completion = round(_ab_treatment["completion_rate"] - _ab_control["completion_rate"], 1)
    _uplift_chain = round(_ab_treatment["avg_chain"] - _ab_control["avg_chain"], 1)

    # ── Онбординг Дня 1 (для панелі дашборду) ──
    try:
        _orep = get_retention_report(load_db)
    except Exception:
        _orep = {}
    _onb_resp = _orep.get("onb_respondents", 0)
    def _onb_dist(field):
        # список {name, count, pct} відсортований за частотою
        d = _orep.get(f"onb_{field}", {})
        base = _onb_resp or 1
        return [{"name": _ONB_LABELS.get(field, {}).get(k, k),
                 "count": v, "pct": round(v / base * 100)} for k, v in d.items()]
    _onb_funnel_list = [
        {"step": st, "name": _ONB_STEP_NAMES.get(st, f"крок {st}"), "reached": rc,
         "pct": round(rc / (_orep.get("onb_opened", 0) or 1) * 100)}
        for st, rc in sorted(_orep.get("onb_funnel", {}).items())
    ]

    # ── Рейтинг демо-фраз: «яка фраза найкраще залучає» ──────────────
    # Сумуємо demo_phrase_stats по всіх юзерах. Кожна фраза: скільки разів
    # її відкрили (demo_start), повторили голосом (demo_complete), пішли в
    # челендж (demo_to_challenge), кинули другу (demo_viral_click).
    _phrase_agg = {}
    for _st in db.values():
        if not isinstance(_st, dict):
            continue
        _dps = _st.get("demo_phrase_stats") or {}
        for _pid, _row in _dps.items():
            if not isinstance(_row, dict):
                continue
            _a = _phrase_agg.setdefault(_pid, {
                "starts": 0, "completes": 0, "to_challenge": 0, "viral": 0, "share": 0})
            _a["starts"]       += _row.get("demo_start", 0)
            _a["completes"]    += _row.get("demo_complete", 0)
            _a["to_challenge"] += _row.get("demo_to_challenge", 0)
            _a["viral"]        += _row.get("demo_viral_click", 0)
            _a["share"]        += _row.get("demo_share_public_click", 0)

    def _phrase_text_by_id(pid):
        import hashlib as _hl
        for _bst in db.values():
            if not isinstance(_bst, dict):
                continue
            _wp = _bst.get("week_phrases") or {}
            for _item in _wp.values():
                _t = _item.get("text") if isinstance(_item, dict) else _item
                if not _t:
                    continue
                _id = (_item.get("id") if isinstance(_item, dict) else None) \
                      or _hl.md5(str(_t).encode()).hexdigest()[:6]
                if _id == pid:
                    return str(_t)
        return pid

    _phrase_ranking = []
    for _pid, _a in _phrase_agg.items():
        _starts = _a["starts"] or 0
        _conv   = round(100 * _a["to_challenge"] / _starts, 1) if _starts else 0.0
        _viral  = round(100 * _a["viral"] / _starts, 1) if _starts else 0.0
        _phrase_ranking.append({
            "phrase_id": _pid, "text": _phrase_text_by_id(_pid),
            "starts": _starts, "completes": _a["completes"],
            "to_challenge": _a["to_challenge"], "viral": _a["viral"],
            "share": _a.get("share", 0),
            "conv_pct": _conv, "viral_pct": _viral,
        })
    _phrase_ranking.sort(key=lambda x: (x["conv_pct"], x["starts"]), reverse=True)

    # ── A/B заклику публічного шеру: сумуємо share_variant_stats ──────
    _variant_names = {
        "fear":       "Страх осуду / акцент",
        "years":      "Вчиш роками — заговоримо",
        "watcher":    "Дивишся контент — практикуй",
        "challenge":  "М'який виклик",
    }
    _variant_agg = {}
    for _st in db.values():
        if not isinstance(_st, dict):
            continue
        for _vid, _cnt in (_st.get("share_variant_stats") or {}).items():
            _variant_agg[_vid] = _variant_agg.get(_vid, 0) + _cnt
    _share_variants = sorted(
        ({"id": k, "name": _variant_names.get(k, k), "shares": v}
         for k, v in _variant_agg.items()),
        key=lambda x: x["shares"], reverse=True)

    # Собівартість AI. Рахуємо ОДИН раз — треба і панелі, і бухгалтерії.
    _ai_c = None if is_dev_only else build_ai_costs(
        db,
        prices     = {"basic":   float(BASIC_AFFILIATE_PRICE),
                      "premium": float(PREMIUM_PRICE_AFF)},
        skip_keys  = DB_SKIP_KEYS,
        is_premium = is_premium,
    )

    # ── Chainy: аномалії за 7 днів ────────────────────────────────
    # build_ai_costs показує ЗАГАЛЬНІ витрати. Тут — ПЕРСОНАЛЬНІ:
    # хто саме витрачає більше, ніж платить. Без цього збиткова людина
    # ховається в середньому по палаті.
    _chainy = {"total": 0, "losers": 0, "loss_month": 0.0, "top": []}
    try:
        from datetime import timedelta as _td
        _wk  = (datetime.now() - _td(days=7)).strftime("%Y-%m-%d")
        _rec = [e for e in (db.get("_chainy_anomalies") or []) if e.get("d", "") >= _wk]
        _by = {}
        for _e in _rec:
            _u = _e.get("uid", "?")
            _d = _by.setdefault(_u, {"days": 0, "max": 0, "cost": 0.0,
                                     "status": _e.get("status", "?")})
            _d["days"] += 1
            _d["max"]   = max(_d["max"], _e.get("count", 0))
            _d["cost"] += _e.get("cost", 0)

        _top = []
        for _u, _d in _by.items():
            _rev   = float(BASIC_AFFILIATE_PRICE) if _d["status"] == "paid" else 0.0
            _month = _d["cost"] / max(1, _d["days"]) * 30
            _lim   = _rev if _rev else 3.0
            _top.append({
                "uid":    _u,
                "status": _d["status"],
                "max":    _d["max"],
                "month":  round(_month, 2),
                "revenue": round(_rev, 2),
                "loss":   _month > _lim,      # 🔴 витрати > виручки
            })
        _top.sort(key=lambda x: x["month"], reverse=True)
        _losers = [t for t in _top if t["loss"]]
        _chainy = {
            "total":      len(_by),
            "losers":     len(_losers),
            "loss_month": round(sum(t["month"] for t in _losers), 2),
            "limit_paid": BASIC_LIMIT,
            "top":        _top[:10],
        }
    except Exception as _ce:
        logger.warning(f"chainy analytics: {_ce}")

    # ── Переходи станів Freemium → Basic / Freemium → None ──────────────
    # Запит власниці: бачити, скільки з тих, хто пройшов/кинув челендж,
    # реально купують Basic, а скільки "зависають" без плану — окремо
    # для органіки й для блогерського/реферального трафіку.
    # Той самий статус, що й у /buddy_status для мініапу (challenge_done) —
    # єдине джерело правди, не нове визначення.
    def _is_affiliate_user(s):
        # 🔴 БУЛО: s.get("source", "organic") — поле "source" ніде в стані
        # юзера не пишеться (перевірено grep по всьому bot.py), завжди
        # падало в дефолт "organic". Реальне джерело правди — get_source(),
        # та сама функція, що рахує ціни (get_prices) і показує знижку
        # в paywall.html. Один і той самий висновок скрізь у продукті.
        return get_source(s) != SOURCE_LANDING

    def _challenge_finished(s):
        cs = s.get("challenge_state") or {}
        return cs.get("status") in ("completed", "abandoned")

    _trans_raw = {
        "organic":   {"finished": 0, "to_basic": 0, "to_none": 0},
        "affiliate": {"finished": 0, "to_basic": 0, "to_none": 0},
    }
    for _s_tr in students:
        if not _challenge_finished(_s_tr):
            continue
        _bucket = "affiliate" if _is_affiliate_user(_s_tr) else "organic"
        _trans_raw[_bucket]["finished"] += 1
        if is_paid(_s_tr):
            _trans_raw[_bucket]["to_basic"] += 1
        else:
            _trans_raw[_bucket]["to_none"] += 1

    def _trans_rates(d):
        n = d["finished"] or 1
        return {
            "finished":   d["finished"],
            "to_basic":   d["to_basic"],
            "to_none":    d["to_none"],
            "basic_rate": round(d["to_basic"] / n * 100, 1),
            "none_rate":  round(d["to_none"] / n * 100, 1),
        }

    transitions = {
        "organic":   _trans_rates(_trans_raw["organic"]),
        "affiliate": _trans_rates(_trans_raw["affiliate"]),
    }

    return _web.json_response({
        "overview": {
            "total_users": total, "new_today": new_today,
            "new_7d": new_7d, "new_30d": new_30d,
            "active_today": active_today, "paid_users": paid_users,
            "trial_users": trial_users, "chain_breaks_today": chain_breaks_today,
            "avg_chain": avg_chain,
            "days_labels": days_labels,
            "registrations_daily": reg_daily,
            "active_daily": active_daily,
        },
        "retention": {
            "d1": d1_ret, "d7": d7_ret, "d30": d30_ret,
            "avg_sessions": avg_sessions,
            "cohorts": cohorts,
            "break_labels": break_labels,
            "break_data": break_data,
        },
        "funnel": {
            "registered": registered, "demo": demo_users_count,
            "trial": trial_count, "paid": paid_count,
            "avg_trial_chains": avg_trial_chains,
            "sources": sources_list,
        },
        # Freemium → Basic / Freemium → None, окремо органіка/афіліат.
        # Знімок на зараз (не подієвий лог) — рахується з challenge_state.status
        # + plan напряму з бази, так само, як усі інші метрики цього ендпоінту.
        "transitions": transitions,
        "nudge_ab": {
            "control": _ab_control,
            "treatment": _ab_treatment,
            "uplift_paid": _uplift_paid,
            "uplift_completion": _uplift_completion,
            "uplift_chain": _uplift_chain,
            "holdout_pct": NUDGE_HOLDOUT_PCT,
        },
        # Собівартість AI + маржа по тарифах. Ховаємо від розробника, як revenue.
        "ai_costs": None if is_dev_only else _ai_c,
        "chainy":   None if is_dev_only else _chainy,
        "_ai_unused": None if True else build_ai_costs(
            db,
            prices     = {"basic":   float(BASIC_AFFILIATE_PRICE),
                          "premium": float(PREMIUM_PRICE_AFF)},
            skip_keys  = DB_SKIP_KEYS,
            is_premium = is_premium,
        ),
        # Реферали: яке ПОСИЛАННЯ працює. Було тільки в /admin текстом.
        "refs": build_refs(db, skip_keys=DB_SKIP_KEYS),
        # Бухгалтерія: журнал платежів → P&L. Ховаємо від розробника.
        "finance": None if is_dev_only else build_finance(
            db,
            period                      = "month",
            blogger_commission          = BLOGGER_COMMISSION_BASIC,
            blogger_commission_premium  = BLOGGER_COMMISSION_PREMIUM,
            ai_cost                     = (_ai_c or {}).get("total_cost", 0),
        ),
        # 23.07 (H-03): LTV когортами по місяцю реєстрації. Ховаємо від
        # розробника — та сама причина, що й finance вище.
        "ltv_cohorts": None if is_dev_only else build_ltv_cohorts(db),
        "revenue": None if is_dev_only else {
            "mrr": mrr, "mrr_delta": mrr_delta,
            "revenue_month": revenue_month,
            "basic_count": basic_count, "premium_count": premium_count,
            "basic_price": float(BASIC_AFFILIATE_PRICE), "premium_price": float(PREMIUM_PRICE_AFF),
            "months_labels": months_labels,
            "revenue_monthly": revenue_monthly,
            "basic_monthly": basic_monthly,
            "premium_monthly": premium_monthly,
            "bloggers": bloggers_list,
        },
        "buddy": {
            "total_sessions": total_buddy_sessions,
            "sessions_today": buddy_today,
            "active_users": buddy_active,
            "avg_msgs_per_session": avg_msgs,
            "top_scenario": top_scenario,
            "top_scenarios": top_scenarios,
            "topic_popularity": topic_popularity,
            "feedback_good": feedback_good,
            "feedback_tips": feedback_tips,
            "demo_converted": demo_conv,
            "demo_users": demo_users_count,
            "days_labels": days_labels,
            "sessions_daily": buddy_sessions_daily,
        },
        "bloggers": None if is_dev_only else {
            "total_bloggers":     len(bloggers_dict),
            "total_paid_out":     total_paid_out,
            "pending_this_month": pending_this_month,
            "total_referred":     total_referred,
            "blogger_stats":      blogger_stats,
            "payouts_summary":    payouts_summary,
            "months":             blogger_months,
            "unpaid_all":         unpaid_all,
            "unpaid_all_total":   unpaid_all_total,
            # 23.07: ручний журнал виплат (ім'я/дата/сума, введені
            # власницею) — окремо від payouts_summary (те — автоматичне
            # НАРАХУВАННЯ). Стеля 100 — щоб не роздувати payload,
            # найновіші перші (get_payout_log вже сортує).
            "payout_log":         get_payout_log(db)[:100],
        },
        "is_dev": is_dev_only,
        # 23.07: метрика масштабування (Реєстр K-10) — дешевий сигнал
        # "чи наближаємось до стелі", не важке обчислення. total_keys
        # включає і юзерів, і службові "_"-ключі (DB_SKIP_KEYS) — тому
        # НЕ дорівнює точній кількості студентів, це орієнтир розміру.
        # cold_start_ms — None, якщо процес ще не робив холодне
        # читання з моменту рестарту (кеш уже теплий до першого запиту
        # адмінки) — це нормально, не помилка.
        "db_scale": {
            "total_keys":     len(db),
            "cold_start_ms":  _DB_LOAD_MS.get("value"),
        },
        "onboarding": {
            "opened": _orep.get("onb_opened", 0),
            "completed": _onb_resp,
            "completion_rate": _orep.get("onb_completion_rate", 0),
            "funnel": _onb_funnel_list,
            "goals": _onb_dist("goals"),
            "speaking_blocks": _onb_dist("speaking_blocks"),
            "tried_before": _onb_dist("tried_before"),
            "missing_before": _onb_dist("missing_before"),
            "fluent_means": _onb_dist("fluent_means"),
            "expectations": _onb_dist("expectations"),
            "time_per_day": _onb_dist("time_per_day"),
            "written_expectations": _orep.get("onb_expectations_other", [])[-30:],
            "written_missing": _orep.get("onb_missing_other", [])[-30:],
        },
        "diagnostic": {
            "done": _orep.get("diag_done", 0),
            "levels": _orep.get("diag_levels", {}),
            "avg_grammar": _orep.get("diag_avg_grammar", 0),
            "avg_words": _orep.get("diag_avg_words", 0),
            "speech_done": _orep.get("diag_speech_done", 0),
            "speech_rate": _orep.get("diag_speech_rate", 0),
            "top_gaps": _orep.get("diag_top_gaps", {}),
        },
        "actions": _build_actions_analytics(students, days_labels, days_keys),
        "students": _build_students_analytics(students, now, today_str, db),
        "cohorts": _build_cohorts_analytics(students, now, today_str),
        "situations": _build_situations_analytics(students),
        "challenge_funnel": _build_challenge_funnel_analytics(students),
        "phrase_ranking": _phrase_ranking,
        "share_variants": _share_variants,
        # ── BAE-контент: що учні РЕАЛЬНО практикують ─────────────────
        #    Відрізняється від phrase_ranking: той міряє ЗАЛУЧЕННЯ
        #    (хто прийшов за демо-посиланням), а це — ПРАКТИКУ
        #    (що зберігають і проговорюють вголос ті, хто вже всередині).
        #    Дані з лічильників db["_content_stats"] — не перебираємо БД.
        "content": _admin_content_stats(),
        # 🎛 Рубильники — живий стан + інструкція. Вкладка «Рубильники».
        "switches": _switches_state(),
        # 🚨 Журнал помилок — що зламалось. Вкладка «Помилки».
        "errors":   _errors_state(),
        # 📋 Журнал змін — що розробили. Вкладка «Журнал змін».
        "changes":  _changes_state(),
    }, headers=CORS_BUDDY)


def _build_challenge_funnel_analytics(students: list) -> dict:
    """
    📊 Крива відвалу по днях челенджу 1→7 (survivorship), окремо blogger/organic.

    Джерело — events_log (track_event). Рахуємо унікальних юзерів, які досягли
    кожного кроку. Кроки:
      start → day_done_1 … day_done_7 → finale_shown → offer_shown → paid.

    Так видно, НА ЯКОМУ ДНІ тече воронка — головне питання конверсії.

    Повертає для кожного flow (blogger/organic) + total:
      {
        "steps": [{"key","label","count","pct_of_start","drop_from_prev"}...],
        "started": N, "paid": M, "start_to_paid_pct": float
      }
    """
    def _events(s):
        # Durable-віхи (не витісняються 100-буфером) + events_log як доповнення.
        ms = s.get("challenge_milestones") or {}
        ev = s.get("events_log") or []
        keys = set(ms.keys())
        keys |= {e.get("e", "") for e in ev if isinstance(e, dict)}
        return keys

    def _is_paid(s):
        try:
            return bool(is_premium(s))
        except Exception:
            return bool(s.get("premium_until") or s.get("basic_until") or s.get("plan") in ("basic", "premium", "fluent"))

    # Порядок кроків воронки (label — людською мовою)
    # NB: нові кроки (метч Д5, кодова фраза) вставлені за таймінгом арки:
    #   метч — після done_5; фраза 7/7 — на фіналі (проксі доходимості до Д7).
    step_defs = [
        ("start",       "Стартував челендж"),
        ("done_1",      "День 1 завершив"),
        ("done_2",      "День 2 завершив"),
        ("done_3",      "День 3 завершив"),
        ("phrase_3",    "Зібрав 3/7 фрази"),
        ("done_4",      "День 4 завершив"),
        ("done_5",      "День 5 завершив"),
        ("match",       "Зробив спікінг-метч (Д5)"),
        ("done_6",      "День 6 завершив"),
        ("done_7",      "День 7 завершив"),
        ("phrase_full", "Зібрав фразу 7/7"),
        ("finale",      "Побачив фінал"),
        ("offer",       "Побачив оффер"),
        ("paid",        "Купив підписку"),
    ]

    def _is_demo(s):
        # demo-юзер: стартував organic-челендж, АЛЕ прийшов із demo-реклами
        return (s.get("traffic_source") == "demo")

    def _match(evset, s, step, flow):
        # Кожен крок → набір подій, що його підтверджують (з урахуванням flow)
        if step == "start":
            _has_blogger = "challenge_start_blogger" in evset
            _has_organic = "challenge_start_organic" in evset
            if flow == "blogger":
                return _has_blogger
            if flow == "demo":
                # demo = organic-старт + demo-мітка, АЛЕ не blogger (взаємовиключно)
                return _has_organic and not _has_blogger and _is_demo(s)
            if flow == "organic":
                # чиста органіка = organic-старт без demo-мітки і не blogger
                return _has_organic and not _has_blogger and not _is_demo(s)
            return _has_blogger or _has_organic
        if step.startswith("done_"):
            n = step.split("_")[1]
            return f"challenge_day_done_{n}" in evset
        if step == "phrase_3":
            # Зібрано щонайменше 3 слова (будь-яка з подій _3.._7, або фраза завершена)
            if "code_phrase_completed" in evset:
                return True
            return any(f"code_word_collected_{i}" in evset for i in (3, 4, 5, 6, 7))
        if step == "phrase_full":
            return "code_phrase_completed" in evset
        if step == "match":
            return "challenge_match_free" in evset
        if step == "finale":
            return "challenge_finale_shown" in evset
        if step == "offer":
            if flow == "blogger":
                return "challenge_offer_shown_blogger" in evset
            if flow in ("organic", "demo"):
                # demo проходить organic-челендж → бачить organic-оффер
                return "challenge_offer_shown_organic" in evset
            return any(k.startswith("challenge_offer_shown_") for k in evset)
        if step == "paid":
            return _is_paid(s)
        return False

    def _flow_of(s):
        return (s.get("challenge_state") or {}).get("source") or s.get("source") or ""

    def _build_for(flow):
        # Беремо лише тих, хто взагалі стартував відповідний flow
        pool = []
        for s in students:
            if not isinstance(s, dict):
                continue
            ev = _events(s)
            started = _match(ev, s, "start", flow)
            if started:
                pool.append((s, ev))
        started_n = len(pool)

        steps = []
        prev = None
        for key, label in step_defs:
            cnt = sum(1 for (s, ev) in pool if _match(ev, s, key, flow))
            pct = round(cnt / started_n * 100, 1) if started_n else 0.0
            drop = None if prev is None else (round((prev - cnt) / prev * 100, 1) if prev else 0.0)
            steps.append({
                "key": key, "label": label, "count": cnt,
                "pct_of_start": pct, "drop_from_prev": drop,
            })
            prev = cnt

        paid_n = steps[-1]["count"]
        # Швидкі проксі для маркетолога (не ламають існуючий формат steps)
        def _step_count(k):
            return next((st["count"] for st in steps if st["key"] == k), 0)
        _d5 = _step_count("done_5")
        _match_cnt = _step_count("match")
        _full = _step_count("phrase_full")
        _d7 = _step_count("done_7")
        return {
            "steps": steps,
            "started": started_n,
            "paid": paid_n,
            "start_to_paid_pct": round(paid_n / started_n * 100, 1) if started_n else 0.0,
            # ── нові проксі-метрики ──
            "match_rate_of_d5": round(_match_cnt / _d5 * 100, 1) if _d5 else 0.0,
            "phrase_full_of_start": round(_full / started_n * 100, 1) if started_n else 0.0,
            "phrase_full_of_d7": round(_full / _d7 * 100, 1) if _d7 else 0.0,
        }

    # ── Охоплення персоналізації (situation-нудж Д2–5) — ефект «діри 1» ──
    def _pers_cov():
        elig = shown = 0
        for s in students:
            if not isinstance(s, dict):
                continue
            ev = _events(s)
            # eligible = стартував і має відповіді quiz
            started = ("challenge_start_blogger" in ev) or ("challenge_start_organic" in ev)
            has_sits = bool((s.get("challenge_state") or {}).get("discomfort_situations")
                            or s.get("discomfort_situations"))
            if started and has_sits:
                elig += 1
                if any(f"situation_nudge_shown_{d}" in ev for d in (2, 3, 4, 5)):
                    shown += 1
        return {
            "eligible": elig,
            "shown_at_least_once": shown,
            "coverage_pct": round(shown / elig * 100, 1) if elig else 0.0,
        }

    # ── Friend-реферал: віральна петля (запросив → друг стартував → дійшов) ──
    def _friend_metrics():
        invited = joined = reached = 0
        for s in students:
            if not isinstance(s, dict):
                continue
            ev = _events(s)
            if "friend_invite_shown_d6" in ev:
                invited += 1
            if s.get("friend_of"):  # цей юзер прийшов як друг
                joined += 1
                if s.get("friend_bonus_stage") == "big_given":
                    reached += 1
        return {
            "invited_shown": invited,      # скільком показали запрошення (Д6)
            "friends_joined": joined,      # скільки друзів реально стартувало
            "friends_reached_d5": reached, # скільки друзів дійшли до Д5 (бонус)
            "join_to_reach_pct": round(reached / joined * 100, 1) if joined else 0.0,
        }

    # ── Demo-воронка: TikTok холодний трафік (start → complete → signup → challenge) ──
    def _demo_metrics():
        started = completed = signup = to_challenge = 0
        for s in students:
            if not isinstance(s, dict):
                continue
            ev = _events(s)
            if "demo_start" in ev:
                started += 1
            if "demo_complete" in ev:
                completed += 1
            if "demo_signup_click" in ev:
                signup += 1
            # demo-юзер, що дійшов до старту челенджу
            if ("demo_start" in ev) and (
                "challenge_start_organic" in ev or "challenge_start_blogger" in ev):
                to_challenge += 1
        return {
            "started": started,
            "completed": completed,
            "signup_click": signup,
            "reached_challenge": to_challenge,
            "complete_to_signup_pct": round(signup / completed * 100, 1) if completed else 0.0,
            "demo_to_challenge_pct": round(to_challenge / started * 100, 1) if started else 0.0,
        }

    def _winback_metrics():
        # Win-back воронка: показ оффера (offered) → оплата у 48-год вікні (paid).
        # Premium-кнопка = якір; premium_share показує, чи її реально беруть.
        o_bl = o_or = 0
        pb_bl = pb_or = pp_bl = pp_or = 0
        for s in students:
            if not isinstance(s, dict):
                continue
            ev = _events(s)
            if "winback_offered_blogger" in ev: o_bl += 1
            if "winback_offered_organic" in ev: o_or += 1
            if "winback_paid_basic_blogger"   in ev: pb_bl += 1
            if "winback_paid_basic_organic"   in ev: pb_or += 1
            if "winback_paid_premium_blogger" in ev: pp_bl += 1
            if "winback_paid_premium_organic" in ev: pp_or += 1

        offered_total = o_bl + o_or
        paid_basic    = pb_bl + pb_or
        paid_premium  = pp_bl + pp_or
        paid_total    = paid_basic + paid_premium

        def _pct(a, b):
            return round(a / b * 100, 1) if b else 0.0

        return {
            "offered_total":   offered_total,
            "offered_blogger": o_bl,
            "offered_organic": o_or,
            "paid_total":      paid_total,
            "paid_basic":      paid_basic,
            "paid_premium":    paid_premium,
            "conv_pct":        _pct(paid_total, offered_total),
            "conv_blogger":    _pct(pb_bl + pp_bl, o_bl),
            "conv_organic":    _pct(pb_or + pp_or, o_or),
            # головна метрика якоря: частка Premium серед усіх win-back-оплат
            "premium_share":   _pct(paid_premium, paid_total),
        }

    return {
        "total":   _build_for("total"),
        "blogger": _build_for("blogger"),
        "organic": _build_for("organic"),
        "demo":    _build_for("demo"),
        "personalization": _pers_cov(),
        "friend_referral": _friend_metrics(),
        "demo_metrics": _demo_metrics(),
        "winback": _winback_metrics(),
    }


def _build_situations_analytics(students: list) -> dict:
    """
    ⭐ Агрегація ситуацій дискомфорту (quiz дня 1 челенджу).

    За цими даними будується ПОДАРУНОК — уроки під найзатребуваніші ситуації.
    Рахуємо по унікальних юзерах, які пройшли quiz.

    Повертає:
      {
        "total_respondents": N,          # скільки людей пройшло quiz
        "total_selections": M,           # сумарно позначок (людина може обрати кілька)
        "avg_per_user": float,           # середня к-сть ситуацій на людину
        "rows": [                        # відсортовано за спаданням count
          {"key","label","emoji","count","pct"}, ...
        ],
      }
    """
    try:
        from challenge_content import DISCOMFORT_SITUATIONS, DISCOMFORT_BY_KEY
    except Exception:
        return {"total_respondents": 0, "total_selections": 0,
                "avg_per_user": 0, "rows": []}

    counts = {item["key"]: 0 for item in DISCOMFORT_SITUATIONS}
    respondents = 0
    total_selections = 0

    for s in students:
        if not isinstance(s, dict):
            continue
        # Джерело: верхній рівень (дзеркало) або challenge_state
        sits = s.get("discomfort_situations")
        if not sits:
            cstate = s.get("challenge_state") or {}
            sits = cstate.get("discomfort_situations")
        if not sits:
            continue

        # Унікалізуємо на випадок дублів; рахуємо лише відомі ключі
        picked = [k for k in dict.fromkeys(sits) if k in counts]
        if not picked:
            continue

        respondents += 1
        for k in picked:
            counts[k] += 1
            total_selections += 1

    # Формуємо рядки (label з emoji, % від респондентів)
    rows = []
    for item in DISCOMFORT_SITUATIONS:
        c = counts.get(item["key"], 0)
        pct = round(c / respondents * 100, 1) if respondents else 0.0
        rows.append({
            "key":   item["key"],
            "label": item["label"],
            "emoji": item["emoji"],
            "count": c,
            "pct":   pct,
        })
    rows.sort(key=lambda r: r["count"], reverse=True)

    avg = round(total_selections / respondents, 1) if respondents else 0.0

    return {
        "total_respondents": respondents,
        "total_selections":  total_selections,
        "avg_per_user":      avg,
        "rows":              rows,
    }


def _safe_events_log(s: dict, limit: int = 20) -> list:
    """
    Останні N подій студента для картки (admin_analytics), нове зверху.
    Захищено від пошкоджених даних: якщо events_log не список (число,
    dict через збій чи ручне редагування БД) — повертає [] замість
    падіння, яке обвалило б увесь запит для ВСІХ студентів одразу.
    """
    try:
        log = s.get("events_log")
        if not isinstance(log, list):
            return []
        return list(reversed(log[-limit:]))
    except Exception:
        return []


def _safe_challenge_debug(s: dict):
    """
    Текстовий зріз стану челенджу для картки студента (admin_analytics).
    Повертає None, якщо студент ніколи не торкався челенджу — щоб
    порожній блок не засмічував картку тих, хто його не проходив.
    """
    if not s.get("challenge_state"):
        return None
    try:
        import challenge_voice as _cv
        return _cv.debug_state(s)
    except Exception:
        return None


def _build_students_analytics(students: list, now, today_str: str, db: dict = None) -> dict:
    """
    [Phase 1] Трекшн учнів: успіхи, рівні, проблемні.
    Мета — «вести учнів до результату за руку».

    db (опційно, 23.07): якщо передано — рахуємо реальний розмір гілки
    рефералів (build_referral_tree_sizes, та сама функція, що вже рахує
    переможця марафону монологів, A-24). Опційно, з дефолтом None і
    fallback на 0, щоб виклики без db (якщо такі десь лишились) не ламались.

    Повертає:
      level_distribution — скільки учнів на кожному A1→C2 (+ % прогресу всередині)
      stuck              — застрягли (низький % прогресу + давно не заходили)
      churned            — кинули (давно не заходили)
      unpaid             — trial завершується/завершився, не платять
      progressing        — хто рухається (є level_history з переходами)
      summary            — агрегати
    """
    from datetime import datetime as _dt, timedelta as _td

    # 23.07 (H-07/H-10): розмір гілки рефералів для картки студента —
    # та сама функція, що рахує переможця марафону монологів (A-24),
    # тепер видно й тут, без окремої команди /award_marathon top.
    _ref_sizes = build_referral_tree_sizes(db) if db is not None else {}

    # 23.07 (H-03/H-07): LTV кожного студента, порахований ОДНИМ проходом
    # по всьому журналу _payments (не викликаємо build_student_ltv у циклі
    # по students — це було б O(N студентів × M платежів), тут O(M) один раз).
    _ltv_by_uid = {}
    if db is not None:
        for _pay in (db.get("_payments", []) or []):
            _u = str(_pay.get("uid", ""))
            _ltv_by_uid[_u] = _ltv_by_uid.get(_u, 0.0) + float(_pay.get("amount", 0) or 0)
    _payments_journal_from = ((db.get("_payments", []) or [{}])[0].get("date")
                               if db is not None and db.get("_payments") else None)

    def _last_active(s):
        v = s.get("last_date")
        return str(v)[:10] if v else ""

    def _reg(s):
        v = s.get("registered_at")
        return str(v)[:10] if v else ""

    def _days_since(date_str):
        if not date_str:
            return None
        try:
            return (now - _dt.strptime(str(date_str)[:10], "%Y-%m-%d")).days
        except Exception:
            return None

    def _name(s):
        return s.get("name") or s.get("username") or "—"

    def _uid_of(s):
        return s.get("uid") or s.get("id") or s.get("user_id") or ""

    def _level_pct(s):
        """% засвоєних тем всередині поточного рівня."""
        lvl = s.get("level", "A1")
        topics = CEFR_GRAMMAR.get(lvl, [])
        if not topics:
            return 0
        mastered = s.get("mastered_grammar", [])
        return round(len([t for t in mastered if t in topics]) / len(topics) * 100)

    # ── Пороги (легко міняти) ──
    STUCK_INACTIVE_DAYS = 7    # «давно не заходив»
    STUCK_PROGRESS_MAX  = 20   # «низький % прогресу»
    CHURN_DAYS          = 14   # «кинув»

    # ── Розподіл по рівнях ──
    level_dist = {lvl: {"count": 0, "sum_pct": 0} for lvl in LEVELS_ORDER}
    for s in students:
        lvl = s.get("level", "A1")
        if lvl not in level_dist:
            level_dist[lvl] = {"count": 0, "sum_pct": 0}
        level_dist[lvl]["count"] += 1
        level_dist[lvl]["sum_pct"] += _level_pct(s)

    level_distribution = []
    for lvl in LEVELS_ORDER:
        d = level_dist.get(lvl, {"count": 0, "sum_pct": 0})
        cnt = d["count"]
        level_distribution.append({
            "level":     lvl,
            "name":      LEVEL_NAMES.get(lvl, lvl),
            "count":     cnt,
            "avg_pct":   round(d["sum_pct"] / cnt) if cnt else 0,
        })

    # ── Проблемні списки ──
    stuck, churned, unpaid, progressing, all_list = [], [], [], [], []

    for s in students:
        la          = _last_active(s)
        inactive    = _days_since(la)
        pct         = _level_pct(s)
        lvl         = s.get("level", "A1")
        hist        = s.get("level_history", [])
        transitions = max(0, len([h for h in hist if h.get("source") in ("levelup", "placement_retest")]))

        # ── Активність за часом (23.07, H-07/H-10) — не претендує на
        # ідеальну точність (плеєр можна тримати відкритим не слухаючи),
        # тому подаємо ЯК СКЛАДЕНИЙ ENGAGEMENT SCORE з розбивкою по
        # джерелах, а не одне видумане "чесне" число. Джерела:
        #  • speaking_seconds_total — точно, Telegram дає duration
        #    кожного voice/audio/video студента (handle_voice/handle_video)
        #  • player_minutes_total   — точно, playback_sec з player.html
        #    (handle_session_end), вже рахувалось і раніше, просто не
        #    показувалось у картці
        #  • chain — проксі кількості завершених активностей (не часу)
        _speaking_sec = s.get("speaking_seconds_total", 0)
        _player_min   = s.get("player_minutes_total", 0)
        # 23.07 (I-05): Chainy-час НЕ підмішуємо у practice_minutes_total
        # (той рахує лише ТОЧНІ джерела) — окреме поле з явним прапорцем,
        # скільки з нього оцінка, а не факт. Адмінка мусить показати різницю.
        _chainy_sec  = s.get("chainy_seconds_total", 0)
        _chainy_est  = s.get("chainy_seconds_estimated", 0)
        # 23.07: методичний паритет з карткою блогера — той самий
        # compute_vocab_volume, що вже рахує "слів на учня" для
        # _blogger_progress_summary, тепер видно й тут, по кожному
        # студенту окремо (раніше цього поля не було в картці адміна
        # взагалі — адмін бачив менше методики, ніж блогер).
        try:
            _words_count = sum(compute_vocab_volume(s.get("srs_words", {})).values())
        except Exception:
            _words_count = 0
        card = {
            "uid":         _uid_of(s),
            "username":    s.get("username", "") or "",
            "name":        _name(s),
            "level":       lvl,
            "level_name":  LEVEL_NAMES.get(lvl, lvl),
            "progress":    pct,
            "last_active": la,
            "inactive_days": inactive if inactive is not None else -1,
            "lessons":     len(s.get("done_lessons", [])),
            "chain":       chain_links(s),
            "plan":        ("premium" if is_premium_only(s) else "basic" if is_basic(s) else
                            "trial" if is_in_trial(s) else "free"),
            "source":      s.get("source", "organic") or "organic",
            "transitions": transitions,
            "speaking_minutes":  round(_speaking_sec / 60, 1),
            "speaking_clips":    s.get("speaking_clips_total", 0),
            "player_minutes":    _player_min,
            "practice_minutes_total": round(_speaking_sec / 60 + _player_min, 1),
            "words_count":       _words_count,
            "chainy_minutes":         round(_chainy_sec / 60, 1),
            "chainy_estimated_pct":   round(_chainy_est / _chainy_sec * 100) if _chainy_sec else 0,
            "referrals_count":   _ref_sizes.get(str(_uid_of(s)), 0),
            "ltv":               round(_ltv_by_uid.get(str(_uid_of(s)), 0.0), 2),
            "ltv_journal_from":  _payments_journal_from,
            # 20.07: «шлях студента» — власниця прямо просила бачити кліки,
            # переходи, де застряг, не заходячи в сиру БД. events_log уже
            # писався для аналітики (analytics.py:track_event), просто ніде
            # не показувався по одному студенту. Останні 20 (не всі 100 —
            # щоб не роздувати payload на десятки студентів одразу), нове
            # зверху для зручності читання.
            "events_log":  _safe_events_log(s),
            # Стан челенджу текстом — те саме, що видає /challenge_state,
            # але прямо в картці, без окремої команди й ручного вводу uid.
            "challenge_debug": _safe_challenge_debug(s),
        }

        # ЗАСТРЯГ = низький % прогресу + давно не заходив (за вибором адміна)
        if (inactive is not None and inactive >= STUCK_INACTIVE_DAYS
                and pct <= STUCK_PROGRESS_MAX
                and (inactive < CHURN_DAYS)):  # ще не churn, але вже застряг
            stuck.append(card)

        # КИНУВ = дуже давно не заходив
        if inactive is not None and inactive >= CHURN_DAYS:
            churned.append(card)

        # НЕ ПЛАТЯТЬ = trial добіг/добігає, не premium/basic
        if (not is_premium(s)) and (not is_in_trial(s)):
            # був активний колись, але не оплатив
            if s.get("done_lessons") or s.get("buddy_stats") or hist:
                unpaid.append(card)

        # УСІ = повний список незалежно від категорії — щоб благополучний
        # студент, який не потрапляє в жодну з 4 проблемних груп, теж мав
        # рядок для кліку (20.07, прямий запит власниці).
        all_list.append(card)

        # РУХАЄТЬСЯ = мав хоч один перехід рівня
        if transitions >= 1:
            card2 = dict(card)
            card2["history"] = [
                {"level": h.get("level"), "date": h.get("date"),
                 "days_on_prev": h.get("days_on_prev", 0), "source": h.get("source", "")}
                for h in hist
            ]
            progressing.append(card2)

    # Сортування: найпроблемніші зверху
    stuck.sort(key=lambda c: (c["progress"], -c["inactive_days"]))
    churned.sort(key=lambda c: -c["inactive_days"])
    unpaid.sort(key=lambda c: -c["inactive_days"] if c["inactive_days"] >= 0 else 0)
    progressing.sort(key=lambda c: -c["transitions"])
    all_list.sort(key=lambda c: (c["name"] or "").lower())

    # ── Середній час на рівень (з level_history, source=levelup) ──
    days_per_level = {}  # from_level -> [days...]
    for s in students:
        for h in s.get("level_history", []):
            if h.get("source") == "levelup" and h.get("from_level"):
                fl = h["from_level"]
                dp = h.get("days_on_prev")
                if isinstance(dp, (int, float)) and dp > 0:
                    days_per_level.setdefault(fl, []).append(dp)
    avg_days_per_level = [
        {"level": lvl, "avg_days": round(sum(days_per_level[lvl]) / len(days_per_level[lvl])),
         "n": len(days_per_level[lvl])}
        for lvl in LEVELS_ORDER if lvl in days_per_level
    ]

    total = len(students)
    ever_progressed = sum(1 for s in students
                          if any(h.get("source") == "levelup" for h in s.get("level_history", [])))

    return {
        "summary": {
            "total":            total,
            "stuck":            len(stuck),
            "churned":          len(churned),
            "unpaid":           len(unpaid),
            "progressing":      len(progressing),
            "ever_progressed":  ever_progressed,
            "stuck_inactive_days": STUCK_INACTIVE_DAYS,
            "stuck_progress_max":  STUCK_PROGRESS_MAX,
            "churn_days":          CHURN_DAYS,
        },
        "level_distribution": level_distribution,
        "avg_days_per_level": avg_days_per_level,
        "stuck":              stuck[:100],
        "churned":            churned[:100],
        "unpaid":             unpaid[:100],
        "progressing":        progressing[:100],
        "all":                all_list,
    }


def _build_cohorts_analytics(students: list, now, today_str: str) -> dict:
    """
    [Phase 2] Когорти результату — чи система доводить учнів до результату,
    і чи стає це краще з часом.

    Best practice: міряємо ПРОГРЕС РІВНЯ (outcome), не лише втримання.
    Групуємо за місяцем реєстрації, дивимось % що дійшли до A2/B1/B2+
    та середній/медіанний час на кожен перехід рівня.

    ВАЖЛИВО (чесність даних): level_history почали писати з Phase 0.
    Старі акаунти можуть не мати історії переходів → позначаємо когорти
    як 'tracked' (є дані про переходи) чи ні, і рахуємо time-to-result
    ТІЛЬКИ по записах source='levelup' (реальні заміряні переходи).
    """
    from datetime import datetime as _dt, timedelta as _td
    import statistics as _stats

    LEVEL_IDX = {lvl: i for i, lvl in enumerate(LEVELS_ORDER)}

    def _reg_month(s):
        v = s.get("registered_at", "")
        return str(v)[:7] if v else ""   # YYYY-MM

    def _cur_idx(s):
        return LEVEL_IDX.get(s.get("level", "A1"), 0)

    def _hist(s):
        return s.get("level_history", []) or []

    def _reached_idx(s):
        """
        Найвищий рівень, якого учень БУДЬ-КОЛИ досягав.
        Беремо max(поточний рівень, максимум з історії) — навіть якщо
        людина зробила ретест-даунгрейд, факт досягнення зберігається.
        """
        idxs = [_cur_idx(s)]
        for h in _hist(s):
            idxs.append(LEVEL_IDX.get(h.get("level", "A1"), 0))
        return max(idxs) if idxs else 0

    def _has_tracked_levelup(s):
        return any(h.get("source") == "levelup" for h in _hist(s))

    # ── Місячні когорти (останні 8 місяців) ──
    months = []
    for i in range(7, -1, -1):
        # перше число місяця i місяців тому
        y = now.year
        m = now.month - i
        while m <= 0:
            m += 12
            y -= 1
        months.append(f"{y:04d}-{m:02d}")

    cohorts = []
    for ym in months:
        members = [s for s in students if _reg_month(s) == ym]
        n = len(members)
        # скільки місяців тому стартувала когорта (для "ще рано" логіки)
        try:
            cohort_dt = _dt.strptime(ym + "-01", "%Y-%m-%d")
            months_elapsed = (now.year - cohort_dt.year) * 12 + (now.month - cohort_dt.month)
        except Exception:
            months_elapsed = 0

        if n == 0:
            cohorts.append({
                "month": ym, "size": 0,
                "reached_a2_pct": None, "reached_b1_pct": None, "reached_b2plus_pct": None,
                "leveled_up_pct": None, "tracked_pct": 0, "months_elapsed": months_elapsed,
            })
            continue

        reached_a2 = sum(1 for s in members if _reached_idx(s) >= LEVEL_IDX["A2"])
        reached_b1 = sum(1 for s in members if _reached_idx(s) >= LEVEL_IDX["B1"])
        reached_b2 = sum(1 for s in members if _reached_idx(s) >= LEVEL_IDX["B2"])
        # "leveled up" = піднявся хоч на 1 рівень від старту.
        # Старт визначаємо з першого запису історії (placement), інакше A1.
        leveled = 0
        for s in members:
            h = _hist(s)
            start_idx = LEVEL_IDX.get(h[0].get("level", "A1"), 0) if h else LEVEL_IDX.get("A1", 0)
            if _reached_idx(s) > start_idx:
                leveled += 1
        tracked = sum(1 for s in members if _has_tracked_levelup(s) or _hist(s))

        cohorts.append({
            "month":              ym,
            "size":               n,
            "reached_a2_pct":     round(reached_a2 / n * 100),
            "reached_b1_pct":     round(reached_b1 / n * 100),
            "reached_b2plus_pct": round(reached_b2 / n * 100),
            "leveled_up_pct":     round(leveled / n * 100),
            "tracked_pct":        round(tracked / n * 100),
            "months_elapsed":     months_elapsed,
        })

    # ── Level-up funnel (survivorship по всій базі) ──
    # Скільки учнів БУДЬ-КОЛИ досягали кожного рівня.
    total = max(len(students), 1)
    funnel = []
    for lvl in LEVELS_ORDER:
        cnt = sum(1 for s in students if _reached_idx(s) >= LEVEL_IDX[lvl])
        funnel.append({
            "level": lvl,
            "name":  LEVEL_NAMES.get(lvl, lvl),
            "users": cnt,
            "pct":   round(cnt / total * 100),
        })

    # ── Time-to-result: медіана/середнє днів на кожен перехід ──
    # ТІЛЬКИ по реально заміряних переходах (source='levelup', days_on_prev>0).
    trans_days = {}  # from_level -> [days...]
    for s in students:
        for h in _hist(s):
            if h.get("source") == "levelup" and h.get("from_level"):
                dp = h.get("days_on_prev")
                if isinstance(dp, (int, float)) and dp > 0:
                    trans_days.setdefault(h["from_level"], []).append(dp)

    time_to_result = []
    for lvl in LEVELS_ORDER:
        arr = trans_days.get(lvl, [])
        if arr:
            time_to_result.append({
                "from_level": lvl,
                "to_level":   LEVELS_ORDER[LEVEL_IDX[lvl] + 1] if LEVEL_IDX[lvl] + 1 < len(LEVELS_ORDER) else lvl,
                "median_days": round(_stats.median(arr)),
                "avg_days":    round(sum(arr) / len(arr)),
                "n":           len(arr),
            })

    # ── Summary ──
    ever_leveled = sum(1 for s in students if _has_tracked_levelup(s))
    reached_b1_total = sum(1 for s in students if _reached_idx(s) >= LEVEL_IDX["B1"])
    # Скільки взагалі мають хоч якусь історію рівнів (покриття трекінгом)
    with_history = sum(1 for s in students if _hist(s))

    return {
        "summary": {
            "total":            len(students),
            "ever_leveled_up":  ever_leveled,
            "reached_b1_total": reached_b1_total,
            "reached_b1_pct":   round(reached_b1_total / total * 100),
            "tracking_coverage_pct": round(with_history / total * 100),
        },
        "cohorts":        cohorts,
        "funnel":         funnel,
        "time_to_result": time_to_result,
    }


def _build_actions_analytics(students: list, days_labels: list, days_keys: list) -> dict:
    """Повна аналітика дій юзерів — 10 метрик."""
    from collections import Counter
    from datetime import datetime as _dt, timedelta as _td

    today = _dt.now().strftime("%Y-%m-%d")

    # ── 1. Топ кнопок ──
    total_counts = Counter()
    for s in students:
        for btn, cnt in s.get("button_counts", {}).items():
            total_counts[btn] += cnt
    top_buttons = [{"name": b, "count": c} for b, c in total_counts.most_common(20)]

    # ── 2. Активність по годинах ──
    hour_counts = [0] * 24
    for s in students:
        for e in s.get("button_log", [])[-200:]:
            try:
                h = int(e.get("ts","").split(" ")[1].split(":")[0])
                hour_counts[h] += 1
            except Exception:
                pass

    # ── 3. Дії по днях ──
    day_counts = []
    for dk in days_keys:
        cnt = sum(sum(1 for e in s.get("button_log",[]) if e.get("date")==dk) for s in students)
        day_counts.append(cnt)

    # ── 4. Feature usage ──
    total = max(len(students), 1)
    lesson_users  = sum(1 for s in students if "урок_дня"    in s.get("button_counts", {}))
    chainy_users  = sum(1 for s in students if "chainy"       in s.get("button_counts", {}))
    vocab_users   = sum(1 for s in students if "словник"      in s.get("button_counts", {}))
    profile_users = sum(1 for s in students if "мій_профіль" in s.get("button_counts", {}))
    feature_usage = [
        {"name": "▶️ Урок дня",   "users": lesson_users,  "pct": round(lesson_users/total*100)},
        {"name": "🤖 Chainy",      "users": chainy_users,  "pct": round(chainy_users/total*100)},
        {"name": "📚 Словник",     "users": vocab_users,   "pct": round(vocab_users/total*100)},
        {"name": "👤 Мій профіль", "users": profile_users, "pct": round(profile_users/total*100)},
    ]

    # ── 5. Drop-off точки ──
    did_lesson   = sum(1 for s in students if s.get("done_lessons"))
    did_monologue= sum(1 for s in students if s.get("scores"))
    did_chainy   = sum(1 for s in students if s.get("buddy_stats",{}).get("total_messages",0) > 0)
    did_vocab    = sum(1 for s in students if s.get("mined_sentences"))
    dropoff = [
        {"step": "Зареєструвались",    "users": total,        "pct": 100},
        {"step": "Зробили урок",        "users": did_lesson,   "pct": round(did_lesson/total*100)},
        {"step": "Записали монолог",    "users": did_monologue,"pct": round(did_monologue/total*100)},
        {"step": "Говорили з Chainy",   "users": did_chainy,  "pct": round(did_chainy/total*100)},
        {"step": "Зберегли слово",      "users": did_vocab,    "pct": round(did_vocab/total*100)},
    ]

    # ── 6. Session depth distribution ──
    depth_dist = Counter()
    for s in students:
        for sess in s.get("session_depth_log", []):
            d = sess.get("depth", 1)
            bucket = "1" if d == 1 else "2-3" if d <= 3 else "4-6" if d <= 6 else "7+"
            depth_dist[bucket] += 1
    session_depth = [{"bucket": b, "count": depth_dist.get(b, 0)} for b in ["1","2-3","4-6","7+"]]

    # ── 7. Час до першого уроку (в годинах) ──
    hours_list = [s.get("hours_to_first_lesson") for s in students if s.get("hours_to_first_lesson") is not None]
    avg_hours_to_first = round(sum(hours_list)/len(hours_list), 1) if hours_list else None
    fast_activations   = sum(1 for h in hours_list if h <= 1)   # < 1 год
    slow_activations   = sum(1 for h in hours_list if h > 24)   # > 24 год

    # ── 8. Feature discovery (median days to first use) ──
    def _days_from_reg(s, field):
        reg = s.get("registered_at","")[:10]
        first = s.get(field,"")[:10]
        if not reg or not first: return None
        try:
            return (_dt.strptime(first,"%Y-%m-%d") - _dt.strptime(reg,"%Y-%m-%d")).days
        except: return None

    chainy_days  = [d for s in students if (d:=_days_from_reg(s,"first_chainy_date")) is not None]
    vocab_days   = [d for s in students if (d:=_days_from_reg(s,"first_vocab_date"))  is not None]
    profile_days = [d for s in students if (d:=_days_from_reg(s,"first_profile_date")) is not None]

    def _median(lst):
        if not lst: return None
        s = sorted(lst)
        m = len(s)//2
        return s[m] if len(s)%2 else round((s[m-1]+s[m])/2, 1)

    feature_discovery = [
        {"feature": "🤖 Chainy",      "median_days": _median(chainy_days),  "users": len(chainy_days)},
        {"feature": "📚 Словник",     "median_days": _median(vocab_days),   "users": len(vocab_days)},
        {"feature": "👤 Мій профіль", "median_days": _median(profile_days), "users": len(profile_days)},
    ]

    # ── 9. Chainy conversation depth ──
    buddy_msgs = [s.get("buddy_stats",{}).get("total_messages",0) for s in students if s.get("buddy_stats")]
    avg_buddy_msgs = round(sum(buddy_msgs)/len(buddy_msgs), 1) if buddy_msgs else 0
    deep_users     = sum(1 for m in buddy_msgs if m >= 10)
    shallow_users  = sum(1 for m in buddy_msgs if 0 < m < 3)

    # ── 10. Correlation: активність → конверсія ──
    def _conv_rate(filter_fn):
        filtered = [s for s in students if filter_fn(s)]
        if not filtered: return {"users": 0, "paid": 0, "pct": 0}
        paid_cnt = sum(1 for s in filtered if is_premium(s))
        return {"users": len(filtered), "paid": paid_cnt, "pct": round(paid_cnt/len(filtered)*100)}

    correlations = [
        {"segment": "7+ уроків",          **_conv_rate(lambda s: len(s.get("done_lessons",[])) >= 7)},
        {"segment": "5+ розмов Chainy",   **_conv_rate(lambda s: s.get("buddy_stats",{}).get("total_sessions",0) >= 5)},
        {"segment": "10+ слів у словнику", **_conv_rate(lambda s: len(s.get("mined_sentences",[])) >= 10)},
        {"segment": "Chain 7+ днів",       **_conv_rate(lambda s: s.get("streak_days",0) >= 7)},
        {"segment": "0 уроків",            **_conv_rate(lambda s: not s.get("done_lessons"))},
    ]

    return {
        "top_buttons":       top_buttons,
        "hour_labels":       [f"{h}:00" for h in range(24)],
        "hour_data":         hour_counts,
        "days_labels":       days_labels,
        "days_data":         day_counts,
        "feature_usage":     feature_usage,
        "dropoff":           dropoff,
        "session_depth":     session_depth,
        "avg_hours_to_first":avg_hours_to_first,
        "fast_activations":  fast_activations,
        "slow_activations":  slow_activations,
        "feature_discovery": feature_discovery,
        "avg_buddy_msgs":    avg_buddy_msgs,
        "deep_chainy_users": deep_users,
        "shallow_chainy_users": shallow_users,
        "correlations":      correlations,
        "checkin":           _build_checkin_analytics(students),
        "features":          _build_features_analytics(students),
    }


