import hmac as _hmac_buddy, hashlib as _hashlib_buddy
import urllib.parse as _urlp_buddy

PIXABAY_API_KEY      = os.environ.get("PIXABAY_API_KEY", "")
# ══════════════════════════════════════════════════════════════════
# ЛІМІТИ CHAINY — ЦЕ ЗАПОБІЖНИК, А НЕ ОБМЕЖЕННЯ ЛЮДЕЙ
#
# ПОРАХОВАНО (Haiku 4.5, реальні max_tokens із коду):
#   одне повідомлення Chainy ≈ $0.0011 (вхід 928 + вихід 90 токенів)
#
#   типовий платний  (20/день)  → $1.05/міс = 5%  ціни  ✅
#   важкий           (100/день) → $3.99/міс = 20% ціни  ✅
#   ліміт 9999 до дна           → $330/міс  = 1673%     🔴 ЗБИТОК
#
# BASIC_LIMIT був 9999 — це НЕ ліміт, це його ВІДСУТНІСТЬ із виглядом
# ліміту. Один скрипт міг згенерувати $330 витрат за $19.77 виручки —
# з'їсти маржу 16 чесних клієнтів. І Ви б не дізналися до рахунку.
#
# 300/день обрано так, щоб РЕАЛЬНІ люди не помітили:
#   • типовий (20/день)   — у 15 разів нижче стелі
#   • важкий (100/день)   — утричі нижче стелі
#   • на стелі 300/день   → $10/міс витрат, маржа ще $9 — терпимо
#   • скрипт упреться в 300, а не в 9999
#
# ══════════════════════════════════════════════════════════════════
# ЛІМІТИ CHAINY — числа тут, у коді. Міняти ТУТ.
#
# ЧОМУ САМЕ ЦІ ЧИСЛА (звірено зі світовою практикою, 2026):
# Дослідження + Talkio/Speak/TalkPal: 15–30 хв розмови на день дають
# результат за 4–6 тижнів. Один обмін (людина сказала → AI відповів)
# займає ~25 секунд. Отже норма ринку = 36–72 повідомлення на день.
#
#   50/день  = 21 хв  ← РІВНО норма ринку
#   100/день = 42 хв  ← удвічі понад норму (щедро)
#   300/день = 125 хв = 2 години розмови ЩОДНЯ. Так не говорить ніхто.
#
# DEMO 20 → 50. Було 20 = 8 хвилин: людина не встигала відчути, що
#   Chainy працює, — її вже зупиняли. Не «дали спробувати», а
#   «висмикнули з розмови». 50 = вона встигає закохатися.
#
# TRIAL 200 → 100. Не заради економії (собівартість копійчана), а щоб
#   платному тарифу БУЛО КУДИ РОСТИ. При 200 vs 300 апгрейд не
#   відчувається як здобуток. При 100 vs 300 — відчувається.
#
# PAID 300 — НЕ ЧІПАТИ. Це не ліміт для людей, це ЗАПОБІЖНИК ВІД
#   СКРИПТІВ. Реальний клієнт витрачає ~$4.87/міс при ціні $22
#   (Haiku 4.5 — дешева модель) → маржа 78%. Duolingo Max робить так
#   само: розмови без ліміту, і це головна причина апгрейду.
#
# ⚠️ ENV лишається як АВАРІЙНИЙ ВАЖІЛЬ: якщо хтось атакує, ліміт
#    збивається в Railway за 30 секунд, без заливки коду.
#    АЛЕ: якщо ENV задана — вона ПЕРЕБИВАЄ число звідси. Тому нижче
#    бот пише в лог, звідки взяв кожне число. Інакше ви правите код,
#    нічого не змінюється, і ви годину шукаєте причину.
# ══════════════════════════════════════════════════════════════════
DEMO_LIMIT_DEFAULT  = 50    # не купила, челендж позаду · 21 хв — норма ринку
TRIAL_LIMIT_DEFAULT = 100   # челендж або буфер новачка · 42 хв — щедро
PAID_LIMIT_DEFAULT  = 300   # Basic і Premium · запобіжник, не ліміт


def _limit(env_name: str, default: int) -> int:
    """Число з коду; ENV перебиває його, якщо задана. Пише в лог, звідки взято."""
    raw = os.environ.get(env_name)
    if raw is None:
        return default
    try:
        v = int(raw)
        if v < 1:
            logger.warning(f"⚠️ {env_name}={raw} — некоректно (<1). Беру {default} з коду.")
            return default
        if v != default:
            logger.warning(
                f"⚠️ {env_name}={v} у Railway ПЕРЕБИВАЄ {default} з коду. "
                f"Якщо правили код і нічого не змінилось — приберіть цю змінну в Railway."
            )
        return v
    except ValueError:
        logger.warning(f"⚠️ {env_name}={raw!r} — не число. Беру {default} з коду.")
        return default


DEMO_LIMIT  = _limit("CHAINY_LIMIT_DEMO",  DEMO_LIMIT_DEFAULT)
TRIAL_LIMIT = _limit("CHAINY_LIMIT_TRIAL", TRIAL_LIMIT_DEFAULT)
BASIC_LIMIT = _limit("CHAINY_LIMIT_PAID",  PAID_LIMIT_DEFAULT)

# Поріг «аномалія»: з якої кількості за день писати в лог і в адмінку.
# Не блокує — просто робить видимим ДО того, як прийде рахунок.
CHAINY_ANOMALY_AT = int(os.environ.get("CHAINY_ANOMALY_AT", "150"))
CONTEXT_FREE         = 4
CONTEXT_TRIAL        = 8
CONTEXT_PAID         = 20

# Тимчасові кеші в RAM (картинки і rate limit) — не критичні для персистентності
_PIXABAY_CACHE: dict = {}
_REWARD_RATE: dict   = {}


def verify_telegram_init_data(init_data: str):
    """Перевірка підпису Telegram WebApp initData."""
    if not init_data or not BOT_TOKEN:
        return None
    try:
        params = dict(p.split('=', 1) for p in init_data.split('&') if '=' in p)
        received_hash = params.pop('hash', '')
        data_check = '\n'.join(f"{k}={v}" for k, v in sorted(params.items()))
        secret = _hmac_buddy.new(b'WebAppData', BOT_TOKEN.encode(), _hashlib_buddy.sha256).digest()
        expected = _hmac_buddy.new(secret, data_check.encode(), _hashlib_buddy.sha256).hexdigest()
        if not _hmac_buddy.compare_digest(expected, received_hash):
            return None
        return json.loads(_urlp_buddy.unquote(params.get('user', '{}')))
    except Exception as e:
        logger.warning(f"verify_init_data error: {e}")
        return None


# 21.07: STRICT_INIT_DATA — раніше в 18 HTTP-ендпоінтах (miniapp_action,
# admin_nudge_preview, phrase_spoken та ін.) uid брався з тіла запиту
# ДОВІРЛИВО, коли init_data був порожній (сценарій «сторінка відкрита
# поза Telegram, у звичайному браузері»). Хтось, хто дізнався/підібрав
# чужий uid, міг надіслати запит від чужого імені, включно з is_admin.
#
# Рубильник, не жорстко вшитий True — щоб можна було аварійно відкотити
# з Railway (STRICT_INIT_DATA=false), не чіпаючи код і без нового
# деплою, якщо раптом виявиться легітимний клієнт зі старим кешем, що
# ще не шле init_data.
STRICT_INIT_DATA = os.environ.get("STRICT_INIT_DATA", "true").lower() != "false"


def require_verified_uid(body: dict):
    """
    Єдина точка істини «хто насправді робить цей запит».

    Повертає (uid: int, error_response: dict | None).
    Якщо error_response не None — виклик у handle_* має одразу
    повернути 401 з цим тілом, нічого далі не виконуючи.

    STRICT_INIT_DATA=true (дефолт): init_data ОБОВ'ЯЗКОВИЙ і має
    пройти криптографічну перевірку HMAC. uid з тіла запиту
    ігнорується повністю — тільки uid з підпису.

    STRICT_INIT_DATA=false (аварійний відкат): стара поведінка —
    uid з тіла, init_data лише уточнює, якщо є. НЕ для постійного
    використання, тільки якщо STRICT зламав щось легітимне і треба
    миттєво відкотитись без деплою.
    """
    init_data = body.get("init_data", "")
    body_uid = int(body.get("uid", 0) or 0)

    if not STRICT_INIT_DATA:
        uid = body_uid
        if init_data:
            tg_user = verify_telegram_init_data(init_data)
            if tg_user and tg_user.get("id"):
                uid = int(tg_user["id"])
        return uid, None

    if not init_data:
        return 0, {"error": "init_data обовʼязковий — відкрий через Telegram"}
    tg_user = verify_telegram_init_data(init_data)
    if not tg_user or not tg_user.get("id"):
        return 0, {"error": "init_data не пройшов перевірку"}
    return int(tg_user["id"]), None


def _get_buddy_daily(uid: int) -> dict:
    """
    Повертає buddy_daily стан з БД юзера. Якщо інший день — скидає лічильник.
    Структура: {"date": "YYYY-MM-DD", "count": N}
    """
    import time as _t
    today = _t.strftime("%Y-%m-%d", _t.localtime())
    if not uid:
        return {"date": today, "count": 0}
    try:
        s = get_s(uid)
        bd = s.get("buddy_daily", {})
        if bd.get("date") != today:
            return {"date": today, "count": 0}
        return bd
    except Exception:
        return {"date": today, "count": 0}


def _save_buddy_daily(uid: int, bd: dict):
    """Зберігає buddy_daily через upd_s (write-behind → PostgreSQL)."""
    if not uid:
        return
    try:
        upd_s(uid, {"buddy_daily": bd})
    except Exception as e:
        logger.warning(f"buddy_daily save error uid={uid}: {e}")


def get_buddy_user_status(uid: int) -> dict:
    """Статус юзера для Speaking Buddy: 'demo' | 'trial' | 'paid'."""
    if not uid:
        return {"status": "demo", "max_msgs": DEMO_LIMIT, "msg_count": 0,
                "in_challenge": False, "challenge_done": False,
                "trial_limit": TRIAL_LIMIT, "paid_limit": BASIC_LIMIT}
    challenge_done = False
    try:
        s = get_s(uid)
        if is_premium(s):
            status, max_msgs = "paid", BASIC_LIMIT
        elif is_in_trial(s):
            status, max_msgs = "trial", TRIAL_LIMIT
        else:
            status, max_msgs = "demo", DEMO_LIMIT

        # ⚠️ status='trial' — теж ДВОЄ РІЗНИХ ЛЮДЕЙ:
        #   А) in_challenge=True  → справді В ЧЕЛЕНДЖІ (бачила продукт)
        #   Б) in_challenge=False → новачок у буфері 2 дні, челендж ще
        #      НЕ ПОЧАЛА. Обом даємо 100/день, але продавати Basic
        #      можна лише А. Б треба спершу показати челендж.
        cs = (s.get("challenge_state") or {})
        in_challenge   = cs.get("status") == "active"
        challenge_done = cs.get("status") in ("completed", "abandoned")
    except Exception:
        status, max_msgs = "demo", DEMO_LIMIT
        in_challenge = False

    bd = _get_buddy_daily(uid)
    return {
        "status":         status,
        "max_msgs":       max_msgs,
        "msg_count":      bd["count"],
        "in_challenge":   in_challenge,
        "challenge_done": challenge_done,
        # Числа для фронту — щоб він не зашивав їх у себе і не брехав,
        # коли ми міняємо ліміт у коді.
        "trial_limit":    TRIAL_LIMIT,
        "paid_limit":     BASIC_LIMIT,
    }


def _check_and_increment_buddy(uid: int, status: str):
    """Перевірка ліміту і інкремент. Returns (allowed, remaining).

    Тут же — ДЕТЕКТОР АНОМАЛІЙ. Він нічого не блокує (ліміт це вже
    робить вище), він робить ризик ВИДИМИМ.

    ЧОМУ ЦЕ ВАЖЛИВО: рахунок від Anthropic приходить у кінці місяця.
    До цієї правки Ви дізналися б про людину, яка накрутила $300,
    ТІЛЬКИ з рахунку — коли гроші вже витрачено. Тепер аномалія
    з'являється в логах того ж дня.
    """
    limits = {"demo": DEMO_LIMIT, "trial": TRIAL_LIMIT, "paid": BASIC_LIMIT}
    limit = limits.get(status, DEMO_LIMIT)
    bd = _get_buddy_daily(uid)

    if bd["count"] >= limit:
        # Уперся у стелю. Сигналимо РІВНО ОДИН РАЗ за день — інакше скрипт,
        # який гатить тисячами, згенерує тисячі однакових записів і засмітить
        # і логи, і базу. (Знайдено тестом: 9999 спроб → 201 запис замість 1.)
        if not bd.get("capped"):
            bd["capped"] = True
            _save_buddy_daily(uid, bd)
            try:
                _chainy_flag_anomaly(uid, status, bd["count"], limit, hit_cap=True)
            except Exception:
                pass
        return False, 0

    bd["count"] += 1
    _save_buddy_daily(uid, bd)

    # Перетнув поріг аномалії — сигналимо РІВНО ОДИН РАЗ за день
    if bd["count"] == CHAINY_ANOMALY_AT:
        try:
            _chainy_flag_anomaly(uid, status, bd["count"], limit, hit_cap=False)
        except Exception:
            pass

    return True, limit - bd["count"]


def _chainy_flag_anomaly(uid: int, status: str, count: int, limit: int, hit_cap: bool):
    """Фіксує аномальне використання Chainy: у лог + у базу для адмінки.

    Не блокує, не карає, не пише людині. Тільки робить видимим.

    Вартість рахуємо ТУТ ЖЕ, щоб у логах була сума в доларах, а не
    абстрактні «повідомлення» — на цифру в $ реагують швидше.
    """
    # $ за повідомлення: вхід ~928 ток × $0.80/млн + вихід ~90 ток × $4.00/млн
    cost = count * (928 * 0.80 / 1_000_000 + 90 * 4.00 / 1_000_000)
    tag  = "УПЕРСЯ В СТЕЛЮ" if hit_cap else "перетнув поріг"
    logger.warning(
        "⚠️ CHAINY %s: uid=%s status=%s — %s повідомлень за день "
        "(ліміт %s), витрачено ≈$%.2f. Якщо таких днів 30 → ≈$%.0f/міс.",
        tag, uid, status, count, limit, cost, cost * 30,
    )
    # Пишемо в базу — щоб адмінка могла показати список
    try:
        db  = load_db()
        log = db.setdefault("_chainy_anomalies", [])
        import time as _t
        log.append({
            "d":      _t.strftime("%Y-%m-%d"),
            "uid":    str(uid),
            "status": status,
            "count":  count,
            "cap":    bool(hit_cap),
            "cost":   round(cost, 3),
        })
        # Не даємо журналу рости вічно
        db["_chainy_anomalies"] = log[-500:]
    except Exception as e:
        logger.warning(f"chainy anomaly log: {e}")


ROLE_PROMPTS_BUDDY = {
    "friendly": "You are a warm, encouraging English conversation partner. Play the other person in the scenario naturally. After EACH reply, add 1-2 short feedback items in Ukrainian on the learner's last message (grammar, phrasing). Be encouraging. Skip feedback if perfect.",
    "strict": "You are a strict English teacher playing the scenario role. Correct EVERY grammar mistake. After each reply, provide specific corrections in Ukrainian. Be direct and precise.",
    "native": "You are a native English speaker in this scenario. Speak completely naturally — use contractions, colloquialisms, natural rhythm. Don't simplify. Only flag major errors that would confuse a native.",
    "patient": "You are a patient teacher playing the scenario role. Speak clearly. If learner struggles, offer hints. Always encourage. Explain difficult vocabulary. Give gentle, detailed feedback in Ukrainian.",
}

# 21.07 (за прикладом реального відгуку — учениця B2→C1 хвалила саме те,
# що бот "не спускається на її рівень, а підтягує його до себе"): на
# кожному рівні бот говорить трохи ВИЩЕ за учня, не дзеркалить його. Це не
# "спрощуй коли складно" (стара логіка) — а природне збагачення: 1-2 слова
# або звороти рівня вище в кожній репліці, без пояснень і без переходу на
# урок, так само як живий носій підказує кращі формулювання в розмові.
LEVEL_CONTEXT_BUDDY = {
    "beginner":     (
        "Learner level: A1-A2. Use simple vocabulary and short sentences as your "
        "base — but naturally slip in ONE slightly richer word or phrase per reply "
        "(A2-B1 level) where it fits, the way a patient native speaker would with a "
        "beginner. Never stack multiple hard words in one reply, never explain the "
        "word — just use it naturally in context so meaning is guessable."
    ),
    "intermediate": (
        "Learner level: B1-B2. Keep the conversation flowing at their level, but "
        "reach slightly above it: use natural B2-C1 vocabulary, idioms, or phrasal "
        "verbs where a native speaker genuinely would — don't dumb it down to their "
        "exact level. If they clearly don't understand a word, rephrase it simply in "
        "your NEXT reply rather than stopping to explain."
    ),
    "advanced":     (
        "Learner level: C1-C2. Use rich, natural, native-level vocabulary and complex "
        "structures — nuanced phrasing, idioms, collocations a native speaker would "
        "actually reach for. Don't hold back or simplify; this learner wants to be "
        "challenged toward true fluency, not met halfway."
    ),
}


def build_buddy_system_prompt(scenario, scenario_desc, role, level):
    """20.07 (рішення власниці): м'яка недирективна корекція (recast) тепер
    дефолт для БУДЬ-ЯКОЇ ролі, окрім 'strict' — там лишається явна
    grammar_card, як і було. Раніше тут корекція була однакова для всіх
    ролей (тільки стиль/тон різнився через ROLE_PROMPTS_BUDDY) — тепер
    режим корекції теж залежить від ролі, узгоджено з тим самим правилом,
    що вже діє для Chainy й My Situation.
    """
    _strict = (str(role or "").strip().lower() == "strict")
    _correction_block = (
        "\n\nRULES:\n"
        "- Stay in character at all times\n"
        "- Keep YOUR replies to 2-4 sentences max\n"
        "- Feedback in Ukrainian (max 12 words per item)\n"
        "- Conversation in English only\n"
        "- If learner makes a grammar mistake, add grammar_card with correction\n"
        "- NEVER let the conversation stall. If the learner is silent, gives a very short\n"
        "  answer, seems stuck, or doesn't know what to say, gently lead: offer a concrete\n"
        "  example, suggest 2-3 simple things they could say, give the first words of a\n"
        "  sentence for them to finish, or ask an easier, more specific question. Nudge and\n"
        "  encourage — make it effortless to keep talking, while staying in character.\n\n"
        "RESPOND ONLY with valid JSON (no markdown, no backticks):\n"
        "{\n"
        '  "reply": "your English response in character",\n'
        '  "feedback": [{"type": "good", "text": "✓ Ukrainian"}, {"type": "tip", "text": "💡 Ukrainian"}],\n'
        '  "grammar_card": {\n'
        '    "topic": "Present Perfect",\n'
        '    "error": "I have went",\n'
        '    "correct": "I have gone",\n'
        '    "rule": "have/has + past participle (V3)"\n'
        "  }\n"
        "}\n\n"
        'If no grammar mistake: "grammar_card": null\n'
        'Empty feedback array if no corrections: "feedback": []'
    ) if _strict else (
        "\n\nStay in character at all times."
        + _RECAST_BLOCK
    )
    return (
        f"You are an AI English conversation practice partner.\n\n"
        f"SCENARIO: {scenario}\n"
        f"CONTEXT: {scenario_desc}\n\n"
        f"STYLE: {ROLE_PROMPTS_BUDDY.get(role, ROLE_PROMPTS_BUDDY['friendly'])}\n\n"
        f"{LEVEL_CONTEXT_BUDDY.get(level, LEVEL_CONTEXT_BUDDY['intermediate'])}"
        + _correction_block
    )


_BUDDY_JSON_CONTRACT = """

RULES:
- Keep YOUR replies to 2-4 sentences max
- Feedback in Ukrainian (max 12 words per item)
- Conversation in English only
- If learner makes a grammar mistake, add grammar_card with correction
- NEVER let the conversation stall. If the learner is silent, gives a very short
  answer ("yes", "ok", "i don't know"), seems stuck, or doesn't know what to say,
  gently lead: offer a concrete example, suggest 2-3 simple things they could say,
  give the first words of a sentence for them to finish, or ask an easier, more
  specific question. Nudge and encourage — make it effortless to keep talking.
- Reach slightly above their level (see level context above), don't mirror it down —
  but if they're clearly stuck, simplify your NEXT question, not your vocabulary.

RESPOND ONLY with valid JSON (no markdown, no backticks):
{
  "reply": "your English response in character",
  "feedback": [{"type": "good", "text": "✓ Ukrainian"}, {"type": "tip", "text": "💡 Ukrainian"}],
  "grammar_card": {"topic": "Present Perfect", "error": "I have went", "correct": "I have gone", "rule": "have/has + past participle (V3)"}
}
If no grammar mistake: "grammar_card": null. Empty feedback if none: "feedback": []."""


def build_chainy_teacher_prompt(level: str, focus_topic: dict = None) -> str:
    """Chainy у режимі ВЧИТЕЛЯ — виправляє одразу і показує, як правильно.

    ЧОМУ ОКРЕМИЙ ПРОМПТ, А НЕ ПРАПОРЕЦЬ У СТАРОМУ
    ─────────────────────────────────────────────
    Наявний Chainy МАЄ В ПРОМПТІ: "You are their friend, not their teacher".
    Це не випадковість — співрозмовник, який виправляє, перестає бути
    співрозмовником. Людина починає стежити за формою і замовкає.

    Тому режими — ПРОТИЛЕЖНІ, і змішувати їх у одному промпті не можна.
    Два промпти, два режими, людина обирає сама.

    МЕТОДИЧНЕ РІШЕННЯ (важливе):
    Учитель СПЕРШУ відповідає по суті, і ТІЛЬКИ ПОТІМ виправляє.
    Якщо навпаки — діалог перетворюється на диктант: людина сказала,
    її поправили, вона сказала, її поправили. Розмови немає, є екзамен.
    А без розмови немає мовлення — тільки страх помилитись.

    Тому порядок жорсткий: реакція → виправлення → питання далі.
    Розмова не зупиняється, але помилка не проходить повз.

    focus_topic (20.07, рішення власниці): якщо студент зараз активно
    працює над граматичною темою (grammar_pending_topic у стані), Chainy
    свідомо схиляє питання до сигнальних слів цієї теми — "What did you
    do yesterday?" для Past Simple, а не випадкова тема. Доповнює, не
    замінює тренажер 30 вправ Ego4U — усвідомлене закріплення в живій
    розмові, а не окрема механіка.
    """
    _focus_block = ""
    if focus_topic:
        ua      = focus_topic.get("ua", "")
        signals = focus_topic.get("signals") or []
        sig_str = ", ".join(f'"{w}"' for w in signals[:5]) if signals else ""
        _focus_block = (
            "\n\nCURRENT FOCUS TOPIC (soft steering, not a rule to announce):\n"
            f"The learner is actively practicing: {ua}.\n"
            + (f"When it fits naturally, lean your questions toward contexts that "
               f"invite signal words like {sig_str} — e.g. ask about routines, "
               f"habits, or past/future events depending on the topic, so they get "
               f"real practice using this structure in a live conversation.\n"
               if sig_str else "")
            + "Never mention that you're steering the topic or name the grammar "
            "rule — just guide naturally. If the conversation is already going "
            "somewhere good, don't force it."
        )
    return (
        "You are Chainy in TEACHER MODE — a patient, precise English teacher "
        "on the SpeakChain app.\n\n"

        "YOUR JOB:\n"
        "- Correct EVERY mistake the learner makes: grammar, word choice, "
        "word order, articles, tenses, prepositions\n"
        "- Show exactly HOW to say it correctly — give them the right sentence\n"
        "- Explain the rule in ONE short line, in Ukrainian, so it sticks\n"
        "- If a sentence is awkward but not wrong, offer the natural version too "
        "('technically correct, but a native would say...')\n\n"

        "CRITICAL ORDER — DO NOT BREAK THIS:\n"
        "1. FIRST react to WHAT they said (1 sentence — you are still a person, "
        "not a grading machine)\n"
        "2. THEN give the correction\n"
        "3. THEN ask a question so the conversation continues\n\n"
        "Never open with a correction. A learner who is corrected before being "
        "heard stops talking. You are teaching them to SPEAK, not to fear errors.\n\n"

        "TONE:\n"
        "- Warm but precise. Never sarcastic, never impatient\n"
        "- Praise real progress — but only when it is real, not automatically\n"
        "- If they got everything right: say so briefly and raise the difficulty\n"
        "- Never pile on: max 2 corrections per reply, even if there were more. "
        "Pick the ones that matter most (meaning first, then grammar, then style)\n\n"

        "KEEP IT ALIVE:\n"
        "- Your reply stays SHORT (3-4 sentences including the correction)\n"
        "- Always end with a question — the lesson is a conversation, not a test\n"
        "- If they go silent or say 'i dont know' — help: give them the first words, "
        "offer two options to choose from, make it easy to speak again\n\n"

        "Put every correction in grammar_card. Put praise and short tips in feedback.\n"
        f"{LEVEL_CONTEXT_BUDDY.get(level, LEVEL_CONTEXT_BUDDY['intermediate'])}"
        + _focus_block
    ) + _BUDDY_JSON_CONTRACT


def build_chainy_speakintense_prompt(level: str, focus_topic: dict = None) -> str:
    """Chainy — режим непрямого виправлення (recast). Внутрішня назва:
    speakintense. НЕ показувати цю назву юзеру, не згадувати підхід у UI —
    для студента це просто кнопка «🤫 М'яка корекція».

    ЧОМУ ОКРЕМИЙ ПРОМПТ, А НЕ ТРЕТІЙ ПРАПОРЕЦЬ У TEACHER
    ─────────────────────────────────────────────────────
    Teacher МАЄ В ПРОМПТІ: "Correct EVERY mistake... show exactly HOW".
    Це працює, але вимагає explicit grammar_card — розмова зупиняється,
    людина бачить правило. Тут інший механізм: форма засвоюється через
    те, що людина ЧУЄ її в живій репліці співрозмовника, а не читає
    в картці-поясненні. Розмова НІКОЛИ не зупиняється заради форми.

    Дефолт лишається "friend" — цей режим вмикається лише коли студент
    сам обирає його (chainy_mode == "speakintense"). Існуючі Friend і
    Teacher — без жодних змін.

    focus_topic — той самий механізм, що в Teacher/Friend (C-22, 20.07):
    м'яке підживлення сигнальними словами граматичної теми, тихо, без
    називання правила.
    """
    _focus_block = ""
    if focus_topic:
        ua = focus_topic.get("ua", "")
        _focus_block = (
            f"\n\nIf it fits naturally, you can steer the conversation toward "
            f"topics that relate to: {ua}. Never mention this or make it feel "
            f"like a lesson — it's a light nudge, not a rule."
        )
    return (
        "You are Chainy in an immersive conversation mode — corrects the way "
        "a warm, attentive native speaker would in casual talk: by modeling "
        "the right form, never by pointing out the mistake.\n\n"

        "YOUR JOB:\n"
        "- Keep the conversation flowing like a curious friend — never grade, "
        "never lecture\n"
        "- When the learner makes a mistake (grammar, word choice, word order, "
        "tense), NEVER name it, NEVER explain it, NEVER stop to correct\n"
        "- Instead, in YOUR next reply, naturally reuse their sentence with the "
        "correct form, wrapping ONLY the corrected word(s) in **double asterisks** "
        "so it stands out subtly\n"
        "- Then immediately continue with a genuine reaction or question — the "
        "correction rides inside the sentence, never sits alone\n\n"

        "EXAMPLE:\n"
        "Learner: 'Yesterday I go to the cinema'\n"
        "You: 'Oh, you **went** to the cinema? Nice — what did you watch?'\n\n"

        "RULES:\n"
        "- Never use the words 'correction', 'mistake', 'actually', or similar — "
        "you are not grading, you are talking\n"
        "- Reuse and rephrase their idea naturally — don't just repeat their "
        "sentence back like a drill\n"
        "- If there is no error, just react and continue like a friend would\n"
        "- Maximum ONE embedded correction per reply, even if there were "
        "several mistakes — pick the one that most affects meaning\n"
        "- Keep replies SHORT (2-3 sentences), always end with a question\n"
        "- If the learner goes quiet or seems stuck, help them out: suggest a "
        "couple of things they could talk about, or ask a simpler question\n\n"

        "grammar_card is ALWAYS null in this mode — the correction lives "
        "inside your reply text, never in a separate card. Empty feedback "
        "array unless there is a genuine, short positive note.\n\n"
        f"{LEVEL_CONTEXT_BUDDY.get(level, LEVEL_CONTEXT_BUDDY['intermediate'])}"
        + _focus_block + "\n\n"
        "RESPOND ONLY with valid JSON (no markdown, no backticks):\n"
        '{"reply": "your English response in character with **corrections** '
        'woven in", "feedback": [], "grammar_card": null}'
    )


_RECAST_BLOCK = """

CORRECTION STYLE — never interrupt for grammar. If the learner makes a
mistake, naturally reuse their sentence in your NEXT reply with the
correct form, wrapping ONLY the corrected word(s) in **double asterisks**,
then continue the conversation with a genuine reaction or question. Never
name the mistake, never explain a rule, never use words like "correction"
or "mistake" — you are talking, not grading. Maximum ONE embedded
correction per reply, even if there were several — pick the one that
most affects meaning. If there's no error, just react and continue.
grammar_card is ALWAYS null — the correction lives inside your reply text,
never in a separate card.

RULES:
- Keep YOUR replies to 2-4 sentences max
- Feedback in Ukrainian (max 12 words) only for a genuine short positive
  note — never for corrections, those live in the reply
- Conversation in English only
- NEVER let the conversation stall. If the learner is silent, gives a very
  short answer ("yes", "ok", "i don't know"), seems stuck, or doesn't know
  what to say, gently lead: offer a concrete example, suggest 2-3 simple
  things they could say, give the first words of a sentence for them to
  finish, or ask an easier, more specific question.
- Reach slightly above their level (see level context above), don't mirror it down —
  but if they're clearly stuck, simplify your NEXT question, not your vocabulary.

RESPOND ONLY with valid JSON (no markdown, no backticks):
{
  "reply": "your English response in character, with **corrections** woven in when relevant",
  "feedback": [],
  "grammar_card": null
}"""


def build_chainy_system_prompt(level: str, focus_topic: dict = None,
                                register_gap_info: dict = None) -> str:
    """Chainy — режим «Друг». 20.07 (рішення власниці): м'яка недирективна
    корекція (recast) тепер УСЕРЕДИНІ цього промпту за замовчуванням — не
    окремий режим/кнопка. Виправлення вплітається в репліку (**слово**),
    без grammar_card, розмова ніколи не зупиняється. Єдиний виняток —
    Strict Teacher (build_chainy_teacher_prompt) лишається окремим,
    незміненим: явна картка-правило, без вплетеної корекції.

    register_gap_info (L-07, 23.07): якщо студент у своїх останніх
    репліках реально вжив граматичну конструкцію ВИЩЕ заявленого рівня
    (register_gap() з grammar_engine.py — аналізує тільки role="user"
    з history), Chainy природно піднімає регістр відповіді назустріч —
    не одноразовий трюк, а орієнтир на РЕАЛЬНУ продемонстровану
    здатність, а не лише на статичний LEVEL_CONTEXT_BUDDY. Свідомо
    ЛИШЕ для Friend — Teacher і так виправляє кожну помилку явним
    grammar_card, підняття регістру без пояснення там методично зайве.
    """
    _focus_block = ""
    if focus_topic:
        ua = focus_topic.get("ua", "")
        _focus_block = (
            f"\n\nIf it fits naturally, you can steer small talk toward topics "
            f"that relate to: {ua}. Never mention this or make it feel like a "
            f"lesson — you're still just a friend chatting, this is a light nudge, "
            f"not a rule."
        )
    _register_block = ""
    if register_gap_info:
        _gap_cefr = register_gap_info.get("detected_cefr", "")
        _register_block = (
            f"\n\nThe learner just used English noticeably more advanced than "
            f"their profile level (around {_gap_cefr} level) — they can clearly "
            f"handle more. Match that: raise your vocabulary and sentence "
            f"complexity a notch for the rest of this reply, the way a friend "
            f"naturally mirrors someone who's speaking well. Never comment on "
            f"this or praise their level explicitly — just talk to them as an "
            f"equal at that higher level."
        )
    return (
        "You are Chainy — a friendly, warm and genuinely curious AI friend on the "
        "SpeakChain English learning app.\n\n"
        "YOUR PERSONALITY:\n"
        "- You are upbeat, empathetic, and fully present in every conversation\n"
        "- You are genuinely interested in the person — their life, thoughts, feelings, dreams\n"
        "- You ask follow-up questions naturally, like a real friend would\n"
        "- You share your own \"thoughts\" and opinions to keep conversation flowing\n"
        "- You celebrate their effort to speak English without making it feel like a class\n"
        "- You are never formal or stiff — you speak like a real person\n"
        "- You can handle ANY topic: life, work, family, travel, dreams, pop culture, news\n\n"
        "CONVERSATION STYLE:\n"
        "- Keep your replies SHORT and conversational (2-3 sentences max)\n"
        "- Always end with a genuine follow-up question or reaction\n"
        "- Never lecture or explain — just chat\n"
        "- If they go quiet, answer in one word, or don't know what to say, help them "
        "out: suggest a couple of things they could talk about, share something about "
        "yourself to react to, or ask a simpler, more concrete question. Keep the ball "
        "rolling so they never feel stuck.\n\n"
        "REMEMBER: You are their friend, not their teacher. Make them WANT to keep talking.\n"
        f"{LEVEL_CONTEXT_BUDDY.get(level, LEVEL_CONTEXT_BUDDY['intermediate'])}"
        + _focus_block
        + _register_block
        + _RECAST_BLOCK
    )


def build_my_situation_prompt(who: str, what: str, focus: str, level: str) -> str:
    def clean(x, limit):
        return str(x or "").replace("\n", " ").replace("\r", " ").strip()[:limit]
    who   = clean(who,   120) or "a relevant conversation partner"
    what  = clean(what,  200) or "a realistic everyday situation"
    focus = clean(focus, 200) or "natural conversation and useful vocabulary"
    return (
        f"You are role-playing a custom speaking practice scenario.\n"
        f"YOUR ROLE: Play this person — {who}.\n"
        f"THE SITUATION: {what}.\n"
        f"WHAT THE LEARNER WANTS TO PRACTICE: {focus}.\n"
        f"Stay fully in character the whole time and make it realistic and immersive. "
        f"{LEVEL_CONTEXT_BUDDY.get(level, LEVEL_CONTEXT_BUDDY['intermediate'])}"
        + _RECAST_BLOCK
    )


