async def handle_duo_room_state(request):
    """GET /duo_room_state?room_id=... → поточний стан спільної кімнати.

    Поллінгом, не WebSocket — той самий компроміс, що обговорювали:
    дешевше за реальну інфраструктуру, для темпу розмови різниці немає.
    """
    if request.method == "OPTIONS":
        return _web.Response(headers=CORS_BUDDY)
    room_id = request.rel_url.query.get("room_id", "").strip()
    if not room_id:
        return _web.json_response({"error": "room_id обовʼязковий"}, status=400, headers=CORS_BUDDY)
    room = _get_duo_room(room_id)
    if not room:
        return _web.json_response({"error": "not_found"}, status=404, headers=CORS_BUDDY)
    return _web.json_response({
        "ok": True,
        "scenario_title": room.get("scenario_title", ""),
        "scenario_desc":  room.get("scenario_desc", ""),
        "role_a_label":   room.get("role_a_label", ""),
        "role_b_label":   room.get("role_b_label", ""),
        "uid_a":          room.get("uid_a", ""),
        "uid_b":          room.get("uid_b", ""),
        "messages":       room.get("messages", []),
        "status":         room.get("status", "active"),
    }, headers=CORS_BUDDY)


async def handle_relay_room_state(request):
    """GET /relay_room_state?room_id=... → стан кімнати «Плітки» (C-16).

    НАВМИСНО віддає лише ОСТАННЮ ланку (last_link), не весь links[] —
    показ повної історії ламає ефект несподіванки шепіт-естафети, який
    і є суттю прийому (документ 11, «Секрет і змова»). Якщо колись
    з'явиться режим «Спільна історія» з повним контекстом, це буде
    окремий query-параметр чи окремий endpoint, не зміна цього.
    """
    if request.method == "OPTIONS":
        return _web.Response(headers=CORS_BUDDY)
    room_id = request.rel_url.query.get("room_id", "").strip()
    if not room_id:
        return _web.json_response({"error": "room_id обовʼязковий"}, status=400, headers=CORS_BUDDY)
    room = _get_relay_room(room_id)
    if not room:
        return _web.json_response({"error": "not_found"}, status=404, headers=CORS_BUDDY)
    last = _relay_room_last_link(room)
    return _web.json_response({
        "ok": True,
        "status":        room.get("status", "active"),
        "n_links":       len(room.get("links") or []),
        "link_limit":    RELAY_LINK_LIMIT,
        "last_sender":   last.get("sender", ""),
        "last_transcript": last.get("transcript", ""),
        "last_is_video": last.get("is_video", False),
        "final_video_file_id": room.get("final_video_file_id", ""),
    }, headers=CORS_BUDDY)


async def handle_buddy_image(request):
    """GET /buddy_image?q=airport → {url}"""
    import time as _t
    q = request.rel_url.query.get("q", "").strip()
    if not q:
        return _web.json_response({"url": None}, headers=CORS_BUDDY)
    cached = _PIXABAY_CACHE.get(q.lower())
    if cached and _t.time() < cached.get("exp", 0):
        return _web.json_response({"url": cached["url"]}, headers=CORS_BUDDY)
    if not PIXABAY_API_KEY:
        return _web.json_response({"url": None}, headers=CORS_BUDDY)
    try:
        async with aiohttp.ClientSession() as sess:
            async with sess.get(
                "https://pixabay.com/api/",
                params={"key": PIXABAY_API_KEY, "q": q, "image_type": "photo",
                        "orientation": "horizontal", "min_width": 640,
                        "safesearch": "true", "per_page": 5},
                timeout=aiohttp.ClientTimeout(total=5)
            ) as resp:
                hits = (await resp.json()).get("hits", [])
        url = hits[0]["webformatURL"] if hits else None
        _PIXABAY_CACHE[q.lower()] = {"url": url, "exp": _t.time() + 86400}
        return _web.json_response({"url": url}, headers=CORS_BUDDY)
    except Exception as e:
        logger.warning(f"Pixabay error '{q}': {e}")
        return _web.json_response({"url": None}, headers=CORS_BUDDY)


def build_video_practice_prompt(topic: str, mode: str, level: str, summary: str = "") -> str:
    """Промпт для практики по відео: переказ або обговорення (серверний).
    summary — конспект змісту відео з субтитрів (якщо є)."""
    topic = str(topic or "").replace("\n", " ").strip()[:150] or "the video the learner watched"
    summary = str(summary or "").replace("\n", " ").strip()[:500]
    content_ctx = (f" Here is what the video actually covers: {summary}" if summary else "")
    if mode == "retell":
        task = (
            f"The learner just watched a video: \"{topic}\". "
            f"Your job: help them RETELL it in English. Listen to their summary, "
            f"gently encourage more detail, ask what happened next, help with words "
            f"they're missing. Keep them speaking and summarizing."
            + content_ctx +
            " Use this to check their retelling and prompt details they missed."
        )
    else:
        task = (
            f"The learner just watched a video: \"{topic}\". "
            f"Your job: DISCUSS it with them in English as a KNOWLEDGEABLE conversation "
            f"partner in whatever field the video belongs to (business, psychology, "
            f"relationships, science, philosophy, etc.). Take on the role of a thoughtful, "
            f"well-informed interlocutor in that topic: offer substantive angles, gently "
            f"challenge their view, bring a relevant idea or perspective, and go deeper — "
            f"either practically/subject-matter or philosophically, following their lead. "
            f"Still ask one open question at a time to keep them talking, and stay warm, "
            f"not lecture-y. "
            f"IMPORTANT FRAMING: this is a spoken-English practice exercise. Whatever the "
            f"topic — including sensitive ones like politics, medicine, defense or military "
            f"affairs — engage openly and keep the conversation flowing as a discussion "
            f"partner. Your goal is to help the learner express themselves and practice "
            f"speaking, NOT to give professional advice (medical, legal, etc.) or "
            f"operational instructions. On contested topics, stay balanced and even-handed "
            f"rather than pushing a single position. Discuss ideas, perspectives and "
            f"opinions freely, but don't provide step-by-step technical instructions for "
            f"causing harm. Do not derail the conversation with disclaimers — just keep it "
            f"natural and let them talk."
            + content_ctx +
            " Ground your points and questions in this actual content."
        )
    return (
        "You are Chainy, a warm English-speaking practice partner.\n"
        + task + "\n"
        + LEVEL_CONTEXT_BUDDY.get(level, LEVEL_CONTEXT_BUDDY["intermediate"])
        + _RECAST_BLOCK
    )


async def handle_buddy_chat(request):
    """POST /buddy_chat → {reply, feedback} або {error}"""
    import time as _t
    if request.method == "OPTIONS":
        return _web.Response(headers=CORS_BUDDY)
    try:
        data = await request.json()
    except Exception:
        return _web.json_response({"error": "Invalid JSON"}, status=400, headers=CORS_BUDDY)

    # 21.07: require_verified_uid — init_data обовʼязковий (STRICT_INIT_DATA)
    uid, _auth_err = require_verified_uid(data)
    if _auth_err:
        return _web.json_response(_auth_err, status=401, headers=CORS_BUDDY)

    user_status = get_buddy_user_status(uid) if uid else {"status": "demo"}
    status = user_status["status"]

    allowed, remaining = _check_and_increment_buddy(uid or -1, status)
    if not allowed:
        # ══════════════════════════════════════════════════════════════
        # 🔴 БУЛО: одне повідомлення для ВСІХ — «починай безкоштовний тріал».
        #
        # Дві помилки:
        #  1) слова «тріал» у продукті НЕМАЄ. Є челендж. Обіцяли сутність,
        #     якої не існує — те саме слово-привид, що вже прибрали з paywall.
        #  2) те саме казали ПЛАТНОМУ клієнту: людина віддала $22, уперлась
        #     у стелю — і їй пропонують «безкоштовний тріал».
        #
        # ТЕПЕР кожен бачить СВІЙ наступний крок. Момент, коли людина
        # уперлась у ліміт, — це момент, коли вона ХОЧЕ ГОВОРИТИ ДАЛІ.
        # Найкраща мить, щоб показати, що дає Basic. Не пізніше, не раніше.
        # ══════════════════════════════════════════════════════════════
        if status == "paid":
            # Уперся ПЛАТНИЙ. 300/день ≈ 2 години розмови — це вже не
            # навчання. Нічого не продаємо (вона вже купила), просто
            # чесно кажемо і відпускаємо.
            reply = (f"Ти сьогодні наговорила на {BASIC_LIMIT} повідомлень — це рекорд 🔥\n\n"
                     f"Ліміт оновиться завтра. Відпочинь: мозок закріплює вивчене уві сні.")
        elif status == "trial":
            # ЧЕЛЕНДЖ — головний момент продажу. Вона хоче далі ПРЯМО ЗАРАЗ.
            reply = (f"Це {TRIAL_LIMIT} повідомлень за сьогодні — чудова робота! 🎉\n\n"
                     f"Хочеш говорити без зупинок? У Basic — {BASIC_LIMIT} на день. "
                     f"Це майже 2 години розмови щодня.")
        else:
            # ── status == "demo" — це ДВОЄ РІЗНИХ ЛЮДЕЙ! ──
            #
            # 🔴 БУВ БАГ: обом писали «У Basic — 300 на день», тобто
            # ПРОДАВАЛИ навіть тій, яка ще НЕ ПРОБУВАЛА челендж.
            #
            # is_in_trial() = False у двох випадках:
            #   А) челендж completed/abandoned → челендж ПОЗАДУ, час платити ✅
            #   Б) буфер 2 дні вийшов, а челендж НЕ ПОЧАТО → їй треба
            #      В ЧЕЛЕНДЖ, а не в Basic. Продавати тому, хто ще не бачив
            #      продукту, — найшвидший спосіб його втратити.
            #
            # Воронка: демо-петля → ЧЕЛЕНДЖ → paywall. Не можна перестрибувати.
            cs = (get_s(uid) or {}).get("challenge_state") or {}
            challenge_done = cs.get("status") in ("completed", "abandoned")

            if challenge_done:
                # А) Челендж позаду — це і є момент paywall.
                reply = (f"{DEMO_LIMIT} повідомлень за сьогодні — ти молодець 👏\n\n"
                         f"У Basic — {BASIC_LIMIT} на день, і Chainy завжди поруч.")
            else:
                # Б) Челенджу ще НЕ БУЛО. Не продаємо — ведемо у воронку.
                reply = (f"{DEMO_LIMIT} повідомлень за сьогодні — чудовий початок 👏\n\n"
                         f"Хочеш більше? У 7-денному челенджі — {TRIAL_LIMIT} на день, "
                         f"і повний доступ до всього. Безкоштовно.")

        return _web.json_response({
            "show_paywall": True,
            "reply": reply,
        }, headers=CORS_BUDDY)

    rate_key = f"_buddy_rate_{uid}"
    last = getattr(handle_buddy_chat, rate_key, 0)
    if _t.time() - last < 2:
        return _web.json_response({"error": "Зачекай секунду..."}, status=429, headers=CORS_BUDDY)
    setattr(handle_buddy_chat, rate_key, _t.time())

    ctx_limits = {"demo": CONTEXT_FREE, "trial": CONTEXT_TRIAL, "paid": CONTEXT_PAID}
    ctx_limit = ctx_limits.get(status, CONTEXT_FREE)
    history = [m for m in data.get("history", []) if m.get("content") != "[START]"][-ctx_limit:]

    # Промпт будується НА СЕРВЕРІ (фронт не диктує system prompt)
    level = data.get("level", "intermediate")
    ms = data.get("my_situation")
    vp = data.get("video_practice")
    # L-07: ініціалізується тут (не всередині гілки is_chainy/friend нижче),
    # інакше _reg_gap не існує як ім'я для інших гілок (video_practice,
    # my_situation, is_chainy+teach, звичайні сценарії) — NameError нижче
    # при спробі прочитати її для запису targeted у srs_words.
    _reg_gap = None
    if ENABLE_VIDEO_TO_BUDDY and isinstance(vp, dict):
        system = build_video_practice_prompt(
            vp.get("topic", ""), vp.get("mode", "discuss"), level, vp.get("summary", ""))
        # Лічильник: рахуємо СТАРТ відео-практики раз (короткий history = початок)
        try:
            _hist = data.get("history", [])
            if len([m for m in _hist if m.get("role") == "user" and m.get("content") != "[START]"]) <= 1:
                _feature_log_event("video_practice", "start")
                _feature_log_event("video_practice",
                                   "with_summary" if vp.get("summary") else "by_title")
                _feature_log_event("video_practice", vp.get("mode", "discuss"))
        except Exception:
            pass
    elif isinstance(ms, dict):
        system = build_my_situation_prompt(
            ms.get("who", ""), ms.get("what", ""), ms.get("focus", ""), level)
    elif data.get("is_chainy"):
        # Два режими Chainy — ПРОТИЛЕЖНІ за задумом, тому й промпти різні.
        #   friend  — співрозмовник. НЕ виправляє (у промпті прямо:
        #             "You are their friend, not their teacher"). Мета —
        #             розговорити, зняти страх.
        #   teacher — учитель. Виправляє КОЖНУ помилку і показує, як правильно.
        #
        # Дефолт "friend": стара поведінка. Хто не обрав режим — отримає
        # рівно те, що й раніше. Нічого не ламається для наявних людей.
        #
        # ── СТИЛЬ КЕРУЄ ВСІМ ──
        # Раніше було ДВІ окремі сутності, які робили одне:
        #   chainy_mode = friend / teacher      (перемикач у чаті)
        #   role        = friendly / strict / … (стиль мовлення)
        # І вони НЕ ЗУСТРІЧАЛИСЬ: учениця обирала «📝 Strict teacher»,
        # заходила в Chainy — і вибір мовчки ігнорувався, бо Chainy
        # йшов гілкою chainy_mode. Прихований баг.
        #
        # Тепер стиль — єдине джерело правди. `strict` вмикає промпт
        # виправлення скрізь: і в Chainy, і в рольових сценаріях.
        # chainy_mode лишається для сумісності зі старим фронтом.
        _cmode = (data.get("chainy_mode") or "").strip().lower()
        _role  = (data.get("role") or "").strip().lower()

        _teach = (_cmode == "teacher") or (_role == "strict")

        # 20.07 (рішення власниці): якщо студент саме зараз активно працює
        # над граматичною темою (тренажер/нудж поставили grammar_pending_topic),
        # Chainy свідомо схиляє розмову до сигнальних слів цієї теми —
        # доповнення до 30 вправ Ego4U, не заміна. Тихо — якщо теми немає
        # чи студент її вже завершив, промпт лишається як був.
        _focus_topic = None
        try:
            _s_focus = get_s(uid) if uid else {}
            _pending_key = (_s_focus or {}).get("grammar_pending_topic", "")
            if _pending_key and _pending_key in GRAMMAR_MAP:
                _focus_topic = GRAMMAR_MAP[_pending_key]
        except Exception:
            _focus_topic = None

        if _teach:
            system = build_chainy_teacher_prompt(level, _focus_topic)
            try:
                _feature_log_event("chainy_mode", "teacher")
            except Exception:
                pass
        else:
            # ── L-07 (23.07) + L-07b лексика (23.07, другий чат): ──
            # register_gap піднімає регістр Chainy, коли студент РЕАЛЬНО
            # випередив заявлений рівень — граматикою АБО лексикою.
            # Тільки Friend (рішення наради вище).
            #
            # ВАЖЛИВО: `level` тут — грубий бакет beginner/intermediate/
            # advanced (вибір сценарію фронтом), НЕ CEFR-профіль студента.
            # register_gap() потребує саме CEFR (A1..C2) — береться з
            # s.get("level"), окремо від `level` змінної цієї функції.
            #
            # ВАЖЛИВО: лише role=="user" з history — інакше вимірюємо
            # складність власних реплік Chainy, а не студента (клас
            # багу L-06 — тихе спотворення сигналу).
            #
            # ЛЕКСИКА (L-07b, за прямим методичним зауваженням власниці):
            # до цього моменту register_gap бачив ЛИШЕ граматику
            # (detect_topics_complex). Студент, що вживає C1-слова в
            # простих реченнях ("I feel euphoric today"), не піднімав
            # регістр Chainy взагалі — прогалина. Тепер паралельно
            # перевіряємо кожне слово реплік студента через
            # classify_word_cefr() (той самий детермінований Oxford-
            # словник, що вже рахує SRS-прогрес, L-05) — і беремо
            # НАЙВИЩИЙ CEFR серед граматики й лексики РАЗОМ, той самий
            # принцип "лише вгору", що й граматична частина L-07.
            # НЕ використовує detect_spoken_vocab() з vocab_cefr.py —
            # та функція вирішує ІНШУ задачу (залік слова в SRS-прогрес,
            # з фільтром "рівень студента і на 1 нижче", стоп-словами
            # для боротьби з переоцінкою). Тут потрібне дзеркальне:
            # слова СТРОГО ВИЩЕ рівня студента, без фільтра "теж
            # рахувати трохи нижче" — інша ціль, тому окрема, коротша
            # перевірка тут, а не виклик чужої функції не за призначенням.
            _reg_gap = None
            try:
                if uid:
                    _s_reg = get_s(uid) or {}
                    _student_cefr = _s_reg.get("level", "A1")
                    _user_texts = [
                        m.get("content", "") for m in (data.get("history", []) or [])
                        if m.get("role") == "user" and m.get("content") != "[START]"
                    ]
                    _reg_gap = register_gap(_user_texts, _student_cefr)

                    # Лексичний розрив — паралельно граматичному, той самий
                    # "лише вгору". Не перезаписує граматичний результат,
                    # якщо лексика випередила ще сильніше — замінює.
                    try:
                        import re as _re_lex
                        _cefr_rank_lex = {"A1":0,"A2":1,"B1":2,"B2":3,"C1":4,"C2":5}
                        _student_rank_lex = _cefr_rank_lex.get(_student_cefr, 0)
                        _srs_lex = _s_reg.get("srs_words", {})
                        _best_word_cefr, _best_word_rank, _best_word = None, -1, None
                        _seen_lex = set()
                        for _txt in _user_texts:
                            for _w in _re_lex.findall(r"[a-zA-Z']+", str(_txt).lower()):
                                if len(_w) < 3 or _w in _seen_lex:
                                    continue
                                _seen_lex.add(_w)
                                _wc = classify_word_cefr(_w, _srs_lex.get(_w))
                                if not _wc or _wc not in _cefr_rank_lex:
                                    continue
                                _wr = _cefr_rank_lex[_wc]
                                if _wr > _student_rank_lex and _wr > _best_word_rank:
                                    _best_word_rank, _best_word_cefr, _best_word = _wr, _wc, _w
                        if _best_word_cefr:
                            _gram_rank = _cefr_rank_lex.get(
                                (_reg_gap or {}).get("detected_cefr"), -1)
                            if _best_word_rank > _gram_rank:
                                _reg_gap = {
                                    "detected_cefr": _best_word_cefr,
                                    "gap_levels": _best_word_rank - _student_rank_lex,
                                    "topic_key": None,
                                    "topic_ua": f'слово "{_best_word}"',
                                }
                    except Exception as _lge:
                        logger.warning(f"register_gap lexical fail uid={uid}: {_lge}")

                    if _reg_gap:
                        _feature_log_event("register_gap", _reg_gap["detected_cefr"])
            except Exception as _rge:
                logger.warning(f"register_gap fail uid={uid}: {_rge}")
                _reg_gap = None

            # 20.07 (рішення власниці): м'яка недирективна корекція (recast)
            # тепер УСЕРЕДИНІ build_chainy_system_prompt за замовчуванням —
            # не окремий режим/кнопка. build_chainy_speakintense_prompt лишився
            # в коді невикористаним (дублює те, що тепер у Friend) — не
            # видаляла сама, звіт+питання: приберемо разом, коли підтвердите.
            system = build_chainy_system_prompt(level, _focus_topic, _reg_gap)
            try:
                _feature_log_event("chainy_mode", "friend")
            except Exception:
                pass
    else:
        system = build_buddy_system_prompt(
            data.get("scenario", "General conversation"),
            data.get("scenario_desc", ""),
            data.get("role", "friendly"),
            level,
        )

    # ── Bug #4: підмішуємо пам'ять минулих розмов, коли починається новий чат ──
    # Якщо фронт прислав порожню/коротку історію (нова сесія), але в юзера є
    # збережений buddy_history — даємо Chainy короткий контекст, щоб він НЕ
    # «знайомився вперше». Не чіпаємо активну сесію (де історія вже довга).
    try:
        if uid and len(history) <= 1:
            _saved = get_s(uid).get("buddy_history", [])
            if _saved:
                _recent = _saved[-8:]
                _mem_lines = []
                for m in _recent:
                    _who = "Learner" if m.get("role") == "user" else "You (Chainy)"
                    _txt = str(m.get("content", "")).strip()
                    if _txt:
                        _mem_lines.append(f"{_who}: {_txt}")
                _last_topic = (get_s(uid).get("last_buddy_topic") or "").strip()
                if _mem_lines:
                    _mem_note = (
                        "\n\nMEMORY — you have talked with this same person before. "
                        "Do NOT introduce yourself as if meeting for the first time; "
                        "continue naturally, like a friend who remembers them."
                        + (f" Last time you talked about: {_last_topic}." if _last_topic else "")
                        + "\nRecent snippets from your previous conversations:\n"
                        + "\n".join(_mem_lines)
                    )
                    system = system + _mem_note
    except Exception:
        pass

    try:
        response = await claude_create_async(
            model="claude-haiku-4-5-20251001",
            max_tokens=400,
            system=system,
            messages=history or [{"role": "user", "content": "Let's start the scenario."}],
        )
        raw = response.content[0].text.strip()
        raw = raw[raw.find("{"):raw.rfind("}")+1]
        parsed = json.loads(raw)

        # ── Зберігаємо статистику сесії в БД (write-behind) ──
        if uid:
            try:
                import time as _t
                _s = get_s(uid)
                stats = _s.get("buddy_stats", {
                    "total_messages": 0,
                    "total_sessions": 0,
                    "scenarios_tried": [],
                    "last_session_date": None,
                    "feedback_good_count": 0,
                    "feedback_tip_count": 0,
                })
                stats["total_messages"] = stats.get("total_messages", 0) + 1
                stats["last_session_date"] = datetime.now().isoformat()

                scenario_name = data.get("scenario", "")
                is_chainy = data.get("is_chainy", False)

                if scenario_name and scenario_name not in stats.get("scenarios_tried", []):
                    stats.setdefault("scenarios_tried", []).append(scenario_name)
                    stats["scenarios_tried"] = stats["scenarios_tried"][-50:]
                    stats["total_sessions"] = stats.get("total_sessions", 0) + 1

                # ── Аналітика: глобальний лічильник популярності тем ──
                # Рахуємо КОЖНЕ відкриття теми (не лише унікальних юзерів),
                # щоб бачити реальний обсяг попиту. Живе в _DB під ключем _topic_popularity.
                if scenario_name and not is_chainy:
                    try:
                        _db = load_db()
                        _pop = _db.setdefault("_topic_popularity", {})
                        _pop[scenario_name] = int(_pop.get(scenario_name, 0)) + 1
                        _DB_MEM["data"] = _db
                        _DB_DIRTY.add("_topic_popularity")
                    except Exception:
                        pass

                for f in parsed.get("feedback", []):
                    if f.get("type") == "good":
                        stats["feedback_good_count"] = stats.get("feedback_good_count", 0) + 1
                    elif f.get("type") == "tip":
                        stats["feedback_tip_count"] = stats.get("feedback_tip_count", 0) + 1

                buddy_updates = {"buddy_stats": stats}

                # ── L-07: targeted — слова, які Chainy підсвітив піднятим ──
                # регістром, позначаються в srs_words. Спрацьовує ЛИШЕ коли
                # register_gap реально виявив розрив (_reg_gap не None) —
                # інакше немає підстави вважати якісь слова "цілеспрямовано
                # підсвіченими", Chainy просто говорив на звичайному рівні.
                #
                # Джерело слів — САМА відповідь Chainy (parsed["reply"]),
                # не заздалегідь відомий список: бекенд не знає наперед,
                # які слова згенерує Claude API. Позначаємо ті слова з
                # reply, чий CEFR СТРОГО вищий за рівень студента —
                # це і є "нові" слова, які студент міг почути вперше
                # завдяки піднятому регістру.
                #
                # Той самий lazy-backfill патерн, що cefr/topic у
                # _srs_update_word (L-05) — не перезаписує вже існуючі
                # поля слова, лише додає targeted=True якщо його ще нема.
                if _reg_gap and is_chainy:
                    try:
                        import re as _re_tg
                        _student_rank = {"A1":0,"A2":1,"B1":2,"B2":3,"C1":4,"C2":5}
                        _reply_words = _re_tg.findall(r"[a-zA-Z']+", str(parsed.get("reply", "")).lower())
                        _s_lvl = _s.get("level", "A1")
                        _s_rank = _student_rank.get(_s_lvl, 0)
                        _srs_tg = _s.get("srs_words", {})
                        _touched = False
                        _seen_tg = set()
                        for _w in _reply_words:
                            if len(_w) < 3 or _w in _seen_tg:
                                continue
                            _seen_tg.add(_w)
                            _entry_tg = _srs_tg.get(_w)
                            if _entry_tg and _entry_tg.get("targeted"):
                                continue  # вже позначено раніше — не перезаписуємо
                            _w_cefr = classify_word_cefr(_w, _entry_tg)
                            if not _w_cefr or _w_cefr not in _student_rank:
                                continue
                            if _student_rank[_w_cefr] <= _s_rank:
                                continue  # не вище рівня студента — не "підсвічене"
                            _entry_tg = _entry_tg or {"interval_days": 0, "count_know": 0, "count_learn": 0}
                            _entry_tg["cefr"] = _w_cefr
                            _entry_tg["targeted"] = True
                            _srs_tg[_w] = _entry_tg
                            _touched = True
                        if _touched:
                            buddy_updates["srs_words"] = _srs_tg
                            _feature_log_event("register_gap", "targeted_words_marked")
                    except Exception as _tge:
                        logger.warning(f"L-07 targeted marking fail uid={uid}: {_tge}")

                # ── [B] Memory-гачок для Daily Check-in: тема останньої розмови ──
                try:
                    if isinstance(ms, dict):
                        _topic = (ms.get("what") or ms.get("who") or "").strip()
                    elif scenario_name:
                        _topic = scenario_name.strip()
                    elif is_chainy and history:
                        # перша репліка юзера як тема, якщо нема сценарію
                        _first_user = next((m.get("content","") for m in history if m.get("role")=="user"), "")
                        _topic = _first_user.strip()
                    else:
                        _topic = ""
                    if _topic:
                        buddy_updates["last_buddy_topic"] = _topic[:80]
                except Exception:
                    pass

                # ── Bug #4: пам'ять розмови між сесіями ──
                # Зберігаємо останні репліки (без [START]), щоб у наступному чаті
                # Chainy пам'ятав контекст, а не «знайомився вперше».
                try:
                    _prev = _s.get("buddy_history", [])
                    _clean_hist = [
                        {"role": m.get("role"), "content": str(m.get("content", ""))[:500]}
                        for m in history
                        if m.get("content") and m.get("content") != "[START]"
                    ]
                    # додаємо свіжу відповідь асистента
                    _reply_txt = parsed.get("reply", "")
                    if _reply_txt:
                        _clean_hist = _clean_hist + [{"role": "assistant", "content": str(_reply_txt)[:500]}]
                    # склеюємо з попереднім і тримаємо останні 20 реплік
                    _merged = (_prev + _clean_hist)[-20:]
                    buddy_updates["buddy_history"] = _merged
                    buddy_updates["buddy_history_ts"] = datetime.now().isoformat()
                except Exception:
                    pass

                # First Chainy date
                if is_chainy and not _s.get("first_chainy_date"):
                    buddy_updates["first_chainy_date"] = datetime.now().strftime("%Y-%m-%d %H:%M")

                # ── Граматичний decay від помилки в розмові (під flag) ──
                # Якщо Chainy виявив помилку (grammar_card) — тема просідає
                # через decay-механіку (не штраф). Реабілітація — будь-яка
                # практика теми скидає decay_boost.
                if ENABLE_GRAMMAR_DECAY_FROM_CHAT:
                    try:
                        gc = parsed.get("grammar_card")
                        if isinstance(gc, dict):
                            from grammar_engine import (
                                detect_topic as _dt, detect_topics_all as _dta,
                                mark_topic_event as _mte2, GRAMMAR_MAP as _GM_dec,
                            )
                            # L-10 (23.07, знайдено власною перевіркою): detect_topic()
                            # (перший-переможець) на КОРОТКОМУ фрагменті помилки —
                            # ризикований. Підтверджено конкретно: "The man which
                            # called" (помилка в relative_clause_defining) детектується
                            # detect_topic() як article_the, бо той стоїть вище в
                            # TOPIC_PATTERNS. Студент, що помиляється в новій темі,
                            # тихо НЕ отримує доопрацювання саме цієї теми.
                            #
                            # Виправлення: збираємо ВСІ збіги (detect_topics_all,
                            # не обмежена CEFR, на відміну від detect_topics_complex),
                            # і якщо AI сам назвав тему (gc["topic"], вільний текст
                            # типу "Present Perfect") — звіряємо текстово з ua/section
                            # знайдених тем, щоб обрати правильну серед кількох
                            # збігів. Якщо підказки немає або жодна не збіглась —
                            # fallback на стару поведінку (перший detect_topic) —
                            # безпечніше, ніж вигадувати евристику без даних.
                            _err_text = str(gc.get("error", "") or "")
                            _cor_text = str(gc.get("correct", "") or "")
                            _ai_topic = str(gc.get("topic", "") or "").lower().strip()

                            _hits = list(dict.fromkeys(_dta(_err_text) + _dta(_cor_text)))
                            _tk = None
                            if _ai_topic and _hits:
                                for _h in _hits:
                                    # AI пише topic АНГЛІЙСЬКОЮ (gc["topic"]) — звіряємо
                                    # з topic_key і signals (теж англійські), НЕ з ua/
                                    # section (українські, порівняння різними мовами
                                    # ніколи не збігається — знайдено власним тестом
                                    # до показу власниці, перша версія цієї перевірки
                                    # порівнювала англ. ai_topic з укр. ua/section).
                                    _h_signals = " ".join(
                                        str(s).lower() for s in _GM_dec.get(_h, {}).get("signals", [])
                                    )
                                    if (_ai_topic in _h.replace("_", " ")
                                            or _h.replace("_", " ") in _ai_topic
                                            or any(w in _h.replace("_", " ") or w in _h_signals
                                                   for w in _ai_topic.split() if len(w) > 3)):
                                        _tk = _h
                                        break
                            if not _tk and len(_hits) == 1:
                                _tk = _hits[0]  # єдиний збіг — без амбівалентності
                            if not _tk:
                                _tk = _dt(_err_text) or _dt(_cor_text)  # старий fallback
                            if _tk:
                                _s_dec = _mte2(get_s(uid), _tk, "error_in_free")
                                upd_s(uid, {"grammar_topics": _s_dec["grammar_topics"]})
                                _feature_log_event("grammar_decay", "error")
                                # ── Накопичуємо теми помилок за сесію (для підсумку у фіналі) ──
                                # Не заважає нуджам під час розмови — лише збирає список.
                                try:
                                    _sess_err = get_s(uid).get("buddy_session_errors", [])
                                    if _tk not in _sess_err:
                                        _sess_err.append(_tk)
                                        upd_s(uid, {"buddy_session_errors": _sess_err[-20:]})
                                except Exception:
                                    pass
                                # Відсилання повторити тему: 3+ помилки в одній темі
                                # → пропозиція закріпити (переиспользує nudge-систему).
                                try:
                                    _t_data = _s_dec.get("grammar_topics", {}).get(_tk, {})
                                    _err_n = _t_data.get("buddy_error_count", 0)
                                    if _err_n >= 3 and should_nudge(_s_dec, _tk):
                                        from grammar_engine import GRAMMAR_MAP as _GM
                                        _s_n = mark_nudge_sent(get_s(uid), _tk)
                                        upd_s(uid, {"grammar_topics": _s_n["grammar_topics"]})
                                        _ua = _GM.get(_tk, {}).get("ua", _tk)
                                        _feature_log_event("grammar_decay", "nudge_sent")
                                        await _HTTP_BOT.send_message(
                                            chat_id=uid,
                                            text=(f"📉 Помічаю, що тема *{_ua}* дається важкувато "
                                                  f"в розмові — кілька помилок поспіль.\n\n"
                                                  f"Хочеш закріпити її? Це підніме твій рівень володіння 💪"),
                                            parse_mode="Markdown",
                                            reply_markup=nudge_keyboard(),
                                        )
                                except Exception as _ne:
                                    logger.warning(f"repeat-topic nudge fail uid={uid}: {_ne}")
                    except Exception as _e:
                        logger.warning(f"grammar decay from chat fail uid={uid}: {_e}")

                # Session depth tracking for Chainy
                _track_button(uid, "chainy" if is_chainy else "buddy_scenario")

                upd_s(uid, buddy_updates)
            except Exception as e:
                logger.warning(f"buddy_stats save error uid={uid}: {e}")

        return _web.json_response({
            "reply":        parsed.get("reply", raw),
            "feedback":     parsed.get("feedback", []),
            "grammar_card": parsed.get("grammar_card", None),
            "remaining":    remaining,
        }, headers=CORS_BUDDY)
    except json.JSONDecodeError:
        return _web.json_response({"reply": raw, "feedback": []}, headers=CORS_BUDDY)
    except Exception as e:
        logger.error(f"buddy_chat error uid={uid}: {e}")
        return _web.json_response(
            {"reply": "Ого, зараз багато охочих поговорити 😅 Дай мені секунду й напиши ще раз — я тут!",
             "feedback": []},
            headers=CORS_BUDDY)


# ── Toast rewards ──
RATE_WINDOW_SEC_R = 60
RATE_MAX_PER_WINDOW_R = 30


def award_chain_link(uid: int, source: str = "") -> dict:
    """
    НАДБУДОВА: спільна точка нарахування ланки ланцюжка для БУДЬ-ЯКОЇ активності.

    Ідея: кожна завершена активність (buddy, vocab/progress miniapp, відео,
    збережена фраза тощо) дає +1 ланку. Існуючу логіку (XP, стрік, картки) НЕ
    чіпаємо — вона працює як була. Це лише додає ріст chain.length зверху.

    ВАЖЛИВО — без подвійного нарахування:
      • Монолог-урок НЕ викликає цю функцію (він нарощує ланцюжок напряму через
        chain_complete у process_text_monologue). Виклик звідси створив би дубль.
      • Захист від подвійного кліку: та сама активність в межах кількох секунд
        рахується один раз (поле last_link_ts).

    Повертає оновлений chain dict (або поточний, якщо нарахування пропущено).
    """
    import time as _t
    try:
        s = get_s(uid)
    except Exception:
        return {}

    # Анти-дубль: не частіше ніж раз на 3 секунди (захист від подвійного webhook/кліку)
    now_ts   = _t.time()
    last_ts  = s.get("last_link_ts", 0) or 0
    if now_ts - last_ts < 3:
        return get_chain(s)

    chain     = get_chain(s)
    new_chain = build_chain_after_session(chain)   # чиста функція: +1 length
    try:
        upd_s(uid, {
            "chain":            new_chain,
            "last_lesson_date": new_chain.get("last_active", ""),
            "last_link_ts":     now_ts,
            "last_link_source": source,
        })
    except Exception as e:
        logger.warning(f"award_chain_link {uid} ({source}): {e}")
        return chain
    return new_chain


def _check_reward_rate(uid: int) -> bool:
    """Anti-spam: не більше N подій за хвилину."""
    import time as _t
    now = _t.time()
    events = _REWARD_RATE.get(uid, [])
    events = [t for t in events if now - t < RATE_WINDOW_SEC_R]
    if len(events) >= RATE_MAX_PER_WINDOW_R:
        return False
    events.append(now)
    _REWARD_RATE[uid] = events
    return True


async def handle_sc_reward(request):
    """POST /sc_reward — toast подія від miniapp, записує XP + chain."""
    if request.method == "OPTIONS":
        return _web.Response(headers=CORS_BUDDY)
    try:
        data = await request.json()
    except Exception:
        return _web.json_response({"ok": False}, status=400, headers=CORS_BUDDY)

    # 21.07: require_verified_uid — init_data обовʼязковий (STRICT_INIT_DATA)
    uid, _auth_err = require_verified_uid(data)
    if _auth_err:
        return _web.json_response(_auth_err, status=401, headers=CORS_BUDDY)
    if not uid:
        return _web.json_response({"ok": False}, status=400, headers=CORS_BUDDY)

    if not _check_reward_rate(uid):
        return _web.json_response({"ok": False, "error": "rate limit"}, status=429, headers=CORS_BUDDY)

    action       = data.get("action", "")
    xp_amount    = max(0, min(int(data.get("xp", 0)), 100))
    chain_amount = max(0, min(int(data.get("chain", 0)), 5))

    try:
        s = get_s(uid)
    except Exception:
        return _web.json_response({"ok": False}, status=500, headers=CORS_BUDDY)

    updates = {}
    if xp_amount > 0:
        updates["xp_total"] = s.get("xp_total", 0) + xp_amount
        xp_log = s.get("xp_log", [])
        xp_log.append({
            "date":   datetime.now().isoformat(),
            "action": action,
            "amount": xp_amount,
        })
        updates["xp_log"] = xp_log[-100:]

    if chain_amount > 0:
        today = datetime.now().strftime("%Y-%m-%d")
        actions_today = s.get("actions_today", {})
        if actions_today.get("date") != today:
            actions_today = {"date": today, "count": 0}
        actions_today["count"] += chain_amount
        updates["actions_today"] = actions_today
        if s.get("last_date") != today:
            updates["last_date"] = today

    if updates:
        try:
            upd_s(uid, updates)
        except Exception as e:
            logger.warning(f"sc_reward upd_s error uid={uid}: {e}")
            return _web.json_response({"ok": False}, status=500, headers=CORS_BUDDY)

    # ── НАДБУДОВА: реально нарощуємо ланцюжок за цю активність ──
    if chain_amount > 0:
        award_chain_link(uid, source=f"reward:{action}")

    return _web.json_response({
        "ok":          True,
        "xp_added":    xp_amount,
        "chain_added": chain_amount,
    }, headers=CORS_BUDDY)


def _next_level_xp_line(s: dict) -> str:
    """Будує рядок 'XP в межах рівня / потрібно XP до наступного рівня'."""
    try:
        xp_total = s.get("xp_total", 0)
        level    = s.get("level", "A1")
        d        = get_cefr_xp_progress(xp_total, level)
        levels   = d["levels"]
        cur_idx  = d["cur_idx"]
        # Наступний рівень (якщо не останній)
        nxt_level = levels[cur_idx + 1] if cur_idx + 1 < len(levels) else levels[cur_idx]
        xp_in     = d["xp_in_level"]
        need      = d["level_xp_needed"]
        return f"⚡ +{{xp}} XP → {xp_in:,} / {need:,} XP до {nxt_level}"
    except Exception:
        return "⚡ +{xp} XP"


# Анти-дубль: sendBeacon може спрацювати двічі (visibilitychange + pagehide)
_BUDDY_SESSION_GUARD: dict = {}
_BUDDY_SESSION_GUARD_SEC = 90


async def handle_buddy_session_end(request):
    """POST /buddy_session_end — закриття Chainy → нараховує XP+chain і шле картку."""
    if request.method == "OPTIONS":
        return _web.Response(headers=CORS_BUDDY)
    try:
        data = await request.json()
    except Exception:
        return _web.json_response({"ok": False}, status=400, headers=CORS_BUDDY)

    # 21.07: require_verified_uid — init_data обовʼязковий (STRICT_INIT_DATA)
    uid, _auth_err = require_verified_uid(data)
    if _auth_err:
        return _web.json_response(_auth_err, status=401, headers=CORS_BUDDY)
    if not uid:
        return _web.json_response({"ok": False}, status=400, headers=CORS_BUDDY)

    # Кількість повідомлень користувача за сесію
    msgs = max(0, min(int(data.get("messages", 0) or 0), 200))
    if msgs < 1:
        # Порожня сесія — нічого не нараховуємо
        return _web.json_response({"ok": True, "skipped": "empty"}, headers=CORS_BUDDY)

    # 23.07 (I-05): облік тривалості Chainy-сесії. speaking_buddy.html
    # НЕ завантажений жодного разу в жодному чаті — тому НЕ чіпаємо
    # фронтенд наздогад (той самий принцип обережності, що застосований
    # до finance.py/bloggers_admin.py раніше). Бекенд готовий прийняти
    # duration_sec, ЯКЩО клієнт колись стане його слати (як player.html
    # шле playback_sec) — але без цього не падає, рахує консервативну
    # ОЦІНКУ через кількість повідомлень. Явно позначаємо результат
    # прапорцем is_estimated, щоб адмінка НІКОЛИ не показала оцінку як
    # факт поруч із точними speaking_seconds_total/player_minutes_total.
    _duration_sec = data.get("duration_sec")
    if _duration_sec is not None:
        try:
            _duration_sec = max(0, int(_duration_sec))
            _is_estimated = False
        except (TypeError, ValueError):
            _duration_sec = None
    if _duration_sec is None:
        _duration_sec = msgs * 20   # евристика: ~20 сек читання+відповіді на повідомлення
        _is_estimated = True

    # Анти-дубль по часу
    import time as _t
    now = _t.time()
    last = _BUDDY_SESSION_GUARD.get(uid, 0)
    if now - last < _BUDDY_SESSION_GUARD_SEC:
        return _web.json_response({"ok": True, "skipped": "dup"}, headers=CORS_BUDDY)
    _BUDDY_SESSION_GUARD[uid] = now

    async def _process():
        try:
            bot = _HTTP_BOT
            if not bot:
                return
            s     = get_s(uid)
            today = datetime.now().strftime("%Y-%m-%d")

            # ── XP: 2 за повідомлення, макс 15 (= один монолог) × triple ──
            base_xp = min(XP_AWARDS.get("session", 15),
                          msgs * XP_AWARDS.get("chainy_msg", 2))
            mult    = 3 if s.get("triple_xp_date") == today else 1
            final_xp = base_xp * mult
            new_xp  = s.get("xp_total", 0) + final_xp
            upd_s(uid, {"xp_total": new_xp})

            # ── XP log ──
            s = get_s(uid)
            xp_log = s.get("xp_log", [])
            xp_log.append({"date": datetime.now().isoformat(),
                           "action": "chainy_session", "amount": final_xp})
            upd_s(uid, {"xp_log": xp_log[-100:]})

            # ── first_chainy_date (для аналітики feature discovery) ──
            if not s.get("first_chainy_date"):
                upd_s(uid, {"first_chainy_date": today})

            # ── Chain: 1 фраза = зараховує день ──
            _, _, milestone = update_streak(uid)   # оновлює streak_days, last_date
            # ── НАДБУДОВА: buddy-сесія теж нарощує ланцюжок (стрік лишаємо як є) ──
            award_chain_link(uid, source="buddy_session")
            s = get_s(uid)
            streak = s.get("streak_days", 0)

            # 23.07 (I-05): накопичуємо тривалість Chainy окремо від
            # ТОЧНИХ джерел (speaking_seconds_total/player_minutes_total).
            # chainy_seconds_estimated рахує, скільки з накопиченого —
            # оцінка (поки duration_sec не приходить від фронтенду) —
            # адмінка має явно попереджати, не видавати за факт.
            upd_s(uid, {
                "chainy_seconds_total": s.get("chainy_seconds_total", 0) + _duration_sec,
                "chainy_seconds_estimated": (s.get("chainy_seconds_estimated", 0) + _duration_sec
                                              if _is_estimated
                                              else s.get("chainy_seconds_estimated", 0)),
            })
            s = get_s(uid)

            # XP за стрік-майлстони (як у решті системи)
            if milestone in ("streak_7", "streak_30", "streak_40", "streak_100"):
                bonus = XP_AWARDS.get(milestone, 0)
                if bonus:
                    upd_s(uid, {"xp_total": get_s(uid).get("xp_total", 0) + bonus})
                # Авто share-картка в момент гордості (найвищий ROI з роадмапу)
                asyncio.create_task(send_milestone_share(bot, uid, milestone))

            # ── Victory card data (під flag): зв'язуємо XP+Chain+Rank ──
            if ENABLE_VICTORY_CARD:
                try:
                    rank_data = _compute_rank_and_gap(uid)
                    prev_rank = s.get("last_session_rank")
                    rank_delta = (prev_rank - rank_data["rank"]) if (prev_rank and rank_data.get("rank")) else 0
                    if rank_data.get("rank"):
                        upd_s(uid, {"last_session_rank": rank_data["rank"]})
                    _BUDDY_VICTORY_CACHE[uid] = {
                        "xp_gained": final_xp, "xp_total": new_xp, "multiplier": mult,
                        "streak": streak, "milestone": milestone,
                        "rank": rank_data.get("rank"), "total": rank_data.get("total"),
                        "gap_to_next": rank_data.get("gap_to_next"),
                        "next_name": rank_data.get("next_name"),
                        "is_top": rank_data.get("is_top"),
                        "percentile": rank_data.get("percentile"),
                        "rank_delta": rank_delta,
                        "ts": __import__("time").time(),
                    }
                    _feature_log_event("victory", "shown")
                    if rank_delta > 0:
                        _feature_log_event("victory", "rank_up")
                except Exception as _e:
                    logger.warning(f"victory cache failed uid={uid}: {_e}")

            # ── Картка ──
            s = get_s(uid)
            phrase   = random.choice(CHAINY_SESSION_PHRASES)
            xp_line  = _next_level_xp_line(s).format(xp=final_xp)
            if mult == 3:
                xp_line += " (×3 🔥)"
            streak_line = f"🔗 chains: *{msgs}*"
            if streak > 1:
                streak_line += f"\n🔥 Дні поспіль: *{streak}*"

            # ── Підсумок граматики за сесію (варіант 2: + до нуджів) ──
            # Збираємо теми, у яких були помилки протягом розмови, і пропонуємо
            # потренувати їх у кінці. Список очищаємо після показу.
            _grammar_line = ""
            _has_topics = False
            try:
                _sess_err = s.get("buddy_session_errors", [])
                if _sess_err:
                    from grammar_engine import GRAMMAR_MAP as _GM
                    _names = []
                    for _k in _sess_err[:3]:
                        _names.append(_GM.get(_k, {}).get("ua", _k))
                    if _names:
                        _has_topics = True
                        _grammar_line = (
                            "\n\n📚 *Варто потренувати:* "
                            + ", ".join(_names)
                        )
                        # зберігаємо теми для кнопки тренування (перш ніж чистити накопичувач)
                        upd_s(uid, {"buddy_train_queue": _sess_err[:3]})
                # очищаємо накопичувач сесії у будь-якому разі
                upd_s(uid, {"buddy_session_errors": []})
            except Exception as _ge:
                logger.warning(f"session grammar summary fail uid={uid}: {_ge}")

            # Кнопки картки: тренування (якщо є теми) + продовжити
            _card_buttons = []
            if _has_topics:
                try:
                    _card_buttons.append([InlineKeyboardButton(
                        "🎯 Потренувати теми", callback_data="chainy_train_errors")])
                except Exception:
                    pass
            _card_buttons.append([InlineKeyboardButton("🚀 Продовжити", callback_data="card_go")])

            await bot.send_message(
                chat_id=uid,
                text=(
                    f"🔥 *Сесію завершено!*\n\n"
                    f"_{phrase}_\n\n"
                    f"{streak_line}\n"
                    f"{xp_line}"
                    f"{_grammar_line}"
                ),
                parse_mode="Markdown",
                reply_markup=InlineKeyboardMarkup(_card_buttons)
            )
        except Exception as e:
            logger.warning(f"buddy_session_end process error uid={uid}: {e}")

    asyncio.create_task(_process())
    return _web.json_response({"ok": True}, headers=CORS_BUDDY)


async def handle_buddy_victory(request):
    """GET /buddy_victory?uid=... — дані останньої сесії для анімованої картки."""
    if not ENABLE_VICTORY_CARD:
        return _web.json_response({"ok": False, "disabled": True}, headers=CORS_BUDDY)
    if request.method == "OPTIONS":
        return _web.Response(headers=CORS_BUDDY)
    try:
        uid = int(request.query.get("uid", "0"))
    except (TypeError, ValueError):
        return _web.json_response({"ok": False}, status=400, headers=CORS_BUDDY)
    data = _BUDDY_VICTORY_CACHE.get(uid)
    if not data:
        return _web.json_response({"ok": False, "empty": True}, headers=CORS_BUDDY)
    return _web.json_response({"ok": True, **data}, headers=CORS_BUDDY)


# ── Універсальна картка для Vocab / Progress ──
_MINIAPP_SESSION_GUARD: dict = {}

_MINIAPP_CFG = {
    "vocab":    {"title": "📚 Словник",  "unit": "слів опрацьовано",  "xp_each": 2},
    "progress": {"title": "📈 Прогрес", "unit": "речень проговорено", "xp_each": 2},
}


async def handle_miniapp_session_end(request):
    """POST /miniapp_session_end — закриття Vocab/Progress → XP+chain+картка."""
    if request.method == "OPTIONS":
        return _web.Response(headers=CORS_BUDDY)
    try:
        data = await request.json()
    except Exception:
        return _web.json_response({"ok": False}, status=400, headers=CORS_BUDDY)

    # 21.07: require_verified_uid — init_data обовʼязковий (STRICT_INIT_DATA)
    uid, _auth_err = require_verified_uid(data)
    if _auth_err:
        return _web.json_response(_auth_err, status=401, headers=CORS_BUDDY)
    if not uid:
        return _web.json_response({"ok": False}, status=400, headers=CORS_BUDDY)

    source = data.get("source", "")
    cfg = _MINIAPP_CFG.get(source)
    if not cfg:
        return _web.json_response({"ok": False}, status=400, headers=CORS_BUDDY)

    count = max(0, min(int(data.get("count", 0) or 0), 300))
    if count < 1:
        return _web.json_response({"ok": True, "skipped": "empty"}, headers=CORS_BUDDY)

    import time as _t
    now = _t.time()
    gkey = f"{source}:{uid}"
    if now - _MINIAPP_SESSION_GUARD.get(gkey, 0) < _BUDDY_SESSION_GUARD_SEC:
        return _web.json_response({"ok": True, "skipped": "dup"}, headers=CORS_BUDDY)
    _MINIAPP_SESSION_GUARD[gkey] = now

    async def _process():
        try:
            bot = _HTTP_BOT
            if not bot:
                return
            s     = get_s(uid)
            today = datetime.now().strftime("%Y-%m-%d")

            base_xp  = min(XP_AWARDS.get("session", 15), count * cfg["xp_each"])
            mult     = 3 if s.get("triple_xp_date") == today else 1
            final_xp = base_xp * mult
            upd_s(uid, {"xp_total": s.get("xp_total", 0) + final_xp})

            s = get_s(uid)
            xp_log = s.get("xp_log", [])
            xp_log.append({"date": datetime.now().isoformat(),
                           "action": f"{source}_session", "amount": final_xp})
            upd_s(uid, {"xp_log": xp_log[-100:]})

            _, _, milestone = update_streak(uid)
            # ── НАДБУДОВА: vocab/progress сесія теж нарощує ланцюжок ──
            award_chain_link(uid, source=f"{source}_session")
            if milestone in ("streak_7", "streak_30", "streak_40", "streak_100"):
                bonus = XP_AWARDS.get(milestone, 0)
                if bonus:
                    upd_s(uid, {"xp_total": get_s(uid).get("xp_total", 0) + bonus})
                asyncio.create_task(send_milestone_share(bot, uid, milestone))

            s = get_s(uid)
            streak  = s.get("streak_days", 0)
            phrase  = random.choice(CHAINY_SESSION_PHRASES)
            xp_line = _next_level_xp_line(s).format(xp=final_xp)
            if mult == 3:
                xp_line += " (×3 🔥)"
            stat_line = f"🔗 chains: *{count}*  ({cfg['unit']})"
            if streak > 1:
                stat_line += f"\n🔥 Дні поспіль: *{streak}*"

            await bot.send_message(
                chat_id=uid,
                text=(f"🔥 *{cfg['title']} — сесію завершено!*\n\n"
                      f"_{phrase}_\n\n{stat_line}\n{xp_line}"),
                parse_mode="Markdown",
                reply_markup=InlineKeyboardMarkup([
                    [InlineKeyboardButton("🚀 Продовжити", callback_data="card_go")],
                ])
            )
        except Exception as e:
            logger.warning(f"miniapp_session_end({source}) error uid={uid}: {e}")

    asyncio.create_task(_process())
    return _web.json_response({"ok": True}, headers=CORS_BUDDY)



async def cb_card_go(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    await q.answer()
    try:
        await q.edit_message_reply_markup(
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton("▶️ Урок дня", callback_data="card_lesson")],
                [InlineKeyboardButton("🌅 Фраза дня", callback_data="card_phrase"),
                 InlineKeyboardButton("🎯 Челендж",   callback_data="card_challenge")],
            ])
        )
    except Exception as e:
        logger.warning(f"cb_card_go error: {e}")


async def cb_card_lesson(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    q    = update.callback_query
    user = q.from_user
    await q.answer()
    try:
        await ctx.bot.send_message(
            chat_id=user.id,
            text="▶️ Готовий до уроку? Натисни *«▶️ Урок дня»* в меню внизу 👇",
            parse_mode="Markdown",
        )
    except Exception as e:
        logger.warning(f"cb_card_lesson error: {e}")


async def cb_card_phrase(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    q    = update.callback_query
    user = q.from_user
    s    = get_s(user.id)
    await q.answer()
    try:
        srs_db = s.get("srs_words", {})
        if srs_db:
            candidates = list(srs_db.items())
            candidates.sort(key=lambda x: x[1].get("count_know", 0))
            word, entry = random.choice(candidates[:5])
            translation = entry.get("translation", "")
            example     = entry.get("example", "")
            intro = random.choice(PHRASE_OF_DAY_INTROS)
            text  = f"{intro}\n\n🔤 *{word}*"
            if translation:
                text += f"\n📖 _{translation}_"
            if example:
                text += f"\n\n💬 _{example}_"
            text += "\n\n👇 Використай цю фразу у монолозі — і вона залишиться назавжди!"
            await ctx.bot.send_message(
                chat_id=user.id, text=text, parse_mode="Markdown",
                reply_markup=InlineKeyboardMarkup([
                    [InlineKeyboardButton("🎙 Записати монолог з цією фразою", callback_data="remind_record")],
                ])
            )
        else:
            await ctx.bot.send_message(
                chat_id=user.id,
                text="🌅 Моя картотека фраз поки порожня. Збережи перші фрази з відеоуроку — і тут з'явиться фраза дня! 💎",
                parse_mode="Markdown",
            )
    except Exception as e:
        logger.warning(f"cb_card_phrase error: {e}")


async def cb_card_challenge(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    q    = update.callback_query
    user = q.from_user
    s    = get_s(user.id)
    await q.answer()
    try:
        bname = s.get("affiliate_blogger", "")
        ch    = get_blogger_challenge(bname) if bname else {}
        if ch and ch.get("active"):
            topic = ch.get("topic", "")
            await ctx.bot.send_message(
                chat_id=user.id,
                text=(f"🎯 *Челендж від @{bname}:*\n\n_{topic}_\n\n"
                      "Запиши голосовий монолог на цю тему 👇"),
                parse_mode="Markdown",
                reply_markup=InlineKeyboardMarkup([
                    [InlineKeyboardButton("🎙 Записати монолог", callback_data="remind_record")],
                ])
            )
        else:
            await ctx.bot.send_message(
                chat_id=user.id,
                text="🎯 Зараз немає активного челенджу. Відкрий *«🎯 Челендж»* в меню, щоб приєднатися до загального speaking challenge! 👇",
                parse_mode="Markdown",
            )
    except Exception as e:
        logger.warning(f"cb_card_challenge error: {e}")


