async def handle_ai_ab_hypotheses(request):
    """
    POST /admin_ab_hypotheses → A/B-гіпотези з кривої відвалу челенджу (крок 3).
    Сам збирає воронку через _build_challenge_funnel_analytics і подає в модель.
    """
    if request.method == "OPTIONS":
        return _web.Response(headers=CORS_BUDDY)

    try:
        body = await request.json()
    except Exception:
        return _web.json_response({"error": "Invalid JSON"}, status=400, headers=CORS_BUDDY)

    # Перевірка адміна (той самий патерн, що в insights/tz)
    # 21.07: require_verified_uid — init_data обовʼязковий (STRICT_INIT_DATA)
    uid, _auth_err = require_verified_uid(body)
    if _auth_err:
        return _web.json_response(_auth_err, status=401, headers=CORS_BUDDY)
    admin_ok = is_admin(uid) or (ADMIN_ID and uid == ADMIN_ID)
    if not admin_ok:
        return _web.json_response({"error": "Доступ заборонено"}, status=403, headers=CORS_BUDDY)

    # Збираємо воронку челенджу
    db = load_db()
    students = [v for k, v in db.items()
                if isinstance(v, dict) and k not in DB_SKIP_KEYS]
    funnel = _build_challenge_funnel_analytics(students)
    today = datetime.now().strftime("%Y-%m-%d")

    # Захист: якщо ще нема стартів — не гати модель, скажи прямо
    started_total = (funnel.get("total") or {}).get("started", 0)
    if not started_total:
        return _web.json_response({
            "analysis": ("Ще нема даних воронки челенджу — ніхто не стартував із "
                         "новим трекінгом. Дай воронці попрацювати кілька днів "
                         "(вкладка «📉 Воронка»), тоді повертайся сюди."),
            "generated_at": today,
        }, headers=CORS_BUDDY)

    import json as _json
    funnel_json = _json.dumps(funnel, ensure_ascii=False, indent=2)

    try:
        cr = await claude_create_async(
            model="claude-opus-4-6",
            max_tokens=2500,
            system=AI_AB_SYSTEM,
            messages=[{
                "role": "user",
                "content": ("Ось поточна крива відвалу челенджу (JSON `challenge_funnel`). "
                            "Згенеруй пріоритезовані A/B-гіпотези за своїм форматом:\n\n"
                            f"```json\n{funnel_json}\n```")
            }]
        )
        analysis = cr.content[0].text.strip()
        return _web.json_response({"analysis": analysis, "generated_at": today}, headers=CORS_BUDDY)
    except Exception as e:
        logger.error(f"AI ab-hypotheses error: {e}")
        return _web.json_response({"error": f"AI error: {e}"}, status=500, headers=CORS_BUDDY)


async def handle_ai_tz(request):
    """POST /admin_tz → ТЗ для Claude на основі аналітики."""
    if request.method == "OPTIONS":
        return _web.Response(headers=CORS_BUDDY)
    try:
        body = await request.json()
    except Exception:
        return _web.json_response({"error": "Invalid JSON"}, status=400, headers=CORS_BUDDY)

    # 21.07: require_verified_uid — init_data обовʼязковий (STRICT_INIT_DATA)
    uid, _auth_err = require_verified_uid(body)
    if _auth_err:
        return _web.json_response(_auth_err, status=401, headers=CORS_BUDDY)

    admin_ok = is_admin(uid) or (ADMIN_ID and uid == ADMIN_ID)
    if not admin_ok:
        return _web.json_response({"error": "Доступ заборонено"}, status=403, headers=CORS_BUDDY)

    # Беремо аналіз якщо переданий, або генеруємо короткий summary
    prev_analysis = body.get("analysis", "")

    db       = load_db()
    students = [v for k,v in db.items()
                if isinstance(v,dict) and k not in DB_SKIP_KEYS and v.get("onboarding_done")]
    total    = max(len(students), 1)
    today    = datetime.now().strftime("%Y-%m-%d")

    from datetime import timedelta
    def pct(a,b): return round(a/max(b,1)*100,1)

    did_lesson   = sum(1 for s in students if s.get("done_lessons"))
    did_chainy   = sum(1 for s in students if s.get("buddy_stats",{}).get("total_messages",0)>0)
    did_vocab    = sum(1 for s in students if s.get("mined_sentences"))
    paid_users   = sum(1 for s in students if is_premium(s))
    active_today = sum(1 for s in students if s.get("last_date","")==today)
    avg_chain    = round(sum(s.get("streak_days",0) for s in students)/total,1)

    chainy_days = []
    for s in students:
        reg   = s.get("registered_at","")[:10]
        first = s.get("first_chainy_date","")[:10]
        if reg and first:
            try:
                from datetime import datetime as _dt
                chainy_days.append((_dt.strptime(first,"%Y-%m-%d")-_dt.strptime(reg,"%Y-%m-%d")).days)
            except: pass
    median_chainy = sorted(chainy_days)[len(chainy_days)//2] if chainy_days else None

    def conv(fn):
        f=[s for s in students if fn(s)]
        return pct(sum(1 for s in f if is_premium(s)),len(f)) if f else 0

    summary = f"""
КЛЮЧОВІ МЕТРИКИ (для ТЗ):
- Всього юзерів: {total}, активних сьогодні: {active_today} ({pct(active_today,total)}%)
- Зробили урок: {pct(did_lesson,total)}% | Говорили Chainy: {pct(did_chainy,total)}% | Словник: {pct(did_vocab,total)}%
- Платних: {paid_users} ({pct(paid_users,total)}%)
- Avg chain: {avg_chain} днів
- Медіана днів до першого Chainy: {median_chainy or 'н/д'}
- Конверсія при 5+ Chainy сесіях: {conv(lambda s: s.get('buddy_stats',{}).get('total_sessions',0)>=5)}%
- Конверсія при 7+ уроках: {conv(lambda s: len(s.get('done_lessons',[]))>=7)}%

ПОПЕРЕДНІЙ АНАЛІЗ (скорочено):
{prev_analysis[:800] if prev_analysis else 'Не надано'}
"""

    system = AI_TZ_SYSTEM.replace("{date}", today)

    try:
        cr = await claude_create_async(
            model="claude-opus-4-6",
            max_tokens=3000,
            system=system,
            messages=[{
                "role": "user",
                "content": f"На основі цих даних згенеруй ТЗ для Claude:\n\n{summary}"
            }]
        )
        tz_text = cr.content[0].text.strip()
        return _web.json_response({"tz": tz_text, "generated_at": today}, headers=CORS_BUDDY)
    except Exception as e:
        logger.error(f"AI TZ error: {e}")
        return _web.json_response({"error": str(e)}, status=500, headers=CORS_BUDDY)


