# BUTTON ANALYTICS — невидимий трекінг для адміна
# ══════════════════════════════════════════════════════════════

def _track_button(uid: int, button_name: str):
    """
    Записує натискання кнопки в профіль юзера (write-behind → PostgreSQL).
    Також трекає:
    - first-time events (перший урок, перший Chainy тощо)
    - session depth (кількість дій за сесію)
    - час між реєстрацією і першою дією
    """
    import time as _t
    try:
        s    = get_s(uid)
        now  = _t.strftime("%Y-%m-%d %H:%M", _t.localtime())
        today= _t.strftime("%Y-%m-%d", _t.localtime())
        ts   = _t.time()

        updates = {}

        # ── Лічильник кнопок ──
        log = s.get("button_log", [])
        log.append({"btn": button_name, "ts": now, "date": today})
        updates["button_log"]    = log[-500:]
        counts = s.get("button_counts", {})
        counts[button_name]      = counts.get(button_name, 0) + 1
        updates["button_counts"] = counts

        # ── First-time events ──
        first_map = {
            "урок_дня":    "first_lesson_date",
            "chainy":      "first_chainy_date",
            "словник":     "first_vocab_date",
            "мій_профіль": "first_profile_date",
            "прогрес":     "first_progress_date",
        }
        fk = first_map.get(button_name)
        if fk and not s.get(fk):
            updates[fk] = now
            # Час до першої дії після реєстрації (в годинах)
            if button_name == "урок_дня":
                reg = s.get("registered_at", "")
                if reg:
                    try:
                        from datetime import datetime as _dt
                        reg_dt  = _dt.strptime(reg[:16], "%Y-%m-%d %H:%M")
                        act_dt  = _dt.strptime(now,       "%Y-%m-%d %H:%M")
                        hours   = round((act_dt - reg_dt).total_seconds() / 3600, 1)
                        updates["hours_to_first_lesson"] = hours
                    except Exception:
                        pass

        # ── Session depth ──
        # Сесія = активність протягом 30 хвилин
        session = s.get("current_session", {"start": ts, "actions": [], "date": today})
        if ts - session.get("start", 0) > 1800 or session.get("date") != today:
            # Нова сесія — зберігаємо стару
            old_depth = len(session.get("actions", []))
            if old_depth > 0:
                depth_log = s.get("session_depth_log", [])
                depth_log.append({
                    "date":    session.get("date", today),
                    "depth":   old_depth,
                    "dur_min": round((ts - session.get("start", ts)) / 60, 1),
                    "actions": session.get("actions", [])[-10:],
                })
                updates["session_depth_log"] = depth_log[-100:]

            session = {"start": ts, "actions": [button_name], "date": today}
        else:
            session["actions"] = session.get("actions", []) + [button_name]

        updates["current_session"] = session

        upd_s(uid, updates)
    except Exception as e:
        logger.debug(f"_track_button error: {e}")


# ══════════════════════════════════════════════════════════════
# МІЙ ПРОФІЛЬ — об'єднує Chain Dashboard + Progress + Timeline
# ══════════════════════════════════════════════════════════════

async def cmd_profile(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """
    👤 Мій профіль — головна кнопка.
    Показує: chain, XP, рівень, граматичний прогрес, аудіо таймлайн.
    Містить кнопки до мініаппів і /plan.
    """
    user = update.effective_user
    s    = get_s(user.id)

    # Chain
    chain      = get_chain(s)
    chain_len  = chain.get("length", 0)
    xp_total   = s.get("xp_total", 0)
    level      = s.get("level", "A1")
    name       = s.get("name", user.first_name or "")

    # XP до наступного рівня
    level_order = ["A1","A2","B1","B2","C1","C2"]
    next_level  = level_order[level_order.index(level)+1] if level in level_order and level != "C2" else None
    xp_to_next  = max(0, CEFR_CUMULATIVE_XP.get(next_level or "C2", 0) - xp_total) if next_level else 0

    # Граматичний прогрес
    grammar_topics = s.get("grammar_topics", {})
    mastered = [k for k,v in grammar_topics.items() if isinstance(v,dict) and v.get("mastered")]
    total_topics = sum(len(v) for v in CEFR_GRAMMAR.values()) if CEFR_GRAMMAR else 60
    grammar_pct = round(len(mastered) / total_topics * 100) if total_topics else 0

    # Аудіо прогрес
    first_score  = s.get("first_voice_score", 0)
    scores       = s.get("scores", [])
    recent_score = scores[-1].get("score", 0) if scores else first_score
    voice_diff   = recent_score - first_score

    # Buddy stats
    buddy_stats = s.get("buddy_stats", {})
    buddy_sessions = buddy_stats.get("total_sessions", 0)

    # Spoken total
    spoken_total = s.get("spoken_total", 0)

    text = (
        f"👤 *{name}*  ·  {level}\n\n"
        f"🔗 Chain: *{chain_len} днів*\n"
        f"⚡ XP: *{xp_total:,}*"
        + (f"  ·  до {next_level}: *{xp_to_next:,}*" if next_level else "") + "\n\n"
        f"📈 Граматика: *{grammar_pct}%* засвоєно ({len(mastered)}/{total_topics} тем)\n"
        f"🗣 Chainy: *{buddy_sessions}* розмов\n"
        f"🎙 Проговорено: *{spoken_total}* фраз\n"
        + (f"\n📊 Голос: *{first_score}→{recent_score}* (+{voice_diff})" if first_score else "") +
        f"\n\n_Більше деталей — у мініаппах нижче_ 👇"
    )

    # URL для мініаппів
    db        = load_db()
    dash_url  = _build_chain_dashboard_url(user.id, s, db=db)
    prog_url  = _build_progress_url(user.id, s)
    paywall_url = _build_paywall_url(user.id, s)

    kb = InlineKeyboardMarkup([
        [InlineKeyboardButton("📊 Chain Dashboard", web_app=WebAppInfo(url=dash_url)),
         InlineKeyboardButton("📈 Прогрес тем",    web_app=WebAppInfo(url=prog_url))],
        [InlineKeyboardButton("🎙 Таймлайн голосу", callback_data="show_timeline"),
         InlineKeyboardButton("🏆 Лідерборд",       callback_data="community_leaderboard")],
        [InlineKeyboardButton("💳 Мій план / підписка", callback_data="show_plan")],
        # Постійна точка входу в Paywall Mini App (рішення аудиту 07/2026, P9):
        # доступна завжди з профілю, незалежно від статусу підписки.
        [InlineKeyboardButton("💎 Обрати / змінити план", web_app=WebAppInfo(url=paywall_url))],
    ])

    await update.message.reply_text(text, parse_mode="Markdown", reply_markup=kb)


async def cmd_plan(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """/plan — Поточна підписка + Paywall + Cancel."""
    user = update.effective_user
    s    = get_s(user.id)

    plan    = s.get("plan", "")
    until   = s.get("premium_until", "")
    is_paid = is_premium(s)
    is_trial_active = is_in_trial(s)

    if is_paid:
        plan_name = "Basic ⭐" if plan == "basic" else "Premium 💎"
        text = (
            f"💳 *Твій план: {plan_name}*\n"
            f"Активний до: *{until}*\n\n"
            f"_Автосписань немає — коли період завершиться, продовжиш вручну._\n"
            "Що входить у план — /help"
        )
        kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("⬆️ Підвищити план",    callback_data="upgrade_plan")],
            [InlineKeyboardButton("🔄 Продовжити зараз",   callback_data="show_monthly_plans")],
        ])
    elif is_trial_active:
        text = "🎓 *Ти на безкоштовному тріалі*\n\nОбери план щоб продовжити після закінчення:"
        p = get_prices(s)
        paywall_url = _build_paywall_url(user.id, s)
        kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("💳 Обрати план", web_app=WebAppInfo(url=paywall_url))],
        ])
    else:
        text = "🔓 *У тебе немає активної підписки*\n\nОбери план щоб отримати повний доступ:"
        paywall_url = _build_paywall_url(user.id, s)
        kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("💳 Переглянути плани", web_app=WebAppInfo(url=paywall_url))],
        ])

    await update.message.reply_text(text, parse_mode="Markdown", reply_markup=kb)


async def cb_show_plan(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    """Callback show_plan — з профілю."""
