if __name__ == "__main__":
    import threading
    from aiohttp import web as _web

    print("=== STARTING HTTP SERVER ===", flush=True)

    def run_http():
        import asyncio as _asyncio
        import time as _t_mod
        print("=== HTTP THREAD STARTED ===", flush=True)

        @_web.middleware
        async def _cors_mw(request, handler):
            # Preflight — відповідаємо одразу з CORS, не доходячи до роутів
            if request.method == "OPTIONS":
                return _web.Response(status=200, headers={
                    "Access-Control-Allow-Origin":  "*",
                    "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
                    "Access-Control-Allow-Headers": "Content-Type, Authorization",
                    "Access-Control-Max-Age":       "86400",
                })
            try:
                resp = await handler(request)
            except _web.HTTPException as ex:
                ex.headers["Access-Control-Allow-Origin"] = "*"
                raise
            except Exception as ex:
                import traceback as _tb
                logger.error(f"HTTP 500 у {request.method} {request.path}: {ex}\n{_tb.format_exc()}")
                return _web.json_response(
                    {"error": "internal", "detail": str(ex)},
                    status=500,
                    headers={
                        "Access-Control-Allow-Origin":  "*",
                        "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
                        "Access-Control-Allow-Headers": "Content-Type, Authorization",
                    },
                )
            resp.headers["Access-Control-Allow-Origin"]  = "*"
            resp.headers["Access-Control-Allow-Methods"] = "GET, POST, OPTIONS"
            resp.headers["Access-Control-Allow-Headers"] = "Content-Type, Authorization"
            return resp

        async def _start():
            wfp = _web.Application(middlewares=[_cors_mw])
            wfp.router.add_get("/pay",                handle_wayforpay_pay_page)
            wfp.router.add_post("/wayforpay_webhook", handle_wayforpay_webhook)
            wfp.router.add_get("/captions",           handle_captions_proxy)
            if ENABLE_VIDEO_TO_BUDDY:
                wfp.router.add_get("/video_summary",      handle_video_summary)
            wfp.router.add_post("/register_ref",     handle_register_ref)
            wfp.router.add_post("/session",           handle_session_end)
            wfp.router.add_post("/player_action",     handle_player_action)
            wfp.router.add_post("/miniapp_action",    handle_miniapp_action)
            wfp.router.add_post("/err_fix",           handle_err_fix)
            wfp.router.add_route("OPTIONS", "/err_fix", lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_route("OPTIONS", "/miniapp_action", lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_get("/chain_dashboard",    handle_chain_dashboard)
            wfp.router.add_get("/social_invite",      handle_social_invite)
            wfp.router.add_get("/leaderboard",        handle_leaderboard)
            wfp.router.add_get("/paywall",            handle_paywall)

            # ── Speaking Buddy API (HTML на GitHub Pages) ──
            # GET /buddy, /progress, /admin_analytics — не потрібні
            # HTML роздає GitHub Pages: https://discoveritschool-hub.github.io/speakchain-app/
            wfp.router.add_post("/buddy_status",     handle_buddy_status)
            wfp.router.add_get ("/duo_room_state",   handle_duo_room_state)
            wfp.router.add_route("OPTIONS", "/duo_room_state", lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_get ("/relay_room_state", handle_relay_room_state)
            wfp.router.add_route("OPTIONS", "/relay_room_state", lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_get ("/buddy_image",      handle_buddy_image)
            wfp.router.add_post("/buddy_chat",       handle_buddy_chat)
            wfp.router.add_post("/sc_reward",        handle_sc_reward)
            wfp.router.add_post("/buddy_session_end", handle_buddy_session_end)
            wfp.router.add_route("OPTIONS", "/buddy_session_end", lambda r: _web.Response(headers=CORS_BUDDY))
            if ENABLE_VICTORY_CARD:
                wfp.router.add_get("/buddy_victory", handle_buddy_victory)
                wfp.router.add_route("OPTIONS", "/buddy_victory", lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_post("/miniapp_session_end", handle_miniapp_session_end)
            wfp.router.add_route("OPTIONS", "/miniapp_session_end", lambda r: _web.Response(headers=CORS_BUDDY))

            # ── Admin Analytics API ──
            wfp.router.add_post("/admin_analytics",   handle_admin_analytics_data)
            wfp.router.add_post("/admin_finance",     handle_finance_settings)
            wfp.router.add_post("/admin_set_blogger_commission", handle_set_blogger_commission)
            wfp.router.add_route("OPTIONS", "/admin_set_blogger_commission", lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_post("/admin_log_payout", handle_log_payout)
            wfp.router.add_route("OPTIONS", "/admin_log_payout", lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_post("/admin_run_job", handle_admin_run_job)
            wfp.router.add_route("OPTIONS", "/admin_run_job", lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_post("/admin_payment_find", handle_payment_lookup)
            wfp.router.add_post("/admin_ai_insights", handle_ai_insights)
            wfp.router.add_post("/admin_ab_hypotheses", handle_ai_ab_hypotheses)
            wfp.router.add_post("/admin_tz",          handle_ai_tz)
            wfp.router.add_route("OPTIONS", "/admin_analytics",   lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_route("OPTIONS", "/admin_ai_insights", lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_route("OPTIONS", "/admin_ab_hypotheses", lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_route("OPTIONS", "/admin_tz",          lambda r: _web.Response(headers=CORS_BUDDY))

            # ── Lottery API (ланки → номерні білети → розіграш поза ботом) ──
            # set_http_deps ОБОВ'ЯЗКОВО перед реєстрацією роутів нижче —
            # require_verified_uid і CORS_BUDDY визначені лише тут, нижче
            # за точку де викликається основний lottery_init() (там, де
            # ai_costs_init/finance_init).
            lottery_set_http_deps(require_verified_uid, is_admin, get_s, _web, CORS_BUDDY)
            wfp.router.add_post("/lottery_buy_ticket",       handle_lottery_buy_ticket)
            wfp.router.add_post("/lottery_status",           handle_lottery_status)
            wfp.router.add_post("/admin_lottery_save",       handle_admin_lottery_save)
            wfp.router.add_get ("/admin_lottery_export",     handle_admin_lottery_export)
            wfp.router.add_post("/admin_lottery_complete",   handle_admin_lottery_complete)
            wfp.router.add_post("/blogger_set_lottery_video", handle_blogger_set_lottery_video)
            wfp.router.add_route("OPTIONS", "/lottery_buy_ticket",        lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_route("OPTIONS", "/lottery_status",           lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_route("OPTIONS", "/admin_lottery_save",        lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_route("OPTIONS", "/admin_lottery_export",      lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_route("OPTIONS", "/admin_lottery_complete",    lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_route("OPTIONS", "/blogger_set_lottery_video", lambda r: _web.Response(headers=CORS_BUDDY))

            # ── Admin Nudge (Phase 3: нагадування проблемним учням) ──
            wfp.router.add_post("/admin_nudge_preview", handle_admin_nudge_preview)
            wfp.router.add_post("/admin_nudge_send",    handle_admin_nudge_send)
            wfp.router.add_route("OPTIONS", "/admin_nudge_preview", lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_route("OPTIONS", "/admin_nudge_send",    lambda r: _web.Response(headers=CORS_BUDDY))

            # ── Vocabulary Miniapp API ──
            wfp.router.add_post("/vocab_data",      handle_vocab_data)
            # ── Shell payload (склеєна оболонка index_v2.html) ──
            wfp.router.add_post("/miniapp_payload", handle_miniapp_payload)
            wfp.router.add_route("OPTIONS", "/miniapp_payload",
                                 lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_post("/vocab_update",    handle_vocab_update)
            wfp.router.add_post("/exercises_data",  handle_exercises_data)
            wfp.router.add_post("/topic_table",     handle_topic_table)
            wfp.router.add_post("/session_activity",handle_session_activity)
            wfp.router.add_post("/phrase_spoken",handle_phrase_spoken)
            wfp.router.add_route("OPTIONS", "/vocab_data",       lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_route("OPTIONS", "/vocab_update",     lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_route("OPTIONS", "/exercises_data",   lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_route("OPTIONS", "/topic_table",      lambda r: _web.Response(headers=CORS_BUDDY))
            wfp.router.add_route("OPTIONS", "/session_activity", lambda r: _web.Response(headers=CORS_BUDDY))

            # ── CORS preflight для всіх ендпоінтів ──────────
            cors_headers = {
                "Access-Control-Allow-Origin":  "*",
                "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
                "Access-Control-Allow-Headers": "Content-Type, Authorization",
            }
            async def handle_options(request):
                return _web.Response(status=200, headers=cors_headers)
            wfp.router.add_route("OPTIONS", "/{path_info:.*}", handle_options)
            wfp.router.add_get("/health",             lambda r: _web.Response(text="ok"))
            wfp.router.add_get("/",                   lambda r: _web.HTTPFound("https://t.me/SpeakChainBot"))
            wfp.router.add_post("/",                  lambda r: _web.HTTPFound("https://t.me/SpeakChainBot"))
            runner = _web.AppRunner(wfp)
            await runner.setup()
            port = int(os.environ.get("PORT", "8080"))
            for _p in [port, 8081, 8082, 9000]:
                try:
                    site = _web.TCPSite(runner, "0.0.0.0", _p)
                    await site.start()
                    print(f"=== HTTP :{_p} READY ===", flush=True)
                    break
                except OSError:
                    print(f"Port {_p} busy, trying next...", flush=True)
            await _asyncio.Event().wait()

        # ══════════════════════════════════════════════════════════
        # САМОЛІКУВАННЯ HTTP-ТРЕДА
        #
        # БУЛО: _asyncio.run(_start()) — БЕЗ try.
        # Будь-яка помилка при реєстрації роутів (як було з handle_err_fix —
        # функції не існувало) вбивала ВЕСЬ тред МОВЧКИ. Разом із ним падали:
        #   /pay · /wayforpay_webhook · усі мініапи · buddy · paywall
        # Тобто ОПЛАТА І ДОДАТОК. І ніхто не дізнавався — бот же «працює».
        #
        # ТЕПЕР: тред ловить помилку, чекає і піднімається САМ.
        # Пауза росте (5с → 10с → 20с → 40с → 60с), щоб не спалити CPU,
        # якщо помилка стала. Після 5 спроб — здається і КРИЧИТЬ в лог,
        # бо далі це вже не тимчасовий збій, а зламаний код.
        # ══════════════════════════════════════════════════════════
        _attempt = 0
        while True:
            try:
                _asyncio.run(_start())
                return                      # штатне завершення (не буває)
            except Exception as _he:
                _attempt += 1
                import traceback as _htb
                logger.error(
                    "🔴 HTTP-ТРЕД УПАВ (спроба %s/5): %s\n%s\n"
                    "   Це вбиває ОПЛАТУ (/pay, вебхук WayForPay) і ВСІ мініапи.",
                    _attempt, _he, _htb.format_exc()
                )
                if _attempt >= 5:
                    logger.error(
                        "🔴🔴 HTTP-ТРЕД НЕ ПІДНІМАЄТЬСЯ ПІСЛЯ 5 СПРОБ.\n"
                        "   Оплата і мініапи НЕ ПРАЦЮЮТЬ. Це зламаний код,\n"
                        "   а не тимчасовий збій. Дивіться трейсбек вище."
                    )
                    return
                _t_sleep = min(60, 5 * (2 ** (_attempt - 1)))   # 5,10,20,40,60
                print(f"HTTP thread restart in {_t_sleep}s...", flush=True)
                _t_mod.sleep(_t_sleep)

    http_thread = threading.Thread(target=run_http, daemon=True)
    http_thread.start()
    import time as _time
    _time.sleep(1)
    print("=== HTTP THREAD LAUNCHED ===", flush=True)

    main()


